export const generatedBatch105Lessons: Record<string, LessonContent> = {
  "major-depressive-disorder-rpn": {
    title: "Major Depressive Disorder",
    cellular: { title: "Pathophysiology of Major Depressive Disorder", content: "Major depressive disorder (MDD) is a mood disorder characterized by persistent depressed mood or loss of interest/pleasure (anhedonia) lasting at least 2 weeks, accompanied by functional impairment. The pathophysiology involves multiple interconnected mechanisms. The monoamine hypothesis proposes that depression results from deficiency of serotonin (5-HT), norepinephrine (NE), and/or dopamine (DA) in synaptic clefts of the limbic system and prefrontal cortex. Serotonin regulates mood, sleep, appetite, and impulse control; norepinephrine regulates energy, alertness, and motivation; dopamine regulates pleasure, reward, and psychomotor activity. Beyond simple neurotransmitter deficiency, current understanding includes neuroplasticity dysfunction: chronic stress elevates cortisol (HPA axis hyperactivation), which damages hippocampal neurons, reduces brain-derived neurotrophic factor (BDNF), and impairs neurogenesis. This leads to hippocampal volume reduction (seen on MRI in chronic depression) and disrupted neural circuits between the prefrontal cortex (executive function), amygdala (emotional processing), and hippocampus (memory and context). Inflammatory mechanisms also contribute: elevated pro-inflammatory cytokines (IL-6, TNF-alpha, CRP) are found in depressed patients and can drive sickness behavior resembling depression. The practical nurse assesses mood, monitors safety, administers medications, and provides therapeutic communication." },
    riskFactors: ["Family history of depression (first-degree relatives have 2-3x increased risk)", "Personal history of previous depressive episodes (50% recurrence after first episode, 80% after second)", "Female sex (2x more common in women, related to hormonal fluctuations)", "Chronic medical illness: heart disease, diabetes, cancer, stroke, chronic pain, hypothyroidism", "Substance use disorders (alcohol, cannabis, opioids)", "Adverse childhood experiences (abuse, neglect, trauma)", "Social isolation, lack of social support, loneliness", "Major life stressors: bereavement, divorce, job loss, financial hardship"],
    diagnostics: ["DSM-5 criteria: at least 5 of 9 symptoms for 2+ weeks including depressed mood OR anhedonia (SIG-E-CAPS mnemonic: Sleep changes, Interest loss, Guilt/worthlessness, Energy loss, Concentration impairment, Appetite/weight changes, Psychomotor changes, Suicidal ideation)", "PHQ-9 (Patient Health Questionnaire-9): validated screening and severity tool (0-4 minimal, 5-9 mild, 10-14 moderate, 15-19 moderately severe, 20-27 severe)", "Columbia Suicide Severity Rating Scale (C-SSRS): structured suicidal ideation and behavior assessment", "TSH level to rule out hypothyroidism (mimics depression)", "CBC and metabolic panel to exclude medical causes (anemia, electrolyte imbalance)", "Vitamin B12, folate, vitamin D levels (deficiencies can cause or worsen depression)"],
    management: ["Mild depression: psychotherapy alone may be sufficient (CBT or interpersonal therapy)", "Moderate to severe depression: combination of antidepressant medication AND psychotherapy (most effective approach)", "First-line medications: SSRIs (sertraline, escitalopram) or SNRIs (venlafaxine, duloxetine)", "Allow 4-6 weeks for full antidepressant effect; do not discontinue early for perceived lack of response", "Safety planning for patients with suicidal ideation: means restriction, crisis contacts, coping strategies", "Exercise: regular aerobic exercise (30 minutes, 3-5 times/week) has evidence-based antidepressant effect comparable to mild medication benefit"],
    nursingActions: ["Assess mood and suicidal ideation at every interaction using validated tools (PHQ-9, C-SSRS)", "Implement suicide precautions if indicated: remove sharps, monitor closely, one-to-one observation for imminent risk", "Administer prescribed antidepressants; educate patient that therapeutic effect takes 4-6 weeks while side effects may appear sooner", "Monitor for serotonin syndrome when starting or increasing serotonergic medications: agitation, confusion, tachycardia, hypertension, hyperthermia, clonus, hyperreflexia, diaphoresis", "Encourage regular sleep-wake schedule (sleep hygiene), structured daily activities, and social engagement", "Provide non-judgmental therapeutic communication: active listening, validation of feelings, open-ended questions", "Document mood assessments, suicidal ideation screening, and medication response at each shift"],
    assessmentFindings: ["Depressed mood: sadness, emptiness, hopelessness, tearfulness (may report feeling numb rather than sad)", "Anhedonia: loss of interest or pleasure in previously enjoyed activities (key diagnostic criterion)", "Sleep disturbances: insomnia (especially early morning awakening -- terminal insomnia) or hypersomnia", "Appetite changes: decreased appetite with weight loss OR increased appetite with weight gain (atypical feature)", "Psychomotor changes: retardation (slowed speech, movement, thinking) OR agitation (restlessness, pacing, hand-wringing)", "Fatigue and low energy despite adequate rest", "Difficulty concentrating, making decisions, or remembering", "Feelings of worthlessness or excessive/inappropriate guilt", "Suicidal ideation: passive (wishing to be dead) or active (plan, intent, means)"],
    signs: { left: ["Mild-moderate depression responding to psychotherapy and/or medication", "No suicidal ideation or plan", "Maintaining basic self-care and daily functioning", "Engaging in treatment and demonstrating coping skills"], right: ["Severe depression with psychotic features (delusions, hallucinations)", "Active suicidal ideation with specific plan and access to means", "Self-harm behaviors or recent suicide attempt", "Catatonic features (immobility, mutism, posturing)", "Significant functional decline (unable to work, self-care, or care for dependents)", "Treatment-resistant depression (failed 2+ adequate medication trials)"] },
    medications: [{ name: "Sertraline (Zoloft)", type: "Selective serotonin reuptake inhibitor (SSRI)", action: "Selectively blocks serotonin reuptake transporter (SERT) in presynaptic neurons, increasing serotonin availability in the synaptic cleft; downstream effects include receptor downregulation and increased neuroplasticity over weeks", sideEffects: "GI disturbances (nausea, diarrhea -- most common early side effect), sexual dysfunction (30-40%), headache, insomnia or sedation, weight gain (long-term), increased anxiety initially", contra: "Concurrent MAOIs (wait 14 days), concurrent pimozide, known hypersensitivity", pearl: "Start 50 mg daily, increase by 50 mg every 2-4 weeks to max 200 mg; therapeutic effect takes 4-6 weeks; MOST COMMON side effect causing discontinuation is sexual dysfunction; GI side effects typically resolve within 1-2 weeks; safest SSRI in cardiac patients (SADHART trial); warn about increased suicidal ideation in adolescents/young adults during first 1-2 weeks (black box warning -- risk is rare but monitoring is required)" }, { name: "Mirtazapine (Remeron)", type: "Noradrenergic and specific serotonergic antidepressant (NaSSA)", action: "Blocks alpha-2 adrenergic autoreceptors (increasing NE and 5-HT release) and blocks 5-HT2 and 5-HT3 serotonin receptors (reduces sexual dysfunction and nausea); also blocks H1 histamine receptors (causing sedation and appetite stimulation)", sideEffects: "Sedation (most significant at lower doses paradoxically), weight gain, increased appetite, dry mouth, elevated cholesterol", contra: "Concurrent MAOIs, known hypersensitivity", pearl: "Start 15 mg at bedtime; paradoxically MORE sedating at 15 mg than 30 mg (at higher doses, noradrenergic activation counteracts antihistamine sedation); excellent choice for depressed patients with insomnia, poor appetite, or weight loss; virtually NO sexual dysfunction (major advantage over SSRIs); also useful as augmentation agent added to SSRI" }, { name: "Trazodone", type: "Serotonin antagonist and reuptake inhibitor (SARI)", action: "Blocks 5-HT2A receptors and weakly inhibits serotonin reuptake; also blocks alpha-1 adrenergic receptors and H1 histamine receptors causing sedation; at low doses (25-100 mg) primarily used as a sleep aid rather than antidepressant", sideEffects: "Sedation (therapeutic when used for insomnia), orthostatic hypotension, priapism (rare but serious in males), dry mouth, dizziness", contra: "Concurrent MAOIs, known hypersensitivity, recent MI (due to orthostatic hypotension risk)", pearl: "25-100 mg at bedtime for insomnia (most common use); antidepressant doses are 300-600 mg/day (rarely used at this dose due to sedation); PRIAPISM is a rare but urological emergency (painful sustained erection requiring emergent intervention -- teach male patients to report immediately); commonly prescribed alongside SSRIs for insomnia since SSRIs can disrupt sleep" }],
    pearls: ["SIG-E-CAPS mnemonic for depression symptoms: Sleep, Interest, Guilt, Energy, Concentration, Appetite, Psychomotor, Suicidal ideation -- need 5 of 9 for diagnosis, must include depressed mood OR anhedonia", "Antidepressants take 4-6 WEEKS for full therapeutic effect -- patients often stop medications early believing they are not working; early side effects (nausea, headache, anxiety) typically resolve in 1-2 weeks", "BLACK BOX WARNING: all antidepressants carry FDA warning for increased suicidal ideation in patients under 25 during first 1-4 weeks of treatment; this risk is rare but requires close monitoring (weekly visits initially)", "SSRIs should NOT be abruptly discontinued: gradual taper over 2-4 weeks to prevent discontinuation syndrome (dizziness, nausea, anxiety, electric shock sensations -- brain zaps)", "Depression is a MEDICAL illness, not a character weakness: therapeutic communication should validate this and reduce stigma", "Morning light exposure (30 minutes of bright light within 1 hour of waking) is an evidence-based adjunct treatment for depression, especially seasonal pattern"],
    quiz: [{ question: "A patient started on sertraline 50 mg daily 5 days ago reports no improvement in mood. The practical nurse should:", options: ["Report that the medication is ineffective and should be changed", "Educate the patient that antidepressants take 4-6 weeks for full therapeutic effect", "Recommend doubling the dose immediately", "Discontinue the medication"], correct: 1, rationale: "SSRIs require 4-6 weeks for full therapeutic effect due to the time needed for receptor downregulation and neuroplasticity changes. The patient should be educated about this timeline and encouraged to continue the medication." }, { question: "Which assessment tool is validated for screening and monitoring depression severity?", options: ["Glasgow Coma Scale", "PHQ-9 (Patient Health Questionnaire-9)", "CAGE questionnaire", "Mini-Mental State Exam"], correct: 1, rationale: "The PHQ-9 is a validated 9-item tool that screens for depression and quantifies severity (0-27 scale). It corresponds to the DSM-5 diagnostic criteria and is widely used in clinical settings." }, { question: "A patient on an SSRI develops agitation, confusion, tremor, tachycardia, and fever after starting tramadol. The practical nurse suspects:", options: ["Neuroleptic malignant syndrome", "Serotonin syndrome", "Medication allergy", "Withdrawal syndrome"], correct: 1, rationale: "Serotonin syndrome results from excessive serotonergic activity, often when two serotonergic medications are combined (SSRI + tramadol). Symptoms include agitation, confusion, tachycardia, hyperthermia, clonus, and hyperreflexia. This is a medical emergency." }]
  },
  "major-depressive-disorder-rn": {
    title: "Major Depressive Disorder",
    cellular: { title: "Neurobiology", content: "The nurse managing MDD must independently perform comprehensive suicide risk assessment, implement safety interventions, manage complex medication regimens, and recognize treatment-resistant depression. Advanced neurobiology of MDD includes the stress-diathesis model: genetic vulnerability (serotonin transporter gene 5-HTTLPR short allele, BDNF Val66Met polymorphism) combined with environmental stressors activates the HPA axis, causing sustained cortisol elevation that is neurotoxic to hippocampal neurons. Neuroimaging findings in MDD include: decreased prefrontal cortex activity (impaired executive function and emotion regulation), increased amygdala reactivity (heightened negative emotional processing), decreased hippocampal volume (impaired memory and contextual processing), and disrupted default mode network connectivity (rumination). The glutamate system is increasingly recognized: NMDA receptor antagonism (ketamine mechanism) produces rapid antidepressant effects within hours, suggesting that glutamatergic dysfunction contributes to depression beyond monoamine deficiency alone. The nurse performs structured suicide risk assessment using evidence-based tools, implements graduated levels of observation, manages medication titration and switching, monitors for treatment response using validated scales (PHQ-9 trending), and coordinates the multidisciplinary treatment team including psychiatry, psychology, social work, and case management." },
    riskFactors: ["Suicide risk factors requiring immediate assessment: previous suicide attempt (strongest predictor of future attempt), family history of suicide, access to lethal means (firearms -- most lethal method), recent discharge from psychiatric hospitalization (highest risk period: first 2 weeks), substance intoxication, social isolation, hopelessness (more predictive than depression severity alone)", "Treatment-resistant depression risk factors: comorbid anxiety disorder, personality disorder, substance use, chronic pain, inadequate treatment duration or dose, non-adherence, psychosocial stressors", "Bipolar depression misdiagnosed as MDD: always screen for history of manic/hypomanic episodes before starting antidepressant (antidepressant monotherapy can trigger mania in bipolar disorder)", "Peripartum depression: affects 10-20% of women; screening recommended at 4-6 weeks postpartum; Edinburgh Postnatal Depression Scale (EPDS) above 10 suggests depression", "Late-life depression: often presents with somatic complaints, cognitive impairment (pseudodementia), and functional decline rather than sadness; high suicide completion rate in elderly white males"],
    diagnostics: ["Columbia Suicide Severity Rating Scale (C-SSRS): structured assessment of suicidal ideation severity (wish to be dead, non-specific active thoughts, active ideation with method, intent, plan) and behavior (preparatory acts, aborted attempt, interrupted attempt, actual attempt)", "PHQ-9 serial monitoring: assess at baseline and every 2-4 weeks; response defined as 50% or greater reduction in score; remission defined as score below 5; failure to respond by 6-8 weeks suggests need for treatment modification", "Medication adherence assessment: patient interview, pharmacy refill records, serum drug levels for TCAs (therapeutic window monitoring)", "Edinburgh Postnatal Depression Scale (EPDS): 10-item screening tool specific to perinatal depression; score above 10 = probable depression; score above 13 = likely major depression; Question 10 specifically asks about self-harm", "GAD-7 for comorbid anxiety (present in 60% of MDD patients)", "MDQ (Mood Disorder Questionnaire) to screen for bipolar spectrum before starting antidepressant"],
    management: ["Suicide risk stratification and intervention: LOW risk (passive ideation, no plan, protective factors) -- safety plan, outpatient follow-up; MODERATE risk (ideation with vague plan, ambivalence) -- psychiatric consultation, consider hospitalization, means restriction; HIGH risk (specific plan, intent, access to means, few protective factors) -- psychiatric emergency, one-to-one observation, voluntary or involuntary hospitalization", "STAR*D trial implications for treatment sequencing: Step 1: SSRI (37% remission); Step 2: switch SSRI, add bupropion, or switch to SNRI (25% additional remission); Step 3: switch to mirtazapine or add lithium/T3; Step 4: MAOI or TCA combination; overall: 67% eventual remission through systematic sequencing", "Augmentation strategies for partial responders: add bupropion to SSRI (most common), add aripiprazole 2-5 mg (FDA-approved augmentation), add lithium, add thyroid hormone (T3 25-50 mcg)", "ECT for treatment-resistant or emergent depression: most effective treatment for severe/refractory depression (70-90% response); indicated for active suicidality, catatonia, psychotic depression, pregnancy (when medications contraindicated), and treatment-resistant depression", "Ketamine/esketamine for treatment-resistant depression: rapid-acting (hours vs weeks); esketamine (Spravato) nasal spray FDA-approved for TRD; administered in certified clinic with 2-hour monitoring"],
    nursingActions: ["Perform comprehensive suicide risk assessment on admission and with any clinical change: use C-SSRS, assess risk factors (previous attempts, access to means, hopelessness, substance use, recent losses) and protective factors (reasons for living, social support, children, religious beliefs)", "Implement appropriate level of observation: constant observation/1:1 (imminent risk), every 15-minute checks (moderate risk), every 30-minute checks (low risk); document patient location, activity, and affect at each check", "Perform environmental safety assessment: remove sharps, cords, belts, plastic bags, glass items; secure medications; check for contraband on admission and after passes/visits; bathroom safety assessment", "Manage antidepressant medication transitions: cross-taper protocols (gradually decrease old medication while gradually increasing new); MAOI washout periods (14 days from SSRI to MAOI, 5 weeks from fluoxetine to MAOI due to long half-life)", "Monitor for medication-specific adverse effects: SSRI activation syndrome (anxiety, agitation, insomnia in first 1-2 weeks), hyponatremia (SIADH, especially in elderly on SSRIs), serotonin syndrome, QTc prolongation (citalopram dose-dependent)", "Coordinate ECT nursing care: NPO after midnight, remove dentures, pre-procedure atropine or glycopyrrolate, post-procedure monitoring (confusion, headache, memory), document seizure duration", "Conduct therapeutic groups: CBT skills groups, coping skills training, psychoeducation about depression, discharge planning groups"],
    assessmentFindings: ["Suicide risk level determination: ideation type (passive vs active), specificity of plan, access to means, timeline, intent, hopelessness level, protective factors, behavioral indicators (giving away possessions, sudden calmness after severe depression, saying goodbye)", "Treatment response trajectory: early improvement (week 2) predicts eventual response; lack of ANY improvement by week 4 predicts non-response; full response typically by week 6-8; residual symptoms (especially insomnia, fatigue, concentration) common even in responders", "Medication side effect profiles affecting adherence: sexual dysfunction (most common reason for SSRI discontinuation), weight gain (especially paroxetine, mirtazapine), emotional blunting (feeling flat, disconnected), GI disturbance (usually transient)", "Post-ECT assessment: brief confusion and headache are expected and resolve within 1-2 hours; retrograde amnesia (memory loss for events around treatment) is common; anterograde memory typically returns to baseline within 2-4 weeks after treatment course completion", "Discharge readiness indicators: consistent denial of suicidal ideation, future-oriented thinking, engagement with outpatient plan, adequate social support, means restriction implemented, medications filled"],
    signs: { left: ["Depression responding to first-line SSRI with PHQ-9 declining", "Suicidal ideation resolved with safety plan in place", "Engaging in therapy and developing coping skills", "Adequate social support and outpatient follow-up arranged"], right: ["Active suicidal ideation with specific plan and intent requiring 1:1 observation", "Treatment-resistant depression (failed 2+ adequate trials) requiring ECT referral", "Psychotic depression (delusions of guilt, worthlessness, nihilism; auditory hallucinations commanding self-harm)", "Serotonin syndrome from drug interaction requiring emergent treatment", "Severe SSRI-induced hyponatremia (Na below 125) with confusion and seizure risk", "Catatonic depression (immobility, mutism, negativism) requiring ECT"] },
    medications: [{ name: "Escitalopram (Lexapro)", type: "SSRI (S-enantiomer of citalopram)", action: "Most selective SSRI with minimal off-target receptor binding; blocks SERT increasing serotonin availability; clean pharmacological profile with fewest drug interactions among SSRIs", sideEffects: "Nausea, headache, sexual dysfunction, insomnia, QTc prolongation (less than citalopram but still monitor)", contra: "Concurrent MAOIs, QTc prolongation, concurrent pimozide", pearl: "Start 10 mg daily, max 20 mg; considered the cleanest SSRI pharmacologically (fewest drug interactions, most selective for SERT); preferred in patients on multiple medications; QTc prolongation risk is dose-dependent (max 20 mg/day; citalopram max restricted to 40 mg due to QTc risk); RN should obtain baseline ECG in elderly patients or those with cardiac risk factors" }, { name: "Bupropion (Wellbutrin)", type: "Norepinephrine-dopamine reuptake inhibitor (NDRI)", action: "Inhibits reuptake of norepinephrine and dopamine (does NOT affect serotonin); unique mechanism among antidepressants; also a nicotinic acetylcholine receptor antagonist (mechanism for smoking cessation)", sideEffects: "Insomnia, agitation, headache, dry mouth, nausea, SEIZURE RISK (dose-dependent)", contra: "Seizure disorder, bulimia or anorexia nervosa (increased seizure risk), concurrent MAOIs, abrupt alcohol or benzodiazepine withdrawal", pearl: "150-450 mg/day in divided doses (XL formulation allows once-daily dosing); KEY ADVANTAGES: no sexual dysfunction (often used to counteract SSRI sexual side effects), no weight gain (may cause weight loss), helps with smoking cessation (marketed as Zyban); KEY DISADVANTAGE: dose-dependent seizure risk (do not exceed 450 mg/day); can worsen anxiety (avoid as monotherapy in anxious depression); commonly added to SSRI as augmentation for partial response" }, { name: "Aripiprazole (Abilify) as MDD Augmentation", type: "Atypical antipsychotic (dopamine partial agonist)", action: "Partial agonist at D2 dopamine receptors and 5-HT1A serotonin receptors; stabilizes dopamine activity (not full blockade); partial agonist at 5-HT1A enhances serotonergic antidepressant effects; FDA-approved as adjunct to antidepressants for MDD", sideEffects: "Akathisia (most common -- restlessness, inability to sit still), weight gain, metabolic effects, tardive dyskinesia (long-term risk), insomnia", contra: "Known hypersensitivity, dementia-related psychosis in elderly (increased mortality)", pearl: "2-5 mg/day as MDD augmentation (much lower dose than for schizophrenia/bipolar); FDA-approved adjunct to antidepressants for MDD; akathisia is the most common reason for discontinuation (dose-related, may respond to dose reduction or propranolol); RN should assess for akathisia at each visit using Barnes Akathisia Rating Scale; monitor metabolic parameters (weight, glucose, lipids) every 3-6 months" }],
    pearls: ["The most dangerous period for completed suicide is the FIRST 2 WEEKS after psychiatric discharge and the FIRST 2 WEEKS after starting an antidepressant (as energy improves before mood, enabling action on suicidal thoughts)", "STAR*D trial: the most important depression treatment study; showed that with systematic sequencing of medications, 67% of patients eventually achieve remission; however, response rates decline with each subsequent trial (37% -> 25% -> 16% -> 13%)", "Bipolar screening is MANDATORY before starting antidepressants: antidepressant monotherapy in bipolar disorder can trigger mania, rapid cycling, or mixed states; always ask about past episodes of elevated mood, decreased sleep need, risky behavior, grandiosity", "Fluoxetine has the LONGEST half-life of any SSRI (2-6 days for parent compound, 4-16 days for active metabolite norfluoxetine): advantage = no discontinuation syndrome; disadvantage = 5-week washout needed before MAOI", "ECT is the MOST EFFECTIVE treatment for severe depression (70-90% response vs 30-50% for medications): indicated when rapid response is needed (active suicidality), psychotic features present, catatonia, or 2+ medication trials have failed", "Peripartum depression screening is recommended at EVERY postpartum visit: Edinburgh Postnatal Depression Scale (EPDS) above 10 warrants further assessment; untreated maternal depression affects infant attachment and development"],
    quiz: [{ question: "A patient with MDD partially responded to sertraline 200 mg (maximum dose) after 8 weeks. PHQ-9 decreased from 22 to 14. The nurse should anticipate:", options: ["Continuing current dose indefinitely", "Adding bupropion or aripiprazole as augmentation based on STAR*D evidence", "Switching to another SSRI", "Discontinuing all medication"], correct: 1, rationale: "Partial response (50% improvement but not remission) to maximum-dose SSRI warrants augmentation rather than switching. STAR*D evidence supports adding bupropion (most common augmentation) or aripiprazole (FDA-approved MDD augmentation)." }, { question: "Before starting sertraline for depression, the nurse should screen for:", options: ["History of seizures", "History of manic or hypomanic episodes (bipolar screening)", "History of kidney stones", "History of migraines"], correct: 1, rationale: "Bipolar screening is mandatory before starting any antidepressant. Antidepressant monotherapy in undiagnosed bipolar disorder can trigger mania, rapid cycling, or mixed states. Use the MDQ (Mood Disorder Questionnaire) for screening." }, { question: "A patient is being discharged after hospitalization for a suicide attempt. The HIGHEST risk period for another attempt is:", options: ["6 months after discharge", "The first 2 weeks after discharge", "1 year after discharge", "The day of discharge only"], correct: 1, rationale: "The first 2 weeks after psychiatric discharge is the highest-risk period for completed suicide. Close follow-up within 48-72 hours of discharge, safety planning, means restriction, and crisis contact information are essential discharge interventions." }]
  },
  "major-depressive-disorder-np": {
    title: "MDD",
    cellular: { title: "Pharmacotherapy, Neuromodulation", content: "The clinician managing MDD prescribes first-line and augmentation pharmacotherapy, manages treatment-resistant depression (TRD), and coordinates neuromodulation therapies. TRD is defined as failure to achieve remission after 2 or more adequate antidepressant trials (adequate dose for adequate duration of 6-8 weeks each). TRD affects approximately 30% of MDD patients and carries significant morbidity: increased suicide risk, functional disability, healthcare utilization, and mortality. Before diagnosing TRD, the clinician must verify: (1) accurate diagnosis (rule out bipolar disorder, medical causes, substance use), (2) medication adherence (only 50% of patients take antidepressants as prescribed), (3) adequate dose and duration of each trial, (4) comorbid conditions addressed (anxiety, PTSD, personality disorders, chronic pain). Pharmacological management of TRD follows evidence-based algorithms: optimization (maximize current medication dose), augmentation (add a second agent to boost response), switching (change to a different class), and combination (use two antidepressants from different classes simultaneously). Neuromodulation options include: ECT (most effective, 70-90% response), repetitive transcranial magnetic stimulation (rTMS, FDA-approved for TRD), vagus nerve stimulation (VNS, implanted), and deep brain stimulation (DBS, investigational). The newest pharmacotherapy option is esketamine (Spravato) nasal spray, FDA-approved for TRD, which provides rapid antidepressant effect through NMDA receptor antagonism within hours to days, compared to weeks for traditional antidepressants." },
    riskFactors: ["Treatment-resistant depression: comorbid anxiety (60% of MDD patients), personality disorder (especially borderline), chronic pain, substance use disorder, medical comorbidity, psychosocial adversity", "Pharmacogenomic factors: CYP2D6 and CYP2C19 polymorphisms affect metabolism of most antidepressants; poor metabolizers have higher drug levels and more side effects; ultra-rapid metabolizers have subtherapeutic levels despite adequate doses", "SSRI non-response predictors: severe depression (PHQ-9 above 20), psychotic features, melancholic features, chronic depression (dysthymia more than 2 years), early onset (before age 18), comorbid personality disorder", "Peripartum depression requiring prescribing considerations: breastfeeding compatibility, teratogenicity risk, sertraline and paroxetine least transferred in breast milk", "Elderly depression: increased sensitivity to side effects (falls from SSRIs, hyponatremia, QTc prolongation), drug interactions with polypharmacy, cognitive impairment complicating assessment", "Suicidality with treatment initiation: FDA black box warning for age under 25; monitor weekly for first 4 weeks then biweekly for next 4 weeks"],
    diagnostics: ["Pharmacogenomic testing (GeneSight, Genomind): tests CYP2D6, CYP2C19, CYP3A4 polymorphisms to guide medication selection; most useful after 1-2 failed trials to optimize subsequent prescribing; emerging evidence base but not yet universally recommended", "Measurement-based care: PHQ-9 at every visit to quantify response (response = 50% reduction, remission = score below 5); GAD-7 for comorbid anxiety; track side effect burden", "TRD staging: Thase-Rush staging model (Stage 1: failed 1 adequate SSRI trial; Stage 2: failed 2 adequate trials from different classes; Stage 3: failed TCA; Stage 4: failed MAOI; Stage 5: failed ECT); higher stages predict lower probability of response to next intervention", "Thyroid function (TSH, free T4, T3): subclinical hypothyroidism common in TRD; T3 augmentation effective even with normal thyroid function", "Metabolic monitoring for patients on augmentation antipsychotics: fasting glucose, HbA1c, lipid panel, weight, waist circumference at baseline, 3 months, then annually", "Inflammatory biomarkers (emerging): CRP above 3 mg/L may predict better response to anti-inflammatory augmentation strategies (celecoxib, omega-3 fatty acids) or bupropion/nortriptyline over SSRIs"],
    management: ["First-line prescribing: SSRI (sertraline, escitalopram) or SNRI (venlafaxine, duloxetine); start low, titrate to therapeutic dose, monitor 6-8 weeks before declaring failure", "Augmentation for partial response: bupropion addition (most evidence), aripiprazole 2-5 mg (FDA-approved), lithium 300-600 mg (target level 0.6-0.8 mEq/L), T3 thyroid 25-50 mcg, mirtazapine addition (California Rocket Fuel = venlafaxine + mirtazapine)", "Switching for non-response: within-class switch (SSRI to different SSRI: 25% response), between-class switch (SSRI to SNRI, bupropion, or mirtazapine: higher response rate)", "TRD pharmacotherapy: esketamine (Spravato) nasal spray -- 56-84 mg intranasally, administered in REMS-certified clinic, requires 2-hour post-dose monitoring for dissociation, sedation, and BP changes; combined with new oral antidepressant", "Neuromodulation: rTMS (repetitive transcranial magnetic stimulation) -- daily sessions for 4-6 weeks targeting left dorsolateral prefrontal cortex; FDA-approved for TRD; no anesthesia required; side effects: headache, scalp discomfort", "MAOI prescribing for refractory cases: phenelzine 45-90 mg/day or tranylcypromine 30-60 mg/day; most effective antidepressant class but restricted by dietary interactions (tyramine-containing foods: aged cheese, cured meats, draft beer, fermented foods) and drug interactions; hypertensive crisis risk with dietary non-compliance"],
    nursingActions: ["Prescribe antidepressants using measurement-based care: track PHQ-9 at every visit, adjust treatment based on quantified response rather than clinical impression alone", "Select medication based on patient-specific factors: side effect profile (bupropion for patients concerned about sexual dysfunction or weight gain; mirtazapine for patients with insomnia and poor appetite; duloxetine for comorbid chronic pain), drug interactions, cost, prior response", "Order pharmacogenomic testing after 1-2 failed trials to guide subsequent medication selection: CYP2D6 poor metabolizers need lower doses of many antidepressants; CYP2C19 poor metabolizers need dose adjustment for citalopram/escitalopram, sertraline", "Prescribe esketamine for TRD: verify REMS certification of treatment site, combine with new oral antidepressant, monitor BP pre-dose and at 40/60/90/120 minutes post-dose, assess for dissociation using CADSS scale, ensure patient does not drive day of treatment", "Implement MAOI dietary and drug interaction counseling: provide comprehensive tyramine restriction list, medical alert identification, educate about hypertensive crisis symptoms (severe headache, stiff neck, nausea, sweating -- take nifedipine 10 mg PO and go to ER)", "Monitor for metabolic effects of augmentation antipsychotics: weight, waist circumference, fasting glucose, lipid panel at baseline, 3 months, then annually", "Develop long-term maintenance plan: after remission, continue antidepressant for minimum 6-12 months for first episode, 2+ years for recurrent episodes, indefinitely for 3+ episodes or high-risk patients"],
    assessmentFindings: ["Treatment response categorization: non-response (less than 25% PHQ-9 improvement after adequate trial), partial response (25-49% improvement), response (50%+ improvement), remission (PHQ-9 below 5)", "Pharmacogenomic result interpretation: CYP2D6 poor metabolizer (PM) -- reduce doses of drugs metabolized by 2D6 (fluoxetine, paroxetine, venlafaxine, many TCAs); CYP2C19 PM -- reduce citalopram/escitalopram dose (max 20/10 mg respectively); ultra-rapid metabolizer (UM) -- may need higher doses or different medication", "TRD staging for treatment planning: early-stage TRD (failed 1-2 trials) -- switching and augmentation strategies; late-stage TRD (failed 3+ trials) -- neuromodulation (rTMS, ECT), esketamine, MAOIs", "Medication discontinuation planning: taper all antidepressants (except fluoxetine) over 2-4 weeks minimum; venlafaxine and paroxetine have the most severe discontinuation syndromes (require especially slow tapers over 4-8 weeks); symptoms: dizziness, nausea, anxiety, electric shock sensations (brain zaps), irritability"],
    signs: { left: ["Remission achieved on first-line SSRI (PHQ-9 below 5) -- continue maintenance therapy", "Partial response improved to remission with augmentation", "Stable on maintenance therapy with no suicidal ideation and good function", "Pharmacogenomic testing guided successful medication selection"], right: ["TRD after 3+ adequate trials requiring neuromodulation (ECT or rTMS)", "MAOI hypertensive crisis from dietary non-compliance (severe headache, stiff neck, hypertension -- emergency)", "Esketamine severe dissociation or hemodynamic instability during monitored session", "Psychotic depression requiring antipsychotic + antidepressant combination or ECT", "Severe suicidality requiring inpatient ECT", "Serotonin syndrome from drug interaction (SSRI + tramadol, SSRI + MAOI, SSRI + linezolid)"] },
    medications: [{ name: "Esketamine (Spravato) Nasal Spray", type: "NMDA receptor antagonist (S-enantiomer of ketamine)", action: "Blocks NMDA glutamate receptors triggering rapid increase in BDNF and synaptogenesis in prefrontal cortex and hippocampus; produces antidepressant effect within hours to days compared to weeks for traditional antidepressants; also modulates AMPA receptor signaling enhancing synaptic plasticity", sideEffects: "Dissociation (most common, usually resolves within 2 hours), sedation, dizziness, nausea, increased BP, anxiety, altered perception of time", contra: "Aneurysmal vascular disease, AVM, intracerebral hemorrhage history, known hypersensitivity", pearl: "56-84 mg intranasally; REMS program requires administration in certified healthcare setting with 2-hour post-dose monitoring; combined with new oral antidepressant; sessions typically twice weekly for weeks 1-4, then weekly for weeks 5-8, then weekly or biweekly for maintenance; NP must be certified to prescribe; most patients report dissociative effects that resolve within 90 minutes; do not eat 2 hours before or drink 30 minutes before administration" }, { name: "Lithium Augmentation", type: "Mood stabilizer / antidepressant augmentation", action: "Multiple mechanisms: inhibits GSK-3beta (increasing BDNF and neuroplasticity), modulates glutamate neurotransmission, stabilizes circadian rhythms, has anti-suicidal effects independent of mood effects (unique property among psychotropics)", sideEffects: "Narrow therapeutic index (0.6-1.2 mEq/L); GI upset, fine tremor, polyuria/polydipsia (nephrogenic DI), hypothyroidism, weight gain, acne; TOXICITY: coarse tremor, ataxia, confusion, seizures, cardiac arrhythmias", contra: "Severe renal impairment, dehydration, sodium depletion (increases lithium levels), Brugada syndrome", pearl: "300-600 mg/day for MDD augmentation (target level 0.6-0.8 mEq/L, lower than bipolar range); the ONLY medication with anti-suicidal effect independent of mood improvement; monitor levels at 5-7 days, then monthly for 3 months, then every 3-6 months; monitor TSH and creatinine every 6 months; drug interactions: NSAIDs, thiazides, and ACE inhibitors INCREASE lithium levels (potentially toxic); dehydration and low-sodium diet INCREASE levels" }, { name: "Venlafaxine XR (Effexor XR)", type: "Serotonin-norepinephrine reuptake inhibitor (SNRI)", action: "Inhibits serotonin reuptake at lower doses (75 mg) and adds norepinephrine reuptake inhibition at higher doses (150-225 mg), providing dual-mechanism antidepressant effect; at very high doses (above 225 mg) may also inhibit dopamine reuptake", sideEffects: "Nausea (most common, usually transient), headache, dizziness, insomnia, sexual dysfunction, hypertension (dose-dependent -- monitor BP), diaphoresis, severe discontinuation syndrome", contra: "Concurrent MAOIs, uncontrolled hypertension, narrow-angle glaucoma", pearl: "75-375 mg/day; dose-dependent mechanism: 75 mg = primarily serotonergic (like SSRI), 150-225 mg = serotonin + norepinephrine (SNRI effect), 225-375 mg = adds weak dopamine reuptake (triple reuptake); hypertension monitoring required especially above 225 mg; has the WORST discontinuation syndrome of all antidepressants -- taper VERY slowly over 4-8 weeks (25 mg decrements every 1-2 weeks); combined with mirtazapine = California Rocket Fuel (most potent oral combination for TRD)" }],
    pearls: ["Measurement-based care (tracking PHQ-9 at every visit) DOUBLES the rate of depression remission compared to standard clinical impression alone: NP should treat depression like hypertension -- with numbers, not just clinical judgment", "California Rocket Fuel (venlafaxine + mirtazapine): the most potent oral antidepressant combination for TRD; venlafaxine blocks serotonin and NE reuptake while mirtazapine blocks alpha-2 autoreceptors (increasing NE and 5-HT release) and blocks 5-HT2/5-HT3 (reducing sexual dysfunction and nausea from venlafaxine)", "Lithium is the ONLY medication proven to reduce suicide risk independent of its mood effects: NP should strongly consider lithium augmentation in depressed patients with suicidal ideation", "Pharmacogenomic testing is most cost-effective after 1-2 failed trials: CYP2D6 and CYP2C19 results can guide medication selection and dosing; results are lifelong and applicable to future prescribing across all specialties", "Esketamine represents a paradigm shift in depression treatment: hours to response vs weeks for traditional antidepressants; however, it requires REMS-certified clinic, twice-weekly initial visits, and 2-hour monitoring -- significant patient burden", "Antidepressant maintenance duration: first episode = 6-12 months after remission; second episode = 2+ years; third or more episodes = indefinite maintenance (recurrence rate exceeds 90% without maintenance)"],
    quiz: [{ question: "An NP has prescribed sertraline 150 mg for 8 weeks with PHQ-9 improving from 20 to 12 (40% reduction). This represents:", options: ["Remission -- continue current dose", "Response -- continue current dose", "Partial response -- augment or optimize before declaring treatment failure", "Non-response -- switch medication class"], correct: 2, rationale: "A 40% reduction in PHQ-9 is a partial response (25-49% improvement). The clinician should augment (add bupropion, aripiprazole, lithium, or T3) or optimize (increase sertraline to maximum 200 mg) before switching classes." }, { question: "An NP is considering lithium augmentation for a depressed patient with persistent suicidal ideation. A unique benefit of lithium relevant to this patient is:", options: ["It works faster than SSRIs", "It has anti-suicidal effects independent of its mood-stabilizing properties", "It has no side effects at therapeutic doses", "It is the first-line treatment for MDD"], correct: 1, rationale: "Lithium is the ONLY psychotropic medication with proven anti-suicidal properties independent of its mood effects. This makes it particularly valuable for depressed patients with persistent suicidal ideation, even as an augmentation agent at lower doses than used for bipolar disorder." }, { question: "A patient on venlafaxine XR 225 mg reports wanting to stop the medication abruptly due to side effects. The clinician should advise:", options: ["Stopping immediately is safe since venlafaxine is not addictive", "Venlafaxine must be tapered very slowly over 4-8 weeks to prevent severe discontinuation syndrome", "Switching directly to fluoxetine 20 mg", "Halving the dose and stopping after 3 days"], correct: 1, rationale: "Venlafaxine has the WORST discontinuation syndrome of all antidepressants (dizziness, nausea, brain zaps, anxiety, flu-like symptoms). It must be tapered very slowly in 25 mg decrements every 1-2 weeks over 4-8 weeks to minimize withdrawal effects." }]
  },
  "generalized-anxiety-disorder-rpn": {
    title: "Generalized Anxiety Disorder",
    cellular: { title: "Pathophysiology of GAD", content: "Generalized anxiety disorder (GAD) is characterized by excessive, uncontrollable worry about multiple life domains (health, finances, work, family) occurring more days than not for at least 6 months, causing significant distress and functional impairment. The pathophysiology involves dysregulation of the fear circuitry: the amygdala (threat detection center) becomes hyperactive, while the prefrontal cortex (rational thought and emotion regulation) has diminished inhibitory control over the amygdala. Neurotransmitter imbalances include decreased GABA (the primary inhibitory neurotransmitter that normally dampens anxiety), decreased serotonin (which modulates mood and anxiety), and increased norepinephrine (heightened sympathetic arousal). The HPA axis is chronically activated, producing elevated cortisol that maintains a state of hypervigilance. Autonomic nervous system dysregulation results in chronic sympathetic activation producing the physical symptoms of anxiety: muscle tension, GI disturbance, insomnia, tachycardia, and fatigue. The practical nurse assesses anxiety severity, monitors medication effects, and provides supportive care including relaxation techniques." },
    riskFactors: ["Female sex (2x more common)", "Family history of anxiety disorders", "Childhood adversity or trauma", "Chronic medical conditions (thyroid disease, COPD, chronic pain)", "Temperamental traits: behavioral inhibition, neuroticism", "Substance use (caffeine, stimulants) or withdrawal (alcohol, benzodiazepines)", "Comorbid depression (60% overlap)", "Stressful life events"],
    diagnostics: ["DSM-5 criteria: excessive worry about multiple domains for 6+ months with 3+ of 6 symptoms (restlessness, fatigue, concentration difficulty, irritability, muscle tension, sleep disturbance)", "GAD-7 screening tool: 0-4 minimal, 5-9 mild, 10-14 moderate, 15-21 severe", "TSH to rule out hyperthyroidism", "Urine drug screen if substance-induced anxiety suspected", "CBC, BMP to exclude medical causes", "ECG if cardiac symptoms present (palpitations, chest tightness)"],
    management: ["CBT is first-line psychotherapy (most evidence-based for GAD)", "SSRI or SNRI as first-line pharmacotherapy", "Buspirone as non-sedating anxiolytic alternative", "Benzodiazepines for short-term use only (2-4 weeks) while waiting for SSRI/SNRI effect", "Lifestyle modifications: regular exercise, sleep hygiene, caffeine reduction, stress management techniques", "Avoid long-term benzodiazepine use: dependence, tolerance, cognitive impairment, fall risk in elderly"],
    nursingActions: ["Assess anxiety level using GAD-7 at each encounter", "Teach relaxation techniques: deep breathing (diaphragmatic), progressive muscle relaxation, grounding exercises (5-4-3-2-1 senses technique)", "Administer prescribed medications and monitor for side effects", "Monitor for benzodiazepine dependence signs if prescribed: dose escalation, clock-watching, requesting early refills", "Provide calm, reassuring environment with consistent routines", "Educate about caffeine reduction (common anxiety trigger)", "Document anxiety levels, triggers identified, and coping strategies used"],
    assessmentFindings: ["Excessive worry disproportionate to actual circumstances", "Restlessness, feeling keyed up or on edge", "Muscle tension (especially neck, shoulders, jaw -- may present as tension headache)", "Sleep disturbance (difficulty falling asleep due to racing thoughts)", "Difficulty concentrating or mind going blank", "Irritability", "Fatigue despite adequate sleep", "Physical symptoms: GI distress, headaches, palpitations, sweating, trembling"],
    signs: { left: ["Mild-moderate anxiety managed with CBT and lifestyle modifications", "SSRI/SNRI effective with minimal side effects", "Patient using coping strategies successfully", "Functioning maintained in work and relationships"], right: ["Severe anxiety impairing daily functioning despite treatment", "Panic attacks developing alongside generalized anxiety", "Benzodiazepine dependence from long-term use", "Suicidal ideation from co-occurring depression", "Agoraphobia developing (avoiding situations due to anxiety)", "Substance use as self-medication (alcohol most common)"] },
    medications: [{ name: "Buspirone (BuSpar)", type: "5-HT1A partial agonist (azapirone)", action: "Partial agonist at serotonin 5-HT1A receptors in the dorsal raphe and presynaptic autoreceptors; modulates serotonin transmission to reduce anxiety without sedation, cognitive impairment, or dependence risk", sideEffects: "Dizziness, nausea, headache, nervousness initially, lightheadedness", contra: "Concurrent MAOIs, known hypersensitivity", pearl: "5-10 mg TID (max 60 mg/day); takes 2-4 WEEKS for full effect (not useful for acute anxiety); NO sedation, NO dependence, NO withdrawal; will NOT work in patients who have previously used benzodiazepines (they expect immediate sedation and perceive buspirone as ineffective); best for patients who have NEVER taken benzodiazepines; can be combined with SSRI safely" }, { name: "Sertraline (Zoloft)", type: "SSRI", action: "Blocks serotonin reuptake increasing 5-HT availability in the synaptic cleft; anxiolytic effect through downregulation of 5-HT1A autoreceptors and modulation of amygdala reactivity", sideEffects: "GI disturbance, sexual dysfunction, headache, initial anxiety worsening (first 1-2 weeks)", contra: "Concurrent MAOIs, known hypersensitivity", pearl: "Start 25 mg daily for GAD (lower starting dose than for depression to avoid initial anxiety worsening); increase by 25 mg every 1-2 weeks to 50-200 mg; takes 4-6 weeks for full anxiolytic effect; may WORSEN anxiety initially -- warn patients and consider short-term benzodiazepine bridge" }, { name: "Lorazepam (Ativan)", type: "Benzodiazepine (intermediate-acting)", action: "Enhances GABA-A receptor function by binding the benzodiazepine binding site, increasing chloride channel opening frequency, hyperpolarizing neurons, and producing anxiolytic, sedative, and muscle relaxant effects", sideEffects: "Sedation, cognitive impairment, psychomotor slowing, respiratory depression, dependence (with prolonged use), paradoxical agitation (elderly), rebound anxiety on discontinuation", contra: "Severe respiratory insufficiency, sleep apnea, acute narrow-angle glaucoma, pregnancy (category D), concurrent opioids (respiratory depression risk)", pearl: "0.5-1 mg PO every 8 hours PRN; use for SHORT-TERM only (2-4 weeks) as bridge while SSRI/SNRI takes effect; DEPENDENCE develops with regular use beyond 4 weeks; discontinuation requires gradual taper (reduce by 10-25% every 1-2 weeks); abrupt discontinuation can cause seizures; AVOID in elderly (Beers Criteria -- increased fall risk, cognitive impairment, paradoxical agitation)" }],
    pearls: ["SSRIs are FIRST-LINE pharmacotherapy for GAD, NOT benzodiazepines: SSRIs treat the underlying neurotransmitter imbalance; benzodiazepines are symptom-management only and create dependence", "Benzodiazepines should be LIMITED to 2-4 weeks maximum: dependence develops rapidly; cognitive impairment and fall risk in elderly; difficult withdrawal; always have an exit strategy before prescribing", "Buspirone only works if the patient has NEVER taken benzodiazepines: patients who have experienced the immediate relief of benzodiazepines perceive buspirone (which takes weeks to work) as ineffective", "CBT is as effective as medication for GAD and has MORE durable effects: anxiety management skills persist after therapy ends; medication effects disappear when medication stops", "Initial SSRI anxiety worsening: SSRIs can temporarily worsen anxiety during the first 1-2 weeks (serotonin receptor activation before downregulation occurs); start at lower doses and warn patients", "The 5-4-3-2-1 grounding technique: name 5 things you can SEE, 4 things you can TOUCH, 3 things you can HEAR, 2 things you can SMELL, 1 thing you can TASTE -- effective for acute anxiety and panic"],
    quiz: [{ question: "First-line pharmacotherapy for generalized anxiety disorder is:", options: ["Benzodiazepines", "SSRIs or SNRIs", "Antipsychotics", "Opioids"], correct: 1, rationale: "SSRIs and SNRIs are first-line pharmacotherapy for GAD. They treat the underlying serotonin dysregulation. Benzodiazepines are only for short-term bridging (2-4 weeks) while SSRIs take effect." }, { question: "A patient asks why buspirone is not working after 3 days. The practical nurse explains:", options: ["The dose needs to be doubled immediately", "Buspirone takes 2-4 weeks for full effect, similar to SSRIs", "Buspirone should provide immediate relief like benzodiazepines", "The medication should be discontinued"], correct: 1, rationale: "Buspirone takes 2-4 weeks for full anxiolytic effect, similar to SSRIs. It works by modulating serotonin receptors, which requires time for receptor adaptation." }, { question: "An elderly patient with GAD is prescribed lorazepam 2 mg TID on a long-term basis. The practical nurse should:", options: ["Administer as prescribed without concern", "Recognize this as potentially inappropriate per Beers Criteria and report concerns to the prescriber", "Increase the dose if the patient requests it", "Add another benzodiazepine for breakthrough anxiety"], correct: 1, rationale: "Long-term benzodiazepine use in elderly patients is inappropriate per Beers Criteria due to increased risk of falls, cognitive impairment, dependence, and paradoxical agitation. The nurse should report concerns to the prescriber." }]
  },
  "generalized-anxiety-disorder-rn": {
    title: "GAD",
    cellular: { title: "Anxiety Assessment", content: "The nurse managing GAD performs comprehensive anxiety assessment distinguishing GAD from other anxiety disorders, manages acute anxiety episodes, and coordinates stepped-care treatment. GAD must be differentiated from: panic disorder (discrete panic attacks with sudden intense fear, physical symptoms, and fear of losing control), social anxiety disorder (fear of social/performance situations), specific phobias (fear of specific objects/situations), OCD (obsessions and compulsions), and PTSD (following traumatic exposure). Medical mimics must be excluded: hyperthyroidism (weight loss, tremor, heat intolerance, tachycardia), pheochromocytoma (paroxysmal hypertension, diaphoresis, palpitations), cardiac arrhythmias, COPD/asthma (dyspnea causing anxiety), and caffeine/stimulant use. The stepped-care model for GAD includes: Step 1 (mild): psychoeducation, self-help, guided relaxation; Step 2 (moderate): CBT (individual or group), SSRI/SNRI; Step 3 (severe/treatment-resistant): combination therapy, augmentation strategies, specialist referral. The nurse implements crisis intervention for acute anxiety, manages benzodiazepine tapers, monitors for substance use as self-medication, and facilitates transition from acute to maintenance management." },
    riskFactors: ["Comorbidity pattern: GAD + MDD (60%), GAD + social anxiety (30%), GAD + panic disorder (25%), GAD + substance use (20-30%)", "Benzodiazepine dependence risk: develops within 4-6 weeks of daily use; elderly at highest risk for adverse effects", "Misdiagnosis risk: bipolar disorder mixed/hypomanic episodes can present with anxiety and agitation; stimulant use, hyperthyroidism", "Chronic pain comorbidity: anxiety amplifies pain perception through central sensitization and catastrophizing", "Workplace impairment: GAD causes more disability days than many chronic medical conditions", "Treatment dropout: 50% of patients discontinue treatment within 6 months; side effects and perceived lack of improvement are main reasons"],
    diagnostics: ["Structured diagnostic assessment: Mini International Neuropsychiatric Interview (MINI) or Structured Clinical Interview for DSM-5 (SCID-5) for accurate diagnosis and comorbidity identification", "GAD-7 serial monitoring (response = 50% reduction, remission = score below 5)", "Hamilton Anxiety Rating Scale (HAM-A): clinician-administered 14-item scale for severity assessment and treatment response monitoring", "Comprehensive medical workup to exclude organic causes: TSH, CBC, BMP, calcium, B12, cortisol if clinically indicated", "Substance use assessment: AUDIT for alcohol, DAST for drugs (anxiety commonly co-occurs with substance use and each worsens the other)", "Sleep assessment: Insomnia Severity Index (ISI) or Pittsburgh Sleep Quality Index; sleep disturbance is both a symptom and perpetuating factor"],
    management: ["CBT protocol for GAD: cognitive restructuring (challenging worry thoughts), behavioral experiments (testing feared outcomes), progressive relaxation training, worry exposure (scheduled worry time), problem-solving skills; typically 12-16 sessions", "SSRI/SNRI optimization: start at lower dose than for depression (sertraline 25 mg, escitalopram 5 mg, venlafaxine 37.5 mg); titrate more slowly (every 2 weeks); full anxiolytic dose often higher than antidepressant dose", "Benzodiazepine taper protocol for dependent patients: convert to long-acting equivalent (diazepam), reduce by 10-25% every 1-2 weeks, slow further at lower doses, monitor for withdrawal (insomnia, tremor, anxiety, seizure risk), expect 2-4 months for complete taper", "Augmentation for partial SSRI response: add buspirone, add hydroxyzine for acute anxiety, add gabapentin/pregabalin (evidence in GAD, no dependence risk like benzodiazepines)", "Mindfulness-based stress reduction (MBSR): 8-week structured program with evidence equivalent to CBT for GAD; teaches present-moment awareness reducing future-oriented worry"],
    nursingActions: ["Perform comprehensive anxiety assessment differentiating GAD from panic disorder, social anxiety, PTSD, OCD, and medical causes", "Implement stepped-care treatment model: match intervention intensity to symptom severity", "Manage acute anxiety episodes: calm environment, therapeutic presence, guided breathing, grounding techniques; avoid excessive reassurance (reinforces anxiety)", "Implement and monitor benzodiazepine taper protocols: calculate equivalent doses, create taper schedule, monitor withdrawal symptoms (CIWA-like approach), assess for seizure risk", "Teach and reinforce CBT techniques: cognitive restructuring (is this thought realistic? What evidence supports/contradicts it?), behavioral activation (gradually approaching avoided situations), relaxation response training", "Monitor for substance use as self-medication: alcohol use to manage anxiety is extremely common and worsens anxiety long-term through rebound and withdrawal mechanisms", "Coordinate group therapy referrals: CBT groups for anxiety, MBSR programs, support groups; group formats are equally effective and more cost-effective than individual therapy for GAD"],
    assessmentFindings: ["GAD vs panic disorder differentiation: GAD = chronic pervasive worry without discrete attacks; panic disorder = recurrent unexpected panic attacks (intense fear peaking in minutes with physical symptoms: palpitations, chest pain, dyspnea, derealization)", "Anxiety severity impact on functioning: mild (able to work and socialize but with effort), moderate (avoiding some activities, decreased productivity), severe (unable to work, significant avoidance, homebound)", "Somatic presentation of anxiety: some patients present with physical complaints (headaches, GI symptoms, chest pain) without recognizing anxiety as the cause; repeated negative medical workups should prompt anxiety screening", "Benzodiazepine dependence indicators: dose escalation, clock-watching, requesting early refills, obtaining prescriptions from multiple providers, anxiety about running out of medication, withdrawal symptoms between doses"],
    signs: { left: ["GAD responding to CBT and/or SSRI with improving GAD-7 scores", "Successfully using coping strategies to manage worry", "Functioning maintained or improving in work and relationships", "Sleep improving with anxiety treatment"], right: ["Acute anxiety crisis with hyperventilation, dissociation, or functional paralysis", "Benzodiazepine dependence requiring structured taper", "GAD with comorbid MDD and suicidal ideation", "Agoraphobia developing from avoidance behavior generalization", "Substance use disorder complicating anxiety treatment", "Treatment-resistant GAD (failed 2+ adequate medication trials plus CBT)"] },
    medications: [{ name: "Venlafaxine XR (Effexor XR)", type: "SNRI", action: "Dual serotonin and norepinephrine reuptake inhibition; noradrenergic component may provide additional anxiolytic benefit for somatic anxiety symptoms (muscle tension, restlessness)", sideEffects: "Nausea, dizziness, insomnia, sexual dysfunction, hypertension at higher doses, severe discontinuation syndrome", contra: "Concurrent MAOIs, uncontrolled hypertension", pearl: "Start 37.5 mg daily for GAD (even lower than depression starting dose); target 75-225 mg; FDA-approved for GAD; dual mechanism addresses both cognitive worry (serotonin) and somatic symptoms (norepinephrine); RN must monitor BP especially at doses above 150 mg; discontinuation syndrome is SEVERE -- taper very slowly over 4-8 weeks" }, { name: "Hydroxyzine (Vistaril/Atarax)", type: "Antihistamine (H1 antagonist) with anxiolytic properties", action: "Blocks H1 histamine receptors producing sedation and anxiolytic effects; also has anticholinergic and antiserotonergic properties; useful for acute anxiety without benzodiazepine dependence risk", sideEffects: "Sedation, dry mouth, dizziness, QTc prolongation at higher doses, urinary retention", contra: "QTc prolongation, early pregnancy, known hypersensitivity", pearl: "25-50 mg every 6 hours PRN for acute anxiety; NO dependence or abuse potential (major advantage over benzodiazepines); useful as PRN anxiolytic in patients with substance use history who cannot receive benzodiazepines; sedation is the main limitation; monitor QTc if using doses above 100 mg/day" }, { name: "Pregabalin (Lyrica)", type: "Alpha-2-delta calcium channel ligand (anticonvulsant)", action: "Binds alpha-2-delta subunit of voltage-gated calcium channels reducing excitatory neurotransmitter release; FDA-approved for GAD in Europe (not US, but used off-label); effective for both psychological and somatic anxiety symptoms", sideEffects: "Sedation, dizziness, weight gain, peripheral edema, blurred vision; Schedule V (some abuse potential)", contra: "Known hypersensitivity; dose adjustment in renal impairment", pearl: "150-600 mg/day divided BID or TID for GAD; FDA-approved for GAD in Europe; NOT FDA-approved for GAD in the US but widely used off-label; advantages: rapid onset (within 1 week vs 4-6 weeks for SSRI), effective for somatic symptoms, useful when SSRI/SNRI have failed; disadvantages: Schedule V (some abuse potential), weight gain, sedation; do not combine with benzodiazepines (additive sedation)" }],
    pearls: ["GAD is the anxiety disorder MOST LIKELY to present with somatic complaints: headaches, GI disturbance, muscle tension, fatigue, insomnia -- patients may undergo extensive medical workups before anxiety is recognized", "Benzodiazepine taper is one of the most challenging clinical procedures: takes 2-4 months; rebound anxiety is expected and must be differentiated from relapse; rate should slow as dose decreases (last 25% of taper is hardest); psychological support during taper is essential", "CBT has the MOST DURABLE effect of any GAD treatment: relapse rates are lower after CBT (30-40%) than after medication discontinuation (60-70%); skills learned persist indefinitely", "Excessive reassurance is CONTRAINDICATED in GAD: while well-intentioned, reassurance temporarily reduces anxiety but reinforces the worry cycle; instead, validate the emotion while encouraging coping strategies", "Caffeine reduction is a simple, high-yield intervention: caffeine blocks adenosine receptors increasing sympathetic activation; many GAD patients consume 3-5 cups of coffee and notice significant improvement with reduction to 1 cup or elimination"],
    quiz: [{ question: "A patient with GAD has been taking lorazepam 1 mg TID daily for 8 months and wants to stop. The nurse should:", options: ["Recommend stopping immediately since lorazepam is not addictive", "Implement a gradual taper over 2-4 months, reducing dose by 10-25% every 1-2 weeks", "Switch to a higher-potency benzodiazepine for faster discontinuation", "Continue the current dose indefinitely"], correct: 1, rationale: "After 8 months of daily benzodiazepine use, physical dependence has developed. Abrupt discontinuation risks seizures. A gradual taper (10-25% reduction every 1-2 weeks over 2-4 months) with close monitoring is required." }, { question: "A GAD patient asks the nurse for reassurance that their spouse is safe every 30 minutes. The BEST therapeutic response is:", options: ["Provide reassurance each time to reduce anxiety", "Validate the anxiety while encouraging the patient to use coping skills instead of seeking reassurance", "Ignore the requests", "Tell the patient to stop worrying"], correct: 1, rationale: "Excessive reassurance temporarily reduces anxiety but reinforces the worry cycle (negative reinforcement). The therapeutic approach is to validate the emotion while redirecting to coping strategies learned in CBT." }, { question: "An RN notes that a patient with GAD also reports discrete episodes of sudden intense fear with palpitations, chest pain, and feeling of impending doom lasting 10-15 minutes. This suggests:", options: ["Worsening GAD", "Comorbid panic disorder", "Medication side effect", "Cardiac emergency"], correct: 1, rationale: "Discrete episodes of sudden intense fear with physical symptoms (palpitations, chest pain, derealization) peaking in minutes describe panic attacks, suggesting comorbid panic disorder alongside GAD. This requires cardiac workup to rule out arrhythmia and may require treatment modification." }]
  },
  "generalized-anxiety-disorder-np": {
    title: "GAD",
    cellular: { title: "Pharmacotherapy", content: "The clinician managing GAD prescribes first-line and advanced pharmacotherapy, manages treatment-resistant anxiety, coordinates psychotherapy referrals, and addresses complex comorbidity. Treatment-resistant GAD is defined as inadequate response to 2 or more adequate medication trials (adequate dose for 8+ weeks each) plus evidence-based psychotherapy. Before declaring treatment resistance, the clinician must verify: accurate diagnosis (rule out bipolar disorder, medical causes), medication adherence, adequate trial duration (8 weeks minimum for full anxiolytic effect), comorbidity management (depression, substance use, PTSD must be addressed concurrently), and lifestyle factors (caffeine, sleep, exercise). Advanced pharmacotherapy for GAD includes: SSRI/SNRI optimization (doses for anxiety are often HIGHER than for depression), augmentation with buspirone, gabapentin/pregabalin, quetiapine XR (low-dose), or mirtazapine, and combination strategies. Pregabalin has the most robust evidence for GAD in Europe (FDA-approved there but not in the US). Quetiapine XR 50-150 mg has significant evidence for GAD but carries metabolic risks that limit its use to treatment-resistant cases. The clinician also manages benzodiazepine prescribing decisions, recognizing that while these agents provide immediate relief, long-term use carries substantial risks (cognitive impairment, falls in elderly, dependence, withdrawal seizures, association with dementia in some studies)." },
    riskFactors: ["Treatment-resistant GAD risk factors: comorbid personality disorder (especially avoidant and dependent), chronic medical illness, ongoing psychosocial stressors, substance use, inadequate psychotherapy engagement", "Pharmacogenomic considerations: CYP2D6 metabolism affects many anxiolytics (paroxetine, venlafaxine); CYP2C19 affects escitalopram, citalopram; CYP3A4 affects buspirone, alprazolam", "Benzodiazepine prescribing risk assessment: history of substance use disorder (absolute relative contraindication), elderly (Beers Criteria), respiratory disease, concurrent opioids (respiratory depression), pregnancy (cleft palate risk)", "Anxiety-pain cycle: chronic pain conditions (fibromyalgia, IBS, chronic headache) have bidirectional relationship with anxiety; addressing both simultaneously improves outcomes", "Pregnancy considerations: sertraline safest SSRI in pregnancy (most data); paroxetine associated with cardiac malformations (avoid); benzodiazepines associated with floppy infant syndrome and cleft palate (avoid)"],
    diagnostics: ["Treatment response assessment using GAD-7 at every visit: response (50% reduction), partial response (25-49%), non-response (less than 25%), remission (below 5)", "Pharmacogenomic testing for treatment-resistant cases: guides SSRI/SNRI selection and dosing based on metabolizer status", "Cortisol assessment: morning cortisol, 24-hour urinary free cortisol if Cushing syndrome suspected; DHEA-S if adrenal cause suspected", "Sleep study if sleep apnea contributing to daytime anxiety and fatigue", "Neuropsychological testing if cognitive complaints significant (differentiate anxiety-related concentration impairment from neurocognitive disorder)", "QIDS-SR or PHQ-9 for comorbid depression monitoring alongside GAD-7"],
    management: ["First-line: SSRI (sertraline 50-200 mg, escitalopram 10-20 mg) or SNRI (venlafaxine XR 75-225 mg, duloxetine 60-120 mg); start low, titrate slowly over 2-4 weeks to avoid initial anxiety worsening", "Second-line: buspirone (augmentation to SSRI or monotherapy), pregabalin (150-600 mg/day, off-label in US but strong evidence), mirtazapine (15-45 mg, especially if insomnia)", "Augmentation for partial SSRI response: add buspirone 15-30 mg/day, add pregabalin 150-300 mg/day, add hydroxyzine 25-50 mg PRN, add low-dose quetiapine XR 50-150 mg (last resort due to metabolic risks)", "Treatment-resistant strategy: combination therapy (SSRI + pregabalin, SNRI + buspirone + gabapentin), specialized anxiety clinic referral, intensive outpatient CBT program, consider MAOI for refractory cases", "Benzodiazepine prescribing framework: prescribe ONLY with clear time-limited plan (2-4 weeks), document informed consent including dependence risk, use lowest effective dose, schedule follow-up for taper initiation, NEVER prescribe with opioids without compelling justification", "Maintenance therapy: continue medication 12+ months after remission for first episode; indefinite maintenance for recurrent GAD (relapse rate 60-70% within 1 year of discontinuation)"],
    nursingActions: ["Prescribe evidence-based pharmacotherapy with systematic dose optimization using GAD-7 measurement-based care", "Select medication based on comorbidity profile: duloxetine for GAD + chronic pain, mirtazapine for GAD + insomnia + weight loss, bupropion addition for GAD + depression + sexual dysfunction from SSRI", "Manage benzodiazepine prescribing decisions: risk-benefit assessment, informed consent, time-limited prescribing, taper planning from day 1, PDMP (prescription drug monitoring program) check before prescribing", "Order pharmacogenomic testing after 2+ failed trials to optimize subsequent prescribing", "Prescribe and coordinate CBT referral: evidence strongly supports combined medication + CBT over either alone; specify CBT for anxiety (not general counseling)", "Monitor for metabolic effects if using quetiapine augmentation: weight, glucose, lipids at baseline and every 3 months", "Develop relapse prevention plan: identify early warning signs, maintain therapeutic gains, plan for medication tapering if appropriate"],
    assessmentFindings: ["Treatment algorithm position: first-line (SSRI/SNRI naive) vs second-line (failed 1 adequate trial) vs treatment-resistant (failed 2+ trials + CBT)", "Comorbidity mapping for integrated treatment: GAD + MDD = dual SSRI benefit; GAD + chronic pain = duloxetine; GAD + insomnia = mirtazapine or gabapentin; GAD + substance use = avoid benzodiazepines, use buspirone or SSRI", "Benzodiazepine risk stratification: low risk (young, no substance history, acute stressor) vs moderate risk (age above 50, concurrent medications) vs high risk (substance use history, elderly, concurrent opioids, respiratory disease)", "Maintenance therapy decision: first episode with full remission = 12 months minimum then cautious taper; recurrent episodes = indefinite maintenance (relapse rate too high to justify discontinuation)"],
    signs: { left: ["GAD in remission on first-line SSRI with GAD-7 below 5", "Successfully using CBT skills to manage residual worry", "Stable on maintenance therapy without side effects", "Comorbid conditions addressed concurrently"], right: ["Treatment-resistant GAD failing 3+ medication trials and CBT", "Benzodiazepine use disorder developing from chronic prescribing", "GAD with comorbid substance use disorder requiring integrated treatment", "Severe GAD with agoraphobia preventing treatment engagement", "Iatrogenic complications: SSRI-induced hyponatremia, QTc prolongation from polypharmacy", "Pregnancy in patient on teratogenic medications requiring urgent medication review"] },
    medications: [{ name: "Duloxetine (Cymbalta)", type: "SNRI", action: "Balanced serotonin and norepinephrine reuptake inhibition; FDA-approved for GAD, MDD, diabetic neuropathy, fibromyalgia, and chronic musculoskeletal pain; dual anxiolytic and analgesic properties make it ideal for GAD with comorbid pain conditions", sideEffects: "Nausea (most common, take with food), dry mouth, constipation, dizziness, sexual dysfunction, hepatotoxicity (rare, avoid in liver disease), hypertension", contra: "Hepatic impairment, concurrent MAOIs, uncontrolled narrow-angle glaucoma, heavy alcohol use", pearl: "Start 30 mg daily for 1 week then increase to 60 mg; max 120 mg for GAD; the IDEAL choice for GAD + chronic pain (fibromyalgia, neuropathy, musculoskeletal pain); FDA-approved for more indications than any other SNRI; avoid in liver disease (hepatotoxic metabolites); discontinuation syndrome can be significant (taper over 2-4 weeks); nausea is the most common side effect -- taking with food and starting at 30 mg reduces this" }, { name: "Quetiapine XR (Seroquel XR) Low-Dose", type: "Atypical antipsychotic (as GAD augmentation)", action: "At low doses (50-150 mg), primarily blocks H1 (sedation), 5-HT2A (anxiolytic), and alpha-1 adrenergic receptors; norquetiapine metabolite acts as NET inhibitor (norepinephrine reuptake inhibition providing antidepressant/anxiolytic effect similar to SNRI); minimal D2 blockade at low doses", sideEffects: "Sedation (significant), weight gain, metabolic syndrome, QTc prolongation, orthostatic hypotension, akathisia (paradoxical at low doses)", contra: "Dementia-related psychosis (black box), concurrent QTc-prolonging drugs, known hypersensitivity", pearl: "50-150 mg at bedtime for treatment-resistant GAD; the norquetiapine metabolite provides SNRI-like activity at low doses; RCTs support efficacy for GAD but metabolic risks limit use to treatment-resistant cases; NP should use ONLY after 2+ first-line agents have failed; mandatory metabolic monitoring (weight, glucose, lipids); useful as monotherapy in patients who cannot tolerate SSRIs/SNRIs" }, { name: "Gabapentin (Neurontin) for GAD", type: "Alpha-2-delta calcium channel ligand", action: "Binds alpha-2-delta subunit of voltage-gated calcium channels reducing excitatory neurotransmitter release; anxiolytic effect similar to pregabalin but with less predictable pharmacokinetics (saturable absorption); off-label for GAD", sideEffects: "Sedation, dizziness, weight gain, peripheral edema, ataxia", contra: "Known hypersensitivity; dose adjustment in renal impairment", pearl: "300-1800 mg/day divided TID for GAD; advantages: not scheduled (unlike pregabalin which is Schedule V), less expensive, minimal drug interactions, useful for GAD + neuropathic pain; disadvantages: TID dosing, saturable absorption (higher doses have diminishing bioavailability), less robust evidence base than pregabalin for GAD; NP may prefer gabapentin over pregabalin in patients with substance use history (lower perceived abuse potential)" }],
    pearls: ["GAD maintenance therapy should continue for at least 12 months after remission: relapse rate within 1 year of discontinuation is 60-70%; recurrent GAD (2+ episodes) warrants indefinite maintenance", "Duloxetine is the optimal choice for GAD + chronic pain: FDA-approved for both conditions with a single medication, reducing pill burden and side effects", "Quetiapine XR for GAD should be LAST RESORT due to metabolic risks: despite strong RCT evidence, the risk-benefit ratio only favors use in true treatment-resistant cases", "Benzodiazepine prescribing best practice: check PDMP before every prescription, document risk-benefit discussion, set clear timeline (2-4 weeks), plan taper from day 1, never co-prescribe with opioids without documentation of medical necessity", "CBT combined with medication is MORE effective than either alone: NP should prescribe BOTH for moderate-severe GAD; the combination produces higher remission rates and lower relapse rates than monotherapy with either modality"],
    quiz: [{ question: "An NP is selecting medication for a patient with GAD and comorbid fibromyalgia. The OPTIMAL choice is:", options: ["Lorazepam for immediate anxiety relief", "Duloxetine for dual anxiolytic and analgesic benefit", "Propranolol for physical anxiety symptoms", "Quetiapine XR for treatment-resistant anxiety"], correct: 1, rationale: "Duloxetine is FDA-approved for both GAD and fibromyalgia, making it the optimal single-agent choice for this comorbidity pattern. It provides dual anxiolytic and analgesic effects through balanced serotonin and norepinephrine reuptake inhibition." }, { question: "An NP considers prescribing quetiapine XR for GAD. This should be reserved for:", options: ["First-line treatment of mild GAD", "Treatment-resistant cases after 2+ first-line agents have failed", "Any patient requesting a non-SSRI option", "All patients with insomnia and anxiety"], correct: 1, rationale: "Quetiapine XR has metabolic risks (weight gain, diabetes, dyslipidemia) that limit its use to treatment-resistant GAD cases where 2+ first-line agents have failed. Mandatory metabolic monitoring is required." }, { question: "Before prescribing a benzodiazepine, the clinician should:", options: ["Obtain written consent from the patient's family", "Check the prescription drug monitoring program (PDMP), document risk-benefit discussion, and establish a time-limited plan with taper", "Refer to a psychiatrist since NPs cannot prescribe controlled substances", "Prescribe the highest effective dose for rapid relief"], correct: 1, rationale: "Safe benzodiazepine prescribing requires: PDMP check, informed consent with documented risk-benefit discussion, time-limited prescribing (2-4 weeks), taper plan from day 1, and never co-prescribing with opioids without documented justification." }]
  },
  "bipolar-disorder-rpn": {
    title: "Bipolar Disorder",
    cellular: { title: "Pathophysiology of Bipolar Disorder", content: "Bipolar disorder is a chronic mood disorder characterized by cycling between episodes of mania (or hypomania) and depression, with euthymic (normal mood) periods between episodes. Bipolar I disorder requires at least one manic episode (elevated/expansive/irritable mood with increased energy lasting 7+ days or requiring hospitalization). Bipolar II disorder requires at least one hypomanic episode (4+ days, less severe than mania, no psychotic features, no hospitalization required) AND at least one major depressive episode. The pathophysiology involves dysregulation of multiple neurotransmitter systems: excessive dopamine activity during mania (explaining euphoria, grandiosity, psychomotor activation, and psychotic features), serotonin dysfunction (contributing to depressive episodes), and disrupted glutamate/GABA balance affecting neural excitability. Circadian rhythm disruption is central to bipolar disorder: the suprachiasmatic nucleus (biological clock) is dysregulated, causing sleep-wake cycle disturbances that can trigger mood episodes. Kindling theory suggests that initial episodes are triggered by external stressors, but over time, episodes become self-generating and more frequent without treatment, supporting the need for lifelong mood stabilizer therapy. The practical nurse monitors mood states, administers mood stabilizers, implements safety measures during acute episodes, and educates about medication adherence." },
    riskFactors: ["Strong genetic component (80% heritability; 10x risk if first-degree relative affected)", "Sleep disruption as a trigger for manic episodes", "Substance use (stimulants and cocaine can trigger mania; alcohol worsens depression)", "Antidepressant monotherapy without mood stabilizer (can trigger mania/rapid cycling)", "Stressful life events (triggering initial episodes)", "Postpartum period (high risk for mood episodes)", "Seasonal pattern (depression in winter, mania in spring/summer)", "Comorbid ADHD, anxiety disorders, substance use disorders"],
    diagnostics: ["DSM-5 criteria for manic episode: elevated/expansive/irritable mood + increased energy for 7+ days with 3+ symptoms (or 4+ if irritable only): DIG-FAST mnemonic (Distractibility, Impulsivity/Indiscretion, Grandiosity, Flight of ideas, Activity increase, Sleep decreased, Talkativeness/pressured speech)", "Mood Disorder Questionnaire (MDQ) screening tool", "Young Mania Rating Scale (YMRS) for mania severity", "PHQ-9 for depressive episode severity", "TSH (hypothyroidism can mimic bipolar depression; lithium causes hypothyroidism)", "Urine drug screen (stimulant-induced mania must be excluded)", "BMP, CBC, LFTs (baseline before starting mood stabilizers)"],
    management: ["Mood stabilizers are the FOUNDATION of treatment: lithium (gold standard), valproic acid, lamotrigine, carbamazepine", "Acute mania: lithium or valproic acid PLUS atypical antipsychotic (olanzapine, quetiapine, risperidone)", "Bipolar depression: lamotrigine, quetiapine, or lurasidone (NOT antidepressant monotherapy)", "NEVER prescribe antidepressant monotherapy (without mood stabilizer) in bipolar disorder: triggers mania, rapid cycling, or mixed states", "Maintenance therapy is LIFELONG: prevents recurrence and progressive deterioration", "Sleep hygiene and circadian rhythm stabilization: regular sleep-wake schedule is protective against mood episodes"],
    nursingActions: ["Assess current mood state: manic (elevated, irritable, grandiose), depressive (sad, hopeless, anhedonia), mixed (features of both simultaneously), or euthymic (stable)", "During manic episodes: ensure safety (patients may engage in reckless behavior: spending sprees, sexual indiscretions, dangerous activities), set firm limits with empathy, provide low-stimulation environment, ensure adequate nutrition and hydration (patients may forget to eat/drink due to hyperactivity), monitor sleep", "Administer mood stabilizers as prescribed; monitor therapeutic levels: lithium (0.8-1.2 mEq/L acute, 0.6-0.8 maintenance), valproic acid (50-125 mcg/mL)", "Monitor for lithium toxicity: early signs (nausea, vomiting, diarrhea, fine tremor) vs severe toxicity (coarse tremor, ataxia, confusion, seizures, cardiac arrhythmias)", "Teach medication adherence: patients often stop mood stabilizers when feeling well (especially during hypomania when they feel energized and creative) -- this is the most common cause of relapse", "Educate about avoiding alcohol and recreational drugs (trigger mood episodes)", "Monitor for suicidal ideation in both manic and depressive phases"],
    assessmentFindings: ["Manic episode: elevated or irritable mood, grandiosity, decreased need for sleep (3-4 hours and feels rested), pressured speech (rapid, loud, difficult to interrupt), flight of ideas (racing thoughts), distractibility, increased goal-directed activity or psychomotor agitation, excessive involvement in risky activities", "Depressive episode: same as MDD (sadness, anhedonia, sleep changes, energy loss, concentration difficulty, worthlessness, suicidal ideation)", "Mixed features: simultaneous manic and depressive symptoms (e.g., racing thoughts with despair, high energy with hopelessness) -- HIGHEST suicide risk", "Psychotic features in severe mania: grandiose delusions (belief of special powers, identity), auditory hallucinations"],
    signs: { left: ["Euthymic on maintenance mood stabilizer therapy", "Recognizing early warning signs of mood episode", "Adherent to medication and follow-up", "Using coping strategies and maintaining sleep hygiene"], right: ["Acute mania with psychotic features requiring hospitalization", "Mixed episode with severe suicidal ideation", "Rapid cycling (4+ mood episodes per year)", "Medication non-adherence leading to relapse", "Lithium toxicity (coarse tremor, confusion, seizures)", "Substance abuse complicating mood stabilization"] },
    medications: [{ name: "Lithium Carbonate", type: "Mood stabilizer (gold standard)", action: "Multiple mechanisms: inhibits GSK-3beta (promotes neuroplasticity and neuroprotection), modulates glutamate neurotransmission, stabilizes second messenger systems (inositol monophosphatase inhibition), promotes BDNF expression; effective for both mania and depression prevention; UNIQUE anti-suicidal properties", sideEffects: "Fine tremor, GI upset (nausea, diarrhea), polyuria/polydipsia (nephrogenic DI), weight gain, hypothyroidism (20%), acne, cognitive dulling; TOXICITY: coarse tremor, ataxia, confusion, seizures, cardiac arrhythmias, death", contra: "Severe renal impairment, dehydration, sodium depletion, pregnancy first trimester (Ebstein anomaly risk 0.1-0.5%, previously overestimated)", pearl: "Therapeutic range 0.8-1.2 mEq/L (acute mania), 0.6-0.8 mEq/L (maintenance); NARROW therapeutic index -- toxicity begins above 1.5; levels affected by sodium, hydration, and NSAIDs/thiazides/ACE inhibitors (all INCREASE lithium levels); draw level 12 hours after last dose; monitor TSH and creatinine every 6 months; teach patients: maintain consistent sodium and fluid intake, avoid dehydration, avoid NSAIDs" }, { name: "Valproic Acid (Depakote)", type: "Mood stabilizer / anticonvulsant", action: "Enhances GABA transmission by inhibiting GABA transaminase; blocks voltage-gated sodium channels reducing neural excitability; effective for acute mania and rapid cycling; may be more effective than lithium for mixed episodes", sideEffects: "GI upset, weight gain, tremor, hair loss (thinning), thrombocytopenia, elevated LFTs, TERATOGENIC (neural tube defects 1-2%, contraindicated in pregnancy)", contra: "Pregnancy (category X -- neural tube defects), liver disease, urea cycle disorders, mitochondrial disorders (Alpers syndrome)", pearl: "Therapeutic range 50-125 mcg/mL; loading dose for acute mania: 20-30 mg/kg/day; monitor LFTs, CBC (platelets), ammonia level; BLACK BOX: hepatotoxicity, pancreatitis, teratogenicity; ABSOLUTELY CONTRAINDICATED in women of childbearing age without reliable contraception; interaction: valproic acid INCREASES lamotrigine levels 2x (reduce lamotrigine dose by 50%)" }, { name: "Quetiapine (Seroquel)", type: "Atypical antipsychotic", action: "Blocks D2 dopamine receptors (anti-manic), 5-HT2A serotonin receptors (antidepressant and anxiolytic), H1 histamine receptors (sedation), and alpha-1 adrenergic receptors (orthostatic hypotension); norquetiapine metabolite has NET inhibition (SNRI-like antidepressant effect); effective for both acute mania AND bipolar depression", sideEffects: "Sedation (significant), weight gain, metabolic syndrome (diabetes, dyslipidemia), orthostatic hypotension, QTc prolongation, cataracts (monitor with baseline and periodic slit lamp exam)", contra: "Dementia-related psychosis (black box), concurrent QTc-prolonging drugs", pearl: "Dose varies by indication: bipolar depression 300 mg, acute mania 400-800 mg, maintenance 400-800 mg; one of the few medications effective for BOTH poles of bipolar disorder; significant metabolic side effects require monitoring (weight, glucose, lipids every 3 months); sedation is useful for patients with insomnia but can impair functioning" }],
    pearls: ["DIG-FAST mnemonic for mania: Distractibility, Impulsivity/Indiscretion, Grandiosity, Flight of ideas, Activity increase, Sleep decreased, Talkativeness -- need 3+ (or 4+ if mood is irritable rather than elevated)", "NEVER give antidepressant ALONE in bipolar disorder: antidepressant monotherapy can trigger mania, rapid cycling, or mixed states; always combine with a mood stabilizer", "Lithium is the ONLY medication with proven anti-suicidal effect: unique property; consider for any bipolar patient with suicidal risk", "Patients often STOP mood stabilizers during hypomania because they feel well, creative, and energized: this is the most common cause of relapse; education about lifelong maintenance is critical", "Mixed episodes (simultaneous manic and depressive features) carry the HIGHEST suicide risk in bipolar disorder: the combination of hopelessness with high energy provides the motivation and means to act", "Sleep disruption both TRIGGERS and IS CAUSED BY mood episodes: maintaining regular sleep-wake schedule is one of the most important preventive measures"],
    quiz: [{ question: "A patient with bipolar disorder stops lithium because they feel great and creative. The practical nurse recognizes this as:", options: ["Appropriate -- the patient is cured", "Dangerous -- medication discontinuation is the most common cause of relapse in bipolar disorder", "Acceptable if the patient feels better", "Only a concern during depressive episodes"], correct: 1, rationale: "Stopping mood stabilizers during euthymia or hypomania is the most common cause of bipolar relapse. Patients often feel well and believe they no longer need medication, but bipolar disorder is a lifelong condition requiring maintenance therapy." }, { question: "A newly diagnosed bipolar patient is prescribed fluoxetine (SSRI) alone for bipolar depression. The practical nurse should:", options: ["Administer as prescribed without concern", "Question the order because antidepressant monotherapy in bipolar disorder can trigger mania", "Request a higher dose for faster response", "Add a benzodiazepine for anxiety"], correct: 1, rationale: "Antidepressant monotherapy (without a mood stabilizer) is CONTRAINDICATED in bipolar disorder because it can trigger manic episodes, rapid cycling, or dangerous mixed states. The nurse should question this order." }, { question: "Early signs of lithium toxicity include:", options: ["Euphoria and grandiosity", "Nausea, vomiting, diarrhea, and fine tremor progressing to coarse tremor", "Rash and fever", "Weight loss and insomnia"], correct: 1, rationale: "Early lithium toxicity presents with GI symptoms (nausea, vomiting, diarrhea) and worsening tremor (fine to coarse). As toxicity progresses, ataxia, confusion, seizures, and cardiac arrhythmias develop. Therapeutic range is narrow (0.6-1.2 mEq/L)." }]
  },
  "bipolar-disorder-rn": {
    title: "Bipolar Disorder",
    cellular: { title: "Bipolar Management, Drug Monitoring", content: "The nurse manages acute manic and depressive episodes, monitors therapeutic drug levels, recognizes and manages lithium toxicity, and coordinates discharge planning for bipolar patients. Lithium monitoring requires understanding of factors affecting levels: dehydration increases levels (concentrated in reduced plasma volume), NSAIDs increase levels (reduce renal clearance), thiazide diuretics increase levels (enhance proximal tubule reabsorption), ACE inhibitors increase levels, low-sodium diet increases levels (kidney retains lithium instead of sodium). Lithium toxicity management: mild (1.5-2.0 mEq/L) -- hold lithium, IV normal saline hydration, monitor levels every 2-4 hours; moderate (2.0-2.5 mEq/L) -- aggressive IV hydration, continuous cardiac monitoring, consider nephrology consultation; severe (above 2.5 mEq/L) -- emergent hemodialysis, ICU admission, continuous cardiac monitoring. The nurse managing acute mania implements behavioral management strategies: provide structured environment, reduce stimulation (low lighting, quiet room, limited visitors), set firm consistent limits without escalating confrontation, redirect grandiose energy into safe activities, ensure nutrition (finger foods the patient can eat while moving) and hydration, monitor sleep (patients in mania may go days without sleeping). Involuntary hospitalization criteria must be known: danger to self, danger to others, or gravely disabled (unable to provide for basic needs)." },
    riskFactors: ["Lithium toxicity precipitants: dehydration (gastroenteritis, diuretic use, hot weather, exercise), NSAIDs, ACE inhibitors, thiazide diuretics, low-sodium diet, renal impairment", "Rapid cycling (4+ episodes/year): associated with female sex, bipolar II, hypothyroidism, antidepressant use, mixed episodes", "Valproic acid teratogenicity: neural tube defects in 1-2% of exposed pregnancies; absolute contraindication in women of childbearing age without contraception", "Medication non-adherence: 40-60% of bipolar patients are non-adherent; common during euthymia and hypomania", "Substance use comorbidity: 50-60% of bipolar patients have co-occurring substance use disorder", "Metabolic syndrome from atypical antipsychotics: olanzapine and quetiapine have highest metabolic risk"],
    diagnostics: ["Lithium level monitoring: draw at 12 hours after last dose (trough level); check 5-7 days after dose change, monthly for 3 months, then every 3-6 months when stable; target 0.8-1.2 acute, 0.6-0.8 maintenance", "Valproic acid level: 50-125 mcg/mL; monitor CBC (thrombocytopenia), LFTs (hepatotoxicity), ammonia (hyperammonemia -- can cause encephalopathy even at therapeutic levels)", "Carbamazepine level: 4-12 mcg/mL; monitor CBC (aplastic anemia, agranulocytosis), sodium (SIADH causing hyponatremia), LFTs; auto-induces own metabolism (levels decrease over time, may need dose increase)", "Lamotrigine: no routine blood level monitoring required; MUST titrate slowly to prevent Stevens-Johnson syndrome (SJS): start 25 mg daily for 2 weeks, then 50 mg for 2 weeks, then 100 mg, then 200 mg target; if on valproic acid, halve these doses", "Metabolic monitoring for atypical antipsychotics: weight, fasting glucose, HbA1c, lipid panel at baseline, 3 months, then annually", "TSH every 6 months for patients on lithium (hypothyroidism in 20%), creatinine and urinalysis for renal function"],
    management: ["Acute mania protocol: mood stabilizer (lithium or valproic acid) PLUS atypical antipsychotic (olanzapine, quetiapine, risperidone); provide calm, structured environment; consider IM olanzapine or IM haloperidol for acute agitation; avoid physical restraints when possible", "Bipolar depression protocol: quetiapine (most evidence), lurasidone, lamotrigine, or lithium; NEVER antidepressant monotherapy; if antidepressant added, always combine with mood stabilizer (prefer bupropion or SSRI over SNRI; avoid TCAs and MAOIs)", "Lithium toxicity management: hold lithium immediately, aggressive IV NS hydration (200-300 mL/hr), check level every 2-4 hours, continuous cardiac monitoring; hemodialysis for level above 2.5 or symptomatic above 2.0", "Rapid cycling management: optimize mood stabilizer (lithium + valproic acid combination), treat hypothyroidism, discontinue any antidepressant, add lamotrigine for depressive predominance", "Pregnancy planning in bipolar women: discuss risks/benefits of each medication; lamotrigine has best safety profile in pregnancy; lithium: Ebstein anomaly risk 0.1-0.5% (requires fetal echocardiography); valproic acid ABSOLUTELY contraindicated; minimize polypharmacy"],
    nursingActions: ["Monitor lithium levels and recognize toxicity stages: therapeutic (0.6-1.2) -- fine tremor, mild GI upset acceptable; early toxicity (1.5-2.0) -- worsening GI, coarse tremor, lethargy, confusion; severe toxicity (above 2.5) -- ataxia, seizures, cardiac arrhythmias, coma -- EMERGENT hemodialysis required", "Manage acute mania behavioral interventions: structured schedule, reduced stimulation, consistent limits, redirect energy, ensure adequate nutrition (offer high-calorie finger foods and fluids frequently as patients cannot sit for meals), protect from consequences of impulsive behavior (lock credit cards, monitor phone use for excessive spending)", "Titrate lamotrigine according to strict schedule to prevent SJS: rash is the signal to STOP immediately and report; risk is highest in first 8 weeks and with rapid titration; valproic acid doubles lamotrigine levels requiring halved dose schedule", "Monitor metabolic parameters for patients on atypical antipsychotics: weekly weight for first month, monthly for 3 months, then quarterly; fasting glucose and lipids at baseline, 3 months, annually", "Assess medication adherence using multiple methods: self-report, drug levels, pharmacy refill records, family report; address barriers (side effects, cost, belief they do not need medication, substance use)", "Implement safety measures for suicidal patients: mixed episodes carry highest risk; continuous observation, environmental safety check, remove sharps and potential ligature points, therapeutic engagement"],
    assessmentFindings: ["Mania severity staging: hypomania (elevated mood, increased productivity, maintained insight) vs mania (impaired judgment, grandiosity, reckless behavior, possible psychosis) vs mania with psychotic features (delusions, hallucinations, disorganized thinking)", "Lithium toxicity staging: mild (GI, fine tremor, lethargy), moderate (coarse tremor, ataxia, confusion, dysarthria), severe (seizures, coma, cardiac arrhythmias, renal failure)", "Lamotrigine rash assessment: benign rash (occurs in 10% -- macular, non-painful, non-progressive) vs SJS/TEN warning signs (confluent, painful, involving mucous membranes, systemic symptoms -- fever, malaise, facial edema); ANY rash requires immediate medication hold and dermatology evaluation", "Rapid cycling identification: document mood episodes and cycle frequency; 4+ episodes per year = rapid cycling; investigate causes (thyroid, antidepressant use, substance use, non-adherence)"],
    signs: { left: ["Stable on maintenance mood stabilizer with therapeutic levels", "Recognizing prodromal symptoms and seeking early intervention", "Adherent to medication and lifestyle modifications", "Using wellness action plans and mood tracking"], right: ["Acute mania with psychotic features requiring involuntary hospitalization", "Lithium toxicity requiring emergent hemodialysis", "Lamotrigine-associated Stevens-Johnson syndrome", "Mixed episode with active suicidal plan", "Rapid cycling despite dual mood stabilizer therapy", "Metabolic syndrome from long-term antipsychotic use"] },
    medications: [{ name: "Lamotrigine (Lamictal)", type: "Mood stabilizer / anticonvulsant", action: "Blocks voltage-gated sodium channels and inhibits glutamate release; primary role in bipolar disorder is DEPRESSION PREVENTION (limited antimanic efficacy); neuroprotective and neuroplasticity-enhancing properties", sideEffects: "RASH (10% benign, 0.1-0.3% SJS/TEN), headache, dizziness, nausea, insomnia, blurred vision", contra: "Known hypersensitivity, previous SJS from lamotrigine", pearl: "The ONLY mood stabilizer primarily effective for bipolar DEPRESSION; slow titration is MANDATORY to prevent SJS: 25 mg daily x2 weeks -> 50 mg daily x2 weeks -> 100 mg daily x2 weeks -> target 200 mg daily; if on valproic acid, HALVE all doses (VPA doubles lamotrigine levels); ANY rash requires IMMEDIATE discontinuation and medical evaluation; if discontinued for more than 5 days, must re-titrate from the beginning; no blood level monitoring needed" }, { name: "Olanzapine (Zyprexa)", type: "Atypical antipsychotic", action: "Blocks D2 dopamine, 5-HT2A serotonin, H1 histamine, and muscarinic receptors; highly effective for acute mania and maintenance; IM formulation available for acute agitation", sideEffects: "HIGHEST weight gain and metabolic risk of all atypical antipsychotics; sedation, hyperglycemia, dyslipidemia, orthostatic hypotension", contra: "Dementia-related psychosis (black box), IM formulation contraindicated within 1 hour of IM benzodiazepine (respiratory depression risk)", pearl: "10-20 mg/day for acute mania; IM 10 mg for acute agitation (onset 15-30 minutes); the most effective antimanic antipsychotic but the WORST metabolic offender; average weight gain 4-5 kg in first year; monitor weight weekly initially; olanzapine-fluoxetine combination (Symbyax) is FDA-approved for bipolar depression; CRITICAL: do NOT give IM olanzapine and IM benzodiazepine within 1 hour (risk of fatal respiratory depression and hypotension)" }, { name: "Lurasidone (Latuda)", type: "Atypical antipsychotic", action: "Blocks D2 dopamine and 5-HT2A and 5-HT7 serotonin receptors; 5-HT7 antagonism is believed to contribute to antidepressant efficacy; FDA-approved for bipolar depression (as monotherapy or adjunct to lithium/valproic acid)", sideEffects: "Akathisia (most common), nausea, sedation, EPS; LOWEST metabolic risk of atypical antipsychotics (weight-neutral)", contra: "Concurrent strong CYP3A4 inhibitors/inducers, dementia-related psychosis", pearl: "20-120 mg/day; MUST be taken with food (at least 350 calories -- absorption requires fat); FDA-approved for bipolar depression as monotherapy or adjunct; key advantage: weight-neutral and minimal metabolic effects (unlike quetiapine and olanzapine); best choice for bipolar depression in patients concerned about weight gain" }],
    pearls: ["Lamotrigine is primarily for bipolar DEPRESSION, not mania: the most common prescribing error is using lamotrigine for acute mania (it has minimal antimanic efficacy); its value is in preventing depressive relapse", "SJS risk with lamotrigine: slow titration is NON-NEGOTIABLE; the risk is highest in the first 8 weeks and is dramatically increased by: rapid titration, concurrent valproic acid (doubles lamotrigine levels), and younger age", "IM olanzapine + IM benzodiazepine = potentially FATAL combination: do not administer within 1 hour of each other; respiratory depression, hypotension, and death have been reported; use one OR the other for acute agitation", "Lithium level drug interactions to memorize: NSAIDs, ACE inhibitors, thiazide diuretics all INCREASE lithium levels -> toxicity risk; caffeine and theophylline DECREASE lithium levels -> subtherapeutic risk", "Bipolar depression is undertreated: patients spend 3x more time depressed than manic; bipolar depression causes more disability than mania; quetiapine, lurasidone, and lamotrigine are the three pillars of bipolar depression treatment"],
    quiz: [{ question: "An RN is titrating lamotrigine for a bipolar patient also taking valproic acid. The appropriate starting dose adjustment is:", options: ["Double the standard lamotrigine dose", "No adjustment needed", "HALVE the standard lamotrigine dose (valproic acid doubles lamotrigine levels)", "Triple the dose to overcome the interaction"], correct: 2, rationale: "Valproic acid inhibits lamotrigine glucuronidation, doubling lamotrigine levels. All lamotrigine doses must be HALVED when co-administered with valproic acid (start 12.5 mg instead of 25 mg) to prevent SJS." }, { question: "A lithium level drawn 12 hours after the last dose returns at 2.3 mEq/L. The patient has coarse tremor, ataxia, and confusion. The nurse should:", options: ["Continue lithium and recheck in 24 hours", "Hold lithium, start aggressive IV normal saline, initiate continuous cardiac monitoring, and prepare for possible hemodialysis", "Increase fluids orally and recheck", "Administer the next scheduled lithium dose"], correct: 1, rationale: "Lithium level of 2.3 with neurological symptoms (coarse tremor, ataxia, confusion) indicates moderate-severe toxicity. Management requires: hold lithium, IV NS hydration (200-300 mL/hr), continuous cardiac monitoring, recheck levels every 2-4 hours, and nephrology consultation for possible hemodialysis." }, { question: "A patient in acute mania requires IM medication for agitation. The nurse administered IM olanzapine 10 mg. When can an IM benzodiazepine be safely given?", options: ["Immediately if agitation persists", "Not within at least 1 hour due to risk of respiratory depression", "After 15 minutes", "Only if the patient requests it"], correct: 1, rationale: "IM olanzapine and IM benzodiazepine must NOT be administered within 1 hour of each other due to risk of fatal respiratory depression and hypotension. If additional sedation is needed, alternative agents should be considered." }]
  },
  "bipolar-disorder-np": {
    title: "Bipolar Disorder",
    cellular: { title: "Psychopharmacology", content: "The clinician managing bipolar disorder prescribes mood stabilizer regimens, manages treatment-resistant cases, navigates pregnancy planning, and coordinates long-term maintenance. The Canadian Network for Mood and Anxiety Treatments (CANMAT) and International Society for Bipolar Disorders (ISBD) guidelines provide evidence-based treatment algorithms. For acute mania: first-line monotherapy (lithium, valproic acid, quetiapine, risperidone, aripiprazole, paliperidone, asenapine, cariprazine); first-line combination (lithium or VPA + quetiapine, risperidone, aripiprazole, or asenapine). For bipolar depression: first-line (quetiapine, lurasidone + Li/VPA, lamotrigine, lithium, lurasidone monotherapy); adding an antidepressant is second-line and ONLY with mood stabilizer. For maintenance: lithium (strongest evidence for suicide prevention and long-term stabilization), quetiapine, lamotrigine (depression prevention), valproic acid (mania prevention in rapid cyclers). Treatment-resistant bipolar disorder may require: clozapine (most effective antipsychotic for refractory mania), ECT (effective for both acute mania and depression, safe in pregnancy), combination mood stabilizers (lithium + valproic acid + lamotrigine), or newer agents (cariprazine for bipolar depression). The clinician also manages the complex psychopharmacology of bipolar disorder in pregnancy: lithium (Ebstein anomaly 0.1-0.5%, requires fetal echo and third-trimester level monitoring), lamotrigine (safest mood stabilizer in pregnancy, but levels drop significantly requiring dose increase), valproic acid (ABSOLUTELY CONTRAINDICATED -- 1-2% neural tube defects, cognitive impairment in exposed children)." },
    riskFactors: ["Treatment-resistant bipolar disorder: rapid cycling, mixed features, comorbid substance use, personality disorder, inadequate medication trial", "Pregnancy planning: all mood stabilizers carry some teratogenic risk; valproic acid is most dangerous; lamotrigine is safest; lithium requires fetal echo and close monitoring", "Metabolic syndrome prevalence: 40-50% of bipolar patients develop metabolic syndrome, partly from medications and partly from lifestyle factors", "Cardiovascular mortality: bipolar patients have 1.5-2.5x increased cardiovascular mortality; aggressive risk factor management needed", "Cognitive impairment: progressive cognitive decline in bipolar disorder (especially with recurrent manic episodes); early treatment and prevention of episodes is neuroprotective", "Pharmacogenomics: HLA-B*1502 allele (common in Asian populations) increases SJS risk with carbamazepine and oxcarbazepine; screen BEFORE prescribing"],
    diagnostics: ["CANMAT/ISBD treatment algorithm positioning: identify which treatment step the patient is at to guide next intervention", "Pharmacogenomic testing: HLA-B*1502 (required before carbamazepine/oxcarbazepine in Asian patients for SJS risk); CYP2D6 for antipsychotic metabolism; CYP2C19 for mood stabilizer metabolism", "Comprehensive metabolic monitoring panel: fasting glucose, HbA1c, lipid panel, waist circumference, BMI at baseline and regular intervals for all patients on atypical antipsychotics", "Lithium renal monitoring: GFR calculation, urinalysis (specific gravity, urine osmolality for nephrogenic DI), serum creatinine every 6 months; approximately 1% develop CKD with chronic use", "Thyroid monitoring on lithium: TSH every 6 months; 20% develop hypothyroidism (treat with levothyroxine, do NOT discontinue lithium unless thyroid disease is the cause of mood symptoms)", "Cognitive assessment: baseline and periodic screening for cognitive decline (MoCA); more frequent manic episodes are associated with progressive cognitive impairment"],
    management: ["Acute mania first-line: lithium OR valproic acid + atypical antipsychotic (quetiapine, risperidone, aripiprazole); response typically within 1-2 weeks; target lithium 0.8-1.2 mEq/L", "Bipolar depression first-line: quetiapine 300 mg, OR lurasidone 20-120 mg (with food), OR lamotrigine 200 mg (requires slow titration); lithium monotherapy may be sufficient for mild-moderate", "Maintenance first-line: lithium (best evidence for suicide prevention and long-term mood stabilization); combine with lamotrigine for depressive predominance or valproic acid for manic predominance", "Treatment-resistant mania: clozapine 200-600 mg (requires REMS for ANC monitoring due to agranulocytosis risk); ECT (highly effective, safe in pregnancy)", "Treatment-resistant depression: add cariprazine (FDA-approved for bipolar depression, unique D3 partial agonism), ECT, or ketamine/esketamine (emerging evidence)", "Pregnancy management: preconception counseling (50% transmission risk to offspring); lamotrigine preferred (monitor levels, usually need 50-100% dose increase during pregnancy due to enhanced clearance); lithium requires: fetal echocardiography at 16-20 weeks, level monitoring (levels drop during pregnancy, spike postpartum), dose adjustment postpartum (reduce to pre-pregnancy dose immediately after delivery to prevent toxicity); NEVER use valproic acid"],
    nursingActions: ["Prescribe mood stabilizer regimen based on CANMAT/ISBD guidelines matching treatment to predominant pole: lithium for balanced bipolar I, lamotrigine for depressive-predominant, valproic acid for rapid cycling or mixed features", "Order HLA-B*1502 testing before prescribing carbamazepine or oxcarbazepine in patients of Asian descent (required to prevent SJS/TEN)", "Manage complex polypharmacy: understand drug interactions (valproic acid increases lamotrigine, carbamazepine induces many medications, lithium interactions with NSAIDs/diuretics/ACE inhibitors)", "Prescribe clozapine for treatment-resistant mania: requires REMS enrollment, weekly CBC for first 6 months (agranulocytosis risk), then biweekly for 6 months, then monthly; ANC thresholds for continuation, interruption, and discontinuation", "Manage bipolar pregnancy: select safest medication (lamotrigine first-line), monitor levels monthly (lamotrigine clearance increases 50-100%), coordinate fetal monitoring, plan postpartum dose reduction, arrange close psychiatric follow-up postpartum (highest relapse risk)", "Implement metabolic risk reduction: prescribe exercise program, dietary counseling, consider metformin for antipsychotic-induced weight gain, switch to metabolically favorable antipsychotic (aripiprazole, ziprasidone, lurasidone) when possible", "Coordinate long-term care: psychiatric follow-up, therapy referral (IPSRT -- Interpersonal and Social Rhythm Therapy, specifically designed for bipolar disorder to stabilize circadian rhythms), substance use treatment, cardiovascular risk management"],
    assessmentFindings: ["Treatment algorithm position: first-line responsive (stable on monotherapy) vs second-line (needed combination or switch) vs treatment-resistant (failed 2+ adequate trials)", "Predominant pole assessment: manic-predominant (more frequent/severe manic episodes) vs depressive-predominant (more frequent/severe depressive episodes) -- guides maintenance selection", "Metabolic risk profile: BMI, waist circumference, fasting glucose, lipids; antipsychotic metabolic risk ranking: olanzapine/clozapine (highest) > quetiapine > risperidone > aripiprazole/ziprasidone/lurasidone (lowest)", "Cognitive trajectory: baseline cognitive function, change over time; recurrent manic episodes are associated with progressive cognitive decline; early and sustained treatment is neuroprotective", "Functional outcome assessment: work/school performance, relationship stability, quality of life; functional recovery often lags behind symptomatic recovery"],
    signs: { left: ["Stable on evidence-based maintenance therapy with sustained remission", "Successfully preventing mood episodes through medication adherence and lifestyle management", "Healthy pregnancy managed with lamotrigine and close monitoring", "Metabolic parameters stable with risk reduction strategies"], right: ["Treatment-resistant mania requiring clozapine (REMS enrollment and monitoring)", "Valproic acid exposure in pregnancy requiring urgent medication change and genetic counseling", "Clozapine-induced agranulocytosis (ANC below 1000) requiring immediate discontinuation", "Rapid cycling on multiple mood stabilizers requiring ECT", "Severe metabolic syndrome with new-onset diabetes from antipsychotic therapy", "Postpartum psychosis (a psychiatric emergency -- occurs in 1-2% of bipolar women)"] },
    medications: [{ name: "Cariprazine (Vraylar)", type: "Atypical antipsychotic (D3/D2 partial agonist)", action: "Unique D3 receptor partial agonism (10x higher affinity for D3 than D2) plus D2 partial agonism and 5-HT2A antagonism; D3 partial agonism in the prefrontal cortex may explain antidepressant and pro-cognitive effects; FDA-approved for both acute mania AND bipolar depression (rare dual approval)", sideEffects: "Akathisia (most common), EPS, nausea, restlessness, insomnia; relatively weight-neutral compared to quetiapine and olanzapine", contra: "Known hypersensitivity, concurrent strong CYP3A4 inhibitors", pearl: "Bipolar depression: 1.5 mg/day (unique low-dose antidepressant effect); acute mania: 3-6 mg/day; extremely long half-life (2-4 days for parent compound, 1-3 WEEKS for active metabolites) meaning effects persist long after discontinuation; FDA-approved for BOTH poles of bipolar disorder; NP considers for bipolar depression when quetiapine not tolerated (metabolic concerns) or lurasidone not effective" }, { name: "Clozapine (Clozaril)", type: "Atypical antipsychotic (for treatment-resistant cases)", action: "Blocks D4 (more than D2) dopamine, 5-HT2A serotonin, H1 histamine, muscarinic, and alpha-adrenergic receptors; most effective antipsychotic for treatment-resistant mania and psychosis; unique anti-suicidal properties (FDA-approved for suicide prevention in schizophrenia)", sideEffects: "AGRANULOCYTOSIS (1-2% risk -- potentially fatal, requires REMS monitoring), metabolic syndrome (highest weight gain), myocarditis (1st month), seizures (dose-dependent), sedation, sialorrhea (excessive drooling), constipation (can progress to ileus)", contra: "History of clozapine-induced agranulocytosis, concurrent myelosuppressive agents, uncontrolled epilepsy", pearl: "Reserved for treatment-resistant bipolar disorder (failed 2+ first-line agents); requires Clozapine REMS Program: weekly CBC with ANC for first 6 months, biweekly for months 7-12, monthly thereafter; ANC below 1500 = report to REMS; below 1000 = STOP clozapine; re-challenge after agranulocytosis is dangerous; NP must be REMS-certified to prescribe; despite risks, may be life-saving for truly refractory patients" }, { name: "Long-Acting Injectable Aripiprazole (Abilify Maintena)", type: "Atypical antipsychotic (monthly depot injection)", action: "D2/5-HT1A partial agonist with 5-HT2A antagonist activity; monthly IM injection providing continuous drug delivery eliminating adherence concerns; FDA-approved for bipolar I maintenance as monotherapy", sideEffects: "Injection site reactions, akathisia, weight gain (less than olanzapine), insomnia, EPS", contra: "Known hypersensitivity", pearl: "400 mg IM monthly; overlapping oral aripiprazole for 14 days after first injection to ensure therapeutic levels; MAJOR advantage: eliminates medication non-adherence (most common cause of bipolar relapse); NP considers for patients with documented non-adherence, frequent hospitalizations, or forensic settings; metabolically favorable compared to other LAIs (paliperidone palmitate has more metabolic effects)" }],
    pearls: ["CANMAT/ISBD guidelines rank treatments by evidence level: Level 1 (RCTs and meta-analyses) > Level 2 (open trials, large case series) > Level 3 (case reports, expert opinion); NP should prescribe Level 1 evidence first-line", "Cariprazine fills a unique niche: one of the few medications FDA-approved for BOTH bipolar mania AND bipolar depression; its D3 partial agonism provides antidepressant and pro-cognitive effects not seen with other antipsychotics", "Clozapine for bipolar disorder: NP should consider when 2+ first-line agents have failed; despite monitoring burden, clozapine can be life-saving for treatment-resistant mania; also has anti-suicidal properties", "LAI aripiprazole for bipolar maintenance: addresses the fundamental problem of non-adherence (40-60% of bipolar patients); monthly injection ensures consistent drug levels; especially valuable for patients with insight-impaired non-adherence", "Postpartum psychosis is a PSYCHIATRIC EMERGENCY: occurs in 1-2% of bipolar women within first 2 weeks postpartum; presents with confusion, disorganized behavior, delusions, command hallucinations; risk of infanticide; requires immediate hospitalization; lithium is most effective treatment and prevention", "Valproic acid in pregnancy: NEVER prescribe -- 1-2% neural tube defect rate, IQ reduction of 8-10 points in exposed children, increased autism risk; NP must ensure effective contraception in all women of childbearing age on valproic acid"],
    quiz: [{ question: "An NP is selecting medication for bipolar depression in a patient concerned about weight gain. The BEST choice is:", options: ["Olanzapine-fluoxetine combination", "Quetiapine 300 mg", "Lurasidone 40 mg with food", "Valproic acid alone"], correct: 2, rationale: "Lurasidone is FDA-approved for bipolar depression and is weight-neutral (lowest metabolic risk among effective bipolar depression treatments). It must be taken with food (at least 350 calories for absorption). Olanzapine and quetiapine cause more weight gain." }, { question: "A bipolar woman on valproic acid wants to become pregnant. The clinician should:", options: ["Continue valproic acid with folic acid supplementation", "Switch to lamotrigine before conception (safest mood stabilizer in pregnancy) and discontinue valproic acid", "Add lithium and continue valproic acid", "Discontinue all medications"], correct: 1, rationale: "Valproic acid is ABSOLUTELY CONTRAINDICATED in pregnancy (neural tube defects, cognitive impairment). Switch to lamotrigine (safest mood stabilizer in pregnancy) before conception. Never simply discontinue all medications as this risks severe relapse." }, { question: "An NP considers clozapine for a bipolar patient who has failed lithium, valproic acid, quetiapine, and aripiprazole. The CRITICAL monitoring requirement for clozapine is:", options: ["Monthly liver function tests", "Weekly CBC with ANC for first 6 months (REMS requirement)", "Daily blood pressure monitoring", "Weekly lithium levels"], correct: 1, rationale: "Clozapine requires REMS program monitoring with weekly CBC/ANC for the first 6 months (agranulocytosis risk 1-2%), then biweekly for 6 months, then monthly. ANC below 1000 requires immediate discontinuation." }]
  },
  "ptsd-rpn": {
    title: "Post-Traumatic Stress Disorder (PTSD)",
    cellular: { title: "Pathophysiology of PTSD", content: "PTSD develops after exposure to a traumatic event involving actual or threatened death, serious injury, or sexual violence. The pathophysiology involves maladaptive fear conditioning: the amygdala (fear center) becomes hyperactivated and encodes the traumatic memory with intense emotional valence, while the medial prefrontal cortex (mPFC), which normally inhibits fear responses, shows decreased activity. The hippocampus, responsible for contextualizing memories (placing them in time and space), shows volume reduction and dysfunction, causing traumatic memories to be experienced as current rather than past events. Neurochemically, the HPA axis is paradoxically dysregulated: cortisol levels are often LOW (unlike depression where they are elevated), but the stress response system is hyper-reactive, producing exaggerated catecholamine (norepinephrine, epinephrine) responses to perceived threats. This creates a state of persistent hyperarousal. The noradrenergic system is overactive (explaining hypervigilance, exaggerated startle, insomnia), and the endogenous opioid system may be dysregulated (explaining emotional numbing). Traumatic memories are stored as sensory fragments rather than coherent narratives, causing intrusive re-experiencing through flashbacks, nightmares, and emotional/physiological reactions to trauma-related cues. The practical nurse provides trauma-informed care, monitors safety, administers medications, and supports the patient through recovery." },
    riskFactors: ["Direct exposure to traumatic event (combat, assault, accident, disaster, childhood abuse)", "Witnessing trauma directly or learning of trauma to a close person", "Repeated or extreme indirect exposure (first responders, emergency nurses, forensic professionals)", "Prior trauma history (cumulative risk with each exposure)", "Female sex (2x higher PTSD rates, possibly due to higher interpersonal trauma exposure)", "Lack of social support after trauma", "Pre-existing mental health conditions (depression, anxiety)", "Peritraumatic dissociation (dissociating during the traumatic event)"],
    diagnostics: ["DSM-5 criteria: exposure to trauma + symptoms from all 4 clusters lasting more than 1 month: (1) Intrusion (flashbacks, nightmares, distressing memories), (2) Avoidance (avoiding trauma-related stimuli), (3) Negative cognitions and mood (persistent negative beliefs, emotional numbness, detachment, anhedonia), (4) Arousal and reactivity (hypervigilance, exaggerated startle, insomnia, irritability, reckless behavior)", "PCL-5 (PTSD Checklist for DSM-5): 20-item self-report screening tool; score above 31-33 suggests probable PTSD", "Primary Care PTSD Screen (PC-PTSD-5): brief 5-item screening tool for primary care settings", "Duration: symptoms must persist more than 1 month (if 3 days to 1 month = Acute Stress Disorder)", "Functional impairment in social, occupational, or other important areas required for diagnosis"],
    management: ["Trauma-focused psychotherapy is FIRST-LINE: Prolonged Exposure (PE), Cognitive Processing Therapy (CPT), or Eye Movement Desensitization and Reprocessing (EMDR)", "SSRI/SNRI as first-line pharmacotherapy: sertraline and paroxetine are FDA-approved for PTSD", "Prazosin for PTSD-related nightmares (alpha-1 blocker reduces noradrenergic hyperactivation during sleep)", "Avoid benzodiazepines in PTSD: they impair fear extinction (the therapeutic mechanism of trauma-focused therapy) and worsen outcomes", "Trauma-informed care approach: safety, trustworthiness, choice, collaboration, empowerment", "Address comorbid conditions: substance use (50% comorbidity), depression (50%), chronic pain"],
    nursingActions: ["Implement trauma-informed care: ask permission before touching, explain procedures, allow patient choices, avoid re-traumatization, recognize trauma responses (dissociation, hyperarousal, avoidance)", "Assess for PTSD symptoms using PCL-5 or structured interview", "Monitor for dissociative episodes: patient appears disconnected, staring, unresponsive; ground the patient using sensory techniques (cold water, strong scent, tactile stimulation)", "Provide safety: assess for suicidal ideation (PTSD has 2-3x increased suicide risk), substance use, and self-harm", "Administer prescribed medications and monitor for side effects", "Avoid potential trauma triggers when possible: sudden loud noises, unexpected touch, being alone with unfamiliar individuals, feeling trapped or confined", "Teach coping strategies: grounding techniques, deep breathing, safe place visualization, progressive muscle relaxation"],
    assessmentFindings: ["Intrusion symptoms: unwanted distressing memories, nightmares, flashbacks (reliving the event with sensory vividness), intense psychological distress and physiological reactions to trauma cues", "Avoidance: actively avoiding trauma-related thoughts, feelings, people, places, activities, and conversations", "Negative cognitions: persistent distorted blame of self or others, emotional numbness, inability to experience positive emotions, feeling detached from others, diminished interest in activities", "Arousal/reactivity: hypervigilance (scanning for threats), exaggerated startle response, sleep disturbance, irritability/angry outbursts, reckless or self-destructive behavior, difficulty concentrating"],
    signs: { left: ["PTSD symptoms improving with trauma-focused therapy", "Engaging in treatment and using coping strategies", "Nightmares decreasing with prazosin treatment", "Social functioning improving with reduced avoidance"], right: ["Severe dissociative episodes with amnesia or depersonalization", "Active suicidal ideation or self-harm", "Comorbid severe substance use disorder", "Psychotic features (rare but possible in severe PTSD)", "Severe aggression or domestic violence related to hyperarousal", "Treatment avoidance due to fear of re-traumatization"] },
    medications: [{ name: "Sertraline (Zoloft)", type: "SSRI (FDA-approved for PTSD)", action: "Increases serotonin availability in the synaptic cleft modulating amygdala reactivity and enhancing prefrontal cortex inhibitory control over fear circuits", sideEffects: "GI disturbance, sexual dysfunction, insomnia, initial anxiety worsening", contra: "Concurrent MAOIs, known hypersensitivity", pearl: "Start 25 mg daily, titrate to 50-200 mg; one of two FDA-approved medications for PTSD (along with paroxetine); takes 4-8 weeks for full PTSD symptom improvement; reduces all 4 symptom clusters but is most effective for arousal/reactivity and negative cognitions; trauma-focused psychotherapy should be offered concurrently" }, { name: "Prazosin", type: "Alpha-1 adrenergic antagonist", action: "Blocks alpha-1 receptors in the CNS reducing noradrenergic hyperactivation; specifically reduces trauma-related nightmares by blocking norepinephrine's role in activating fear memories during REM sleep", sideEffects: "Orthostatic hypotension (especially first dose), dizziness, headache, nasal congestion, drowsiness", contra: "Known hypersensitivity to quinazolines, concurrent PDE-5 inhibitors (sildenafil -- severe hypotension)", pearl: "Start 1 mg at bedtime, titrate by 1-2 mg every 3-7 days up to 6-15 mg at bedtime; FIRST-DOSE PHENOMENON: significant orthostatic hypotension with first dose (give at bedtime, warn patient to sit up slowly); specifically targets PTSD nightmares (not a general sleep aid); studies show mixed results but clinical experience strongly supports use; most effective for combat-related and interpersonal trauma nightmares" }, { name: "Hydroxyzine (for acute PTSD anxiety)", type: "H1 antihistamine with anxiolytic properties", action: "Blocks H1 receptors producing sedation and anxiolysis without benzodiazepine dependence risk; useful for acute anxiety in PTSD patients", sideEffects: "Sedation, dry mouth, dizziness, QTc prolongation at high doses", contra: "QTc prolongation, early pregnancy", pearl: "25-50 mg every 6 hours PRN; use INSTEAD of benzodiazepines for acute anxiety in PTSD; benzodiazepines are CONTRAINDICATED in PTSD because they impair fear extinction (the mechanism of trauma-focused therapy) and worsen long-term outcomes; hydroxyzine provides acute anxiety relief without these risks" }],
    pearls: ["Benzodiazepines are CONTRAINDICATED in PTSD: they impair fear extinction (the therapeutic mechanism of exposure-based therapies), increase PTSD severity, and worsen substance use outcomes; use hydroxyzine, gabapentin, or prazosin instead", "Trauma-informed care means asking WHAT HAPPENED TO YOU rather than WHAT IS WRONG WITH YOU: this shift in perspective recognizes behaviors as adaptive responses to trauma rather than pathology", "Flashbacks are NOT memories -- they are RE-EXPERIENCES: the patient physiologically relives the trauma (accelerated HR, diaphoresis, fear) because the hippocampus has not properly contextualized the memory as past; grounding techniques help orient the patient to the present", "PTSD has 2-3x increased suicide risk: assess suicidal ideation at EVERY encounter; risk is highest during anniversary reactions, legal proceedings, and media coverage of similar events", "Comorbidity is the RULE, not the exception: 50% have MDD, 50% have substance use disorder, 30% have anxiety disorders; all must be addressed for successful PTSD treatment", "First responders and nurses are at HIGH risk for PTSD: recognize symptoms in colleagues; promote peer support and professional help-seeking without stigma"],
    quiz: [{ question: "A PTSD patient is prescribed lorazepam for anxiety. The practical nurse should:", options: ["Administer as prescribed without concern", "Question the prescription because benzodiazepines are contraindicated in PTSD", "Request a higher dose for better anxiety relief", "Combine with alcohol for enhanced effect"], correct: 1, rationale: "Benzodiazepines are contraindicated in PTSD because they impair fear extinction (the mechanism by which trauma-focused therapy works) and worsen long-term outcomes. Hydroxyzine, gabapentin, or prazosin are safer alternatives for PTSD-related anxiety." }, { question: "A patient with PTSD suddenly appears disconnected, staring blankly, and unresponsive to their name. This most likely represents:", options: ["Seizure activity", "Medication side effect", "A dissociative flashback", "Normal sleep"], correct: 2, rationale: "Dissociative flashbacks cause the patient to re-experience the trauma, appearing disconnected from the present. The nurse should use grounding techniques (say the patient's name, offer cold water or ice, encourage them to describe what they see/hear in the present environment)." }, { question: "First-line treatment for PTSD is:", options: ["Benzodiazepines", "Antipsychotics", "Trauma-focused psychotherapy (PE, CPT, or EMDR)", "Electroconvulsive therapy"], correct: 2, rationale: "Trauma-focused psychotherapy (Prolonged Exposure, Cognitive Processing Therapy, or EMDR) is first-line treatment for PTSD. These therapies process and integrate traumatic memories through exposure and cognitive restructuring." }]
  },
  "ptsd-rn": {
    title: "PTSD",
    cellular: { title: "PTSD Assessment", content: "The nurse managing PTSD performs comprehensive trauma assessment, implements trauma-informed care principles across all clinical settings, manages acute trauma responses, and coordinates evidence-based treatment. Advanced assessment includes identifying PTSD subtypes: classic PTSD (predominantly re-experiencing and avoidance), dissociative subtype (prominent depersonalization or derealization -- affects 15-30% of PTSD patients; associated with childhood trauma, higher symptom severity, and may require modified treatment approach), and delayed-onset PTSD (symptoms emerge 6+ months after trauma, often triggered by life changes or new stressors). Complex PTSD (C-PTSD), recognized in ICD-11 but not DSM-5, encompasses the standard PTSD criteria PLUS disturbances in self-organization: emotional dysregulation (difficulty modulating emotional responses), negative self-concept (persistent feelings of worthlessness, shame, guilt), and interpersonal difficulties (difficulties in sustaining relationships, feeling distant from others). C-PTSD typically develops from prolonged, repeated trauma (childhood abuse, domestic violence, captivity). The nurse implements trauma-informed care at the organizational level: universal screening for trauma exposure, creating physically and psychologically safe environments, avoiding re-traumatization through clinical procedures, recognizing and responding to trauma responses in patients and staff, and promoting recovery through empowerment and choice." },
    riskFactors: ["Dissociative subtype risk: childhood sexual abuse (strongest predictor), early-onset trauma, repeated/prolonged trauma, female sex", "Complex PTSD risk: prolonged captivity, domestic violence, childhood abuse/neglect, human trafficking, torture, war imprisonment", "Secondary traumatic stress / vicarious trauma in healthcare providers: ICU nurses, emergency nurses, psychiatric nurses, first responders", "Moral injury: psychological damage from perpetrating, failing to prevent, or witnessing acts that violate one's moral code (common in military and healthcare settings during crises)", "Comorbid TBI (traumatic brain injury): overlapping symptoms complicate diagnosis; 30-50% of combat veterans with TBI also have PTSD", "Treatment barriers: avoidance (patients avoid therapy because processing trauma is distressing), stigma (especially in military/first responder cultures), substance use as self-medication"],
    diagnostics: ["Clinician-Administered PTSD Scale for DSM-5 (CAPS-5): gold standard diagnostic interview; assesses each symptom for frequency and intensity; provides severity score", "PCL-5 with Life Events Checklist (LEC-5): self-report measure combined with trauma exposure assessment; score above 31-33 suggests probable PTSD", "Dissociative Experiences Scale (DES-II): screens for dissociative symptoms (depersonalization, derealization, absorption, amnesia); helps identify dissociative subtype", "International Trauma Questionnaire (ITQ): assesses PTSD and C-PTSD according to ICD-11 criteria; useful for identifying C-PTSD in patients with chronic trauma history", "PHQ-9 and GAD-7 for comorbid depression and anxiety", "AUDIT-C for alcohol use and DAST-10 for drug use (50% substance use comorbidity)", "Suicide risk assessment: PTSD confers 2-3x suicide risk; use Columbia C-SSRS at every encounter"],
    management: ["Trauma-focused psychotherapy (first-line): Prolonged Exposure (8-15 sessions of imaginal and in vivo exposure to trauma memories and cues), Cognitive Processing Therapy (12 sessions of cognitive restructuring targeting stuck points and distorted beliefs), EMDR (bilateral stimulation during trauma memory processing); all three have Level 1 evidence", "SSRI/SNRI pharmacotherapy: sertraline 50-200 mg or paroxetine 20-50 mg (both FDA-approved); venlafaxine XR also effective; combine with trauma-focused therapy", "Prazosin for nightmares: titrate from 1 mg at bedtime to 6-15 mg based on response; monitor orthostatic hypotension", "Dissociative subtype: may require phase-based treatment (stabilization and safety before trauma processing); skills-based approaches first (dialectical behavior therapy skills, sensory modulation)", "Complex PTSD: phase-based treatment recommended: Phase 1 (safety, stabilization, skills), Phase 2 (trauma processing), Phase 3 (reconnection and integration); may require 1-3 years of therapy", "Secondary traumatic stress prevention: regular supervision, peer support, self-care practices, organizational support, monitoring for burnout and compassion fatigue"],
    nursingActions: ["Implement universal trauma screening in all clinical settings: brief questions about trauma history using validated tools; frame as routine care to normalize disclosure", "Create trauma-informed clinical environment: explain all procedures before performing, ask permission for physical contact, provide choices whenever possible, ensure privacy, avoid power dynamics that replicate trauma dynamics", "Manage acute dissociative episodes: orient patient to present (state their name, location, date), use grounding techniques (cold water on hands, strong mint, describe 5 visible objects), maintain calm presence, do NOT touch without permission, document the episode", "Implement trauma-specific safety planning: identify triggers, create personalized coping strategies, establish crisis contacts, plan for high-risk situations (anniversaries, court dates, media exposure)", "Screen for and address comorbid conditions: substance use (50%), depression (50%), chronic pain, TBI, suicidal ideation at every encounter", "Recognize secondary traumatic stress in yourself and colleagues: symptoms mirror PTSD (intrusive thoughts about patients' trauma, avoidance of certain patients, hyperarousal, emotional numbing); seek supervision and support"],
    assessmentFindings: ["PTSD cluster severity assessment: which clusters are most prominent guides treatment focus (re-experiencing dominant = exposure therapy most effective; avoidance dominant = behavioral activation + gradual exposure; negative cognitions dominant = cognitive processing therapy; hyperarousal dominant = medication + relaxation training)", "Dissociative subtype identification: depersonalization (feeling detached from one's own body or mental processes), derealization (feeling that the external world is unreal or distorted); affects treatment approach (standard PE may need modification)", "Complex PTSD features: emotional dysregulation (affect storms, chronic emptiness, self-destructive behavior), negative self-concept (shame, worthlessness, guilt, feeling permanently damaged), interpersonal disturbance (difficulty trusting, oscillating between closeness and withdrawal)", "Functional impact assessment: ability to work, maintain relationships, self-care, parenting capacity, engagement in treatment, quality of life"],
    signs: { left: ["PTSD responding to trauma-focused therapy with declining PCL-5 scores", "Nightmares improving with prazosin", "Reduced avoidance and increased social engagement", "Using coping skills effectively during trigger exposure"], right: ["Severe dissociative episodes with amnesia or fugue states", "Active suicidal crisis with access to lethal means", "Comorbid severe substance use requiring detoxification before trauma therapy", "Severe aggression or violence related to hyperarousal", "Complex PTSD with severe emotional dysregulation and self-harm", "Secondary traumatic stress in nursing staff requiring organizational intervention"] },
    medications: [{ name: "Paroxetine (Paxil)", type: "SSRI (FDA-approved for PTSD)", action: "Selective serotonin reuptake inhibition; also has mild noradrenergic and anticholinergic effects providing additional anxiolytic and sedative properties", sideEffects: "Weight gain (most of SSRIs), sexual dysfunction, sedation, dry mouth, constipation, SEVERE discontinuation syndrome, teratogenic (category D)", contra: "Pregnancy (cardiac malformations), concurrent MAOIs, concurrent thioridazine or pimozide", pearl: "20-50 mg daily; FDA-approved for PTSD; may be more sedating than sertraline (useful for insomnia-predominant PTSD); WORST discontinuation syndrome of SSRIs (must taper very slowly); TERATOGENIC (avoid in women of childbearing age without contraception); potent CYP2D6 inhibitor (multiple drug interactions); RN should generally prefer sertraline as first-line SSRI for PTSD due to fewer drug interactions and no teratogenicity" }, { name: "Topiramate (off-label for PTSD)", type: "Anticonvulsant with multiple mechanisms", action: "Enhances GABA, blocks glutamate (AMPA/kainate receptors), blocks voltage-gated sodium channels; may reduce re-experiencing and hyperarousal symptoms by dampening overactive neural circuits", sideEffects: "Cognitive dulling (word-finding difficulty), paresthesias, weight LOSS (unique advantage), kidney stones, metabolic acidosis, acute glaucoma (rare)", contra: "Kidney stones, metabolic acidosis, pregnancy (cleft lip/palate risk)", pearl: "25-200 mg/day; off-label for PTSD; RCTs show benefit for re-experiencing and hyperarousal symptoms; promotes weight LOSS (unique among psych medications); cognitive side effects limit tolerability; RN monitors for paresthesias and cognitive complaints; may be combined with SSRI for augmentation" }, { name: "Gabapentin (for PTSD-related insomnia/anxiety)", type: "Alpha-2-delta calcium channel ligand", action: "Reduces excitatory neurotransmitter release; provides anxiolytic and sleep-promoting effects without benzodiazepine dependence risk", sideEffects: "Sedation, dizziness, peripheral edema, weight gain", contra: "Known hypersensitivity; dose adjust in renal impairment", pearl: "300-1800 mg/day; particularly useful for PTSD patients with insomnia and anxiety when benzodiazepines are contraindicated; can be combined with SSRI; no dependence risk (unlike benzodiazepines which are contraindicated in PTSD); sedating properties are therapeutic for insomnia-predominant PTSD" }],
    pearls: ["Trauma-informed care is NOT just for psychiatric settings: every clinical interaction can re-traumatize or empower; simple actions (explaining before touching, offering choices, maintaining predictability) make a significant difference", "Phase-based treatment for complex PTSD: jumping directly to trauma processing without adequate stabilization can worsen symptoms and lead to treatment dropout; Phase 1 (stabilization) may take months before Phase 2 (processing) begins", "Dissociative subtype requires modified exposure therapy: standard prolonged exposure may overwhelm dissociative patients; grounding skills must be solidly established before processing; shorter exposure periods with more grounding breaks may be needed", "Secondary traumatic stress / vicarious trauma is an OCCUPATIONAL HAZARD for nurses: symptoms parallel PTSD (intrusive thoughts, avoidance, hyperarousal); organizations have a responsibility to provide support, supervision, and prevention programs", "Prazosin is the ONLY medication specifically targeting PTSD nightmares: SSRIs help overall symptoms but are less effective for nightmares; prazosin blocks noradrenergic activation of fear memories during sleep"],
    quiz: [{ question: "An RN is preparing a trauma-informed care plan. Which action BEST exemplifies trauma-informed care?", options: ["Performing procedures quickly without explanation to minimize discomfort", "Explaining each procedure, asking permission before touching, and offering the patient choices whenever possible", "Restricting the patient's choices to maintain clinical efficiency", "Avoiding all discussion of the patient's trauma history"], correct: 1, rationale: "Trauma-informed care principles include safety, trustworthiness, choice, collaboration, and empowerment. Explaining procedures, asking permission, and offering choices restores a sense of control that was lost during the traumatic experience." }, { question: "A PTSD patient becomes rigid, stares blankly, and does not respond to verbal cues. The nurse recognizes this as dissociation and should:", options: ["Call a code blue", "Use grounding techniques: state the patient's name, location, and date; offer cold water or ice; ask them to describe objects in the room", "Shake the patient vigorously", "Administer intramuscular lorazepam"], correct: 1, rationale: "Dissociative episodes require grounding to orient the patient to the present. Use calm verbal cues (name, location, date), sensory stimulation (cold water, strong scent), and visual grounding (describe surroundings). Physical contact without permission can worsen the episode." }, { question: "An emergency department nurse notices she has been having nightmares about a patient's traumatic injuries and avoiding the trauma bay. This suggests:", options: ["Normal work stress", "Secondary traumatic stress requiring support and intervention", "Physical illness", "Medication side effect"], correct: 1, rationale: "Intrusive thoughts/nightmares about patients' traumas and avoidance of clinical settings are hallmarks of secondary traumatic stress (vicarious trauma). This is an occupational hazard for trauma-exposed clinicians requiring supervision, peer support, and possibly individual therapy." }]
  },
  "ptsd-np": {
    title: "PTSD",
    cellular: { title: "Psychopharmacology", content: "The clinician managing PTSD prescribes evidence-based pharmacotherapy, coordinates trauma-focused psychotherapy, manages complex comorbidity, and addresses special populations. The VA/DoD Clinical Practice Guidelines rank PTSD treatments: STRONG recommendation for trauma-focused psychotherapy (PE, CPT, EMDR); WEAK recommendation for SSRI/SNRI pharmacotherapy (sertraline, paroxetine, venlafaxine); AGAINST benzodiazepines, cannabis, and atypical antipsychotics as monotherapy. Pharmacotherapy selection should address the predominant symptom cluster: re-experiencing (SSRI/SNRI, prazosin for nightmares), avoidance (SSRI/SNRI, psychotherapy), negative cognitions (SSRI/SNRI, psychotherapy), and hyperarousal (prazosin, alpha-agonists, SSRI/SNRI). Emerging therapies include: MDMA-assisted psychotherapy (FDA breakthrough therapy designation; Phase 3 trials show 67% no longer meeting PTSD criteria after 3 MDMA-assisted therapy sessions vs 32% placebo); stellate ganglion block (SGB, cervical sympathetic block that may reset sympathetic hyperactivation; promising preliminary evidence); psilocybin-assisted therapy (early investigations for treatment-resistant PTSD); and novel rapid-acting anxiolytics targeting glutamate systems. For treatment-resistant PTSD (failed 2+ adequate SSRI/SNRI trials plus evidence-based psychotherapy), options include: augmentation with prazosin, addition of second-generation antipsychotic (quetiapine, risperidone -- for comorbid psychotic features or severe hyperarousal), and referral for specialized programs." },
    riskFactors: ["Treatment-resistant PTSD: comorbid substance use disorder, TBI, chronic pain, personality disorder, ongoing trauma exposure, inadequate psychotherapy engagement", "Military/veteran-specific considerations: combat trauma, military sexual trauma (MST), moral injury, TBI comorbidity, cultural barriers to help-seeking", "Childhood trauma survivors: complex PTSD presentation, attachment disruption, higher dissociation rates, personality disorder comorbidity", "Pregnancy: PTSD increases preterm birth, low birth weight, and peripartum depression risk; medication safety considerations", "Chronic pain comorbidity: central sensitization from shared neurobiological mechanisms; requires integrated treatment", "Substance use disorder: 50% comorbidity; PTSD treatment should proceed concurrently with SUD treatment (previously, sequential treatment was recommended but concurrent integrated treatment shows better outcomes)"],
    diagnostics: ["CAPS-5 (gold standard): clinician-administered diagnostic and severity measure; assesses each symptom cluster", "PCL-5 for treatment monitoring: administer at baseline and every 2-4 weeks; response = 10-point decrease; remission = score below 33 with no longer meeting diagnostic criteria", "Comprehensive comorbidity assessment: PHQ-9, GAD-7, AUDIT, DAST, PCL-5, Columbia C-SSRS at every visit", "Pharmacogenomic testing for treatment-resistant cases: CYP2D6 affects paroxetine metabolism, CYP2C19 affects sertraline and citalopram", "TBI screening (DVBIC 3-question screen) in military/veteran populations with PTSD", "Sleep study consideration for PTSD with severe sleep disturbance: sleep apnea is highly comorbid and worsens PTSD outcomes"],
    management: ["First-line pharmacotherapy: sertraline 50-200 mg or paroxetine 20-50 mg (both FDA-approved for PTSD); venlafaxine XR 75-225 mg (strong evidence but not FDA-approved); combine with trauma-focused psychotherapy for best outcomes", "Prazosin for nightmares: titrate from 1 mg to 6-15 mg at bedtime; monitor orthostatic BP; some evidence for daytime dosing for overall PTSD severity", "Treatment-resistant PTSD augmentation: add prazosin for nightmares, quetiapine 25-200 mg for severe hyperarousal/insomnia, topiramate 25-200 mg for re-experiencing", "Comorbid PTSD + substance use: prescribe naltrexone for alcohol use disorder (reduces alcohol craving AND may reduce PTSD symptoms through opioid system modulation); integrated treatment model", "Complex PTSD: phase-based approach; consider DBT-PE (dialectical behavior therapy adapted for PTSD) or STAIR/NST (Skills Training in Affective and Interpersonal Regulation followed by Narrative Story Telling)", "Emerging therapies: MDMA-assisted psychotherapy (anticipated FDA approval); stellate ganglion block (SGB) for treatment-resistant cases; ketamine/esketamine (early evidence for PTSD-related depression)"],
    nursingActions: ["Prescribe SSRI/SNRI using measurement-based care: track PCL-5 at every visit; optimize dose over 8-12 weeks; if less than 10-point decrease, augment or switch", "Coordinate concurrent psychotherapy: refer to PE, CPT, or EMDR-trained therapist; pharmacotherapy alone is less effective than combined treatment", "Prescribe prazosin for PTSD nightmares with careful titration and orthostatic BP monitoring", "Manage complex comorbidity: concurrent substance use treatment (naltrexone for alcohol, buprenorphine for opioid use disorder), depression treatment, chronic pain management (duloxetine addresses PTSD + pain)", "Screen for and manage sleep apnea in PTSD patients: CPAP treatment improves both sleep apnea and PTSD symptoms", "Evaluate for emerging therapies: MDMA-assisted therapy, stellate ganglion block for treatment-resistant cases", "Develop comprehensive treatment plan: pharmacotherapy + psychotherapy + lifestyle (exercise, sleep hygiene, social support) + comorbidity management"],
    assessmentFindings: ["Treatment response trajectory: pharmacotherapy typically shows improvement by 4-8 weeks; full response by 8-12 weeks; if no improvement by 8 weeks at adequate dose, consider augmentation or switch", "PTSD phenotype for treatment matching: re-experiencing predominant (PE most effective), negative cognitions predominant (CPT most effective), dissociative subtype (modified PE with stabilization), complex PTSD (phase-based approach)", "Comorbidity impact on treatment selection: PTSD + depression = SSRI/SNRI (treats both); PTSD + chronic pain = duloxetine; PTSD + alcohol use = naltrexone; PTSD + insomnia = prazosin + sleep hygiene", "Functional recovery assessment: return to work, relationship functioning, parenting capacity, quality of life; symptom improvement often precedes functional improvement by weeks to months"],
    signs: { left: ["PTSD responding to SSRI + trauma-focused therapy with declining PCL-5", "Nightmares resolved on prazosin", "Comorbid conditions concurrently treated", "Functional recovery progressing"], right: ["Treatment-resistant PTSD failing 2+ medication trials and evidence-based therapy", "Severe dissociation preventing engagement in trauma processing", "Active substance use disorder requiring concurrent management", "Severe suicidality requiring intensive safety planning", "Complex PTSD with severe emotional dysregulation, self-harm", "Moral injury not responding to standard PTSD treatment approaches"] },
    medications: [{ name: "Venlafaxine XR (for PTSD)", type: "SNRI", action: "Dual serotonin and norepinephrine reuptake inhibition; noradrenergic component may provide additional benefit for hyperarousal symptoms; strong evidence for PTSD though not FDA-approved", sideEffects: "Nausea, dizziness, insomnia, sexual dysfunction, hypertension, severe discontinuation syndrome", contra: "Concurrent MAOIs, uncontrolled hypertension", pearl: "75-225 mg for PTSD; NOT FDA-approved for PTSD but VA/DoD guidelines consider it an evidence-based first-line option alongside sertraline and paroxetine; dual mechanism may address both cognitive/emotional (serotonin) and physiological/arousal (norepinephrine) symptoms; may be preferred for PTSD with comorbid chronic pain; severe discontinuation syndrome requires very slow taper" }, { name: "Naltrexone (for PTSD + Alcohol Use Disorder)", type: "Opioid antagonist", action: "Blocks mu-opioid receptors reducing alcohol craving; may also modulate endogenous opioid system dysregulation in PTSD, potentially reducing emotional numbing and dissociation", sideEffects: "Nausea (most common, usually transient), headache, dizziness, hepatotoxicity (rare), injection site reactions (monthly injection formulation)", contra: "Current opioid use (precipitates withdrawal), acute hepatitis, liver failure", pearl: "50 mg PO daily or 380 mg IM monthly (Vivitrol); for comorbid PTSD + alcohol use disorder; integrated treatment model: treat BOTH conditions simultaneously rather than sequentially; naltrexone reduces alcohol use AND some PTSD symptoms (emotional numbing may improve); monthly injection eliminates adherence concerns; LFTs at baseline and periodically" }, { name: "MDMA-Assisted Psychotherapy (Emerging)", type: "Empathogen / entactogen (investigational)", action: "MDMA increases serotonin, dopamine, norepinephrine, and oxytocin release; reduces amygdala fear response while enhancing prefrontal cortex activity; creates a window of reduced fear and increased empathy allowing trauma processing without being overwhelmed; does NOT work as a standalone medication -- only effective when combined with psychotherapy sessions", sideEffects: "Jaw clenching, nausea, decreased appetite, increased BP and HR during session, depressed mood 3-5 days after session, theoretical neurotoxicity risk (not confirmed at therapeutic doses)", contra: "Uncontrolled hypertension, cardiac disease, hepatic impairment, concurrent serotonergic medications (serotonin syndrome risk), psychotic disorders, seizure disorders", pearl: "Administered in 2-3 supervised sessions (8 hours each) with integration psychotherapy between sessions; Phase 3 trials (MAPS): 67% of PTSD participants no longer met diagnostic criteria vs 32% placebo therapy; anticipated FDA review; NOT a take-home medication -- administered in certified clinical settings; NP should be aware of this emerging treatment as it may represent the most significant advance in PTSD treatment in decades" }],
    pearls: ["VA/DoD guidelines recommend trauma-focused psychotherapy as FIRST-LINE over medication: PE, CPT, and EMDR have stronger evidence than any medication; NP should prescribe BOTH medication AND psychotherapy referral", "Benzodiazepines are SPECIFICALLY recommended AGAINST in PTSD (VA/DoD guidelines): they worsen outcomes by impairing fear extinction, increasing avoidance, and complicating substance use comorbidity", "Concurrent treatment of PTSD + substance use disorder is NOW recommended over sequential treatment: waiting for sobriety before treating PTSD is outdated; integrated treatment addresses the self-medication cycle", "Sleep apnea is highly comorbid with PTSD and worsens outcomes: screen with STOP-BANG questionnaire; CPAP treatment improves both sleep apnea and PTSD symptoms", "MDMA-assisted psychotherapy may revolutionize PTSD treatment: Phase 3 trials show 67% remission rate vs 32% for therapy alone; this is NOT recreational MDMA use -- it is a medically supervised treatment model combining the substance with intensive psychotherapy", "Prazosin titration for nightmares: the dose required is often higher than expected (6-15 mg); undertitration is the most common reason for perceived treatment failure; monitor for orthostatic hypotension especially in the first week"],
    quiz: [{ question: "An NP is treating a veteran with PTSD and alcohol use disorder. Current evidence-based practice recommends:", options: ["Treating alcohol use first, then addressing PTSD after sobriety", "Treating PTSD first, then addressing alcohol use", "Integrated concurrent treatment of both PTSD and alcohol use disorder", "Treating neither until the patient is motivated"], correct: 2, rationale: "Current evidence supports integrated concurrent treatment of PTSD and substance use disorder. The previous sequential approach (treat SUD first) is outdated. Concurrent treatment breaks the self-medication cycle and produces better outcomes for both conditions." }, { question: "An NP prescribes prazosin 2 mg for PTSD nightmares. After 2 weeks, the patient reports minimal improvement. The clinician should:", options: ["Discontinue prazosin as it is not effective", "Titrate the dose upward (prazosin often requires 6-15 mg for PTSD nightmares)", "Switch to a benzodiazepine", "Add a sedative-hypnotic"], correct: 1, rationale: "Prazosin for PTSD nightmares often requires higher doses than expected (6-15 mg). Undertitration is the most common reason for perceived treatment failure. The clinician should titrate upward in 1-2 mg increments every 3-7 days while monitoring orthostatic blood pressure." }, { question: "Based on VA/DoD guidelines, which medication class is specifically recommended AGAINST for PTSD?", options: ["SSRIs", "SNRIs", "Benzodiazepines", "Alpha-1 antagonists"], correct: 2, rationale: "VA/DoD Clinical Practice Guidelines specifically recommend AGAINST benzodiazepines for PTSD. They impair fear extinction (the mechanism of trauma-focused therapy), worsen long-term PTSD outcomes, complicate substance use comorbidity, and have addiction potential." }]
  },
  "schizophrenia-rpn": {
    title: "Schizophrenia",
    cellular: { title: "Pathophysiology of Schizophrenia", content: "Schizophrenia is a chronic psychotic disorder characterized by positive symptoms (hallucinations, delusions, disorganized speech/behavior), negative symptoms (flat affect, alogia, avolition, anhedonia, asociality), and cognitive impairment (working memory, attention, executive function deficits). The dopamine hypothesis remains central: mesolimbic pathway hyperactivity (excess dopamine) produces positive symptoms, while mesocortical pathway hypoactivity (insufficient dopamine) produces negative and cognitive symptoms. This dual dysfunction explains why typical antipsychotics (which globally block D2 receptors) improve positive symptoms but may worsen negative symptoms. The glutamate hypothesis proposes NMDA receptor hypofunction leads to disrupted glutamate-GABA balance and downstream dopamine dysregulation. Serotonin dysregulation also contributes, explaining why atypical antipsychotics (which block 5-HT2A in addition to D2) are more effective for negative symptoms. Neurodevelopmental factors are important: prenatal complications (viral infection, malnutrition, hypoxia), genetic vulnerability (polygenic, hundreds of risk genes), and structural brain changes (enlarged ventricles, reduced hippocampal and prefrontal cortex volume, progressive gray matter loss) suggest schizophrenia begins as a neurodevelopmental disruption that manifests clinically in late adolescence/early adulthood." },
    riskFactors: ["Genetic predisposition (80% heritability; 10% risk with one affected parent, 50% with identical twin)", "Cannabis use during adolescence (2-6x increased risk, especially with genetic vulnerability)", "Urban upbringing and migration (social stress, isolation)", "Prenatal complications (maternal infection, malnutrition, obstetric complications)", "Late adolescence/early adulthood onset (males 18-25, females 25-35)", "First-degree relative with schizophrenia or other psychotic disorder", "Childhood adversity and trauma", "Advanced paternal age at conception"],
    diagnostics: ["DSM-5 criteria: 2+ symptoms for 1+ month (delusions, hallucinations, disorganized speech, disorganized/catatonic behavior, negative symptoms); must include at least 1 of the first 3; continuous disturbance for 6+ months; functional decline", "Mental status examination: assess for hallucinations (ask directly: do you hear voices others cannot?), delusions (fixed false beliefs), thought process (tangential, loose associations, thought blocking, word salad), affect (flat, inappropriate), insight (awareness of illness)", "PANSS (Positive and Negative Syndrome Scale): 30-item clinician-rated scale for symptom severity", "CBC, BMP, LFTs, lipid panel, fasting glucose, HbA1c (baseline before antipsychotic therapy)", "TSH (hypothyroidism can mimic negative symptoms)", "Urine drug screen (substance-induced psychosis must be excluded)"],
    management: ["Antipsychotic medication is the CORNERSTONE of treatment: atypical (second-generation) antipsychotics are first-line", "First episode psychosis: lower starting doses, careful titration, antipsychotic trial of 4-6 weeks at adequate dose", "Medication adherence is the greatest challenge: 50-75% of patients are non-adherent within 2 years", "Long-acting injectable (LAI) antipsychotics for adherence challenges: paliperidone palmitate, aripiprazole lauroxil, risperidone microspheres", "Psychosocial interventions: supported employment, social skills training, cognitive behavioral therapy for psychosis (CBTp), family psychoeducation", "Avoid benzodiazepines long-term; use for acute agitation only"],
    nursingActions: ["Build therapeutic relationship through consistency, honesty, and non-judgmental approach; do not argue with delusions or try to convince the patient their hallucinations are not real", "Assess for hallucinations: ask directly, observe for signs (appearing to listen, talking to self, looking at things others cannot see), document type (auditory most common in schizophrenia), content (command hallucinations asking patient to harm self/others are EMERGENT)", "Assess for command hallucinations specifically: ask if the voices tell the patient to DO things; command hallucinations to harm self/others require immediate safety intervention", "Administer antipsychotic medications; monitor for side effects including EPS (dystonia, akathisia, parkinsonism, tardive dyskinesia), metabolic syndrome (weight gain, hyperglycemia, dyslipidemia), and sedation", "Monitor for extrapyramidal symptoms (EPS): acute dystonia (muscle spasms, torticollis -- treat with benztropine or diphenhydramine IM), akathisia (restlessness -- may be mistaken for anxiety), pseudoparkinsonism (bradykinesia, tremor, rigidity)", "Provide structured environment with consistent routines; minimize stimulation during acute psychosis", "Teach about medication adherence: explain that symptoms may return if medication is stopped; discuss barriers and solutions"],
    assessmentFindings: ["Positive symptoms: auditory hallucinations (most common; often voices commenting or commanding), delusions (persecutory most common; also grandiose, referential, thought insertion/withdrawal/broadcasting), disorganized speech (tangentiality, derailment, word salad), bizarre behavior", "Negative symptoms: flat/blunted affect (limited emotional expression), alogia (poverty of speech), avolition (lack of motivation), anhedonia (inability to experience pleasure), asociality (social withdrawal) -- often more disabling than positive symptoms", "Cognitive symptoms: impaired working memory, difficulty with attention and concentration, poor executive function (planning, organizing, abstract thinking) -- affect functional capacity", "Insight assessment: most patients with schizophrenia have limited insight into their illness (anosognosia), which is a significant barrier to treatment adherence"],
    signs: { left: ["Positive symptoms controlled on antipsychotic medication", "Engaging in psychosocial rehabilitation", "No command hallucinations", "Medication adherent with acceptable side effects"], right: ["Command hallucinations to harm self or others", "Acute psychotic episode with agitation and aggression", "Neuroleptic malignant syndrome (NMS): hyperthermia, muscle rigidity, altered mental status, autonomic instability", "Tardive dyskinesia (involuntary orofacial/limb movements from chronic antipsychotic use)", "Catatonia: immobility, mutism, posturing, waxy flexibility", "Treatment-resistant schizophrenia (failed 2+ antipsychotic trials)"] },
    medications: [{ name: "Risperidone (Risperdal)", type: "Atypical antipsychotic", action: "Blocks D2 dopamine receptors (reduces positive symptoms) and 5-HT2A serotonin receptors (reduces negative symptoms and EPS risk compared to typical antipsychotics); also blocks alpha-1 adrenergic and H1 histamine receptors", sideEffects: "Weight gain, hyperprolactinemia (most significant -- causes gynecomastia, amenorrhea, galactorrhea, sexual dysfunction, osteoporosis), EPS (dose-dependent, more common above 6 mg), sedation, orthostatic hypotension", contra: "Known hypersensitivity, concurrent use with paliperidone (active metabolite of risperidone -- same drug)", pearl: "Start 1-2 mg daily, target 4-6 mg; HIGHEST prolactin elevation of all atypical antipsychotics; dose-dependent EPS risk; available as LAI (Risperdal Consta: 25-50 mg IM every 2 weeks; continue oral for 3 weeks after first injection to cover loading period); paliperidone (Invega) is the active metabolite of risperidone with similar efficacy but fewer drug interactions" }, { name: "Olanzapine (Zyprexa)", type: "Atypical antipsychotic", action: "Broad receptor antagonism: D2, 5-HT2A, H1, muscarinic, alpha-1; highly effective for positive and negative symptoms and acute agitation", sideEffects: "HIGHEST weight gain and metabolic risk of all antipsychotics; sedation, hyperglycemia, dyslipidemia, orthostatic hypotension", contra: "Dementia-related psychosis (black box), IM form contraindicated within 1 hour of IM benzodiazepine", pearl: "5-20 mg daily; most effective oral antipsychotic for acute psychosis alongside clozapine; IM formulation (10 mg) effective for acute agitation; average weight gain 4-5 kg in first year; monitor metabolic parameters closely; never give IM olanzapine within 1 hour of IM benzodiazepine (respiratory depression risk)" }, { name: "Haloperidol (Haldol)", type: "Typical (first-generation) antipsychotic", action: "Potent D2 receptor antagonism in the mesolimbic pathway reducing positive symptoms; minimal effects on negative and cognitive symptoms; used primarily for acute psychosis and agitation", sideEffects: "HIGH EPS risk (dystonia, akathisia, parkinsonism, tardive dyskinesia), NMS risk, QTc prolongation (IV route), hyperprolactinemia, minimal metabolic effects", contra: "Parkinson disease, QTc prolongation, dementia-related psychosis", pearl: "5-10 mg PO or IM for acute psychosis/agitation; onset IM: 20-40 minutes; often combined with lorazepam 2 mg and diphenhydramine 50 mg IM (B52 cocktail) for severe agitation; HIGH EPS risk -- always have benztropine or diphenhydramine available for acute dystonia; QTc monitoring required especially IV route; used less commonly now as first-line due to EPS risk" }],
    pearls: ["Auditory hallucinations are the MOST COMMON type in schizophrenia: voices may comment on behavior, carry on conversations, or give commands; COMMAND HALLUCINATIONS to harm self/others are a psychiatric emergency", "Never argue with delusions: do not try to convince the patient their beliefs are false; acknowledge their distress without validating the delusion (I understand that is frightening for you; I see things differently, but I want to help you)", "Negative symptoms are MORE DISABLING than positive symptoms: flat affect, avolition, and social withdrawal cause greater functional impairment and are harder to treat", "Neuroleptic Malignant Syndrome (NMS): EMERGENCY -- fever above 38C/100.4F, severe muscle rigidity (lead-pipe), altered mental status, autonomic instability (tachycardia, labile BP, diaphoresis); STOP antipsychotic immediately; supportive care, dantrolene, bromocriptine; mortality 5-20%", "Medication non-adherence is the #1 cause of relapse: 50-75% of patients stop medications within 2 years; long-acting injectable (LAI) antipsychotics dramatically reduce relapse and hospitalization", "Acute dystonia: sudden, painful involuntary muscle contraction (often neck/jaw/tongue/eyes) occurring within hours to days of antipsychotic initiation; treat IMMEDIATELY with benztropine 1-2 mg IM or diphenhydramine 50 mg IM; onset of relief within minutes"],
    quiz: [{ question: "A patient on haloperidol develops sudden neck twisting and jaw clenching. The practical nurse recognizes this as acute dystonia and should:", options: ["Reassure the patient it will pass", "Administer benztropine 1-2 mg IM or diphenhydramine 50 mg IM immediately", "Increase the haloperidol dose", "Apply warm compresses"], correct: 1, rationale: "Acute dystonia (involuntary muscle contractions, often of neck, jaw, tongue, or eyes) is a medical emergency requiring immediate treatment with an anticholinergic: benztropine 1-2 mg IM or diphenhydramine 50 mg IM. Relief occurs within minutes." }, { question: "A patient with schizophrenia reports that voices are telling him to hurt his roommate. The practical nurse should:", options: ["Document and monitor", "Immediately report command hallucinations to harm others as a psychiatric emergency", "Ask the patient to ignore the voices", "Increase activity to distract the patient"], correct: 1, rationale: "Command hallucinations directing harm to others are a psychiatric emergency requiring immediate reporting, safety assessment, and intervention. The patient may feel compelled to obey the voices, creating imminent danger." }, { question: "Which antipsychotic side effect is MOST associated with olanzapine?", options: ["Akathisia", "Hyperprolactinemia", "Weight gain and metabolic syndrome", "QTc prolongation"], correct: 2, rationale: "Olanzapine has the highest weight gain and metabolic syndrome risk of all atypical antipsychotics (average 4-5 kg in first year, plus hyperglycemia and dyslipidemia). Mandatory metabolic monitoring includes weight, fasting glucose, and lipids." }]
  },
  "schizophrenia-rn": {
    title: "Schizophrenia",
    cellular: { title: "Antipsychotic Pharmacology", content: "The nurse managing schizophrenia independently monitors complex antipsychotic regimens, recognizes and responds to emergent side effects, manages acute psychotic episodes including de-escalation and medication administration, and coordinates long-term rehabilitation. EPS management requires systematic recognition: Type 1 Acute dystonia (hours to days after initiation; sustained muscle contraction; treat with anticholinergic IM); Type 2 Akathisia (days to weeks; restlessness, inability to sit still; commonly mistaken for anxiety or agitation, leading to inappropriate dose increases which worsen symptoms; treat with beta-blocker, benzodiazepine, or dose reduction); Type 3 Pseudoparkinsonism (weeks to months; bradykinesia, cogwheel rigidity, pill-rolling tremor, masked facies; treat with anticholinergic or dose reduction); Type 4 Tardive dyskinesia (months to years; involuntary choreiform movements especially of mouth, face, tongue; often irreversible; assess with AIMS scale every 6 months; treat with valbenazine or deutetrabenazine). NMS is the most feared antipsychotic complication: hyperthermia, severe rigidity, autonomic instability, elevated CK (often above 1000), leukocytosis. Mortality is 5-20%. Management: stop antipsychotic immediately, aggressive cooling, IV hydration, dantrolene (1 mg/kg IV, muscle relaxant), bromocriptine (2.5-10 mg PO TID, dopamine agonist to reverse D2 blockade), ICU admission." },
    riskFactors: ["NMS risk factors: high-potency typical antipsychotics (haloperidol), IM administration, rapid dose escalation, dehydration, agitation, male sex, first episode", "Tardive dyskinesia risk factors: older age, female sex, longer duration of treatment, higher doses, typical antipsychotics, mood disorders", "Metabolic syndrome: olanzapine and clozapine highest risk; prevalence 40-50% in chronic schizophrenia patients", "QTc prolongation: ziprasidone (highest QTc risk among atypicals), IV haloperidol, thioridazine", "Clozapine-specific risks: agranulocytosis (1-2%), myocarditis (first month), seizures (dose-dependent, above 600 mg), metabolic syndrome, sialorrhea, constipation progressing to ileus", "Antipsychotic-induced hyperprolactinemia: risperidone and paliperidone have highest risk; monitor for galactorrhea, amenorrhea, sexual dysfunction, osteoporosis"],
    diagnostics: ["AIMS (Abnormal Involuntary Movement Scale): screen every 6 months for tardive dyskinesia; 12-item examination assessing facial, oral, extremity, and trunk movements", "NMS diagnostic criteria: hyperthermia (above 38C), severe muscle rigidity, altered mental status PLUS at least 2 of: CK elevation (often above 10,000), tachycardia, labile BP, diaphoresis, incontinence, leukocytosis, metabolic acidosis", "Metabolic monitoring schedule: weight/BMI at every visit; fasting glucose/HbA1c, lipid panel at baseline, 3 months, then annually; waist circumference annually", "QTc monitoring: baseline ECG for high-risk antipsychotics (ziprasidone, thioridazine, IV haloperidol); QTc above 500 ms = discontinue medication", "Clozapine monitoring: ANC weekly x6 months, biweekly x6 months, then monthly; fasting glucose and lipids; cardiac monitoring for myocarditis (troponin, CRP, echo if symptoms develop)", "Prolactin level if symptomatic hyperprolactinemia suspected (galactorrhea, amenorrhea, gynecomastia)"],
    management: ["Acute psychotic agitation de-escalation: verbal de-escalation first (offer choices, use calm voice, create space, avoid confrontation); offer oral medication (olanzapine 10 mg, risperidone 2 mg, or lorazepam 2 mg PO); if refused or unable: IM medication (olanzapine 10 mg IM OR haloperidol 5 mg + lorazepam 2 mg + diphenhydramine 50 mg IM); physical restraint as LAST RESORT only", "NMS management: STOP antipsychotic immediately, aggressive IV hydration, cooling measures, dantrolene 1 mg/kg IV (repeat up to 10 mg/kg/day), bromocriptine 2.5 mg PO TID (DA agonist to reverse D2 blockade), ICU monitoring; recovery takes 7-14 days", "TD management: assess with AIMS; consider dose reduction or switch to lower-risk antipsychotic; valbenazine (Ingrezza) 40-80 mg daily or deutetrabenazine (Austedo) 6-48 mg daily (both FDA-approved for TD; VMAT2 inhibitors)", "LAI transition protocol: continue oral antipsychotic for loading period (risperidone LAI: 3 weeks; paliperidone palmitate: first injection 234 mg deltoid, second 156 mg deltoid 1 week later, then monthly); overlap prevents psychotic relapse during transition", "Metabolic risk reduction: switch to metabolically favorable antipsychotic (aripiprazole, ziprasidone, lurasidone); prescribe metformin for antipsychotic-induced weight gain; dietary counseling and exercise program"],
    nursingActions: ["Implement systematic EPS monitoring at each encounter: assess for dystonia (muscle spasms), akathisia (inner restlessness, inability to sit still), parkinsonism (tremor, rigidity, bradykinesia), and tardive dyskinesia (involuntary movements of face/tongue/extremities using AIMS scale)", "Recognize and manage NMS: assess vital signs and CK in any patient on antipsychotics who develops fever, rigidity, and altered mental status; NMS is a medical EMERGENCY with 5-20% mortality", "Manage acute agitation using least-restrictive approach: verbal de-escalation -> offer oral medication -> IM medication -> physical restraint (last resort); document justification, monitor continuously if restrained, reassess every 15 minutes", "Administer LAI antipsychotics: proper injection technique (deltoid or gluteal depending on formulation), observe for post-injection syndrome (paliperidone palmitate: monitor 3 hours after each injection for sedation, delirium)", "Implement clozapine monitoring protocol: weekly ANC draws, assess for sialorrhea (manage with glycopyrrolate), constipation (manage with daily stimulant laxative -- clozapine constipation can progress to fatal ileus), metabolic parameters", "Coordinate psychosocial rehabilitation: supported employment programs (evidence-based: Individual Placement and Support model), social skills training, cognitive remediation, family psychoeducation", "Assess medication adherence using multiple methods: ask directly, check drug levels if available, pharmacy records, family input; address barriers (side effects, lack of insight, cost, stigma)"],
    assessmentFindings: ["EPS type identification and management: dystonia = acute onset, sustained muscle contraction (treat with anticholinergic IM); akathisia = subjective restlessness + objective motor restlessness (treat with propranolol 10-20 mg TID); parkinsonism = tremor + rigidity + bradykinesia (treat with benztropine 1-2 mg BID); TD = involuntary choreiform movements (assess with AIMS, treat with VMAT2 inhibitor)", "NMS vs serotonin syndrome differentiation: NMS = lead-pipe rigidity, hyperthermia, autonomic instability, elevated CK, slow onset (days); serotonin syndrome = clonus, hyperreflexia, agitation, hyperthermia, diarrhea, rapid onset (hours)", "Functional assessment: many schizophrenia patients achieve symptom control but remain functionally impaired (negative symptoms, cognitive deficits); functional recovery requires psychosocial rehabilitation in addition to medication", "Clozapine-specific assessment: weekly ANC (agranulocytosis), daily bowel movement documentation (constipation -> ileus), metabolic parameters, cardiac symptoms (myocarditis risk peaks in first month)"],
    signs: { left: ["Positive symptoms controlled on oral or LAI antipsychotic", "No EPS or metabolic complications", "Engaging in psychosocial rehabilitation", "Medication adherent with good insight"], right: ["NMS: fever, rigidity, altered mental status, elevated CK -- EMERGENT", "Acute dystonia requiring emergent IM anticholinergic treatment", "Severe akathisia causing suicidal ideation (recognized association)", "Tardive dyskinesia requiring VMAT2 inhibitor treatment", "Clozapine-induced agranulocytosis (ANC below 1000)", "Treatment-resistant schizophrenia (failed 2+ adequate antipsychotic trials)"] },
    medications: [{ name: "Aripiprazole (Abilify)", type: "Atypical antipsychotic (dopamine partial agonist)", action: "Partial agonist at D2 receptors (stabilizes dopamine rather than blocking it completely) and 5-HT1A receptors; 5-HT2A antagonist; reduces positive symptoms while minimizing EPS and metabolic effects due to partial rather than full D2 antagonism", sideEffects: "Akathisia (most common), insomnia, restlessness, headache, nausea; minimal weight gain, minimal metabolic effects, minimal sedation, minimal prolactin elevation", contra: "Known hypersensitivity", pearl: "10-30 mg daily; BEST metabolic profile among commonly used antipsychotics (weight-neutral, no diabetes/dyslipidemia risk); partial D2 agonism means it can WORSEN psychosis in some acutely ill patients (not as potent as full antagonists for severe acute psychosis); akathisia is dose-limiting in 10-15%; available as LAI monthly (Abilify Maintena 400 mg) or every 2 months (Aristada); ideal for maintenance in patients concerned about weight/metabolic effects" }, { name: "Paliperidone Palmitate (Invega Sustenna/Trinza/Hafyera)", type: "LAI atypical antipsychotic", action: "Active metabolite of risperidone; blocks D2 and 5-HT2A receptors; palmitate ester formulation allows sustained release from deltoid or gluteal injection site", sideEffects: "Hyperprolactinemia (highest of all antipsychotics), weight gain, EPS at higher doses, injection site reactions, sedation; POST-INJECTION DELIRIUM/SEDATION SYNDROME (PDSS) unique to paliperidone palmitate -- rare but requires 3-hour post-injection observation", contra: "Known hypersensitivity to risperidone or paliperidone", pearl: "Loading: 234 mg deltoid day 1, 156 mg deltoid day 8, then monthly; also available as 3-month (Trinza) and 6-month (Hafyera) formulations after stabilization on monthly; PDSS (post-injection delirium/sedation syndrome): occurs in 0.07% of injections -- sudden onset sedation, confusion, delirium within 1 hour of injection; RN must observe patient for 3 HOURS after EVERY injection; keep patient in observable area; greatest adherence advantage: 6-month injection = only 2 injections per year" }, { name: "Valbenazine (Ingrezza)", type: "VMAT2 inhibitor (for tardive dyskinesia)", action: "Inhibits vesicular monoamine transporter 2 (VMAT2), reducing dopamine packaging into synaptic vesicles, decreasing dopaminergic transmission to the basal ganglia which is responsible for the involuntary movements of TD", sideEffects: "Sedation, QTc prolongation, suicidal ideation (monitor), akathisia, balance difficulties", contra: "Known hypersensitivity, concurrent strong CYP3A4 inhibitors or inducers", pearl: "40 mg daily for 1 week then 80 mg daily; FDA-approved for tardive dyskinesia; does NOT require antipsychotic discontinuation (can be added to ongoing antipsychotic); improvement seen within 2 weeks, full effect by 6 weeks; the ONLY treatment specifically approved for TD (along with deutetrabenazine); RN should monitor for mood changes and suicidal ideation; may need to continue indefinitely as TD may return upon discontinuation" }],
    pearls: ["Akathisia is the most MISDIAGNOSED EPS: inner restlessness and inability to sit still is often mistaken for anxiety or psychotic agitation, leading to inappropriate antipsychotic dose increase which WORSENS akathisia; treat with propranolol, benzodiazepine, or dose reduction", "NMS vs malignant catatonia differentiation is challenging: both have hyperthermia, rigidity, and altered mental status; catatonia has waxy flexibility, echophenomena, and responds to benzodiazepines (lorazepam challenge); NMS has CK elevation and responds to dantrolene/bromocriptine", "LAI antipsychotics reduce relapse by 30-50% compared to oral medications: RN should advocate for LAI use in patients with adherence challenges; early LAI use (even first episode) is increasingly recommended", "Post-injection delirium/sedation syndrome (PDSS) with paliperidone palmitate: rare but potentially serious; patient must be observed for 3 HOURS after EVERY injection; teach RNs to recognize (sudden sedation, confusion, disorientation within 1 hour of injection)", "Clozapine constipation can be FATAL: clozapine's anticholinergic effects cause severe constipation that can progress to paralytic ileus, bowel obstruction, perforation, and death; daily bowel movement documentation and prophylactic stimulant laxative are essential"],
    quiz: [{ question: "A patient on risperidone reports feeling restless, unable to sit still, and pacing constantly. This is MOST likely:", options: ["Worsening psychosis requiring higher antipsychotic dose", "Akathisia requiring dose reduction or propranolol", "Anxiety disorder requiring benzodiazepine", "Normal restlessness"], correct: 1, rationale: "Akathisia (inner restlessness, inability to sit still, pacing) is commonly misdiagnosed as anxiety or worsening psychosis. Increasing the antipsychotic dose will WORSEN akathisia. Treatment includes dose reduction, switching to a lower-EPS antipsychotic (aripiprazole), or adding propranolol." }, { question: "After paliperidone palmitate injection, a patient must be observed for:", options: ["30 minutes", "1 hour", "3 hours for post-injection delirium/sedation syndrome (PDSS)", "No observation required"], correct: 2, rationale: "Paliperidone palmitate carries risk of PDSS (post-injection delirium/sedation syndrome) occurring within 1 hour of injection. Patients must be observed for 3 FULL HOURS after EVERY injection in a healthcare setting with access to emergency care." }, { question: "A patient on clozapine has not had a bowel movement in 5 days. The nurse should:", options: ["Document and continue monitoring", "Recognize this as potentially life-threatening (clozapine-induced ileus) and intervene immediately with aggressive bowel management and provider notification", "Increase fluid intake only", "Reassure the patient"], correct: 1, rationale: "Clozapine-induced constipation can progress to paralytic ileus, bowel obstruction, perforation, and death. Five days without a bowel movement requires urgent intervention: stimulant laxative, enema if needed, abdominal assessment, and provider notification." }]
  },
  "schizophrenia-np": {
    title: "Schizophrenia",
    cellular: { title: "Psychopharmacology", content: "The clinician managing schizophrenia prescribes antipsychotic regimens, manages treatment-resistant schizophrenia (TRS), coordinates metabolic risk reduction, and makes complex treatment decisions including clozapine initiation. TRS is defined as failure to achieve adequate symptom response after 2 adequate antipsychotic trials (adequate dose for adequate duration of 6-8 weeks each). TRS affects approximately 30% of schizophrenia patients. Clozapine is the ONLY medication with proven superiority for TRS, yet it is significantly underutilized (only 5-10% of eligible patients receive it, despite 30-60% response rate). Barriers include: REMS monitoring requirements, side effect profile, prescriber reluctance, and patient/family hesitancy. The clinician should advocate for earlier clozapine use based on evidence that delays in clozapine initiation worsen outcomes. Clozapine pharmacology is unique: relatively weak D2 blockade (explaining low EPS and TD risk), high 5-HT2A affinity, significant muscarinic, histaminic, and alpha-adrenergic blockade. Clozapine monitoring includes: ANC (agranulocytosis risk 1-2%, highest in first 6 months), metabolic panel (highest weight gain and diabetes risk), cardiac monitoring (myocarditis risk in first month -- monitor troponin, CRP, echo), and bowel function (constipation leading to ileus). The clinician also manages first-episode psychosis (FEP), where early intervention with lower-dose antipsychotic, coordinated specialty care (CSC), and psychosocial support dramatically improves long-term outcomes." },
    riskFactors: ["Treatment-resistant schizophrenia: earlier age of onset, male sex, substance use, poor premorbid functioning, longer duration of untreated psychosis (DUP)", "Clozapine-specific risks: agranulocytosis peaks at weeks 6-18 (monitor ANC weekly for 6 months), myocarditis typically in first 4 weeks (monitor troponin and CRP), seizures dose-dependent (above 600 mg), metabolic syndrome (highest risk of all antipsychotics), sialorrhea, constipation/ileus", "Duration of untreated psychosis (DUP): longer DUP predicts worse outcomes; average DUP in the US is 74 weeks; early intervention dramatically improves prognosis", "Polypharmacy: combining two antipsychotics (except clozapine augmentation) is generally NOT recommended due to increased side effects without proven benefit; taper and switch rather than add", "Cardiovascular disease: leading cause of premature death in schizophrenia (15-20 year reduced life expectancy); metabolic syndrome, smoking, and sedentary lifestyle all contribute"],
    diagnostics: ["Treatment response assessment: PANSS reduction of 20% or more from baseline = minimal response; 50% or more = good response; PANSS total below 58 suggests remission", "Clozapine level monitoring: target trough level 350-600 ng/mL for therapeutic response; levels above 1000 ng/mL increase seizure risk; draw 12 hours after last dose, at steady state (after 5 days at stable dose)", "CYP1A2 interaction awareness for clozapine: smoking INDUCES CYP1A2 (lowers clozapine levels 50%); if patient quits smoking, levels RISE dramatically (reduce dose 25-50%); fluvoxamine INHIBITS CYP1A2 (raises levels); caffeine inhibits CYP1A2 (raises levels modestly)", "Comprehensive metabolic monitoring: fasting glucose/HbA1c, lipid panel, weight/BMI, waist circumference; most aggressive monitoring with olanzapine and clozapine", "Cardiac monitoring for clozapine: baseline ECG, troponin, CRP; repeat troponin and CRP weekly for first 4 weeks (myocarditis screening); echo if symptoms develop (dyspnea, chest pain, tachycardia)", "Prolactin level for symptomatic hyperprolactinemia on risperidone/paliperidone; consider switching to aripiprazole or adding aripiprazole (partial D2 agonism reduces prolactin)"],
    management: ["First-episode psychosis: coordinated specialty care (CSC) model; low-dose antipsychotic (aripiprazole 5-10 mg or risperidone 1-2 mg preferred); CBTp, family psychoeducation, supported employment/education, case management; RAISE trial showed superiority of CSC model", "Treatment algorithm: Step 1: atypical antipsychotic monotherapy (4-6 weeks adequate trial); Step 2: switch to different atypical antipsychotic; Step 3: clozapine (if 2 trials failed = treatment-resistant); augmentation of clozapine if partial response (amisulpride, aripiprazole, or ECT)", "Clozapine initiation: start 12.5 mg daily or BID, increase by 25-50 mg every 1-2 days to target 300-450 mg/day; target trough level 350-600 ng/mL; prescriber and pharmacy must be registered with Clozapine REMS; ANC thresholds: above 1500 (general) or above 1000 (benign ethnic neutropenia) to continue", "Metabolic risk management: switch to metabolically favorable antipsychotic when possible (aripiprazole, ziprasidone, lurasidone); metformin 500-2000 mg for antipsychotic-induced weight gain (most evidence); topiramate as alternative; lifestyle intervention (diet, exercise, smoking cessation)", "LAI antipsychotic prescribing: consider early in disease course (not just for non-adherent patients); PRELAPSE trial suggested LAI superiority even in first-episode; monthly (paliperidone palmitate, aripiprazole), every 2 months (aripiprazole lauroxil), every 3 months (paliperidone Trinza), every 6 months (paliperidone Hafyera)", "Smoking cessation: nicotine enhances dopamine release which partially self-medicates negative symptoms; 60-80% of schizophrenia patients smoke; smoking induces CYP1A2 requiring higher clozapine and olanzapine doses; assist with cessation but ADJUST antipsychotic doses when quitting (levels will rise)"],
    nursingActions: ["Prescribe first-line antipsychotic based on patient-specific factors: aripiprazole (metabolically neutral, partial agonism), risperidone (effective but prolactin risk), quetiapine (sedating, metabolic risk), olanzapine (most effective but worst metabolic profile); match to patient concerns", "Initiate clozapine after 2 failed adequate antipsychotic trials: register in Clozapine REMS, start low and titrate slowly, implement comprehensive monitoring protocol", "Manage clozapine titration and monitoring: weekly ANC for 6 months, biweekly for 6 months, monthly thereafter; fasting metabolic panel; troponin/CRP weekly for first month; clozapine level at steady state; bowel function documentation", "Prescribe LAI antipsychotics to improve adherence: explain to patients that LAI reduces relapse risk by 30-50%; advocate for early LAI use in disease course", "Implement comprehensive metabolic monitoring and intervention: prescribe metformin for weight gain, statin for dyslipidemia, diabetes management; smoking cessation support with medication dose adjustment", "Manage hyperprolactinemia: switch to or add aripiprazole (partial D2 agonism normalizes prolactin); if unable to switch, monitor bone density, offer contraception counseling for amenorrheic patients (anovulation is not reliable contraception at lower prolactin elevations)", "Coordinate first-episode psychosis care: implement CSC model, maintain lower antipsychotic doses, prioritize psychosocial interventions, engage family"],
    assessmentFindings: ["Treatment resistance confirmation: verify adequate trial duration (6-8 weeks each), adequate dose (within therapeutic range), medication adherence (drug levels, pharmacy records, LAI consideration), substance use screening, comorbidity assessment", "Clozapine response monitoring: 30-60% of TRS patients respond to clozapine; response may take 3-6 months at therapeutic levels; track PANSS scores monthly", "Metabolic syndrome prevalence and management: 40-50% of chronic schizophrenia patients; metabolic risk ranking: clozapine = olanzapine >> quetiapine > risperidone > aripiprazole = ziprasidone = lurasidone", "Smoking and medication interaction: CYP1A2 induction by smoking lowers clozapine and olanzapine levels; quitting smoking raises levels (reduce dose 25-50% when patient stops smoking to prevent toxicity)"],
    signs: { left: ["First-episode psychosis responding to low-dose antipsychotic in CSC model", "Treatment-resistant schizophrenia responding to clozapine", "Metabolic parameters stable with monitoring and intervention", "Functional recovery progressing with psychosocial rehabilitation"], right: ["Clozapine-refractory schizophrenia (failed clozapine at therapeutic levels)", "Clozapine-induced agranulocytosis requiring immediate discontinuation", "Clozapine-induced myocarditis in first month of treatment", "Severe metabolic syndrome with new-onset diabetes and cardiovascular risk", "Clozapine-induced ileus from severe constipation", "Persistent suicidality despite adequate antipsychotic treatment"] },
    medications: [{ name: "Clozapine (Clozaril)", type: "Atypical antipsychotic (for treatment-resistant schizophrenia)", action: "Unique pharmacology: relatively weak D2 blockade with strong 5-HT2A, D4, muscarinic, histaminic, and alpha-adrenergic antagonism; the ONLY antipsychotic proven superior for treatment-resistant schizophrenia; anti-suicidal properties (FDA-approved indication in schizophrenia)", sideEffects: "Agranulocytosis (1-2%), metabolic syndrome (highest risk), myocarditis (first month), seizures (dose-dependent), sedation, sialorrhea, constipation/ileus (potentially fatal), orthostatic hypotension, tachycardia", contra: "History of clozapine-induced agranulocytosis, concurrent myelosuppressive agents, severe granulocytopenia", pearl: "Start 12.5 mg daily, titrate slowly to 300-450 mg; target trough level 350-600 ng/mL; REMS monitoring: ANC weekly x6 months, biweekly x6 months, monthly thereafter; agranulocytosis risk peaks weeks 6-18; myocarditis risk peaks weeks 2-4 (monitor troponin/CRP weekly for first month); benign ethnic neutropenia (BEN) in African-American patients: lower ANC threshold (above 1000 vs 1500) allows continued treatment; smoking cessation increases levels 50% (reduce dose); clozapine is UNDERUTILIZED: only 5-10% of TRS patients receive it despite 30-60% response rate; NP should advocate for earlier initiation" }, { name: "Aripiprazole Lauroxil (Aristada)", type: "LAI atypical antipsychotic (every 1-2 months)", action: "Prodrug converted to aripiprazole (D2/5-HT1A partial agonist, 5-HT2A antagonist); provides sustained plasma levels from deltoid or gluteal injection", sideEffects: "Akathisia, injection site reactions, weight gain (minimal), insomnia, restlessness", contra: "Known hypersensitivity", pearl: "Available as 441 mg monthly, 662 mg monthly, 882 mg monthly, or 1064 mg every 2 months; initiation options: 21-day oral aripiprazole overlap OR single Aristada Initio 675 mg deltoid injection (with one dose oral aripiprazole) for same-day LAI start; BEST metabolic profile among LAI options; NP selects for patients concerned about weight gain or metabolic effects; every-2-month option provides maximum convenience" }, { name: "Metformin (for antipsychotic-induced weight gain)", type: "Biguanide antihyperglycemic", action: "Reduces hepatic glucose production, increases insulin sensitivity, and decreases intestinal glucose absorption; also promotes modest weight loss (2-3 kg); counteracts antipsychotic-induced metabolic effects", sideEffects: "GI disturbance (nausea, diarrhea -- take with food, start low), lactic acidosis (rare), B12 deficiency with long-term use", contra: "eGFR below 30, acute or chronic metabolic acidosis, severe hepatic impairment", pearl: "500 mg BID with meals, titrate to 1000 mg BID; most evidence-based intervention for antipsychotic-induced weight gain (average 3 kg weight loss vs continued gain); also improves insulin resistance and lipid profile; can be used even without diabetes for weight management; monitor B12 annually with long-term use; NP should prescribe for all patients with significant antipsychotic-induced weight gain (above 7% of baseline)" }],
    pearls: ["Clozapine is the most UNDERUTILIZED effective treatment in psychiatry: 30% of schizophrenia patients are treatment-resistant, but only 5-10% receive clozapine; average delay from TRS identification to clozapine initiation is 4-5 YEARS; NP should advocate for earlier use", "CYP1A2 and smoking: the polycyclic aromatic hydrocarbons in cigarette smoke (not nicotine) induce CYP1A2; this affects clozapine and olanzapine levels; when a patient QUITS smoking, clozapine levels can DOUBLE within days causing toxicity; reduce dose 25-50% immediately upon smoking cessation; nicotine replacement does NOT affect CYP1A2", "Duration of untreated psychosis (DUP) is the strongest modifiable predictor of long-term outcome: every month of delayed treatment worsens prognosis; NP should prioritize rapid antipsychotic initiation in first-episode psychosis", "Benign ethnic neutropenia (BEN): many patients of African and some Middle Eastern descent have lower baseline ANC (1000-1500) that is NOT pathological; updated Clozapine REMS allows continued clozapine with ANC above 1000 (vs 1500 for general population); NP should not deny clozapine to BEN patients based on lower baseline ANC", "Metabolic syndrome is the leading cause of the 15-20 year reduced life expectancy in schizophrenia: aggressive metabolic monitoring and intervention (metformin, statin, exercise, dietary counseling, smoking cessation) are as important as antipsychotic prescribing"],
    quiz: [{ question: "An NP is treating a patient with schizophrenia who has failed two adequate antipsychotic trials (risperidone 6 mg x 8 weeks and olanzapine 20 mg x 8 weeks). The next step is:", options: ["Try a third typical antipsychotic", "Initiate clozapine (treatment-resistant schizophrenia)", "Add a second antipsychotic to the current one", "Refer for psychotherapy only"], correct: 1, rationale: "Failure of 2 adequate antipsychotic trials defines treatment-resistant schizophrenia. Clozapine is the ONLY medication with proven superiority for TRS, with 30-60% response rate. It should not be delayed further." }, { question: "A patient on clozapine 400 mg quits smoking. The clinician should:", options: ["Continue the same clozapine dose", "REDUCE clozapine dose by 25-50% (smoking cessation increases clozapine levels)", "Increase clozapine dose to maintain therapeutic effect", "Switch to a different antipsychotic"], correct: 1, rationale: "Smoking induces CYP1A2 which metabolizes clozapine. When smoking stops, CYP1A2 activity decreases and clozapine levels can DOUBLE, causing toxicity. Immediately reduce the dose by 25-50% and monitor levels." }, { question: "An NP prescribes metformin 500 mg BID for a patient who gained 10 kg on olanzapine. The PRIMARY rationale is:", options: ["Metformin is an antipsychotic", "Metformin is the most evidence-based intervention for antipsychotic-induced weight gain", "Metformin enhances antipsychotic efficacy", "Metformin treats the psychosis directly"], correct: 1, rationale: "Metformin is the most evidence-based pharmacological intervention for antipsychotic-induced weight gain, producing average 2-3 kg weight loss and improving insulin resistance. It should be offered to all patients with significant weight gain (above 7% of baseline)." }]
  },
  "substance-use-disorders-rpn": {
    title: "Substance Use Disorders",
    cellular: { title: "Pathophysiology of Substance Use Disorders", content: "Substance use disorder (SUD) is a chronic, relapsing brain disease characterized by compulsive drug seeking and use despite harmful consequences. The neurobiology centers on the mesolimbic dopamine reward pathway: drugs of abuse hijack the natural reward system by flooding the nucleus accumbens with dopamine at levels 2-10x greater than natural rewards (food, social bonding). With repeated use, neuroadaptation occurs: the brain downregulates dopamine receptors (tolerance) and reduces natural dopamine production, creating a state where the individual needs the substance just to feel normal (dependence) and natural rewards become less pleasurable (anhedonia). The prefrontal cortex (decision-making, impulse control) shows decreased activity in addiction, explaining the loss of control over substance use despite awareness of consequences. Withdrawal occurs when the neuroadapted brain is suddenly deprived of the substance: the opposite of the drug's effects emerge (alcohol/benzodiazepine withdrawal causes CNS hyperexcitability because GABA suppression is removed; opioid withdrawal causes sympathetic hyperactivity because opioid suppression of the locus coeruleus is removed). The practical nurse monitors for withdrawal syndromes, administers prescribed withdrawal management medications, provides non-judgmental care, and supports recovery." },
    riskFactors: ["Genetic predisposition (40-60% of addiction risk is genetic)", "Adverse childhood experiences (ACEs) -- dose-response relationship with SUD risk", "Co-occurring mental health disorders (depression, anxiety, PTSD, ADHD, bipolar disorder)", "Early age of first substance use (before age 15 significantly increases lifetime SUD risk)", "Family history of addiction", "Peer influence and social environment", "Chronic pain (gateway to opioid use disorder)", "Trauma history"],
    diagnostics: ["DSM-5 SUD criteria: 2+ of 11 criteria in 12-month period (impaired control, social impairment, risky use, pharmacological indicators); severity: mild (2-3), moderate (4-5), severe (6+)", "CAGE questionnaire (alcohol): Cut down, Annoyed, Guilty, Eye-opener; 2+ positive = probable AUD", "AUDIT-C: 3-item alcohol screening (frequency, quantity, binge episodes)", "DAST-10: Drug Abuse Screening Test", "CIWA-Ar (Clinical Institute Withdrawal Assessment for Alcohol Revised): 10-item scale guiding alcohol withdrawal management; score above 8 = pharmacological treatment needed; above 15 = severe withdrawal; above 20 = risk of seizures/DT", "COWS (Clinical Opiate Withdrawal Scale): 11-item scale for opioid withdrawal severity; guides medication-assisted treatment initiation", "Urine drug screen, blood alcohol level, LFTs (AST:ALT ratio above 2:1 suggests alcoholic hepatitis)"],
    management: ["Alcohol withdrawal: benzodiazepines are first-line (chlordiazepoxide or lorazepam), CIWA-Ar protocol-driven dosing; thiamine 100-500 mg IV/IM BEFORE glucose (prevents Wernicke encephalopathy); monitor for delirium tremens (DTs: 48-96 hours, mortality 5-15% untreated)", "Opioid withdrawal: NOT life-threatening but extremely uncomfortable; buprenorphine-naloxone (Suboxone) or methadone for medication-assisted treatment (MAT); clonidine for autonomic symptoms if MAT not available", "Opioid use disorder maintenance: buprenorphine-naloxone (Suboxone), methadone, or naltrexone (Vivitrol) -- ALL are evidence-based first-line treatments; MAT reduces overdose death by 50%+", "Alcohol use disorder maintenance: naltrexone (reduces craving), acamprosate (reduces glutamate excitotoxicity), disulfiram (aversion therapy)", "Psychosocial interventions: motivational interviewing, CBT, contingency management, 12-step facilitation, peer support"],
    nursingActions: ["Assess withdrawal risk and severity using validated tools: CIWA-Ar for alcohol, COWS for opioids", "Monitor vital signs frequently during withdrawal: tachycardia, hypertension, hyperthermia, diaphoresis indicate worsening withdrawal", "Administer prescribed withdrawal management medications: benzodiazepines for alcohol (symptom-triggered protocol per CIWA score), buprenorphine for opioids (wait for COWS score 8+ before initiating to avoid precipitated withdrawal)", "Maintain safety: seizure precautions for alcohol withdrawal, fall prevention, aspiration precautions", "Provide thiamine 100-500 mg IV/IM BEFORE any glucose-containing fluids (prevents Wernicke encephalopathy -- confusion, ataxia, ophthalmoplegia)", "Use motivational interviewing approach: express empathy, develop discrepancy, roll with resistance, support self-efficacy; AVOID confrontation and moralizing", "Have naloxone (Narcan) readily available for opioid overdose reversal: 0.4-2 mg IV/IM/IN, repeat every 2-3 minutes"],
    assessmentFindings: ["Alcohol withdrawal timeline: 6-12 hours (tremor, anxiety, tachycardia, diaphoresis, nausea); 12-24 hours (visual/tactile hallucinations -- alcoholic hallucinosis); 24-48 hours (seizures); 48-96 hours (delirium tremens: severe confusion, agitation, hallucinations, autonomic instability, hyperthermia -- mortality 5-15%)", "Opioid withdrawal timeline: 8-24 hours after last use (anxiety, lacrimation, rhinorrhea, yawning, diaphoresis); 36-72 hours peak (severe cramps, diarrhea, nausea/vomiting, piloerection/goosebumps, mydriasis, tachycardia, insomnia, bone/muscle pain)", "Opioid intoxication: miosis (pinpoint pupils), respiratory depression, sedation, constipation, euphoria, decreased GI motility", "Stimulant intoxication (cocaine, methamphetamine): mydriasis, tachycardia, hypertension, hyperthermia, agitation, paranoia, chest pain"],
    signs: { left: ["Mild withdrawal managed with symptom-triggered protocol", "Engaging in MAT and psychosocial treatment", "Stable on maintenance medication (buprenorphine, methadone, naltrexone)", "Active in recovery support (12-step, peer support)"], right: ["Delirium tremens (confusion, agitation, hallucinations, hyperthermia, seizures)", "Opioid overdose (respiratory depression, pinpoint pupils, unresponsive)", "Seizures from alcohol or benzodiazepine withdrawal", "Wernicke encephalopathy (confusion, ataxia, ophthalmoplegia)", "Suicidal ideation during withdrawal or early recovery", "Polysubstance use complicating withdrawal management"] },
    medications: [{ name: "Buprenorphine-Naloxone (Suboxone)", type: "Partial opioid agonist + antagonist", action: "Buprenorphine: partial mu-opioid agonist (activates receptors enough to prevent withdrawal and craving but has a ceiling effect for respiratory depression); naloxone: opioid antagonist added to deter IV misuse (causes precipitated withdrawal if injected)", sideEffects: "Headache, nausea, constipation, insomnia, diaphoresis, precipitated withdrawal if given too early", contra: "Active use of full opioid agonist within 12-24 hours (precipitated withdrawal risk)", pearl: "Wait until COWS score 8+ (moderate withdrawal) before initiating to avoid precipitated withdrawal; sublingual administration (hold under tongue until dissolved); buprenorphine alone (Subutex) used in pregnancy; ceiling effect on respiratory depression makes it SAFER than methadone for overdose risk; NP can prescribe with X-waiver (now eliminated -- all DEA-licensed prescribers can prescribe); reduces overdose death by 50%+" }, { name: "Chlordiazepoxide (Librium)", type: "Long-acting benzodiazepine", action: "Enhances GABA-A receptor function providing cross-tolerance with alcohol; prevents seizures and DTs by compensating for the loss of alcohol's GABA-enhancing effect during withdrawal", sideEffects: "Sedation, respiratory depression, ataxia, paradoxical agitation in elderly", contra: "Severe hepatic impairment (use lorazepam instead -- does not require hepatic metabolism), respiratory failure", pearl: "Preferred for alcohol withdrawal due to long half-life (smooth, gradual decline in levels reduces rebound symptoms); symptom-triggered dosing per CIWA-Ar protocol: give chlordiazepoxide 25-100 mg when CIWA score above 8, reassess hourly; use LORAZEPAM instead in patients with liver disease (lorazepam undergoes glucuronidation, not hepatic oxidation); taper benzodiazepines after acute withdrawal phase" }, { name: "Naloxone (Narcan)", type: "Pure opioid antagonist", action: "Competitive antagonist at mu-opioid receptors; rapidly displaces opioids from receptors reversing respiratory depression, sedation, and miosis within 2-5 minutes", sideEffects: "Precipitated withdrawal (vomiting, agitation, tachycardia, piloerection), pulmonary edema (rare)", contra: "No absolute contraindications in life-threatening opioid overdose", pearl: "0.4-2 mg IV/IM/SubQ or 4 mg intranasal; onset IV: 2 minutes, IM: 5 minutes, IN: 8-13 minutes; duration 30-90 minutes -- SHORTER than most opioids, so patient may re-sedate (monitor for at least 2-4 hours after last dose); repeat every 2-3 minutes until respiratory rate above 12; available over-the-counter (Narcan nasal spray); teach patients and families of opioid users to carry and use naloxone" }],
    pearls: ["Addiction is a BRAIN DISEASE, not a moral failing: the mesolimbic dopamine system is hijacked by substances creating compulsive use despite consequences; stigmatizing language (addict, junkie, abuser) should be replaced with person-first language (person with substance use disorder)", "Alcohol withdrawal can be FATAL: unlike opioid withdrawal (extremely uncomfortable but rarely fatal), alcohol and benzodiazepine withdrawal can cause fatal seizures and delirium tremens; NEVER discontinue alcohol or benzodiazepines abruptly in dependent patients", "Thiamine BEFORE glucose: always administer thiamine before glucose-containing fluids in suspected alcohol use; glucose metabolism requires thiamine, and administering glucose without thiamine can precipitate Wernicke encephalopathy (confusion, ataxia, ophthalmoplegia) or Korsakoff syndrome (irreversible memory loss)", "MAT saves lives: medication-assisted treatment (buprenorphine, methadone, naltrexone) reduces opioid overdose death by 50%+; it is NOT replacing one addiction with another -- it normalizes brain chemistry and allows recovery", "Naloxone should be prescribed to ALL patients on chronic opioids and ALL patients with opioid use disorder: it is available over-the-counter; teach patients, families, and caregivers to use it", "CIWA-Ar symptom-triggered protocol is safer and uses less benzodiazepine than fixed-schedule dosing: assess every 1-2 hours, medicate only when score exceeds threshold (8+)"],
    quiz: [{ question: "Before administering IV dextrose to an intoxicated patient, the practical nurse should ensure:", options: ["An ECG has been completed", "Thiamine has been administered first to prevent Wernicke encephalopathy", "The patient has eaten a meal", "Blood type has been verified"], correct: 1, rationale: "Thiamine must be given BEFORE glucose-containing fluids. Glucose metabolism requires thiamine (vitamin B1). In thiamine-deficient alcoholic patients, glucose administration without thiamine can precipitate Wernicke encephalopathy (confusion, ataxia, ophthalmoplegia)." }, { question: "A patient with opioid use disorder is starting buprenorphine-naloxone. When should the first dose be administered?", options: ["Immediately upon admission", "When the COWS score reaches 8 or higher (moderate withdrawal)", "24 hours after the last opioid dose regardless of symptoms", "Only after complete detoxification"], correct: 1, rationale: "Buprenorphine must NOT be initiated until the patient is in moderate withdrawal (COWS 8+). Giving it too early while full opioid agonist is still on receptors causes PRECIPITATED WITHDRAWAL (sudden, severe withdrawal from buprenorphine displacing the full agonist)." }, { question: "Delirium tremens typically occurs how many hours after the last alcohol drink?", options: ["2-6 hours", "6-12 hours", "48-96 hours", "7-10 days"], correct: 2, rationale: "Delirium tremens (DTs) typically occurs 48-96 hours after the last drink. It is characterized by severe confusion, agitation, hallucinations, autonomic instability, and hyperthermia. Without treatment, mortality is 5-15%." }]
  },
  "substance-use-disorders-rn": {
    title: "Substance Use Disorders",
    cellular: { title: "Withdrawal Assessment", content: "The nurse managing SUD implements withdrawal protocols, coordinates MAT initiation, manages comorbid medical complications, and facilitates transition to ongoing recovery services. Alcohol withdrawal pathophysiology involves chronic GABA-A receptor downregulation and glutamate NMDA receptor upregulation from prolonged alcohol exposure. When alcohol is removed, the inhibitory GABA system is insufficient and the excitatory glutamate system is overactive, producing CNS hyperexcitability manifesting as tremor, seizures, and delirium. CIWA-Ar protocol implementation: assess every 1-2 hours; score 0-9 (mild, supportive care), 10-18 (moderate, pharmacological treatment indicated), above 18 (severe, intensive monitoring). Benzodiazepine selection: long-acting (chlordiazepoxide, diazepam) for uncomplicated withdrawal; lorazepam for hepatic impairment (conjugation metabolism, not oxidation). Refractory DTs may require phenobarbital or propofol/ICU transfer. Opioid MAT initiation requires understanding of pharmacology: buprenorphine (partial agonist, ceiling effect, precipitated withdrawal risk if given too early, safe in overdose); methadone (full agonist, no ceiling effect, overdose risk, QTc prolongation, requires federally licensed opioid treatment program); naltrexone (full antagonist, blocks opioid effects, requires 7-10 days opioid-free before starting, available as monthly injection)." },
    riskFactors: ["DT risk factors: history of DTs, seizure history, heavy prolonged use, concurrent medical illness, elevated BAL at admission, CIWA above 15 at presentation", "Opioid overdose risk: return to use after period of abstinence (tolerance lost), polysubstance use (opioid + benzodiazepine most dangerous), injection drug use, high-dose prescriptions, history of overdose", "Wernicke-Korsakoff syndrome: chronic alcohol use with thiamine deficiency; Wernicke (acute, reversible with thiamine) vs Korsakoff (chronic, irreversible amnesia)", "Infectious complications of injection drug use: endocarditis (S. aureus, tricuspid valve), HIV, hepatitis B and C, cellulitis, abscess, osteomyelitis", "Alcohol-related liver disease progression: steatosis -> alcoholic hepatitis -> cirrhosis; AST:ALT ratio above 2:1 is characteristic", "Fetal alcohol spectrum disorder: alcohol is the leading preventable cause of intellectual disability"],
    diagnostics: ["CIWA-Ar serial scoring: assess nausea, tremor, paroxysmal sweats, anxiety, agitation, tactile/auditory/visual disturbances, headache, orientation; maximum score 67", "COWS serial scoring: resting pulse, sweating, restlessness, pupil size, bone/joint aches, rhinorrhea/lacrimation, GI upset, tremor, yawning, anxiety, piloerection; guides buprenorphine initiation", "PAWSS (Prediction of Alcohol Withdrawal Severity Scale): predicts which patients are at risk for complicated withdrawal before symptoms begin", "Labs: BAL (blood alcohol level), CBC (macrocytic anemia from folate/B12 deficiency), LFTs (GGT most sensitive for alcohol use; AST:ALT above 2:1), ammonia (hepatic encephalopathy), lipase (alcoholic pancreatitis), magnesium (hypomagnesemia common, increases seizure risk), phosphate, INR", "Infectious disease screening for IVDU: HIV, hepatitis B surface antigen/antibody, hepatitis C antibody, blood cultures if febrile", "ECG: QTc monitoring if starting methadone (dose-dependent QTc prolongation)"],
    management: ["Alcohol withdrawal CIWA-Ar protocol: assess every 1-2 hours; CIWA 10-18: chlordiazepoxide 25-50 mg PO (or lorazepam 1-2 mg if liver disease) every 1-2 hours; CIWA above 18: higher doses, more frequent assessment, ICU consideration; refractory DTs: phenobarbital 130-260 mg IV or propofol infusion", "Buprenorphine induction: standard (wait for COWS 8+, give 2-4 mg SL, reassess in 1 hour, additional doses up to 8-16 mg day 1); micro-dosing/Bernese method (start 0.5 mg while still on full agonist, increase gradually over 3-7 days -- avoids precipitated withdrawal, useful for fentanyl users where traditional induction is difficult)", "Methadone induction: start 20-30 mg PO day 1, observe 2-4 hours; additional 10 mg if withdrawal persists (max 40 mg day 1); increase by 5-10 mg every 3-5 days; target dose typically 80-120 mg; requires OTP (opioid treatment program) setting", "Naltrexone initiation: patient must be opioid-free 7-10 days (confirmed by negative urine and naloxone challenge); 50 mg PO daily or 380 mg IM monthly (Vivitrol); blocks opioid effects for 24 hours (PO) or 30 days (IM)", "Alcohol maintenance: naltrexone 50 mg PO daily or 380 mg IM monthly (reduces craving); acamprosate 666 mg TID (restores glutamate balance); disulfiram 250-500 mg daily (aversion -- inhibits aldehyde dehydrogenase causing severe nausea/vomiting/flushing with alcohol use)"],
    nursingActions: ["Implement and manage CIWA-Ar protocol: assess every 1-2 hours, administer benzodiazepines per protocol, document scores and interventions, recognize DT warning signs (CIWA above 20, fever, severe confusion, autonomic instability)", "Manage buprenorphine induction: verify COWS score 8+ before first dose, administer sublingual buprenorphine, observe for precipitated withdrawal (would present as sudden worsening of symptoms after dose), reassess and give additional doses as prescribed", "Monitor for alcohol withdrawal complications: seizures (peak 24-48 hours), DTs (peak 48-96 hours), Wernicke encephalopathy (confusion, ataxia, ophthalmoplegia -- administer high-dose IV thiamine 500 mg TID for 3 days)", "Manage electrolyte abnormalities: replace magnesium (hypomagnesemia lowers seizure threshold), potassium, phosphate; monitor glucose", "Implement harm reduction education: naloxone training and distribution, safe injection practices, HIV/HCV prevention, fentanyl test strips", "Coordinate transition to ongoing recovery: connect with MAT provider, schedule follow-up within 48-72 hours of discharge, provide crisis hotline numbers, connect with peer support, arrange counseling"],
    assessmentFindings: ["CIWA-Ar interpretation: 0-9 (mild, outpatient management possible), 10-18 (moderate, inpatient recommended), above 18 (severe, ICU consideration), above 25 (very severe, high DT risk)", "Precipitated withdrawal recognition: sudden onset of severe withdrawal symptoms within 30-60 minutes of buprenorphine dose; caused by buprenorphine displacing full agonist from receptors; management: supportive care, additional buprenorphine (does NOT worsen it -- more buprenorphine actually helps by fully occupying receptors)", "Wernicke encephalopathy triad: confusion (most common), ataxia, ophthalmoplegia (cranial nerve VI palsy); only 10-16% present with all three; treat empirically with IV thiamine in any suspected case", "Motivational stage assessment: precontemplation (not considering change), contemplation (ambivalent), preparation (planning change), action (implementing change), maintenance (sustaining change); tailor interventions to stage"],
    signs: { left: ["Alcohol withdrawal managed with CIWA protocol without complications", "Successfully induced on buprenorphine with stable dosing", "Engaging in MAT and psychosocial treatment", "Transitioning to outpatient recovery support"], right: ["Delirium tremens with hemodynamic instability requiring ICU", "Refractory alcohol withdrawal requiring phenobarbital or propofol", "Precipitated withdrawal from premature buprenorphine induction", "Opioid overdose requiring repeated naloxone doses", "Wernicke encephalopathy progressing to Korsakoff syndrome", "Endocarditis from injection drug use requiring surgical valve replacement"] },
    medications: [{ name: "Methadone (for OUD)", type: "Full mu-opioid agonist", action: "Full agonist at mu-opioid receptors providing cross-tolerance, preventing withdrawal, and blocking euphoria from other opioids at adequate doses; also NMDA receptor antagonist (may help with chronic pain and tolerance prevention)", sideEffects: "Respiratory depression (no ceiling effect unlike buprenorphine), QTc prolongation (dose-dependent), sedation, constipation, diaphoresis, hypogonadism, weight gain", contra: "Respiratory depression, concurrent CNS depressants (relative), severe QTc prolongation", pearl: "80-120 mg is typical effective maintenance dose; must be dispensed through OTP (daily observed dosing initially, earn take-homes with compliance); QTc monitoring: baseline ECG, repeat at 30 days and annually, or with dose changes above 100 mg; NO ceiling effect for respiratory depression (unlike buprenorphine) making overdose risk higher; drug interactions: many CYP3A4 interactions; STILL REDUCES overdose death compared to no treatment despite higher risk profile than buprenorphine" }, { name: "Naltrexone Extended-Release (Vivitrol)", type: "Opioid antagonist (monthly injection)", action: "Full competitive antagonist at mu-opioid receptors blocking euphoric effects of opioids for 30 days; also reduces alcohol craving through modulation of endogenous opioid system", sideEffects: "Injection site reactions (induration, pain), nausea, headache, hepatotoxicity (rare, monitor LFTs), depression", contra: "Current opioid use (precipitates severe withdrawal), acute hepatitis, opioid dependence (must be opioid-free 7-10 days)", pearl: "380 mg IM gluteal monthly; requires 7-10 day opioid-free period verified by negative urine and optional naloxone challenge (0.8 mg IM, observe 45 minutes); FDA-approved for both OUD and AUD; advantage: no abuse potential, no diversion risk, monthly injection; disadvantage: difficult to achieve 7-10 day abstinence from opioids to start; does NOT protect against overdose if patient overcomes blockade with massive opioid doses (patient should carry medical alert)" }, { name: "Acamprosate (Campral)", type: "NMDA receptor modulator / glutamate stabilizer", action: "Modulates glutamatergic neurotransmission and GABA activity; normalizes the hyperexcitable state that persists after alcohol cessation; reduces protracted withdrawal symptoms (anxiety, insomnia, dysphoria, craving)", sideEffects: "Diarrhea (most common), nausea, headache", contra: "Severe renal impairment (CrCl below 30 -- renally eliminated)", pearl: "666 mg TID (challenging pill burden -- 6 pills per day); FDA-approved for alcohol use disorder maintenance; works best in patients who have already achieved abstinence (reduces relapse, does not reduce drinking in active users); can be combined with naltrexone for dual mechanism; no hepatic metabolism (safe in liver disease, unlike disulfiram and naltrexone); does NOT interact with alcohol (unlike disulfiram)" }],
    pearls: ["DTs have 5-15% mortality if untreated: CIWA-Ar monitoring every 1-2 hours with symptom-triggered benzodiazepines is the standard of care; fixed-schedule dosing uses more benzodiazepine and has more complications than symptom-triggered dosing", "Buprenorphine micro-dosing (Bernese method) is increasingly used for fentanyl users: traditional induction (wait for COWS 8+) is very difficult with fentanyl (extremely long withdrawal timeline, precipitated withdrawal even at COWS 12+); micro-dosing starts at 0.5 mg while still on fentanyl and gradually increases, avoiding precipitated withdrawal", "Magnesium replacement in alcohol withdrawal: hypomagnesemia is nearly universal in chronic alcohol use and significantly lowers seizure threshold; replace magnesium empirically (2 g MgSO4 IV) even before levels return", "Naltrexone is the only MAT option that does NOT require special prescribing credentials or OTP setting: any provider can prescribe; monthly injection (Vivitrol) eliminates adherence concerns; particularly useful for patients who prefer non-opioid treatment", "Harm reduction saves lives: naloxone distribution, syringe exchange, fentanyl test strips, and supervised consumption sites reduce overdose deaths and disease transmission without requiring abstinence as a prerequisite for treatment"],
    quiz: [{ question: "A patient on methadone maintenance presents with QTc of 520 ms on routine ECG. The nurse should:", options: ["Continue methadone as prescribed", "Report to prescriber immediately for dose reduction or medication change (QTc above 500 = significant arrhythmia risk)", "Increase the methadone dose", "Discontinue methadone abruptly"], correct: 1, rationale: "QTc above 500 ms is a significant risk factor for torsades de pointes (potentially fatal ventricular arrhythmia). The prescriber must be notified for dose reduction, switch to buprenorphine, or discontinuation with close monitoring." }, { question: "A patient presents with CIWA-Ar score of 22, temperature 102.4F, and confusion 72 hours after last alcohol intake. This presentation is most consistent with:", options: ["Mild alcohol withdrawal", "Alcohol intoxication", "Delirium tremens requiring ICU-level care", "Medication side effect"], correct: 2, rationale: "CIWA above 20, hyperthermia, and confusion at 72 hours post-last drink are characteristic of delirium tremens, a life-threatening complication of alcohol withdrawal requiring aggressive benzodiazepine treatment and potentially ICU transfer." }, { question: "The Bernese method (buprenorphine micro-dosing) is particularly useful for:", options: ["Alcohol withdrawal management", "Fentanyl users where traditional buprenorphine induction often causes precipitated withdrawal", "Benzodiazepine detoxification", "Stimulant use disorder"], correct: 1, rationale: "Traditional buprenorphine induction requires waiting until COWS 8+, which is very difficult with fentanyl (long-acting, difficult to achieve adequate withdrawal). Micro-dosing starts buprenorphine at tiny doses (0.5 mg) while the patient continues fentanyl use, gradually increasing buprenorphine and decreasing fentanyl to avoid precipitated withdrawal." }]
  },
  "eating-disorders-rpn": {
    title: "Eating Disorders",
    cellular: { title: "Pathophysiology of Eating Disorders", content: "Eating disorders are psychiatric conditions with the HIGHEST mortality rate of any mental illness. Anorexia nervosa (AN) is characterized by restriction of energy intake leading to significantly low body weight, intense fear of gaining weight, and distorted body image. Bulimia nervosa (BN) involves recurrent episodes of binge eating followed by compensatory behaviors (purging via self-induced vomiting, laxative/diuretic misuse, fasting, excessive exercise). Binge eating disorder (BED) involves recurrent binge episodes without compensatory behaviors. AN pathophysiology includes starvation-induced metabolic adaptations: decreased metabolic rate, hypothermia, bradycardia, hypotension, amenorrhea (from hypothalamic suppression of GnRH), osteoporosis (from estrogen deficiency), muscle wasting, lanugo (fine body hair as insulation), and electrolyte abnormalities. Refeeding syndrome is the most dangerous complication of AN treatment: rapid reintroduction of nutrition in a starved patient causes insulin surge, driving phosphate, potassium, and magnesium intracellularly, causing severe hypophosphatemia, cardiac arrhythmias, heart failure, and death. BN complications include dental erosion (perimolysis from stomach acid), esophageal tears (Mallory-Weiss), metabolic alkalosis from vomiting (loss of HCl), hypokalemia, parotid gland enlargement (chipmunk cheeks), and Russell sign (calluses on knuckles from self-induced vomiting)." },
    riskFactors: ["Female sex (AN 10:1, BN 10:1, BED 3:2 female to male)", "Adolescent and young adult onset (peak 14-18 years)", "Perfectionism, high achievement, anxiety disorders", "Sports/activities emphasizing leanness (gymnastics, ballet, wrestling, running)", "Family history of eating disorders or other psychiatric conditions", "Childhood trauma and adverse childhood experiences", "Type 1 diabetes (insulin omission for weight control -- diabulimia)", "Media exposure and sociocultural pressures regarding body image"],
    diagnostics: ["AN criteria: BMI below 18.5 (or significantly low weight for age), fear of weight gain, body image distortion; severity: mild (BMI 17-18.5), moderate (16-16.99), severe (15-15.99), extreme (below 15)", "BN criteria: binge eating and compensatory behaviors at least once/week for 3 months", "Labs: BMP (hypokalemia, hypochloremia, metabolic alkalosis from purging; hypoglycemia in AN), phosphate (critical for refeeding syndrome monitoring), magnesium, CBC (leukopenia, anemia), albumin/prealbumin (nutritional status), TSH (thyroid dysfunction), LH/FSH (hypothalamic amenorrhea)", "ECG: bradycardia in AN, QTc prolongation from electrolyte abnormalities, arrhythmias", "DEXA scan for bone density (osteoporosis risk in AN, especially after 6+ months amenorrhea)", "SCOFF screening: Sick, Control, One stone (14 lbs), Fat, Food (2+ positive suggests eating disorder)"],
    management: ["AN: nutritional rehabilitation is first priority; START LOW AND GO SLOW to prevent refeeding syndrome (start 1000-1200 kcal/day, increase by 200-300 kcal every 2-3 days); monitor phosphate, potassium, magnesium daily; supplement phosphate prophylactically", "BN: CBT-E (enhanced cognitive behavioral therapy) is first-line psychotherapy; fluoxetine 60 mg is the ONLY FDA-approved medication (higher dose than for depression)", "BED: CBT is first-line; lisdexamfetamine (Vyvanse) 50-70 mg is FDA-approved; topiramate off-label", "Medical stabilization: correct electrolyte abnormalities, rehydrate cautiously, treat cardiac complications", "Hospitalization criteria: BMI below 15, heart rate below 50, systolic BP below 90, severe electrolyte abnormalities, suicidal ideation, failure of outpatient treatment"],
    nursingActions: ["Monitor vital signs frequently: bradycardia (HR below 60), hypotension, hypothermia (temperature below 97.0F/36.1C) indicate medical instability in AN", "Implement refeeding syndrome monitoring: check phosphate, potassium, magnesium DAILY during initial refeeding; replace phosphate prophylactically; monitor for signs (tachycardia, edema, confusion, respiratory distress) -- refeeding syndrome typically occurs days 2-5 of nutritional rehabilitation", "Monitor meals and post-meal behavior: observe patients during and for 1-2 hours after meals to prevent purging; check bathrooms after meals; document intake accurately", "Daily weights: weigh in gown only, back to scale (patient should not see weight if this causes distress), same time each day, after voiding", "Monitor for purging behaviors: check for laxatives/diuretics in belongings, Russell sign on knuckles, parotid enlargement, dental erosion", "Provide non-judgmental, empathetic care: eating disorders involve intense shame; avoid comments about weight, food choices, or appearance; focus on health behaviors rather than weight"],
    assessmentFindings: ["AN physical findings: emaciation, lanugo (fine body hair), dry skin, brittle nails, hair loss, hypothermia, bradycardia, orthostatic hypotension, pedal edema (hypoalbuminemia), amenorrhea, muscle wasting", "BN physical findings: Russell sign (calluses on dorsum of hand from self-induced vomiting), dental erosion (perimolysis, especially lingual surface of teeth), parotid gland enlargement (chipmunk cheeks), metabolic alkalosis, hypokalemia", "Refeeding syndrome: occurs 2-5 days into nutritional rehabilitation; severe hypophosphatemia (below 1.0 mg/dL), hypokalemia, hypomagnesemia, fluid retention, peripheral edema, tachycardia, cardiac arrhythmias, heart failure, delirium, seizures", "Psychological assessment: body image distortion, fear of weight gain, denial of illness severity, perfectionism, control issues, comorbid depression and anxiety"],
    signs: { left: ["Medically stable with normal vital signs and electrolytes", "Tolerating nutritional rehabilitation without refeeding syndrome", "Engaging in psychotherapy and nutritional counseling", "Weight restoration progressing appropriately"], right: ["Refeeding syndrome (hypophosphatemia, cardiac failure, death)", "Severe bradycardia (HR below 40) or cardiac arrhythmia", "Severe hypokalemia (below 2.5 mEq/L) with ECG changes", "Esophageal rupture (Boerhaave syndrome) from forceful vomiting", "Suicidal ideation (eating disorders have highest suicide rate among psychiatric disorders)", "Superior mesenteric artery syndrome (SMA compresses duodenum in severely emaciated patients)"] },
    medications: [{ name: "Fluoxetine (Prozac) for Bulimia", type: "SSRI", action: "Reduces binge-purge frequency through serotonin modulation in appetite and impulse control circuits; the ONLY FDA-approved medication for bulimia nervosa", sideEffects: "Nausea, headache, insomnia, sexual dysfunction, anxiety initially", contra: "Concurrent MAOIs, known hypersensitivity", pearl: "60 mg daily (higher than depression dose of 20 mg); reduces binge-purge frequency by 50-70%; FDA-approved for BN only (no medication is FDA-approved for AN); combine with CBT-E for best outcomes; long half-life means missed doses are less problematic; SSRIs should be used cautiously in severely underweight AN patients due to QTc prolongation risk with electrolyte imbalances" }, { name: "Potassium Chloride (KCl) Replacement", type: "Electrolyte replacement", action: "Replaces potassium lost through purging (vomiting, laxative, diuretic misuse); prevents cardiac arrhythmias, muscle weakness, and cardiac arrest from hypokalemia", sideEffects: "GI irritation, nausea, hyperkalemia if over-replaced", contra: "Hyperkalemia, severe renal impairment, concurrent potassium-sparing diuretics", pearl: "Replace based on serum level: K+ 3.0-3.5: 40-80 mEq PO daily; K+ below 3.0: 10-20 mEq/hr IV with cardiac monitoring; CRITICAL: always check magnesium -- hypomagnesemia prevents potassium repletion (magnesium is required for renal potassium retention); refractory hypokalemia = check and replace magnesium first" }, { name: "Sodium Phosphate Replacement", type: "Electrolyte replacement (refeeding syndrome prevention)", action: "Replaces phosphate driven intracellularly during refeeding when insulin surges; prevents cardiac failure, respiratory failure, and death from refeeding syndrome", sideEffects: "Hypocalcemia (phosphate binds calcium), diarrhea, hyperphosphatemia if over-replaced", contra: "Hyperphosphatemia, severe renal impairment", pearl: "Prophylactic replacement during AN refeeding: 1-1.5 mmol/kg/day PO or IV; therapeutic replacement for hypophosphatemia below 2.0: IV sodium/potassium phosphate 0.08-0.16 mmol/kg over 6 hours; check phosphate DAILY during first week of refeeding; refeeding syndrome is the #1 cause of death during AN treatment -- preventable with prophylactic phosphate, slow caloric advancement, and daily electrolyte monitoring" }],
    pearls: ["Eating disorders have the HIGHEST MORTALITY of any psychiatric illness: AN has a mortality rate of 5-10% per decade; causes include cardiac arrhythmia, suicide, and starvation-related organ failure", "Refeeding syndrome prevention: START LOW AND GO SLOW (1000-1200 kcal/day initially, increase by 200-300 kcal every 2-3 days); replace phosphate prophylactically; monitor phosphate, potassium, and magnesium DAILY for the first week", "Refractory hypokalemia: if potassium does not correct with replacement, CHECK MAGNESIUM -- hypomagnesemia prevents the kidney from retaining potassium; replace magnesium first, then potassium will correct", "Russell sign: calluses on the dorsum of the hand from repeated self-induced vomiting; a specific physical finding for bulimia nervosa purging behavior", "AN is the only psychiatric disorder where FORCED treatment may be medically necessary to prevent death: some jurisdictions allow involuntary feeding for life-threatening AN; this involves complex ethical and legal considerations", "Dental erosion in bulimia: stomach acid erodes dental enamel, especially the lingual (tongue-side) surface of upper front teeth (perimolysis); refer to dentistry; advise against brushing immediately after vomiting (spreads acid)"],
    quiz: [{ question: "A patient with severe anorexia nervosa (BMI 14) begins nutritional rehabilitation. On day 3, she develops tachycardia, confusion, and peripheral edema. The practical nurse suspects:", options: ["Fluid overload from IV fluids", "Refeeding syndrome -- check phosphate level immediately", "Medication reaction", "Heart failure from pre-existing condition"], correct: 1, rationale: "Refeeding syndrome occurs 2-5 days after initiating nutrition in severely malnourished patients. Insulin surge drives phosphate intracellularly causing severe hypophosphatemia leading to cardiac failure, respiratory failure, and death. Immediate phosphate level check and replacement is critical." }, { question: "A patient with bulimia has a potassium level of 2.8 mEq/L that is not correcting despite oral supplementation. The practical nurse should:", options: ["Continue current potassium replacement", "Check magnesium level -- hypomagnesemia prevents potassium correction", "Increase oral potassium dose", "Discontinue replacement and recheck in 24 hours"], correct: 1, rationale: "Refractory hypokalemia is most commonly caused by concurrent hypomagnesemia. Magnesium is required for the kidney to retain potassium. Replace magnesium first, then potassium will correct." }, { question: "Which physical finding is specific to bulimia nervosa purging?", options: ["Lanugo body hair", "Russell sign (calluses on knuckles)", "Hypothermia", "Amenorrhea"], correct: 1, rationale: "Russell sign (calluses on the dorsum of the hand from repeatedly inducing vomiting) is specific to bulimia nervosa purging. Lanugo, hypothermia, and amenorrhea are more characteristic of anorexia nervosa." }]
  },
  "eating-disorders-rn": {
    title: "Eating Disorders",
    cellular: { title: "Eating Disorder Assessment", content: "The nurse managing eating disorders implements medical stabilization protocols, prevents and manages refeeding syndrome, monitors complex physiological derangements, and coordinates multidisciplinary care. Refeeding syndrome pathophysiology: during starvation, the body shifts from carbohydrate to fat and protein metabolism; intracellular stores of phosphate, potassium, and magnesium are depleted despite initially normal serum levels (serum levels reflect only 1% of total body stores). When carbohydrates are reintroduced, insulin is secreted, driving glucose and electrolytes (especially phosphate) intracellularly. The sudden intracellular phosphate shift causes serum hypophosphatemia. Phosphate is essential for ATP production, 2,3-DPG (oxygen delivery), and cell membrane integrity. Severe hypophosphatemia causes: cardiac failure (ATP depletion in myocardium), respiratory failure (diaphragm weakness), rhabdomyolysis, hemolytic anemia (RBC membrane fragility), seizures, and death. The NICE guidelines for refeeding risk include: BMI below 16, weight loss greater than 15% in 3-6 months, little or no intake for 10+ days, and low baseline phosphate/potassium/magnesium. Prevention requires: starting at 10-20 kcal/kg/day (not 1000-1200 kcal), prophylactic phosphate and thiamine supplementation, daily electrolyte monitoring, and gradual caloric advancement over 7-10 days." },
    riskFactors: ["Refeeding syndrome risk: BMI below 16, weight loss greater than 15% in 3-6 months, negligible intake for 10+ days, low baseline electrolytes, alcohol use disorder, oncology patients, post-bariatric surgery", "Cardiac complications in AN: QTc prolongation (risk of torsades de pointes), mitral valve prolapse (from cardiac muscle wasting), pericardial effusion, heart failure", "Bone density loss: occurs after 6+ months of amenorrhea; may be irreversible; DEXA scan recommended after 6 months; weight restoration is the ONLY treatment that reliably improves BMD in AN", "Osteoporosis: AN is the #1 cause of osteoporosis in young women; estrogen replacement alone does NOT prevent bone loss in AN (weight restoration is necessary)", "Sudden cardiac death: leading cause of death in AN; from hypokalemia-induced arrhythmia or QTc prolongation", "Diabulimia: patients with type 1 diabetes who omit insulin to lose weight; extremely dangerous (DKA risk, accelerated microvascular complications)"],
    diagnostics: ["Comprehensive metabolic panel with phosphate and magnesium: daily during initial refeeding (days 1-7), then every other day for week 2, then twice weekly until nutritionally stable", "ECG monitoring: QTc measurement at baseline and with any electrolyte abnormality; QTc above 450 ms in AN requires correction of electrolytes and cardiac monitoring; QTc above 500 ms is high risk for torsades", "Prealbumin (half-life 2-3 days, more sensitive than albumin for acute nutritional changes); albumin (half-life 20 days, reflects longer-term status)", "DEXA scan after 6+ months of amenorrhea or low body weight for bone density assessment", "Cardiac echo for patients with very low BMI (below 15): assess for pericardial effusion, mitral valve prolapse, impaired cardiac contractility", "Calorie count and I&O monitoring: document all intake, output, and behaviors (purging attempts, exercise, food hiding)"],
    management: ["Refeeding protocol (NICE-based): high risk (BMI below 14 or negligible intake 15+ days): start 5-10 kcal/kg/day; moderate risk (BMI 14-16): start 15-20 kcal/kg/day; supplement thiamine 200-300 mg PO/IV daily, phosphate prophylactically, multivitamin; advance calories by 200 kcal every 2-3 days as tolerated and electrolytes remain stable", "Cardiac monitoring: telemetry for patients with BMI below 14, QTc above 450, heart rate below 40, or significant electrolyte abnormalities", "Target weight gain: 0.5-1.0 kg/week for inpatients (1-1.5 lbs/week); overly aggressive refeeding increases refeeding syndrome risk", "Behavioral meal management: structured meals (3 meals, 2-3 snacks), supervised eating (30 minutes for meals, 15 for snacks), post-meal supervision 1-2 hours, bathroom supervision after meals to prevent purging", "Outpatient monitoring criteria: medically stable vital signs, electrolytes stable, weight gain trajectory established, outpatient team in place"],
    nursingActions: ["Implement refeeding syndrome prevention protocol: calculate starting calories based on BMI and starvation severity, supplement phosphate and thiamine prophylactically, check electrolytes DAILY for first 7 days", "Monitor for refeeding syndrome signs: tachycardia (earliest cardiac sign), peripheral edema (fluid retention), confusion (neurological phosphate depletion), respiratory distress (diaphragm weakness), cardiac failure", "Implement structured meal supervision: sit with patient during meals, provide emotional support, use therapeutic communication (avoid power struggles about food), document intake accurately (calorie count), observe for food hiding/disposal", "Manage post-meal anxiety: stay with patient 1-2 hours after meals, provide distraction and coping activities, monitor bathroom use, document any purging attempts", "Monitor daily weights: same time, after voiding, in gown only, patient facing away from scale (if blind weights ordered); weight may initially increase from fluid retention before true weight gain", "Implement exercise restriction: patients with AN may engage in compulsive exercise; restrict activity to prescribed levels; provide alternative coping strategies for anxiety"],
    assessmentFindings: ["Refeeding syndrome laboratory changes: phosphate below 2.5 (mild), below 1.5 (moderate), below 1.0 (severe/life-threatening); concurrent hypokalemia, hypomagnesemia, fluid retention; occurs days 2-5 of refeeding", "Cardiovascular assessment in AN: resting heart rate below 50 (severe bradycardia), orthostatic changes (drop greater than 20 systolic on standing), QTc prolongation, peripheral edema, mitral valve click (MVP)", "Nutritional recovery indicators: normalization of heart rate and blood pressure, resolution of orthostatic changes, return of menses (may take months to years), improving albumin/prealbumin, stable weight gain trajectory", "Psychological readiness indicators: decreasing food anxiety, improving body image flexibility, engaging in therapy, decreasing compensatory behaviors"],
    signs: { left: ["Refeeding progressing without electrolyte complications", "Weight gaining 0.5-1.0 kg/week inpatient", "Vital signs normalizing with improved cardiac function", "Engaging in eating disorder-focused psychotherapy"], right: ["Refeeding syndrome with phosphate below 1.0 mg/dL and cardiac failure", "QTc above 500 ms with ventricular arrhythmia risk", "Severe hypokalemia (below 2.5) with cardiac arrest risk", "Esophageal perforation (Boerhaave) from forceful vomiting", "Suicide attempt (eating disorders have high suicide rate)", "Superior mesenteric artery (SMA) syndrome compressing duodenum in severely emaciated patient"] },
    medications: [{ name: "Thiamine (Vitamin B1) in Refeeding", type: "Vitamin supplementation", action: "Essential cofactor for carbohydrate metabolism (pyruvate dehydrogenase, alpha-ketoglutarate dehydrogenase, transketolase); when carbohydrates are reintroduced in starvation, increased metabolic demand depletes remaining thiamine stores potentially causing Wernicke encephalopathy or cardiac beriberi", sideEffects: "Rare: anaphylaxis with IV administration (very rare), injection site pain", contra: "Known hypersensitivity (extremely rare)", pearl: "200-300 mg IV/PO daily for first 10 days of refeeding; MUST be given BEFORE or concurrent with caloric reintroduction; thiamine is a water-soluble vitamin that is rapidly depleted in starvation; without supplementation, carbohydrate refeeding can precipitate Wernicke encephalopathy (confusion, ataxia, ophthalmoplegia) or wet beriberi (high-output cardiac failure)" }, { name: "Lisdexamfetamine (Vyvanse) for BED", type: "Prodrug stimulant (converted to dextroamphetamine)", action: "CNS stimulant that increases dopamine and norepinephrine in the prefrontal cortex; reduces binge eating frequency through improved impulse control and appetite suppression; the ONLY FDA-approved medication for binge eating disorder", sideEffects: "Insomnia, dry mouth, tachycardia, hypertension, anxiety, decreased appetite, weight loss, abuse potential (Schedule II)", contra: "Advanced cardiovascular disease, uncontrolled hypertension, concurrent MAOIs, glaucoma, history of stimulant abuse", pearl: "50-70 mg daily in morning; reduces binge frequency by 50-70%; FDA-approved for moderate-severe BED in adults; NOT approved for weight loss (the appetite suppression is a side effect); contraindicated in AN and BN (would worsen restriction); Schedule II with abuse potential; NP should assess cardiovascular risk before prescribing and monitor BP/HR; also effective for comorbid ADHD" }, { name: "Ondansetron (Zofran) for Purging Reduction", type: "5-HT3 receptor antagonist (off-label for BN)", action: "Blocks serotonin 5-HT3 receptors in the GI tract and CTZ; may reduce urge to purge through modulation of vagal signaling and serotonin-mediated gut-brain axis", sideEffects: "Headache, constipation, QTc prolongation", contra: "Congenital long QT syndrome, concurrent QTc-prolonging medications", pearl: "4-8 mg PO prior to meals; off-label use in BN to reduce purging frequency; small studies show reduction in purge episodes; mechanism may involve reducing nausea/GI discomfort that triggers purging; monitor QTc (risk compounded with eating disorder-related electrolyte abnormalities); not widely used but can be a helpful adjunct when standard treatments are insufficient" }],
    pearls: ["Refeeding syndrome prevention saves lives: the MOST important nursing intervention is prophylactic phosphate supplementation and daily electrolyte monitoring during the first week of nutritional rehabilitation", "Weight restoration is the ONLY proven treatment for osteoporosis in anorexia nervosa: oral contraceptives do NOT prevent bone loss in AN (unlike postmenopausal osteoporosis where estrogen helps); bisphosphonates are relatively contraindicated in premenopausal women", "QTc monitoring in eating disorders: both hypokalemia AND hypomagnesemia prolong QTc; correct BOTH electrolytes to reduce arrhythmia risk; QTc above 500 ms requires telemetry and aggressive electrolyte correction", "Meal supervision techniques: sit at a 45-degree angle (not directly across -- less confrontational), use matter-of-fact tone, avoid commenting on specific foods or amounts, provide emotional support for anxiety, document intake without making it punitive", "Compulsive exercise in AN: this is a compensatory behavior equivalent to purging; restrict to bed rest or supervised gentle movement; patients may exercise covertly (running in place, isometric exercises, standing instead of sitting)"],
    quiz: [{ question: "An RN is managing refeeding in a patient with AN (BMI 13). Day 3 labs show phosphate 0.9 mg/dL. The PRIORITY action is:", options: ["Continue current feeding rate", "Hold nutrition and replace phosphate IV emergently; notify provider", "Increase caloric intake to accelerate recovery", "Recheck phosphate in 24 hours"], correct: 1, rationale: "Phosphate below 1.0 mg/dL is a life-threatening emergency during refeeding. IV phosphate replacement must be initiated immediately while temporarily reducing caloric advancement. This level can cause cardiac arrest, respiratory failure, and death." }, { question: "Which statement about bone health in anorexia nervosa is CORRECT?", options: ["Oral contraceptives effectively prevent bone loss in AN", "Weight restoration is the only proven treatment for AN-related osteoporosis", "Bisphosphonates are first-line for AN bone loss", "Bone loss does not occur until BMI drops below 15"], correct: 1, rationale: "Unlike postmenopausal osteoporosis, oral contraceptives do NOT prevent bone loss in AN. Weight restoration (and return of menses) is the ONLY treatment proven to improve bone mineral density. Bisphosphonates are relatively contraindicated in premenopausal women." }, { question: "An RN notes that a patient with AN has a resting heart rate of 38 bpm and QTc of 510 ms. These findings indicate:", options: ["Normal adaptive response to dieting", "Medical emergency requiring telemetry, electrolyte correction, and possible cardiac consultation", "Medication side effect requiring dose adjustment", "Typical findings that will resolve with nutrition"], correct: 1, rationale: "Heart rate below 40 bpm and QTc above 500 ms are medically dangerous in AN. QTc above 500 ms creates significant risk for torsades de pointes (potentially fatal ventricular arrhythmia). Immediate interventions include telemetry, aggressive electrolyte correction, and cardiac consultation." }]
  },
  "eating-disorders-np": {
    title: "Eating Disorders",
    cellular: { title: "Evidence-Based Eating Disorder Treatment", content: "The clinician managing eating disorders makes critical decisions regarding level of care, medical stabilization, pharmacotherapy, and coordination of the multidisciplinary treatment team. Level-of-care determination uses the APA Practice Guidelines and ASAM-like criteria: inpatient medical hospitalization (BMI below 15, HR below 40, syncope, severe electrolyte abnormalities, refeeding syndrome risk), residential eating disorder treatment (medical stability but unable to manage eating in less structured setting), partial hospitalization (stepping down from residential, needs meal supervision but medically stable), intensive outpatient (3+ days/week group therapy with meal support), and outpatient (weekly individual therapy with dietitian). Pharmacotherapy in eating disorders is limited: NO medication is FDA-approved for AN (SSRIs may help prevent relapse after weight restoration but are ineffective during acute starvation); fluoxetine 60 mg is the ONLY medication FDA-approved for BN; lisdexamfetamine 50-70 mg is the ONLY medication FDA-approved for BED. The clinician manages medical complications including: cardiac monitoring and electrolyte management, osteoporosis screening and management, reproductive health (amenorrhea evaluation, fertility counseling), endocrine abnormalities (sick euthyroid syndrome, hypercortisolism, growth hormone resistance), and GI complications (gastroparesis from AN, constipation, SMA syndrome, pancreatitis)." },
    riskFactors: ["Mortality prediction: BMI below 13 carries extremely high mortality; Admission BMI below 15 associated with 5x increased inpatient complication rate", "Chronic AN (illness duration above 7 years): poorer prognosis, higher treatment resistance, higher mortality", "Comorbid diabetes (diabulimia): patients with T1DM who omit insulin for weight loss have DKA risk and 3x higher mortality than T1DM alone", "Male eating disorders: underdiagnosed due to stigma; may present with muscle dysmorphia (desire for muscularity rather than thinness); anabolic steroid use", "Avoidant/restrictive food intake disorder (ARFID): not driven by body image distortion; associated with sensory sensitivity, fear of choking/vomiting, or lack of interest in eating; can cause same medical complications as AN", "Pregnancy in patients with eating disorder history: increased risk of hyperemesis, preterm birth, low birth weight, postpartum depression, relapse of ED"],
    diagnostics: ["Level-of-care assessment: BMI, vital signs stability, electrolytes, cardiac status, psychological stability, suicide risk, motivation, environmental support", "Comprehensive endocrine evaluation for AN: LH/FSH (low in hypothalamic amenorrhea), estradiol (low), cortisol (elevated -- pseudo-Cushing), T3/T4 (low T3 with normal TSH -- sick euthyroid syndrome), IGF-1 (low -- growth hormone resistance), bone age in adolescents", "Body composition assessment: BMI alone may be misleading (muscular patients may have normal BMI; edematous patients may have falsely elevated weight); consider bioimpedance analysis or clinical assessment", "Gastroparesis evaluation: gastric emptying study if patients report early satiety, nausea, bloating (common in AN from gastric smooth muscle atrophy)", "Reproductive health assessment: pregnancy test (amenorrhea may not be reliable contraception even without menses), bone density, discuss fertility implications"],
    management: ["Level-of-care algorithm: inpatient medical (BMI below 15 or medically unstable) -> residential (medically stable, cannot manage eating) -> PHP (stepping down, needs meal support) -> IOP (3+ days/week groups) -> outpatient (weekly therapy + dietitian)", "AN pharmacotherapy: no medication accelerates weight gain during acute phase; fluoxetine may reduce relapse risk AFTER weight restoration; olanzapine 2.5-10 mg off-label for severe AN (reduces anxiety around eating, may promote modest weight gain through H1 antagonism)", "BN pharmacotherapy: fluoxetine 60 mg daily (FDA-approved); topiramate off-label (reduces binge-purge frequency and promotes weight loss -- useful for BN patients who are overweight); CBT-E is MORE effective than medication alone", "BED pharmacotherapy: lisdexamfetamine 50-70 mg (FDA-approved, reduces binge frequency 50-70%); topiramate off-label (reduces binge frequency and promotes weight loss); naltrexone-bupropion (Contrave) off-label for BED with obesity", "Osteoporosis management: weight restoration is primary treatment; calcium 1200 mg + vitamin D 800-1000 IU daily; transdermal estrogen (not OCP) may have modest benefit in adolescents with AN; teriparatide for severe osteoporosis with fractures (off-label in premenopausal); bisphosphonates generally avoided in premenopausal women", "Family-Based Treatment (FBT/Maudsley approach) for adolescents: parents take control of child's eating; most effective treatment for adolescent AN; empowers parents rather than blaming them"],
    nursingActions: ["Determine appropriate level of care using evidence-based criteria and facilitate transitions between care levels", "Prescribe pharmacotherapy based on eating disorder type: fluoxetine 60 mg for BN, lisdexamfetamine 50-70 mg for BED, olanzapine 2.5-10 mg off-label for severe AN with treatment resistance", "Manage refeeding syndrome prevention: calculate starting calories, order prophylactic supplementation, specify monitoring frequency", "Screen for and manage bone health: order DEXA after 6+ months of amenorrhea, prescribe calcium/vitamin D, determine need for advanced bone treatment", "Manage cardiovascular complications: order baseline ECG, establish telemetry criteria, correct electrolyte abnormalities aggressively", "Coordinate multidisciplinary team: psychiatrist, therapist (CBT-E trained), dietitian, medical provider, family therapist; ensure consistent treatment approach", "Address reproductive health: fertility counseling, contraception (amenorrhea does not equal infertility), pregnancy management in patients with ED history"],
    assessmentFindings: ["Medical acuity assessment: HR below 40 (severe), orthostatic HR change above 20 (moderate), QTc above 500 (severe), temperature below 96F/35.5C (severe), phosphate below 1.0 (critical), K below 2.5 (critical)", "Treatment response indicators: weight gain 0.5-1.0 kg/week inpatient, normalizing vital signs, stabilizing electrolytes, decreasing ED behaviors (restriction, purging, binge episodes), improving psychological flexibility", "Chronic AN assessment: illness duration above 7 years, multiple treatment failures, significant medical damage (osteoporosis, organ damage); may require harm reduction approach rather than full recovery model", "Recovery stage assessment: early recovery (behavioral change, medical stabilization), middle recovery (cognitive flexibility, body image improvement), sustained recovery (no ED behaviors for 1+ year, flexible eating, positive body relationship)"],
    signs: { left: ["Weight restoration progressing on appropriate nutritional plan", "Electrolytes stable without refeeding syndrome", "Engaging in evidence-based psychotherapy (CBT-E, FBT)", "Medical complications resolving with nutritional rehabilitation"], right: ["Refeeding syndrome with cardiac failure requiring ICU", "Severe osteoporosis with pathological fractures in young patient", "Treatment-resistant chronic AN with multiple failed treatment attempts", "Diabulimia with recurrent DKA and advancing microvascular disease", "Superior mesenteric artery syndrome requiring surgical intervention", "Completed suicide (eating disorders have highest psychiatric mortality)"] },
    medications: [{ name: "Olanzapine (Low-Dose for AN)", type: "Atypical antipsychotic (off-label for AN)", action: "H1 antagonism promotes appetite and weight gain; 5-HT2A antagonism reduces anxiety (particularly meal-related anxiety and body image distress); may help reduce obsessive rumination about food, weight, and body shape", sideEffects: "Weight gain (therapeutic in AN), sedation, metabolic effects (less concerning in underweight AN patients), QTc prolongation (monitor in context of electrolyte abnormalities)", contra: "QTc prolongation with electrolyte abnormalities, dementia-related psychosis", pearl: "2.5-10 mg at bedtime for severe AN; multiple RCTs show modest benefit for weight gain and anxiety reduction; most beneficial in severe, treatment-resistant AN; sedating properties help with insomnia (common in AN); metabolic side effects (weight gain, appetite increase) are actually THERAPEUTIC in AN; monitor QTc carefully as eating disorder-related electrolyte abnormalities compound the QTc prolongation risk" }, { name: "Topiramate (off-label for BN/BED)", type: "Anticonvulsant with appetite-suppressing properties", action: "Multiple mechanisms: GABA enhancement, glutamate antagonism, carbonic anhydrase inhibition; reduces binge eating through appetite suppression and impulse control improvement; promotes weight loss", sideEffects: "Cognitive dulling (word-finding difficulty), paresthesias, kidney stones, metabolic acidosis, weight loss, teratogenicity (cleft lip/palate)", contra: "Pregnancy (category D), kidney stones, metabolic acidosis, glaucoma, AN (weight loss would be harmful)", pearl: "25-200 mg daily for BN or BED; promotes weight loss (unlike fluoxetine which is weight-neutral); useful for BN/BED patients who are also overweight; CONTRAINDICATED in AN (weight loss would worsen condition); cognitive side effects limit tolerability; must NOT be used in women of childbearing age without reliable contraception (teratogenic); can be combined with fluoxetine for enhanced BN response" }, { name: "Transdermal Estradiol (for AN-related Bone Loss)", type: "Estrogen replacement (physiological)", action: "Provides physiological estrogen levels to partially mitigate bone loss from hypoestrogenic state in AN-related amenorrhea; transdermal delivery avoids hepatic first-pass effects that suppress IGF-1", sideEffects: "Skin irritation at patch site, breast tenderness, headache", contra: "Estrogen-dependent malignancy, active thromboembolic disease, undiagnosed vaginal bleeding", pearl: "100 mcg/day transdermal patch; IMPORTANT: oral contraceptives do NOT prevent bone loss in AN (oral estrogen suppresses IGF-1 through hepatic first-pass effect, which is critical for bone formation in young women); transdermal estradiol bypasses the liver and provides physiological estrogen without suppressing IGF-1; most effective in adolescents; studies show modest improvement in bone density when combined with weight restoration; weight restoration remains the MOST important intervention for bone health" }],
    pearls: ["No medication reliably promotes weight gain in acute AN: this is fundamentally a psychotherapy-mediated recovery; olanzapine shows modest benefit but is not transformative; nutritional rehabilitation and psychotherapy (CBT-E for adults, FBT for adolescents) are the cornerstones", "FBT (Family-Based Treatment/Maudsley) is the MOST effective treatment for adolescent AN: parents are empowered to take control of their child's eating; success rates 50-75% full remission at 1 year; NP should refer adolescents to FBT-trained therapists", "Fluoxetine 60 mg (NOT 20 mg) for BN: the higher dose is specifically indicated for bulimia; lower doses are less effective; reduces binge-purge frequency by 50-70% when combined with CBT-E", "Eating disorder mortality is highest among ALL psychiatric disorders: AN mortality 5-10% per decade; BN mortality 1-3% per decade; suicide accounts for 20-30% of eating disorder deaths; NP must routinely screen for suicidal ideation", "Osteoporosis in AN is unique: it does NOT respond well to bisphosphonates or oral contraceptives; weight restoration and transdermal estradiol (not OCP) show the most benefit; the damage may be partially irreversible"],
    quiz: [{ question: "An NP is selecting pharmacotherapy for a patient with binge eating disorder. The ONLY FDA-approved medication is:", options: ["Fluoxetine", "Topiramate", "Lisdexamfetamine (Vyvanse) 50-70 mg", "Naltrexone"], correct: 2, rationale: "Lisdexamfetamine (Vyvanse) 50-70 mg is the ONLY FDA-approved medication for binge eating disorder. It reduces binge frequency by 50-70%. It is NOT approved for weight loss." }, { question: "For adolescent anorexia nervosa, the MOST effective psychotherapy approach is:", options: ["Individual CBT", "Psychodynamic therapy", "Family-Based Treatment (FBT/Maudsley approach)", "Dialectical behavior therapy"], correct: 2, rationale: "Family-Based Treatment (FBT) empowers parents to take control of their adolescent's eating, achieving 50-75% full remission at 1 year. It is the most evidence-based treatment for adolescent AN." }, { question: "Oral contraceptives do NOT prevent bone loss in anorexia nervosa because:", options: ["They contain too much estrogen", "Oral estrogen suppresses IGF-1 through hepatic first-pass effect, which is needed for bone formation in young women", "They are contraindicated in underweight patients", "They only work in postmenopausal women"], correct: 1, rationale: "Unlike transdermal estradiol, oral estrogen undergoes hepatic first-pass metabolism which suppresses IGF-1, a critical growth factor for bone formation in young women. Transdermal estradiol bypasses the liver and preserves IGF-1 levels, showing modest bone density improvement." }]
  },
  "personality-disorders-rpn": {
    title: "Personality Disorders",
    cellular: { title: "Understanding Personality Disorders in", content: "Personality disorders (PDs) are enduring patterns of inner experience and behavior that deviate markedly from cultural expectations, are pervasive and inflexible, begin in adolescence or early adulthood, are stable over time, and lead to distress or functional impairment. They are organized into three clusters. Cluster A (odd/eccentric): paranoid PD (pervasive distrust and suspiciousness), schizoid PD (detachment from social relationships, restricted emotions), schizotypal PD (eccentric behavior, cognitive/perceptual distortions, magical thinking). Cluster B (dramatic/erratic): borderline PD (instability in relationships, self-image, and affect; impulsivity; self-harm; fear of abandonment), antisocial PD (disregard for rights of others, deceit, manipulation, lack of remorse), histrionic PD (excessive emotionality and attention-seeking), narcissistic PD (grandiosity, need for admiration, lack of empathy). Cluster C (anxious/fearful): avoidant PD (social inhibition, feelings of inadequacy, hypersensitivity to criticism), dependent PD (excessive need to be taken care of, submissive behavior), obsessive-compulsive PD (preoccupation with orderliness, perfectionism, control -- distinct from OCD). Borderline PD (BPD) is the most commonly encountered in clinical settings and has the most evidence-based treatments. BPD pathophysiology involves amygdala hyperreactivity (intense emotional responses to perceived threats), prefrontal cortex hypoactivity (impaired emotion regulation), and disrupted attachment circuits from early relational trauma. The practical nurse maintains professional boundaries, uses consistent therapeutic communication, and avoids taking manipulative behaviors personally." },
    riskFactors: ["Childhood trauma and abuse (especially BPD and antisocial PD)", "Invalidating childhood environment (BPD -- emotions were dismissed, punished, or ignored)", "Genetic predisposition (temperament, heritability 40-60% for most PDs)", "Disrupted attachment in early childhood", "Family dysfunction and neglect", "Comorbid substance use disorders (very high in Cluster B)", "Comorbid mood and anxiety disorders", "Head injury or neurodevelopmental disorders (antisocial PD association)"],
    diagnostics: ["Clinical interview assessing pervasive patterns across multiple domains (relationships, self-image, affect, impulse control)", "Personality Disorder diagnosis requires pattern present since adolescence/early adulthood, pervasive across situations, inflexible, causing distress or impairment", "McLean Screening Instrument for BPD (MSI-BPD): 10-item screening tool", "PHQ-9 and GAD-7 for comorbid depression and anxiety (very common in PDs)", "Substance use screening (AUDIT, DAST -- extremely high comorbidity)", "Safety assessment: self-harm and suicidal ideation screening (BPD has 8-10% completed suicide rate)"],
    management: ["BPD: Dialectical Behavior Therapy (DBT) is first-line (teaches distress tolerance, emotion regulation, interpersonal effectiveness, mindfulness); no FDA-approved medications for BPD", "Antisocial PD: limited treatment options; CBT for anger management; address substance use; no effective pharmacotherapy", "Cluster C PDs: CBT and psychodynamic therapy; SSRIs for comorbid anxiety/depression", "Medications for symptom management in BPD: mood stabilizers for affective instability, low-dose antipsychotics for transient psychotic symptoms, SSRIs for comorbid depression (no medication treats BPD core symptoms)", "Consistent therapeutic boundaries across the treatment team are ESSENTIAL: patients with BPD may split staff (idealizing some while devaluing others); unified approach prevents splitting"],
    nursingActions: ["Maintain firm, consistent boundaries: communicate expectations clearly, enforce limits consistently across all staff, avoid making exceptions that create precedent; boundaries are THERAPEUTIC, not punitive", "Recognize and manage splitting: BPD patients may idealize one nurse while devaluing another (I love you, you're the only one who understands me vs She is terrible, she hates me); team communication prevents staff division -- discuss in team meetings, maintain consistent approach", "Use DBT skills in interactions: validate the patient's emotion while setting limits on behavior (I can see you are in a lot of pain right now. I cannot let you hurt yourself, but let's work together on a coping strategy)", "De-escalate emotional crises: remain calm, validate emotions, offer distraction or grounding techniques, avoid arguing or becoming defensive", "Monitor for self-harm: assess for cutting, burning, hitting, head-banging; these are typically emotion regulation strategies, NOT suicide attempts (though they carry accidental lethality risk); treat self-harm wounds with professional compassion, not judgment", "Document behavioral patterns objectively: use factual, non-judgmental language; avoid subjective labels like manipulative or attention-seeking in charting"],
    assessmentFindings: ["BPD presentation: intense fear of abandonment, pattern of unstable relationships (idealization/devaluation), identity disturbance (unstable self-image), impulsivity (spending, sex, substances, binge eating), recurrent self-harm or suicidal behavior, affective instability (rapid mood shifts lasting hours not days), chronic emptiness, intense anger, transient stress-related paranoia or dissociation", "Splitting pattern: patient idealizes certain staff while devaluing others; rapid shifts from idealization to devaluation based on perceived rejection or disappointment", "Self-harm vs suicide attempt: self-harm in BPD is typically an emotion regulation strategy (cutting to relieve emotional pain, burning to feel something when numb); suicidal behavior involves intent to die; BOTH require clinical attention and should never be dismissed", "Staff countertransference reactions: feeling frustrated, helpless, angry, or manipulated are common reactions to patients with PDs; these feelings are expected and should be processed in supervision rather than acted upon"],
    signs: { left: ["Patient using DBT skills to manage distress", "Decreased frequency of self-harm episodes", "More stable relationships and self-image", "Engaging productively in therapy"], right: ["Acute suicidal crisis requiring safety intervention", "Severe self-harm requiring medical treatment", "Staff splitting causing inconsistent care", "Substance intoxication complicating presentation", "Aggressive or violent behavior toward staff or others", "Psychotic symptoms (transient, stress-related in BPD)"] },
    medications: [{ name: "No FDA-approved medications for BPD", type: "Important clinical concept", action: "No medication treats the core features of BPD (identity disturbance, fear of abandonment, unstable relationships, chronic emptiness). Medications are used for specific symptom targets only", sideEffects: "Polypharmacy is a significant risk in BPD as providers may add medications for each symptom cluster", contra: "Benzodiazepines should generally be AVOIDED in BPD (disinhibition, impulsivity worsening, dependence risk)", pearl: "Symptom-targeted prescribing: mood instability/irritability = mood stabilizer (lamotrigine, valproic acid); transient psychotic symptoms = low-dose antipsychotic (aripiprazole 2-5 mg, quetiapine 25-100 mg); comorbid depression = SSRI; comorbid anxiety = SSRI or buspirone (NOT benzodiazepines); impulsivity = mood stabilizer or SSRI; key principle: use the MINIMUM number of medications, avoid polypharmacy, and always frame medication as adjunct to DBT (the primary treatment)" }, { name: "Lamotrigine (off-label for BPD)", type: "Mood stabilizer", action: "Modulates glutamate release and stabilizes mood; may reduce affective instability, impulsivity, and anger outbursts in BPD", sideEffects: "Rash (SJS risk with rapid titration), headache, dizziness, nausea", contra: "Known hypersensitivity, previous SJS from lamotrigine", pearl: "25 mg daily, titrate slowly over 6-8 weeks to 200-400 mg; most promising mood stabilizer for BPD based on several RCTs; slow titration essential to prevent SJS; may be particularly helpful for depressive symptoms and mood instability in BPD; better tolerated than valproic acid or lithium for BPD patients" }, { name: "Aripiprazole (low-dose for BPD)", type: "Atypical antipsychotic (dopamine partial agonist)", action: "D2 partial agonism and 5-HT2A antagonism; at low doses (2-10 mg), reduces interpersonal sensitivity, anger, and transient psychotic symptoms in BPD", sideEffects: "Akathisia, insomnia, restlessness, headache; minimal metabolic effects at low doses", contra: "Known hypersensitivity", pearl: "2-10 mg daily for BPD symptoms; evidence for reducing anger, interpersonal sensitivity, and transient psychotic symptoms; better metabolic profile than olanzapine or quetiapine; akathisia may be problematic in patients with already high baseline agitation; short-term use is better studied than long-term maintenance in BPD" }],
    pearls: ["DBT is the GOLD STANDARD for BPD: it is the only psychotherapy with Level 1 evidence for reducing self-harm and suicidal behavior in BPD; NP should refer to DBT-trained therapists", "Splitting is NOT intentional manipulation: it is an unconscious defense mechanism arising from inability to hold ambivalent feelings about the same person; consistent team communication is the antidote", "Self-harm in BPD is an emotion REGULATION strategy, not an attention-seeking behavior: validating the emotional pain while setting limits on the behavior is more therapeutic than dismissing it", "Benzodiazepines are generally CONTRAINDICATED in BPD: they can cause disinhibition (worsening impulsive behavior), are highly addictive in this population, and do not address the underlying emotional dysregulation", "The 8-10% completed suicide rate in BPD is REAL: while many self-harm episodes are non-suicidal, this population has a genuine and significant suicide risk that must be taken seriously", "Staff self-care is essential when working with PD patients: countertransference reactions (frustration, helplessness, anger) are expected; regular clinical supervision helps process these feelings and prevent burnout"],
    quiz: [{ question: "A patient with BPD tells Nurse A: You're the only one who understands me. Everyone else here is terrible. The practical nurse recognizes this as:", options: ["A genuine compliment", "Splitting -- an unconscious defense mechanism requiring consistent team communication", "Proof that other staff are providing poor care", "Manipulation that should be confronted directly"], correct: 1, rationale: "Splitting (idealizing one person while devaluing another) is an unconscious defense mechanism in BPD, not intentional manipulation. The team should communicate about the behavior and maintain a consistent approach to prevent staff division." }, { question: "Which psychotherapy has the STRONGEST evidence for BPD?", options: ["Psychoanalysis", "Cognitive Behavioral Therapy", "Dialectical Behavior Therapy (DBT)", "Family therapy"], correct: 2, rationale: "DBT is the gold standard for BPD with Level 1 evidence for reducing self-harm and suicidal behavior. It teaches four key skills: distress tolerance, emotion regulation, interpersonal effectiveness, and mindfulness." }, { question: "Benzodiazepines are generally avoided in BPD because:", options: ["They are too expensive", "They cause disinhibition, worsen impulsivity, and have high dependence risk in this population", "They are not effective for anxiety", "They interact with SSRIs"], correct: 1, rationale: "Benzodiazepines can cause behavioral disinhibition in BPD patients (worsening impulsive and self-destructive behavior), are highly addictive in this population, and do not address the underlying emotional dysregulation." }]
  },
  "personality-disorders-rn": {
    title: "Personality Disorders",
    cellular: { title: "BPD Assessment", content: "The nurse managing personality disorders, particularly BPD, implements DBT-informed nursing interventions, manages team dynamics affected by splitting, conducts safety assessments for self-harm and suicidal behavior, and navigates complex therapeutic relationships. DBT biosocial theory posits that BPD develops from the transaction between biological emotional vulnerability (innate emotional sensitivity, reactivity, and slow return to baseline) and an invalidating environment (caregivers who dismiss, trivialize, or punish emotional experiences). This creates a pattern where the individual never learns effective emotion regulation strategies and oscillates between emotional inhibition and extreme emotional expression. DBT core skills applicable to nursing: Distress tolerance (crisis survival skills: TIPP -- Temperature change, Intense exercise, Paced breathing, Progressive muscle relaxation; ACCEPTS -- Activities, Contributing, Comparisons, Emotions, Pushing away, Thoughts, Sensations), Emotion regulation (identify and label emotions, opposite action, build positive experiences), Interpersonal effectiveness (DEAR MAN -- Describe, Express, Assert, Reinforce, Mindful, Appear confident, Negotiate), and Mindfulness (observe, describe, participate non-judgmentally, one-mindfully, effectively). The nurse uses these skills both for patient coaching and personal emotional regulation when managing challenging patient interactions." },
    riskFactors: ["Chronic suicidality in BPD: 75% of BPD patients make at least one suicide attempt; 8-10% die by suicide; each self-harm episode carries risk of accidental death even when intent is non-suicidal", "Staff burnout: BPD patients are among the most emotionally demanding; nurses report higher burnout rates when caring for BPD patients; supervision and team support are essential", "Comorbidity amplifying risk: BPD + substance use (30-50%), BPD + MDD (60-80%), BPD + PTSD (25-55%), BPD + eating disorders (25%)", "Iatrogenic harm: excessive medication prescribing (polypharmacy without evidence base), punitive responses to self-harm, inconsistent boundaries, and therapeutic nihilism (belief that PDs are untreatable) all worsen outcomes", "Termination sensitivity: discharge or transition in care can trigger abandonment fears and escalation of self-destructive behaviors"],
    diagnostics: ["Comprehensive safety assessment in BPD: distinguish non-suicidal self-injury (NSSI -- function is emotion regulation, pain relief, self-punishment, or communication) from suicidal behavior (intent to die); assess method lethality, access to means, plan specificity, and intent", "Chain analysis: detailed examination of events leading to self-harm or crisis behavior: vulnerability factors -> prompting event -> links (thoughts, emotions, body sensations, behaviors) -> problem behavior -> consequences; identifies intervention points for future prevention", "Treatment target hierarchy in DBT: (1) life-threatening behaviors, (2) therapy-interfering behaviors, (3) quality-of-life interfering behaviors, (4) skills acquisition; address in this order", "Behavioral pattern recognition: identify triggers for self-harm, interpersonal crises, and emotional dysregulation episodes; document patterns over time to guide treatment planning", "Functional assessment of self-harm: determine the function (emotion regulation, interpersonal influence, self-punishment, dissociation management) to guide replacement behaviors"],
    management: ["DBT implementation: comprehensive DBT includes individual therapy, skills group (2.5 hours/week), phone coaching, and therapist consultation team; standard treatment duration 1 year; RN can reinforce DBT skills in inpatient/acute settings", "Crisis management protocol for BPD: validate emotional pain, coach distress tolerance skills (cold water immersion, intense exercise, paced breathing), develop safety plan collaboratively, avoid providing secondary reinforcement for self-destructive behavior (excessive attention after self-harm can inadvertently reinforce the behavior)", "Self-harm wound care: treat injuries professionally and compassionately, not punitively; ask about function of self-harm in a non-judgmental manner; help identify alternative coping strategies that serve the same function", "Team approach to splitting: regular team meetings to ensure consistent messaging, treatment plan visible to all providers, identify primary nurse for therapeutic relationship, avoid secret agreements with the patient", "Termination/transition planning: address early and explicitly; provide clear timeline; normalize feelings about endings; ensure warm handoff to next provider"],
    nursingActions: ["Implement DBT-informed therapeutic communication: validate emotions while setting limits on behavior (validation + change strategy); avoid invalidating responses (just calm down, you're overreacting, other people have it worse)", "Conduct chain analysis after self-harm or crisis: collaboratively review the sequence of events to identify vulnerability factors, triggers, and intervention points for future crises", "Coach distress tolerance skills during acute crises: TIPP skills (holding ice, cold water on face to activate dive reflex which slows heart rate), paced breathing (exhale longer than inhale), distraction techniques", "Manage team dynamics: facilitate regular team huddles about PD patients, discuss splitting patterns and countertransference, ensure treatment plan consistency, support colleagues experiencing burnout", "Implement least-restrictive safety interventions: collaborative safety planning over unilateral restriction; engage patient in developing their own crisis plan; avoid unnecessary hospitalization (can reinforce crisis behaviors in some BPD patients while being essential for genuine suicidal crises)", "Monitor and document behavioral patterns: use objective, non-judgmental language; track frequency, duration, and severity of target behaviors over time; note effective interventions"],
    assessmentFindings: ["NSSI vs suicidal behavior: NSSI typically involves low-lethality methods (superficial cutting, burning), occurs in pattern, serves emotion regulation function, patient may feel relief afterward; suicidal behavior involves higher-lethality methods, expressed desire to die, hopelessness, may involve concealment and planning", "Emotional cascade model: seemingly minor trigger -> rapid escalation of emotional intensity -> overwhelming affect -> impulsive behavior (self-harm, substance use, binge eating) -> temporary relief -> shame/guilt -> vulnerability to next cascade", "Idealization-devaluation cycle timing: typically triggered by perceived rejection or abandonment (clinician absence, perceived favoritism, discharge planning); anticipate and prepare for these transitions", "Countertransference assessment: nurse feeling special/chosen (response to idealization), angry/frustrated (response to devaluation), helpless (response to repeated crises), guilty (response to setting limits); all are expected and should be discussed in supervision"],
    signs: { left: ["Using DBT skills to manage emotional crises", "Decreasing frequency and severity of self-harm", "More stable therapeutic relationships with less splitting", "Engaging in chain analysis and learning from crises"], right: ["Genuine suicidal crisis requiring acute intervention (differentiate from chronic suicidality)", "Severe self-harm requiring emergency medical treatment", "Team splitting causing inconsistent care and patient destabilization", "Severe substance intoxication overlapping with personality disorder crisis", "Violence toward staff or other patients", "Treatment-interfering behavior preventing engagement in therapy"] },
    medications: [{ name: "Naltrexone (off-label for NSSI)", type: "Opioid antagonist", action: "Blocks endogenous opioid release associated with self-harm; many patients with BPD describe pain relief and emotional numbness during cutting, mediated by endorphin release; naltrexone may reduce the reinforcing properties of self-harm", sideEffects: "Nausea, headache, hepatotoxicity (rare), precipitated withdrawal if on opioids", contra: "Current opioid use, acute hepatitis", pearl: "50 mg PO daily; small studies show reduction in NSSI frequency in BPD patients; theoretically blocks the endogenous opioid response that reinforces self-harm behavior; not widely used but worth considering for patients with frequent cutting who describe emotional relief from the behavior; must rule out opioid use before starting" }, { name: "Clonidine (for acute BPD agitation)", type: "Alpha-2 adrenergic agonist", action: "Reduces noradrenergic hyperactivation producing calming effect without sedation, disinhibition, or dependence risk associated with benzodiazepines", sideEffects: "Hypotension, bradycardia, sedation, dry mouth, rebound hypertension if discontinued abruptly", contra: "Severe hypotension, bradycardia", pearl: "0.1-0.2 mg PO PRN for acute agitation/anxiety in BPD; SAFER alternative to benzodiazepines (no disinhibition, no dependence); particularly useful for autonomic arousal (racing heart, sweating, trembling) associated with emotional crises; also reduces PTSD hyperarousal symptoms (common comorbidity); monitor BP; does not impair cognition or worsen impulsivity" }, { name: "Quetiapine (low-dose for BPD)", type: "Atypical antipsychotic", action: "At low doses (25-100 mg), primarily H1 and alpha-1 blockade providing sedation and anxiolysis; at moderate doses (100-300 mg), 5-HT2A blockade may reduce interpersonal sensitivity and transient psychotic symptoms", sideEffects: "Sedation, weight gain, metabolic effects, orthostatic hypotension", contra: "Dementia-related psychosis, concurrent QTc-prolonging drugs", pearl: "25-100 mg at bedtime for insomnia and anxiety in BPD; 100-300 mg for transient psychotic symptoms, severe dissociation, or intense interpersonal sensitivity; evidence from several RCTs for BPD symptoms; sedation can be therapeutic for patients with severe insomnia; metabolic monitoring required for ongoing use; consider time-limited use rather than indefinite prescribing" }],
    pearls: ["Validation is the most powerful therapeutic tool for BPD: acknowledge the patient's emotional experience as understandable given their history, even when you need to set limits on behavior; I can see you are suffering right now is more effective than You need to stop this behavior", "The dive reflex is a rapid crisis intervention: having the patient hold their breath and submerge their face in cold water for 30 seconds activates the mammalian dive reflex, which rapidly decreases heart rate and reduces emotional arousal; this is a DBT TIPP skill", "Punitive responses to self-harm WORSEN outcomes: making wound care painful, restricting privileges after self-harm, or expressing disgust reinforces shame and increases self-harm frequency; compassionate, matter-of-fact wound care with collaborative safety planning is evidence-based", "Not all crises in BPD require hospitalization: frequent brief hospitalizations can inadvertently reinforce crisis behaviors through secondary gain (attention, escape from stressors); brief crisis stabilization (23-hour observation) may be more appropriate than full admission for many BPD crises", "Countertransference is information, not a problem: feeling frustrated, helpless, or manipulated when caring for BPD patients provides useful clinical information about the patient's relational patterns; discuss in supervision rather than acting on these feelings"],
    quiz: [{ question: "An RN is coaching a BPD patient through an acute emotional crisis. The MOST effective immediate intervention is:", options: ["Prescribing a benzodiazepine for immediate relief", "Coaching the patient to hold ice or submerge their face in cold water to activate the dive reflex (DBT TIPP skill)", "Telling the patient to calm down", "Placing the patient in physical restraints"], correct: 1, rationale: "The dive reflex (cold water on face, holding ice) is a DBT TIPP skill that rapidly reduces emotional arousal by activating the parasympathetic nervous system. It provides immediate, drug-free crisis intervention without the risks of benzodiazepines (disinhibition, dependence)." }, { question: "After a patient with BPD engages in cutting, wound care should be provided:", options: ["As painfully as possible to deter future self-harm", "Professionally and compassionately, followed by collaborative safety planning", "Only after the patient apologizes for self-harming", "By the patient themselves without nursing assistance"], correct: 1, rationale: "Punitive wound care increases shame and worsens self-harm frequency. Professional, compassionate wound care followed by collaborative safety planning (chain analysis, identifying alternative coping strategies) is evidence-based and therapeutic." }, { question: "The primary purpose of chain analysis after self-harm is:", options: ["To assign blame for the behavior", "To identify the sequence of events, triggers, and intervention points for preventing future self-harm", "To document for legal purposes", "To determine appropriate punishment"], correct: 1, rationale: "Chain analysis collaboratively reviews the sequence: vulnerability factors -> trigger -> thoughts/emotions/sensations -> problem behavior -> consequences. It identifies specific intervention points where different coping strategies could have been used, building skills for future crises." }]
  },
  "personality-disorders-np": {
    title: "Personality Disorders",
    cellular: { title: "Evidence-Based Pharmacotherapy", content: "The clinician managing personality disorders navigates the complex pharmacotherapy landscape where no medications are FDA-approved for any PD, yet symptom-targeted prescribing is common and sometimes necessary. Evidence-based guidelines (NICE, APA, Cochrane reviews) generally advise AGAINST polypharmacy for BPD and recommend pharmacotherapy only for specific symptom domains or comorbid conditions. The NP's primary role is coordinating evidence-based psychotherapy (DBT for BPD) while judiciously prescribing for specific targets. Symptom domain approach: (1) Affective dysregulation (mood instability, intense anger, emotional lability) -- mood stabilizers (lamotrigine has most evidence in BPD; valproic acid; lithium less studied), SSRIs; (2) Impulsive-behavioral dyscontrol (self-harm, substance use, binge eating, reckless behavior) -- mood stabilizers, SSRIs, naltrexone (for endorphin-mediated self-harm); (3) Cognitive-perceptual disturbances (transient paranoia, dissociation, ideas of reference) -- low-dose atypical antipsychotics; (4) Comorbid conditions (MDD, GAD, PTSD, ADHD, eating disorders, SUD) -- standard evidence-based treatment for each. The clinician must resist pressure to add medications for each presenting symptom, recognizing that polypharmacy without evidence base is a significant problem in PD treatment. Regular medication review with tapering of ineffective agents is essential." },
    riskFactors: ["Polypharmacy risk: average BPD patient is on 3-4 psychotropic medications despite no FDA approvals; NP should regularly review and taper medications that are not clearly beneficial", "Benzodiazepine prescribing in PD: high risk for disinhibition, dependence, and overdose; should be avoided unless comorbid condition specifically requires it (e.g., severe panic disorder, alcohol withdrawal)", "Stimulant prescribing in BPD + ADHD: comorbid ADHD is common (20-30%); stimulants can be safely prescribed in stable BPD patients but require close monitoring for diversion and impulsivity", "Suicidality management: determining when suicidality in BPD represents genuine suicidal intent vs chronic suicidal ideation as part of the disorder; this distinction guides intervention intensity", "Iatrogenic hospitalization: frequent brief hospitalizations can reinforce crisis behaviors; NP should develop crisis plans that minimize unnecessary hospitalization while ensuring safety"],
    diagnostics: ["Structured clinical interview for personality disorders (SCID-5-PD): gold standard for PD diagnosis; distinguishes PD from state-dependent symptoms (depression can mimic BPD)", "Differential diagnosis: BPD vs bipolar II (BPD mood shifts last hours, bipolar lasts days-weeks; BPD mood reactivity to interpersonal events, bipolar cycling more autonomous); BPD vs C-PTSD (significant overlap, C-PTSD requires identifiable trauma, no identity disturbance criterion)", "Medication audit: review all current prescriptions for evidence base; many BPD patients are on medications prescribed during crises that were never reassessed; systematically review and taper unnecessary medications", "Functional outcome measures: Zanarini Rating Scale for BPD (ZAN-BPD), Borderline Symptom List (BSL-23), Columbia Suicide Severity Rating Scale", "Comorbidity-specific assessment: use standard tools for each comorbid condition (PHQ-9, GAD-7, PCL-5, AUDIT, DAST, ASRS for ADHD)"],
    management: ["Primary treatment: refer to comprehensive DBT program (individual therapy + skills group + phone coaching); medication is ADJUNCT to psychotherapy, never primary treatment for PDs", "Symptom-targeted prescribing (minimal effective regimen): affect instability -> lamotrigine 100-200 mg; impulsivity -> SSRI or mood stabilizer; transient psychosis -> aripiprazole 2-10 mg; comorbid MDD -> SSRI; comorbid PTSD -> SSRI + prazosin; comorbid ADHD -> stimulant with close monitoring", "Medication reduction protocol: identify medications without clear benefit; taper one medication at a time over 2-4 weeks; assess for improvement (some patients improve with FEWER medications as side effects and interactions decrease)", "Antisocial PD management: no effective pharmacotherapy; focus on managing comorbid substance use; cognitive-behavioral interventions for anger management; risk assessment for violence", "Narcissistic PD management: psychotherapy (schema therapy, mentalization-based therapy); no pharmacotherapy for core features; treat comorbid depression/anxiety with standard agents", "Crisis protocol: develop patient-specific crisis plan with clear steps BEFORE crises occur; graduated response (self-management -> phone support -> ED evaluation -> brief observation -> inpatient if genuinely suicidal); avoid reflexive hospitalization for every crisis"],
    nursingActions: ["Prescribe using symptom-domain approach rather than diagnosis-based prescribing: target specific symptoms with evidence-based agents; limit to the minimum effective number of medications", "Conduct regular medication review (every 3-6 months) to assess ongoing benefit and taper ineffective agents; BPD patients should ideally be on 0-2 targeted medications, not 4-5", "Manage the BPD vs bipolar II diagnostic distinction: mood charting over 2-4 weeks can help differentiate (BPD: rapid mood shifts in response to interpersonal events; bipolar: sustained mood episodes lasting days-weeks independent of events)", "Prescribe stimulants cautiously for comorbid ADHD in BPD: start low, titrate slowly, monitor for misuse, consider non-stimulant alternatives (atomoxetine, guanfacine) if diversion/misuse risk is high", "Develop and document crisis protocol for each BPD patient: identify warning signs, self-management strategies, when to call, when to go to ED, when hospitalization is appropriate; share with patient and treatment team", "Coordinate with DBT therapist: maintain consistent treatment philosophy; avoid prescribing changes during crises without consulting the treatment team (medication changes during crises reinforces the crisis -> medication response pattern)"],
    assessmentFindings: ["Polypharmacy assessment: enumerate all medications, identify evidence base for each, identify medications added during crises that were never reviewed, calculate medication burden and side effect load", "Treatment target identification: what are the 1-2 most impactful symptoms to target pharmacologically? Focus prescribing on those rather than trying to medicate every symptom", "Diagnostic clarity: confirmed PD diagnosis vs provisional vs comorbid mood/anxiety disorder mimicking PD; reassess diagnosis periodically as some PD features may represent state-dependent symptoms that resolve with mood treatment"],
    signs: { left: ["Stable on minimal medication regimen (0-2 agents) targeting specific symptoms", "Successfully engaged in DBT with decreasing crisis episodes", "Polypharmacy reduced through systematic medication review", "Crisis protocol in place and functioning effectively"], right: ["Polypharmacy with 5+ medications and unclear benefit", "Repeated hospitalizations without improvement (cycle of crisis-admission-discharge)", "Benzodiazepine dependence complicating PD treatment", "Genuine suicidal crisis in patient with chronic suicidality requiring careful assessment", "Antisocial PD with violence risk requiring forensic risk assessment", "Comorbid severe substance use disorder preventing engagement in PD-specific therapy"] },
    medications: [{ name: "Lamotrigine (off-label for BPD)", type: "Mood stabilizer", action: "Glutamate modulation and sodium channel blockade stabilizing affective dysregulation; most studied mood stabilizer for BPD with several positive RCTs for impulsivity, anger, and affective instability", sideEffects: "Rash (SJS risk with rapid titration), headache, dizziness, nausea", contra: "Previous SJS from lamotrigine", pearl: "25 mg daily, titrate slowly to 200-400 mg over 6-8 weeks; MOST PROMISING mood stabilizer for BPD based on systematic reviews; targets affect instability (the most distressing symptom for many BPD patients); well-tolerated compared to alternatives; slow titration essential to prevent SJS; NP should specify: if rash develops, STOP immediately and contact provider" }, { name: "Fluoxetine (SSRI for BPD comorbid depression)", type: "SSRI", action: "Serotonin reuptake inhibition; in BPD, may reduce impulsivity, aggression, and depressive symptoms through serotonergic modulation", sideEffects: "GI disturbance, sexual dysfunction, insomnia, activation anxiety", contra: "Concurrent MAOIs, known hypersensitivity", pearl: "20-60 mg daily; SSRIs have the most evidence of any antidepressant class for BPD symptom reduction; most benefit seen for anger, aggression, and impulsivity (less benefit for core BPD features like emptiness and identity disturbance); fluoxetine selected for its activating profile and long half-life (less problematic if doses are missed -- common in BPD); NP should be clear with patients that SSRI treats symptoms but NOT the disorder -- DBT addresses core BPD features" }, { name: "Topiramate (off-label for BPD impulsivity)", type: "Anticonvulsant", action: "Multiple mechanisms including GABA enhancement and glutamate antagonism; reduces impulsivity and binge eating in BPD; promotes weight loss (beneficial for patients concerned about antipsychotic-induced weight gain)", sideEffects: "Cognitive dulling (word-finding difficulty), paresthesias, weight loss, kidney stones, metabolic acidosis", contra: "Pregnancy, kidney stones, acute glaucoma", pearl: "25-200 mg daily for BPD; evidence for reducing anger, impulsivity, and binge eating (common in BPD); weight loss is an advantage compared to most other psychotropics; cognitive side effects can be limiting (start low, titrate slowly); especially useful for BPD patients with comorbid binge eating disorder; NP monitors for cognitive complaints and adjusts accordingly" }],
    pearls: ["Medication for BPD should follow the less is more principle: no medication is FDA-approved for BPD; prescribe for specific symptom targets only; regularly review and taper medications that are not clearly helping; the goal is 0-2 targeted medications, not polypharmacy", "DBT is the TREATMENT for BPD; medication is the ADJUNCT: NP should prioritize DBT referral and advocate for access to comprehensive DBT programs; medication without psychotherapy produces minimal benefit for core BPD features", "BPD vs Bipolar II is one of the most important differential diagnoses in psychiatry: misdiagnosing BPD as bipolar leads to inappropriate mood stabilizer polypharmacy; mood charting helps differentiate (BPD = reactive rapid mood shifts; bipolar = sustained autonomous mood episodes)", "Crisis prescribing reinforces crisis behavior: starting new medications during BPD crises teaches the patient that crises produce medication changes, inadvertently reinforcing the crisis behavior pattern; avoid medication changes during crises unless medically necessary", "Benzodiazepines in BPD increase risk of disinhibition, self-harm, and overdose: NP should document rationale and informed consent if prescribing benzodiazepines in any PD patient, and prefer alternatives (hydroxyzine, clonidine, gabapentin, low-dose quetiapine)"],
    quiz: [{ question: "An NP reviews medications for a BPD patient and finds prescriptions for quetiapine, lamotrigine, sertraline, trazodone, and lorazepam. The MOST appropriate action is:", options: ["Continue all medications as prescribed", "Systematically review each medication's evidence base and taper unnecessary agents, targeting 0-2 effective medications", "Add another medication for remaining symptoms", "Discontinue all medications immediately"], correct: 1, rationale: "Polypharmacy is a significant problem in BPD treatment. The clinician should review each medication's evidence base, identify which are clearly beneficial, and systematically taper unnecessary agents one at a time. The goal is minimal effective regimen (0-2 targeted medications)." }, { question: "An NP is differentiating BPD from bipolar II disorder. The KEY distinguishing feature is:", options: ["Presence of depressive symptoms", "BPD mood shifts are rapid (hours) and reactive to interpersonal events; bipolar mood episodes last days-weeks and cycle more autonomously", "Age of onset", "Presence of anxiety"], correct: 1, rationale: "BPD mood instability involves rapid shifts (hours, not days) triggered by interpersonal events (perceived rejection, abandonment). Bipolar II involves sustained mood episodes lasting days to weeks that cycle more independently of environmental triggers. Mood charting over 2-4 weeks helps clarify the diagnosis." }, { question: "The PRIMARY treatment for borderline personality disorder is:", options: ["SSRI medication", "Mood stabilizer medication", "Dialectical Behavior Therapy (DBT) -- medication is adjunct only", "Antipsychotic medication"], correct: 2, rationale: "DBT is the gold standard treatment for BPD with the strongest evidence base. No medication is FDA-approved for BPD, and pharmacotherapy should be limited to symptom-targeted adjuncts. The clinician should prioritize DBT referral and limit medication prescribing." }]
  },
  "crisis-intervention-rpn": {
    title: "Crisis Intervention and De-escalation",
    cellular: { title: "Understanding Crisis Theory", content: "A crisis is a state of psychological disequilibrium that occurs when an individual's usual coping mechanisms are insufficient to manage a stressful event, resulting in overwhelming distress and functional impairment. Crisis theory (Caplan, 1964) describes the crisis timeline: the precipitating event disrupts homeostasis, usual coping fails, anxiety escalates through four phases. Phase 1: initial rise in anxiety with activation of habitual coping strategies. Phase 2: continued stress, coping fails, anxiety increases. Phase 3: emergency problem-solving strategies are tried (trial-and-error, novel approaches, redefinition of the problem). Phase 4: if resolution is not achieved, major disorganization occurs with cognitive, emotional, and behavioral deterioration, potentially including psychotic symptoms, violence, or suicide. Crisis resolution typically occurs within 4-6 weeks as the individual either develops new coping skills (positive resolution), returns to pre-crisis functioning (status quo), or develops maladaptive patterns (negative resolution). De-escalation is the systematic process of reducing emotional intensity and aggression through verbal and non-verbal communication techniques. The practical nurse is often the first responder in psychiatric crises and must be competent in verbal de-escalation, safety assessment, and therapeutic crisis intervention." },
    riskFactors: ["Acute psychiatric exacerbation (psychosis, mania, severe depression)", "Substance intoxication or withdrawal (especially stimulants, alcohol, PCP)", "Recent traumatic event or loss", "History of violence or aggression", "Command hallucinations directing harm to self or others", "Feeling trapped, cornered, or disrespected", "Pain, medical illness, or delirium causing confusion and agitation", "Environmental factors: overcrowding, noise, long wait times, physical discomfort"],
    diagnostics: ["Behavioral risk assessment: assess for escalating behaviors (verbal aggression, pacing, clenched fists, threatening gestures, invasion of personal space, raised voice)", "Brøset Violence Checklist: 6-item assessment of imminent violence risk (confusion, irritability, boisterousness, verbal threats, physical threats, attacks on objects); score above 2 = high risk for violence within 24 hours", "Precipitant identification: what triggered the crisis? (medication non-compliance, substance use, psychosocial stressor, acute medical condition, environmental trigger)", "Safety assessment: assess for weapons, potential weapons in environment, patient's history of violence, current substance use, command hallucinations", "Medical screening: rule out medical causes of agitation (hypoglycemia, hypoxia, infection, pain, urinary retention, constipation, head injury, medication side effects -- especially akathisia)"],
    management: ["De-escalation is ALWAYS first-line: verbal de-escalation is effective in 80% of agitation events when implemented early", "Environmental management: move to quiet, low-stimulation area; ensure clear exit for both patient and staff; remove potential weapons and throwable objects", "Verbal de-escalation techniques: maintain safe distance (arm's length plus), non-threatening body posture (hands visible, slightly angled stance, avoid crossing arms), calm low voice, use short clear sentences, offer choices, validate feelings, set clear limits", "Voluntary oral medication: offer PRN medication early (before escalation); patient retains autonomy and choice", "IM medication: if patient refuses oral and continues escalating; prepared medications available (olanzapine 10 mg IM, haloperidol 5 mg + lorazepam 2 mg IM, or midazolam 5 mg IM)", "Physical restraint: LAST RESORT only; requires physician order (or standing protocol in emergency); continuous monitoring; reassess every 15 minutes; document justification"],
    nursingActions: ["Recognize early warning signs of escalation: increased motor activity (pacing, fidgeting), raised voice, clenched fists, threatening gestures, verbal threats, invasion of personal space; intervene EARLY before full escalation", "Implement verbal de-escalation: I can see you're upset. I want to help. Can you tell me what's happening? Use open-ended questions, active listening, reflective statements, and empathy; avoid arguing, commanding, or threatening", "Maintain safety: position yourself between patient and exit (never let patient block your exit), maintain arm's-length distance, remove sharp objects and potential projectiles from environment, have panic button/alarm accessible", "Offer choices to restore autonomy: Would you like to sit down? Would you prefer water or juice? Would you like to talk here or in a quieter room? Offering choices reduces feelings of helplessness that fuel agitation", "Administer PRN medications when appropriate: offer oral first (onset 30-60 min); IM for refusal (onset 15-30 min); monitor vital signs after administration", "Document crisis events: precipitant, patient behavior, interventions tried (in sequence), patient response, rationale for any restraint use, monitoring during restraint", "Debrief after crisis events: process the event with the patient when calm (what happened, what might help next time), debrief with staff (what went well, what could improve, emotional processing)"],
    assessmentFindings: ["Escalation stages: anxiety (restlessness, pacing) -> defensive (argumentative, threatening) -> acting out (physical aggression, property destruction) -> tension reduction (de-escalation, exhaustion); intervene as EARLY as possible", "Medical vs psychiatric agitation: akathisia (medication side effect -- inner restlessness, not aggressive intent), delirium (fluctuating consciousness, inattention, acute onset -- medical emergency), pain-related agitation (grimacing, guarding), hypoglycemia (confusion, diaphoresis)", "Post-crisis assessment: patient's emotional state, physical injuries (to patient or staff), need for medical evaluation, therapeutic relationship repair, crisis debriefing"],
    signs: { left: ["De-escalation successful with verbal intervention alone", "Patient accepted voluntary PRN medication", "Crisis resolved with new coping strategies identified", "Therapeutic relationship maintained through crisis"], right: ["Violence toward staff or other patients despite de-escalation", "Need for physical restraint with continuous monitoring", "Self-harm during crisis event", "Medical emergency (injury from aggression)", "Staff injury requiring treatment", "Continued psychotic agitation not responding to medication"] },
    medications: [{ name: "Olanzapine 10 mg IM", type: "Atypical antipsychotic (for acute agitation)", action: "Rapid D2 and 5-HT2A blockade producing sedation and antipsychotic effect; preferred for psychotic agitation and manic agitation", sideEffects: "Sedation, orthostatic hypotension, respiratory depression; do NOT combine with IM benzodiazepine within 1 hour", contra: "Within 1 hour of IM benzodiazepine (respiratory depression risk), known hypersensitivity, unstable cardiovascular disease", pearl: "Onset 15-30 minutes; preferred IM antipsychotic for agitation due to rapid onset and favorable side effect profile; CRITICAL: do NOT give within 1 hour of IM lorazepam -- risk of fatal respiratory depression and hypotension; repeat dose of 5-10 mg IM can be given after 2 hours if needed; max 30 mg/24 hours" }, { name: "Haloperidol 5 mg + Lorazepam 2 mg + Diphenhydramine 50 mg IM", type: "Combination for severe agitation (B52)", action: "Haloperidol provides D2 blockade for psychosis/agitation, lorazepam provides GABA enhancement for anxiolysis/sedation, diphenhydramine provides H1 blockade preventing EPS from haloperidol", sideEffects: "EPS (dystonia -- diphenhydramine component helps prevent), QTc prolongation (haloperidol), respiratory depression (lorazepam), oversedation", contra: "Known severe QTc prolongation, Parkinson disease, severe respiratory depression", pearl: "The B52 (named for the bomber -- knocks patients out): highly effective for severe agitation; onset 15-20 minutes; the diphenhydramine is NOT for sedation -- it is EPS prophylaxis for the haloperidol; monitor QTc if repeat doses needed; this combination has decades of clinical use and evidence; after administration: vitals every 15 minutes, side-lying position for aspiration prevention, continuous observation" }, { name: "Midazolam 5 mg IM", type: "Short-acting benzodiazepine", action: "Rapid GABA-A enhancement producing anxiolysis, amnesia, and sedation; fastest-onset IM benzodiazepine due to high water solubility allowing rapid absorption", sideEffects: "Respiratory depression, oversedation, paradoxical agitation (especially elderly), anterograde amnesia, hypotension", contra: "Severe respiratory depression, sleep apnea, acute narrow-angle glaucoma, concurrent opioids", pearl: "Fastest onset of any IM benzodiazepine (5-15 minutes); short duration (1-2 hours); useful when rapid sedation is needed for safety and antipsychotic is not available or contraindicated; monitor respiratory status closely; reversal agent: flumazenil 0.2 mg IV (rarely needed); can be given intranasally (0.2 mg/kg) for seizures or acute agitation when IV access unavailable" }],
    pearls: ["De-escalation is effective in 80% of agitation events: verbal techniques (calm voice, empathy, choices, active listening) should ALWAYS be attempted before medication or restraint", "NEVER block a patient's exit: this creates a trapped feeling that dramatically escalates aggression; position yourself between the patient and the door (so YOU can exit), and ensure the patient can also leave if they choose", "Akathisia mimics agitation: a patient on antipsychotics who is restless and cannot sit still may have akathisia (medication side effect), NOT psychiatric agitation; treating with MORE antipsychotic will worsen it; treat with propranolol or benzodiazepine instead", "Post-crisis debriefing is essential: discuss the event with the patient (what happened, what might help next time) and with the team (what interventions worked, staff emotional processing); unprocessed crisis events lead to staff burnout and PTSD", "Physical restraint carries RISKS: positional asphyxia (face-down position with weight on back can be fatal), rhabdomyolysis, DVT, skin breakdown, psychological trauma; use LEAST RESTRICTIVE intervention for shortest duration necessary", "Offering choices is the single most effective de-escalation technique: even small choices (Would you like water? Shall we sit?) restore a sense of control and autonomy, reducing the helplessness that drives aggressive behavior"],
    quiz: [{ question: "A patient becomes increasingly agitated, pacing rapidly and clenching fists. The practical nurse's FIRST intervention should be:", options: ["Call security immediately for physical restraint", "Administer IM haloperidol for rapid sedation", "Attempt verbal de-escalation: acknowledge the patient's distress, offer choices, and move to a quieter area", "Ignore the behavior and wait for it to resolve"], correct: 2, rationale: "Verbal de-escalation is ALWAYS first-line (effective in 80% of agitation events). The nurse should acknowledge distress (I can see you're upset), offer choices, and create a calm environment before considering medication or restraint." }, { question: "During de-escalation, the practical nurse should:", options: ["Block the patient's exit to prevent elopement", "Stand directly in front of the patient with arms crossed", "Maintain a safe distance, position at an angle with hands visible, and ensure both the patient AND nurse have an exit path", "Raise their voice to be heard over the patient"], correct: 2, rationale: "Safe positioning includes: arm's length distance, slightly angled stance (less confrontational), hands visible (non-threatening), and clear exit for both nurse and patient. Blocking exits creates trapped feelings that escalate aggression." }, { question: "IM olanzapine must NOT be given within 1 hour of:", options: ["IM haloperidol", "IM diphenhydramine", "IM lorazepam or other IM benzodiazepines", "Oral medications"], correct: 2, rationale: "IM olanzapine and IM benzodiazepines must NOT be given within 1 hour of each other due to risk of fatal respiratory depression and hypotension. If a benzodiazepine was recently given, use haloperidol-based protocols instead." }]
  },
  "crisis-intervention-rn": {
    title: "Crisis Intervention",
    cellular: { title: "Crisis Assessment", content: "The nurse serves as the clinical leader in psychiatric crisis situations, making rapid assessments, directing the team response, implementing graduated intervention protocols, and managing post-crisis care. Advanced crisis assessment includes differentiation between psychiatric agitation and medical emergencies presenting as behavioral disturbance. Common medical causes of acute agitation: delirium (fluctuating level of consciousness -- most commonly missed medical diagnosis in agitated patients), hypoglycemia, hypoxia, infection/sepsis (especially UTI in elderly), stroke, head injury, medication toxicity (anticholinergic toxicity, serotonin syndrome, NMS), substance intoxication/withdrawal, urinary retention, and severe pain. The nurse implements the Sequential Intercept Model for crisis intervention: Prevention (identify at-risk patients, modify environment, address unmet needs) -> Recognition (early warning signs of escalation) -> De-escalation (verbal techniques, environmental modification) -> Voluntary medication (offer PRN oral medication) -> Involuntary medication (IM medication when safety requires) -> Physical management (restraint as absolute last resort). Each step is documented with clinical rationale for escalation to the next level." },
    riskFactors: ["Medical causes of agitation requiring urgent evaluation: new-onset confusion (delirium until proven otherwise), fever with altered mental status, head injury, focal neurological deficits, acute substance intoxication (PCP, methamphetamine most dangerous)", "High-risk agitation predictors: recent violence, current substance intoxication, command hallucinations, possession or access to weapons, agitation in context of mania (sustained high energy)", "Staff injury risk: 25% of psychiatric nurses experience workplace violence; proper training and institutional protocols reduce injury rates", "Restraint-associated risks: positional asphyxia (greatest risk in prone restraint with weight on back), rhabdomyolysis, DVT, skin breakdown, aspiration, cardiac arrhythmia from agitation + medication + positional stress, psychological trauma to patient and staff", "Post-crisis vulnerability: patients are at increased risk for self-harm, elopement, and decompensation in the hours following a crisis event; enhanced monitoring is indicated"],
    diagnostics: ["Medical screening for agitation: vital signs (fever = infection/NMS/serotonin syndrome, hypoglycemia = glucose, hypoxia = SpO2), pupil assessment (mydriasis = stimulant/anticholinergic, miosis = opioid), level of consciousness (fluctuating = delirium), orientation, focal neurological deficits", "Brøset Violence Checklist (BVC): serial assessment every shift for all psychiatric inpatients; predicts violence within next 24 hours", "Dynamic risk assessment: continuously reassess during crisis intervention -- is the patient escalating, de-escalating, or stable? Adjust intervention level accordingly", "Post-crisis medical evaluation: assess for injuries sustained during crisis (to patient and staff), vital signs, medication effects, dehydration, rhabdomyolysis (CK if prolonged struggle/restraint)", "Root cause analysis: identify modifiable factors that contributed to the crisis (unmet needs, environmental triggers, medication changes, inadequate staffing, communication failures)"],
    management: ["Sequential Intercept Model implementation with documentation at each level of intervention escalation", "Medical agitation management: identify and treat underlying cause (glucose for hypoglycemia, naloxone for opioid overdose, antibiotics for infection, benzodiazepines for alcohol withdrawal); managing the medical cause resolves the agitation", "Restraint protocol: physician order required (or standing emergency protocol); 4-point restraints preferred over 5-point; position patient on side (NEVER prone -- positional asphyxia risk); monitor vitals, circulation, and mental status every 15 minutes; reassess need for restraint every 1-2 hours; release as soon as clinically safe", "Seclusion protocol: safe, designated room; patient must be observable at all times; check every 15 minutes; offer food, water, toileting; document rationale and duration; many institutions are moving toward seclusion-free models", "Post-crisis protocol: medical evaluation, therapeutic debriefing with patient (within 24 hours), staff debriefing, incident documentation, care plan revision to prevent recurrence"],
    nursingActions: ["Lead the crisis response team: assign roles (primary communicator with patient, medication preparation, documentation, environmental safety, notification), maintain calm leadership presence", "Differentiate psychiatric from medical agitation: check glucose, SpO2, temperature, pupil size; NEW onset confusion in any patient = delirium until proven otherwise (medical emergency, NOT psychiatric agitation)", "Implement graduated intervention protocol: prevention -> de-escalation -> voluntary medication -> involuntary medication -> restraint; document clinical rationale for each escalation step", "Manage physical restraint safely: 5+ staff for safe restraint application (1 per limb plus team leader); position on side NEVER prone; monitor airway, circulation (check pedal pulses and skin color distal to restraints), mental status every 15 minutes; offer water, toileting, repositioning every 2 hours", "Conduct therapeutic debriefing with patient after crisis: explore precipitants, identify what could be done differently, develop crisis prevention plan collaboratively; this repair is essential for therapeutic relationship and preventing future crises", "Coordinate staff debriefing: process emotional responses to the crisis, identify what went well and what could improve, assess for staff injuries, provide access to employee assistance program if needed"],
    assessmentFindings: ["Agitation etiology differentiation: psychiatric (psychosis, mania, personality disorder crisis, PTSD) vs medical (delirium, metabolic, infectious, neurological, medication-related) vs substance-related (intoxication, withdrawal); each requires different management", "Restraint safety monitoring findings: adequate circulation (capillary refill less than 3 seconds, no cyanosis distal to restraint), patent airway (especially if sedated), stable vital signs, orientation/LOC (deterioration may indicate medical complication), skin integrity under restraints", "De-escalation effectiveness indicators: decreased motor activity, lowered voice volume, ability to make eye contact, willingness to sit down, ability to identify emotions, acceptance of offered choices or medication"],
    signs: { left: ["Crisis resolved with verbal de-escalation alone", "Voluntary PRN medication accepted with good effect", "Post-crisis debriefing completed with prevention plan developed", "Staff and patient uninjured"], right: ["Violence resulting in staff or patient injury", "Restraint required with ongoing monitoring complications", "Medical emergency discovered during agitation workup (DKA, stroke, NMS)", "Positional asphyxia risk during restraint requiring immediate repositioning", "Post-crisis patient self-harm or elopement", "Staff PTSD symptoms following violent crisis event"] },
    medications: [{ name: "Droperidol (Inapsine) IM", type: "Butyrophenone antipsychotic (rapid-acting)", action: "Potent D2 antagonism with rapid onset of sedation and antipsychotic effect; historically used widely for acute agitation before falling out of favor due to QTc concerns; making a resurgence based on newer safety data", sideEffects: "QTc prolongation (BLACK BOX, but risk appears lower than initially thought), sedation, EPS, hypotension", contra: "Known QTc prolongation above 440, known or suspected torsades risk, known hypersensitivity", pearl: "2.5-5 mg IM; onset 5-15 minutes (FASTEST of all IM antipsychotics); duration 2-4 hours; FDA black box for QTc prolongation led to decreased use, but meta-analyses suggest the risk was overstated; increasingly used again in emergency departments for acute agitation; RN should obtain baseline ECG if available and monitor for QTc prolongation; excellent for undifferentiated acute agitation when rapid sedation is needed" }, { name: "Ketamine IM (for severe agitation)", type: "NMDA receptor antagonist / dissociative anesthetic", action: "At subdissociative doses (1-2 mg/kg IM), produces rapid sedation and dissociation; at full dissociative dose (4-5 mg/kg IM), produces complete dissociation with maintained airway reflexes; increasingly used by EMS and emergency departments for severe agitation not responding to conventional agents", sideEffects: "Emergence reactions (agitation, hallucinations, nightmares), hypertension, tachycardia, nausea/vomiting, laryngospasm (rare), hypersalivation", contra: "Conditions where elevated BP is dangerous (aortic dissection, severe hypertension, acute MI, eclampsia), age below 3 months", pearl: "4-5 mg/kg IM for severe agitation (excited delirium, severe stimulant intoxication, agitated patient who cannot be safely approached); onset 3-5 minutes; duration 15-30 minutes; requires airway management capability; increasingly used in ED and prehospital settings for agitation refractory to standard agents; CONTROVERSIAL: ethics of chemical restraint with dissociative agent; RN should monitor airway and vitals continuously; co-administer midazolam 0.1 mg/kg IM to prevent emergence reactions" }, { name: "Ziprasidone (Geodon) 10-20 mg IM", type: "Atypical antipsychotic", action: "D2 and 5-HT2A antagonism with rapid onset; IM formulation provides faster and more reliable absorption than oral; useful alternative to olanzapine when benzodiazepine has recently been given", sideEffects: "QTc prolongation (monitor), sedation, orthostatic hypotension, injection site pain", contra: "Known QTc prolongation, concurrent QTc-prolonging drugs, recent acute MI, decompensated heart failure", pearl: "10-20 mg IM every 2-4 hours (max 40 mg/day); KEY ADVANTAGE: CAN be given with IM benzodiazepines (unlike olanzapine which is contraindicated within 1 hour of IM benzodiazepine); monitor QTc; less sedating than olanzapine IM; useful for psychotic agitation when patient has already received a benzodiazepine" }],
    pearls: ["DELIRIUM is the most commonly missed medical diagnosis in agitated patients: any NEW onset confusion = medical workup before assuming psychiatric cause; treating delirium with antipsychotics without addressing the underlying medical cause is dangerous", "Prone restraint is the highest-risk position: positional asphyxia occurs when weight on the back compresses the chest in a prone position; ALL patients in restraint should be on their SIDE, never face-down; if a patient is taken to the ground during a crisis, they must be positioned on their side as quickly as safely possible", "Akathisia from antipsychotics is commonly misdiagnosed as agitation: restlessness, pacing, and inability to sit still in a patient on antipsychotics should trigger assessment for akathisia BEFORE escalating to higher antipsychotic doses; treat with propranolol or benzodiazepine", "Post-crisis debriefing reduces repeat crises: patients who participate in structured debriefing (what happened, what were you feeling, what might help next time) have fewer subsequent crises and shorter hospitalizations", "Staff wellness after violent events is a clinical priority: 25% of psychiatric nurses experience workplace violence; institutions must provide immediate support, EAP referral, and follow-up for staff who experience patient violence"],
    quiz: [{ question: "An agitated patient with no psychiatric history presents with fluctuating consciousness, visual hallucinations, and fever. The nurse should:", options: ["Administer IM haloperidol for psychotic agitation", "Prioritize medical evaluation for delirium (infection, metabolic, neurological causes)", "Place in seclusion until calmer", "Administer IM lorazepam for anxiety"], correct: 1, rationale: "Fluctuating consciousness with visual hallucinations and fever in a patient without psychiatric history is delirium until proven otherwise. This is a MEDICAL emergency requiring identification and treatment of the underlying cause (infection, metabolic, neurological), not primarily a psychiatric intervention." }, { question: "A restrained patient must be positioned:", options: ["Prone (face down) for safety", "On their SIDE to prevent positional asphyxia", "Supine with arms above head", "In whatever position is easiest for staff"], correct: 1, rationale: "NEVER prone -- positional asphyxia occurs when weight compresses the chest in face-down position. Side-lying position maintains airway patency and prevents positional asphyxia. Vitals and circulation checks every 15 minutes." }, { question: "An RN can safely give IM ziprasidone after a patient has received IM lorazepam because:", options: ["Ziprasidone has no drug interactions", "Unlike IM olanzapine, ziprasidone can be safely combined with IM benzodiazepines", "Lorazepam is not a benzodiazepine", "The medications work on different receptors"], correct: 1, rationale: "Ziprasidone IM can safely be given with IM benzodiazepines, unlike olanzapine IM which is contraindicated within 1 hour of IM benzodiazepines due to respiratory depression risk. This makes ziprasidone a useful alternative when a patient has already received a benzodiazepine." }]
  },
  "crisis-intervention-np": {
    title: "Crisis Intervention",
    cellular: { title: "Crisis Pharmacotherapy", content: "The clinician in crisis intervention prescribes acute pharmacotherapy for agitation, makes involuntary treatment decisions, implements system-level violence prevention programs, and manages complex medico-legal aspects of crisis care. Prescribing for acute agitation requires rapid assessment of the most likely etiology: psychotic agitation (antipsychotic-based regimen), anxiety/panic agitation (benzodiazepine-based), substance intoxication (depends on substance: benzodiazepine for stimulant-induced agitation, antipsychotic for PCP/hallucinogen-induced, naloxone for opioid), alcohol/benzodiazepine withdrawal (benzodiazepine), and undifferentiated agitation (combination approach or ketamine for severe cases). The clinician understands involuntary treatment criteria (varies by jurisdiction but generally requires: danger to self, danger to others, or gravely disabled/unable to care for basic needs) and implements these with respect for patient autonomy and least-restrictive alternatives. The clinician also leads system-level interventions: implementing Safewards model (environmental and interpersonal interventions to reduce conflict and containment), reducing restraint and seclusion use, trauma-informed crisis response, and staff training in de-escalation. The clinician prescribes and manages PRN medication protocols for psychiatric units, ensuring safe and evidence-based options are available for nursing staff to administer." },
    riskFactors: ["Medico-legal considerations: involuntary treatment must meet jurisdiction-specific criteria; documentation must clearly articulate imminent danger; patient retains right to legal counsel and hearing", "Excited delirium syndrome: controversial entity associated with stimulant intoxication or severe psychiatric agitation; features include hyperthermia, superhuman strength, insensitivity to pain, bizarre behavior; high risk for sudden death; requires aggressive management and medical evaluation", "Prescribing risks: oversedation (aspiration, respiratory depression), QTc prolongation (haloperidol IV, droperidol, ziprasidone), NMS (especially with high-potency antipsychotics in dehydrated patients), serotonin syndrome (in patients on serotonergic medications)"],
    diagnostics: ["Rapid agitation assessment: ABC approach -- Appearance (diaphoretic, cyanotic, pupils, injuries), Behavior (pacing, threatening, self-harm, bizarre), Cognition (oriented, confused, responding to internal stimuli, able to communicate); guides intervention selection", "Medical clearance for psychiatric admission: vital signs, glucose, SpO2, urine drug screen, pregnancy test, focused physical exam, basic labs (CBC, BMP, TSH, LFTs, urinalysis); more extensive workup if delirium suspected", "Risk assessment tools: Brøset Violence Checklist (short-term), HCR-20 (comprehensive violence risk), STAMP (Staring, Tone, Anxiety, Mumbling, Pacing -- nursing tool for early recognition)", "QTc monitoring: obtain ECG before administering QTc-prolonging agents in patients with cardiac risk factors, electrolyte abnormalities, or on other QTc-prolonging medications"],
    management: ["Etiology-specific agitation prescribing: psychotic agitation = olanzapine 10 mg IM or haloperidol 5-10 mg IM; anxious/panic agitation = lorazepam 2 mg IM or midazolam 5 mg IM; stimulant intoxication = lorazepam 2-4 mg IM (benzodiazepines preferred over antipsychotics for lowering seizure threshold); alcohol withdrawal = lorazepam CIWA protocol; PCP intoxication = lorazepam (avoid haloperidol); undifferentiated severe = combination or ketamine IM", "PRN medication protocol development: create evidence-based standing orders for psychiatric units with clear indications, doses, monitoring requirements, and contraindications for each agent; ensure nursing staff can administer safely", "Involuntary treatment implementation: document imminent danger criteria, explore less restrictive alternatives, involve patient in decision-making where possible, arrange for legal review within jurisdiction-specific timeframe", "System-level violence prevention: Safewards model implementation, environmental design (observation-friendly layouts, safe rooms, adequate space), staff training (annual de-escalation training, team response training), patient engagement strategies", "Restraint reduction initiatives: implement least-restrictive philosophy; use sensory modulation rooms (weighted blankets, rocking chairs, calming music, aromatherapy) as alternative to seclusion; comfort rooms instead of seclusion rooms"],
    nursingActions: ["Prescribe acute agitation medication matched to etiology: select antipsychotic for psychosis, benzodiazepine for anxiety/stimulant/alcohol, combination for undifferentiated, considering QTc risk and drug interactions", "Develop and implement unit-specific PRN medication protocols: define medication options, doses, routes, indications, monitoring parameters, contraindications, and maximum daily doses for nursing staff to follow", "Make involuntary treatment determinations: assess imminent danger criteria, document clinical rationale, implement least restrictive intervention, arrange legal safeguards", "Lead system-level violence prevention: analyze crisis events for patterns, implement environmental modifications, ensure staff training compliance, develop patient-specific crisis prevention plans", "Implement restraint and seclusion reduction strategies: sensory modulation rooms, comfort planning, early intervention protocols, post-event debriefing and analysis", "Manage excited delirium presentations: assess for hyperthermia, rapid sedation (ketamine IM 4-5 mg/kg or midazolam IM 5-10 mg), aggressive cooling, IV access, cardiac monitoring, prepare for potential cardiac arrest"],
    assessmentFindings: ["Agitation etiology determination: psychiatric (preceded by psychiatric symptoms, history of mental illness), medical (vital sign abnormalities, new onset, fluctuating consciousness), substance-related (toxidrome features, UDS, history), iatrogenic (recent medication changes, akathisia)", "System-level crisis pattern analysis: identify time of day, staffing levels, patient acuity, precipitating factors for unit-level crisis events; modify systems to address patterns", "Medication effectiveness tracking: document time to response for different agitation protocols; adjust unit formulary based on effectiveness and safety data"],
    signs: { left: ["Crisis resolved with minimal intervention level", "Effective PRN protocols allowing safe nursing-initiated medication", "Decreasing restraint and seclusion rates through prevention strategies", "Staff competent and supported in crisis management"], right: ["Excited delirium with hyperthermia and risk of cardiac arrest", "Restraint-associated injury or death", "Involuntary treatment legal challenge or rights violation", "Staff injury from patient violence requiring medical treatment", "Medication-related adverse event during crisis (oversedation, NMS, QTc-related arrhythmia)", "Repeated crisis events indicating system-level failure"] },
    medications: [{ name: "Loxapine Inhaled (Adasuve)", type: "First-generation antipsychotic (inhaled formulation)", action: "D2 and 5-HT2A antagonism delivered via inhalation for rapid onset (within 10 minutes); provides non-injectable rapid-acting antipsychotic for acute agitation in schizophrenia or bipolar disorder", sideEffects: "Dysgeusia (metallic taste), sedation, throat irritation, BRONCHOSPASM (requires spirometry screening and 1-hour post-dose observation)", contra: "Active airway disease (asthma, COPD), acute respiratory symptoms, current use of inhaled medications; REMS required", pearl: "10 mg single inhalation; onset within 10 minutes (faster than IM); REMS program: administer only in certified healthcare facilities; must have spirometry showing FEV1 above 80% predicted before use; observe 1 hour post-dose for bronchospasm with rescue bronchodilator available; advantage: non-injectable rapid onset respected patient dignity (no forced injection); disadvantage: requires patient cooperation to inhale, REMS restrictions, cannot be used in pulmonary disease patients" }, { name: "Valproic Acid IV (for acute agitation/mania)", type: "Mood stabilizer / anticonvulsant (IV formulation)", action: "Rapid GABA enhancement and sodium channel modulation; IV loading provides rapid antimanic and calming effect; useful alternative to antipsychotics in patients with NMS risk or Parkinson disease", sideEffects: "Sedation, GI upset, thrombocytopenia, hepatotoxicity, teratogenic; pancreatitis (rare)", contra: "Pregnancy (neural tube defects), liver disease, urea cycle disorders, mitochondrial disease", pearl: "IV loading 20-30 mg/kg at 3-6 mg/kg/min; provides rapid mood stabilization within hours; useful for manic agitation when antipsychotics are contraindicated (Parkinson disease, NMS history, medication sensitivity); well-tolerated IV infusion; target serum level 80-120 mcg/mL; NP prescribes as alternative pathway for agitation management when standard agents are unsuitable" }, { name: "Dexmedetomidine (Precedex)", type: "Alpha-2 adrenergic agonist (IV sedation)", action: "Selective alpha-2 agonist producing sedation, anxiolysis, and sympatholytic effects WITHOUT respiratory depression; unique cooperative sedation (patient can be aroused from sedation and return to sleep when unstimulated)", sideEffects: "Bradycardia, hypotension, dry mouth", contra: "Advanced heart block, severe hemodynamic instability", pearl: "Loading dose 1 mcg/kg over 10 minutes, then 0.2-0.7 mcg/kg/hr infusion; requires ICU or monitored setting; KEY ADVANTAGE: produces sedation WITHOUT respiratory depression (unlike benzodiazepines); used for agitation in ICU, alcohol withdrawal (adjunct to benzodiazepines), and procedural sedation; patient remains arousable (cooperative sedation); NP prescribes for severe agitation when respiratory depression from benzodiazepines is a concern (concurrent opioids, respiratory disease)" }],
    pearls: ["Etiology-specific prescribing prevents complications: benzodiazepines for stimulant agitation (antipsychotics lower seizure threshold); antipsychotics for psychotic agitation; combination for undifferentiated; ketamine for severe/refractory cases", "Restraint and seclusion reduction is a QUALITY METRIC: CMS monitors restraint and seclusion rates; evidence shows these can be reduced by 50-80% through environmental interventions, staff training, and sensory modulation alternatives", "Dexmedetomidine represents an advance in agitation management: sedation WITHOUT respiratory depression makes it invaluable for patients at high risk for respiratory complications; cooperative sedation maintains airway reflexes", "Involuntary treatment documentation must be meticulous: clearly state what the imminent danger is, what less restrictive alternatives were considered and why they were insufficient, and the patient's capacity to understand the situation; this protects both the patient's rights and the clinician's legal position", "Crisis prevention is more effective than crisis management: NP should invest in system-level interventions (environmental design, staffing models, patient engagement, de-escalation training) that prevent crises from occurring rather than only managing them when they do"],
    quiz: [{ question: "A patient with known schizophrenia on haloperidol presents with agitation, hyperthermia (104F), lead-pipe rigidity, and altered mental status. The clinician suspects NMS and should:", options: ["Increase the haloperidol dose", "STOP haloperidol immediately, initiate dantrolene and bromocriptine, arrange ICU transfer", "Give IM olanzapine for agitation", "Administer IV benzodiazepine and continue haloperidol"], correct: 1, rationale: "This presentation (hyperthermia, rigidity, altered mental status, on antipsychotic) is classic NMS. Immediate management: STOP the antipsychotic, dantrolene 1 mg/kg IV for rigidity, bromocriptine 2.5 mg PO TID to reverse D2 blockade, aggressive cooling, and ICU transfer. Mortality is 5-20%." }, { question: "For agitation from methamphetamine intoxication, the clinician should preferentially prescribe:", options: ["IM haloperidol (high-potency antipsychotic)", "IM lorazepam (benzodiazepine) -- preferred for stimulant-induced agitation", "IM olanzapine", "No medication -- wait for stimulant to wear off"], correct: 1, rationale: "Benzodiazepines are preferred for stimulant-induced agitation because antipsychotics lower the seizure threshold (stimulant intoxication already increases seizure risk). Lorazepam 2-4 mg IM addresses both agitation and seizure risk." }, { question: "The key advantage of dexmedetomidine for agitation management is:", options: ["It is the cheapest option", "It produces sedation WITHOUT respiratory depression", "It can be given IM in any setting", "It is the fastest-acting agent available"], correct: 1, rationale: "Dexmedetomidine provides sedation and anxiolysis WITHOUT respiratory depression, making it invaluable for patients at risk for respiratory complications (concurrent opioids, respiratory disease). It also produces cooperative sedation where the patient is arousable." }]
  },
  "ocd-rpn": {
    title: "Obsessive-Compulsive Disorder",
    cellular: { title: "Pathophysiology of OCD", content: "OCD is characterized by recurrent, intrusive, unwanted thoughts (obsessions) and repetitive behaviors or mental acts (compulsions) performed to reduce the anxiety caused by obsessions. Obsessions are ego-dystonic (the person recognizes them as irrational but cannot stop them). The pathophysiology involves dysfunction in the cortico-striato-thalamo-cortical (CSTC) circuit: the orbitofrontal cortex (error detection, feeling something is wrong) sends excessive signals through the caudate nucleus and thalamus, creating a loop of persistent anxiety and urge to perform compulsive behaviors. Serotonin system dysfunction is central (explaining why SSRIs are effective, but at HIGHER doses than for depression). Glutamate dysfunction also plays a role (explaining why glutamate-modulating agents like memantine and N-acetylcysteine show benefit in treatment-resistant OCD). Common obsession themes: contamination (most common), symmetry/ordering, forbidden/taboo thoughts (aggressive, sexual, religious), and harm (fear of accidentally causing harm). Common compulsions: washing/cleaning, checking, counting, repeating, ordering/arranging, and mental rituals (praying, reviewing). The practical nurse recognizes OCD symptoms, avoids inadvertently accommodating compulsions, and supports exposure and response prevention therapy." },
    riskFactors: ["Genetic predisposition (45-65% heritability)", "First-degree relative with OCD (4-8x increased risk)", "Childhood onset (mean age 10 years for males, 13 for females; bimodal onset: childhood and late adolescence)", "Comorbid conditions: depression (60%), anxiety disorders (50%), tic disorders/Tourette (15-20%), ADHD", "PANDAS/PANS: pediatric autoimmune neuropsychiatric disorders associated with streptococcal infections; sudden onset of OCD symptoms in children following strep infection", "Stressful life events as triggers for onset or exacerbation", "Perfectionism and high responsibility beliefs as cognitive risk factors"],
    diagnostics: ["DSM-5 criteria: presence of obsessions, compulsions, or both that are time-consuming (1+ hour/day), cause significant distress, or impair functioning", "Yale-Brown Obsessive-Compulsive Scale (Y-BOCS): gold standard severity measure; 0-7 subclinical, 8-15 mild, 16-23 moderate, 24-31 severe, 32-40 extreme", "Differentiation from normal habits: OCD behaviors are ego-dystonic (recognized as excessive/irrational), anxiety-driven, time-consuming, and functionally impairing", "Rule out OCD spectrum conditions: body dysmorphic disorder, hoarding disorder, trichotillomania (hair pulling), excoriation disorder (skin picking)", "Medical workup: TSH (anxiety component), UDS, strep throat culture in children with sudden OCD onset (PANDAS)"],
    management: ["Exposure and Response Prevention (ERP) is first-line psychotherapy: systematically exposing the patient to feared stimuli while preventing compulsive responses; 60-80% response rate", "SSRI at HIGHER doses than for depression: fluoxetine 40-80 mg, sertraline 200 mg, fluvoxamine 200-300 mg, paroxetine 40-60 mg, escitalopram 20 mg", "Allow 8-12 weeks for full SSRI response in OCD (longer than the 4-6 weeks for depression)", "Combination ERP + SSRI is most effective for moderate-severe OCD", "Clomipramine (tricyclic with strong serotonergic activity) is most effective medication for OCD but side effects limit use as first-line"],
    nursingActions: ["Recognize OCD symptoms: repetitive behaviors (handwashing, checking, counting) or mental rituals that the patient acknowledges as excessive but cannot stop", "Do NOT accommodate compulsions: well-intentioned accommodation (allowing extra handwashing time, providing excessive reassurance) reinforces the OCD cycle and worsens symptoms long-term", "Do NOT provide reassurance for obsessional doubts: patients may repeatedly ask Is it safe? Did I lock the door? Am I contaminated? Providing reassurance temporarily reduces anxiety but strengthens the OCD cycle", "Support ERP therapy: encourage the patient to resist compulsions, validate that anxiety will DECREASE over time without performing the ritual (habituation), support sitting with discomfort", "Allow adequate time for daily activities: OCD rituals can consume hours; do not rush the patient but also do not enable unlimited time for compulsions", "Administer prescribed SSRI and educate about the 8-12 week timeline for OCD response (longer than depression)"],
    assessmentFindings: ["Obsession content: contamination fears (excessive handwashing until skin is raw), harm fears (checking stove, locks, repeatedly), symmetry/ordering (items must be perfectly arranged), taboo thoughts (intrusive violent, sexual, or blasphemous thoughts that are extremely distressing because they are ego-dystonic)", "Compulsion manifestations: behavioral (washing, checking, counting, ordering, touching) or mental (praying, counting silently, reviewing conversations, mental neutralizing)", "Skin damage from washing compulsions: chapped, cracked, bleeding hands; dermatitis from excessive cleaning products", "Functional impairment: may take hours to leave the house (checking rituals), avoid contaminated areas, unable to touch certain objects, unable to complete tasks due to perfectionism/ordering rituals", "Insight assessment: good insight (recognizes behaviors are excessive), poor insight (believes rituals are necessary), absent insight (delusional OCD -- believes obsessions are true)"],
    signs: { left: ["Mild-moderate OCD managed with ERP and SSRI", "Compulsion time decreasing with treatment", "Patient using ERP skills independently", "Functioning improving with reduced ritual time"], right: ["Severe OCD consuming 4+ hours daily", "Skin damage from washing compulsions requiring medical treatment", "OCD with absent insight (delusional beliefs about contamination or harm)", "Treatment-resistant OCD (failed 2+ SSRIs and adequate ERP)", "Suicidal ideation from OCD-related distress", "PANDAS in a child requiring strep treatment and immune modulation"] },
    medications: [{ name: "Fluvoxamine (Luvox)", type: "SSRI (strong serotonergic activity)", action: "Potent SSRI with sigma-1 receptor agonism; the most serotonin-specific SSRI; often considered the prototypical SSRI for OCD based on early clinical trials", sideEffects: "Nausea (most common), sedation, headache, multiple CYP interactions (1A2, 2C19, 3A4 inhibitor)", contra: "Concurrent MAOIs, concurrent tizanidine, concurrent thioridazine", pearl: "50-300 mg daily (divided BID for doses above 150 mg); FDA-approved for OCD; requires HIGHER doses than depression (200-300 mg vs 50-100 mg for MDD); 8-12 weeks for full response; MULTIPLE drug interactions (inhibits CYP1A2, 2C19, 3A4) limiting its use in patients on other medications; increases clozapine levels, theophylline levels, warfarin levels; practical nurse must check for drug interactions" }, { name: "Clomipramine (Anafranil)", type: "Tricyclic antidepressant (strong serotonergic)", action: "Potent serotonin reuptake inhibition (most potent of all TCAs for serotonin) with secondary norepinephrine reuptake inhibition; the MOST EFFECTIVE single medication for OCD but side effects limit first-line use", sideEffects: "Anticholinergic effects (dry mouth, constipation, urinary retention, blurred vision), sedation, weight gain, sexual dysfunction, orthostatic hypotension, cardiac conduction abnormalities (QTc prolongation, AV block), SEIZURES (dose-dependent above 250 mg), lethal in overdose", contra: "Recent MI, cardiac conduction abnormalities, concurrent MAOIs, seizure disorder, acute narrow-angle glaucoma", pearl: "25 mg at bedtime, titrate to 150-250 mg; the MOST effective medication for OCD (50-60% response rate vs 40-50% for SSRIs) but NOT first-line due to side effects; second-line after SSRI failure; ECG required before starting and at therapeutic doses; seizure risk increases above 250 mg; LETHAL in overdose (cardiac toxicity) -- assess suicide risk before prescribing; monitor for anticholinergic effects, especially in elderly" }, { name: "N-Acetylcysteine (NAC)", type: "Glutamate modulator (supplement)", action: "Modulates glutamate neurotransmission by activating the cystine-glutamate antiporter, normalizing extracellular glutamate levels in the nucleus accumbens and prefrontal cortex; addresses the glutamatergic dysfunction component of OCD", sideEffects: "Nausea, vomiting, diarrhea, headache; generally well-tolerated", contra: "Known hypersensitivity; caution in asthma (bronchospasm potential with IV formulation -- oral is safe)", pearl: "600-3000 mg/day PO; off-label OCD augmentation; growing evidence as augmentation to SSRI for treatment-resistant OCD; also studied for trichotillomania, excoriation disorder, and substance use disorders; available as supplement without prescription; very well tolerated; NP may recommend as adjunct when SSRI alone is insufficient; best evidence at 2400-3000 mg/day" }],
    pearls: ["OCD requires HIGHER SSRI doses and LONGER treatment duration than depression: doses at the TOP of the therapeutic range (fluoxetine 80 mg, sertraline 200 mg) and 8-12 weeks for response (vs 4-6 weeks for depression)", "ERP is the most effective psychotherapy for OCD: systematic exposure to feared stimuli + prevention of compulsive response leads to habituation (natural decrease in anxiety); 60-80% response rate; NP should refer to ERP-trained therapist", "Do NOT provide reassurance: while compassionate, answering Is everything OK? or You're not contaminated repeatedly reinforces the OCD cycle; therapeutic response: I understand this is difficult. What would your ERP therapist suggest?", "Accommodation by family/staff WORSENS OCD: allowing extra time for rituals, participating in checking, avoiding triggers, and providing reassurance all reinforce the disorder; family psychoeducation about avoiding accommodation is essential", "OCD thoughts are ego-DYSTONIC: patients with violent/sexual/blasphemous obsessions are often terrified by these thoughts and ashamed to disclose them; the fact that these thoughts cause distress means the patient does NOT want to act on them (unlike ego-syntonic thoughts in psychosis)", "PANDAS: sudden-onset OCD in a child following streptococcal infection should prompt ASO titer and throat culture; treatment includes antibiotics and potentially immune modulation (IVIG or plasmapheresis in severe cases)"],
    quiz: [{ question: "A patient with OCD asks the nurse repeatedly: Are you sure the door is locked? Is it really locked? The MOST therapeutic response is:", options: ["Yes, I checked it three times, it's definitely locked", "I understand you're feeling anxious about this. What coping strategy from your ERP therapy might help right now?", "Stop asking me, the door is fine", "I'll go check again for you"], correct: 1, rationale: "Providing reassurance (checking, confirming) temporarily reduces OCD anxiety but REINFORCES the OCD cycle. The therapeutic response validates the emotion while redirecting to ERP coping strategies the patient has learned." }, { question: "SSRIs for OCD differ from SSRIs for depression in that OCD requires:", options: ["Lower doses and shorter treatment duration", "Higher doses and longer treatment duration (8-12 weeks vs 4-6 weeks)", "Different SSRI medications not used for depression", "Combination with benzodiazepines"], correct: 1, rationale: "OCD responds to SSRIs at the TOP of the dosing range (fluoxetine 80 mg, sertraline 200 mg) and requires 8-12 weeks for full response, compared to standard depression doses and 4-6 weeks for depression." }, { question: "The MOST effective psychotherapy for OCD is:", options: ["Psychodynamic therapy", "Supportive counseling", "Exposure and Response Prevention (ERP)", "Relaxation training"], correct: 2, rationale: "ERP systematically exposes the patient to feared stimuli while preventing compulsive responses, allowing natural habituation to occur. It has a 60-80% response rate and is more effective than medication alone for many patients." }]
  },
  "ocd-rn": {
    title: "OCD",
    cellular: { title: "OCD Assessment and ERP-Informed Nursing Care", content: "The nurse manages OCD patients by conducting comprehensive assessments using validated tools, supporting ERP therapy, monitoring medication response and side effects, and distinguishing OCD from related conditions. Advanced assessment requires identifying OCD subtypes and their unique challenges: contamination OCD (washing, cleaning, avoidance of perceived contaminants), checking OCD (repeatedly verifying locks, appliances, actions), symmetry/ordering OCD (items must be just right, repeated arranging), harm OCD (intrusive thoughts of causing harm, excessive checking for safety), sexual/religious OCD (unwanted blasphemous or sexual thoughts causing extreme shame -- patients are often reluctant to disclose these), and relationship OCD (obsessive doubt about partner's suitability). The nurse must differentiate OCD from: OCPD (obsessive-compulsive personality disorder -- ego-syntonic perfectionism and control, NOT anxiety-driven rituals), generalized anxiety disorder (worry about realistic concerns, not ritualistic), psychosis (OCD with poor insight can appear delusional, but the patient typically retains some uncertainty about their beliefs), and tic disorders (comorbid in 15-20%, especially in childhood-onset OCD). The Y-BOCS is administered at baseline and every 2-4 weeks to monitor treatment response; response is defined as 35% or greater reduction; partial response 25-35%; non-response less than 25%." },
    riskFactors: ["Treatment-resistant OCD risk factors: early onset, longer duration of illness, comorbid hoarding, comorbid tic disorder, poor insight, family accommodation", "Hoarding disorder comorbidity: may present alongside OCD; clutter and acquisition behavior may not respond to standard OCD treatment", "OCD-related suicide risk: 10-27% of OCD patients make suicide attempts; risk factors include comorbid depression, symptom severity, hopelessness, and unacceptable obsessional content (sexual/violent)", "Medication side effect challenges: high SSRI doses increase side effect burden (sexual dysfunction, weight gain, QTc prolongation with citalopram); clomipramine has significant cardiac and anticholinergic risks"],
    diagnostics: ["Y-BOCS serial monitoring: administer at baseline, then every 2-4 weeks during treatment; assess obsession and compulsion severity separately (time, interference, distress, resistance, control); total score 0-40", "Treatment response criteria: response = 35%+ Y-BOCS reduction AND CGI-I of 1 or 2; partial response = 25-35% reduction; non-response = less than 25% after adequate trial", "OCD vs OCPD differentiation: OCD = ego-dystonic (unwanted intrusive thoughts cause anxiety), ritualistic behaviors; OCPD = ego-syntonic (person believes their perfectionism and control are reasonable and appropriate), pervasive personality pattern", "Insight assessment: excellent (recognizes OCD beliefs are definitely not true), good (thinks beliefs are probably not true), fair (thinks beliefs are possibly true), poor (thinks beliefs are probably true), absent (completely convinced beliefs are true -- poor prognosis, may need antipsychotic augmentation)"],
    management: ["ERP support in inpatient/outpatient settings: work with OCD therapist to implement exposure hierarchies; nursing staff should understand the patient's specific exposures and response prevention goals", "SSRI dose optimization for OCD: titrate to maximum tolerated dose within therapeutic range before declaring SSRI failure; ensure 8-12 weeks at adequate dose", "Augmentation for partial SSRI response: add low-dose aripiprazole (2-10 mg -- most evidence), risperidone (0.5-2 mg), or quetiapine (50-300 mg); glutamate modulators (NAC, memantine) as further augmentation", "SRI switching for non-response: switch to different SSRI, or try clomipramine (most effective but more side effects); clomipramine + SSRI combination requires careful monitoring (serotonin syndrome and cardiac risk)", "Intensive treatment for severe/refractory OCD: residential OCD treatment programs with intensive daily ERP; may achieve response in patients who fail outpatient treatment"],
    nursingActions: ["Administer Y-BOCS at baseline and every 2-4 weeks: track obsession and compulsion subscores separately; total score guides treatment intensity decisions", "Support ERP exposure hierarchy: coordinate with therapist; understand what exposures the patient is working on; encourage without forcing; validate that anxiety will decrease with prolonged exposure (habituation curve)", "Monitor high-dose SSRI side effects: sexual dysfunction (most common reason for discontinuation), weight gain, bleeding risk (SSRIs inhibit platelet aggregation), hyponatremia (especially elderly), QTc prolongation (citalopram), serotonin syndrome (if combined with other serotonergic agents)", "Differentiate compulsions from tics: OCD compulsions are preceded by anxiety/obsession and are purposeful; tics are sudden, rapid, recurrent motor/vocal movements that are semi-voluntary; both can coexist", "Educate family about accommodation: identify ways family members accommodate OCD (washing patient's items, providing reassurance, avoiding triggers, participating in rituals); help family understand that accommodation maintains OCD and develop plan to gradually reduce it", "Assess and manage comorbid depression: 60% of OCD patients have comorbid MDD; depression often improves when OCD is effectively treated; monitor PHQ-9 alongside Y-BOCS"],
    assessmentFindings: ["Y-BOCS trajectory: monitor trend over time; improvement should be seen by 8-12 weeks on adequate SSRI dose; early partial response (by week 4) predicts eventual full response", "Quality of life impact: OCD is the 10th leading cause of disability worldwide; even mild OCD significantly impacts relationships, work, and daily functioning; measure functional improvement alongside symptom improvement", "Family accommodation assessment: rate of family accommodation correlates with OCD severity and treatment resistance; family therapy targeting accommodation improves outcomes"],
    signs: { left: ["OCD responding to ERP + SSRI with declining Y-BOCS", "Patient independently using ERP skills", "Family reducing accommodation behaviors", "Comorbid depression improving with OCD treatment"], right: ["Severe OCD (Y-BOCS above 30) not responding to 2+ adequate SSRI trials plus ERP", "OCD with absent insight requiring antipsychotic augmentation", "Clomipramine cardiac effects requiring ECG monitoring", "Severe OCD-related suicide risk", "Hoarding comorbidity not responding to standard OCD treatment", "PANDAS requiring immune modulation"] },
    medications: [{ name: "Aripiprazole Augmentation (for treatment-resistant OCD)", type: "Atypical antipsychotic (D2 partial agonist)", action: "Low-dose D2 partial agonism and 5-HT2A antagonism augments serotonergic effect of SSRI; the MOST evidence-based augmentation strategy for treatment-resistant OCD", sideEffects: "Akathisia, restlessness, insomnia; minimal metabolic effects at low doses", contra: "Known hypersensitivity", pearl: "2-10 mg daily added to maximum-dose SSRI; MOST evidence of any augmentation agent for OCD (multiple RCTs); low doses (2-5 mg) are usually sufficient; akathisia is dose-limiting; response to augmentation typically seen within 4-6 weeks; RN monitors Y-BOCS before and after augmentation to document response" }, { name: "Memantine (off-label OCD augmentation)", type: "NMDA receptor antagonist", action: "Modulates glutamatergic neurotransmission by blocking NMDA receptors; addresses glutamate dysfunction in CSTC circuit that contributes to OCD; used as augmentation when serotonergic agents are insufficient", sideEffects: "Dizziness, headache, confusion, constipation", contra: "Known hypersensitivity, severe renal impairment", pearl: "5-20 mg daily as SSRI augmentation for treatment-resistant OCD; growing evidence base from multiple small RCTs; well-tolerated; addresses a different neurochemical pathway than SSRIs (glutamate rather than serotonin); may be particularly useful for patients with contamination OCD; can be combined with SSRI + aripiprazole for triple therapy in severe refractory OCD" }, { name: "Sertraline (high-dose for OCD)", type: "SSRI", action: "Selective serotonin reuptake inhibition at higher doses produces greater synaptic serotonin availability to modulate the hyperactive CSTC circuit", sideEffects: "GI disturbance, sexual dysfunction, headache, insomnia", contra: "Concurrent MAOIs", pearl: "Target 200 mg for OCD (maximum dose); start 50 mg, increase by 50 mg every 2 weeks; may take 8-12 weeks at maximum dose for full OCD response; FDA-approved for OCD in adults and children; if partial response at 200 mg after 12 weeks, consider augmentation rather than switching (partial response predicts augmentation success)" }],
    pearls: ["Y-BOCS is the gold standard for monitoring OCD treatment: track both obsession and compulsion subscores; 35%+ total reduction = response; use it like blood pressure -- quantified, serial measurement guides treatment decisions", "OCD with poor/absent insight: 15-30% of OCD patients have poor insight and may appear delusional; low-dose antipsychotic augmentation is particularly helpful for this subtype; do NOT diagnose psychotic disorder based on OCD beliefs alone", "Augmentation strategy selection for treatment-resistant OCD: aripiprazole 2-10 mg has the MOST evidence; if partial response to aripiprazole, add glutamate modulator (memantine or NAC); if still resistant, consider clomipramine (with cardiac monitoring) or residential intensive ERP", "OCD is the 10th leading cause of disability worldwide: it is NOT simply being neat or organized; the suffering caused by intrusive thoughts and time consumed by compulsions can be devastating; validation of this suffering is an important nursing intervention"],
    quiz: [{ question: "An RN is monitoring OCD treatment. The Y-BOCS decreased from 28 to 16 after 10 weeks of sertraline 200 mg. This represents:", options: ["Non-response", "Partial response", "Response (43% reduction meets the 35% threshold)", "Remission"], correct: 2, rationale: "A decrease from 28 to 16 is a 43% reduction, meeting the 35% threshold for treatment response. The patient should continue current treatment. If further improvement is desired, augmentation can be considered." }, { question: "The MOST evidence-based augmentation strategy for OCD that has partially responded to maximum-dose SSRI is:", options: ["Adding a benzodiazepine", "Adding low-dose aripiprazole (2-10 mg)", "Switching to a different SSRI", "Adding lithium"], correct: 1, rationale: "Low-dose aripiprazole (2-10 mg) has the most robust evidence base for OCD augmentation from multiple RCTs. Response to augmentation typically occurs within 4-6 weeks." }, { question: "An RN notes that a patient's family members wash the patient's clothing twice, avoid touching items the patient considers contaminated, and provide verbal reassurance 20+ times daily. This is:", options: ["Supportive family behavior", "Family accommodation that maintains and worsens OCD -- should be addressed in treatment", "Normal family coping", "Irrelevant to OCD treatment"], correct: 1, rationale: "Family accommodation (participating in rituals, avoiding triggers, providing reassurance) maintains OCD by preventing natural habituation. Reducing accommodation is a critical component of effective OCD treatment." }]
  },
  "ocd-np": {
    title: "OCD",
    cellular: { title: "OCD Pharmacotherapy and Neuromodulation", content: "The clinician managing OCD prescribes evidence-based pharmacotherapy, manages treatment-resistant OCD (TR-OCD), and coordinates neuromodulation therapies for refractory cases. TR-OCD is defined as failure to achieve adequate response (35% Y-BOCS reduction) after 2+ adequate SRI trials (maximum tolerated dose for 8-12 weeks each) plus adequate ERP therapy. TR-OCD affects approximately 40-60% of OCD patients. The NP's treatment algorithm: Step 1 -- SSRI monotherapy (sertraline, fluoxetine, fluvoxamine, paroxetine, escitalopram at maximum doses for 12 weeks); Step 2 -- switch to different SSRI or clomipramine; Step 3 -- augment with antipsychotic (aripiprazole 2-10 mg most evidence) + ensure adequate ERP; Step 4 -- add glutamate modulator (memantine, NAC) or switch to clomipramine if not yet tried; Step 5 -- consider intensive/residential ERP, SSRI + clomipramine combination (with cardiac monitoring), or neuromodulation (deep TMS FDA-approved for OCD, ablative neurosurgery for extreme cases). Deep TMS (transcranial magnetic stimulation) targeting the anterior cingulate cortex and medial prefrontal cortex received FDA approval for OCD in 2018. Gamma knife capsulotomy (ablation of the anterior limb of the internal capsule) is reserved for the most severe, treatment-refractory cases with 50-70% response rates but carries irreversible surgical risks." },
    riskFactors: ["TR-OCD predictors: early onset, hoarding symptoms, comorbid tic disorder, poor insight, family accommodation, comorbid personality disorder, substance use", "Clomipramine cardiac risks: QTc prolongation, AV block, cardiomyopathy; ECG at baseline, at 150 mg, and at target dose; contraindicated in pre-existing cardiac conduction disease", "SSRI + clomipramine combination: serotonin syndrome risk (both are potent SRIs) + clomipramine level elevation (SSRIs inhibit CYP2D6 which metabolizes clomipramine); requires close monitoring of clomipramine levels and ECG", "Pregnancy in OCD: SSRIs generally considered safe (sertraline preferred); clomipramine carries more risk; ERP should be continued; OCD may worsen in perinatal period"],
    diagnostics: ["Y-BOCS treatment response assessment at 8-12 weeks: non-response (less than 25%) = switch; partial response (25-35%) = augment; response (35%+) = continue and optimize", "Clomipramine level monitoring: target 150-300 ng/mL (combined clomipramine + desmethylclomipramine); levels above 450 ng/mL increase seizure and cardiac risk", "ECG monitoring for clomipramine: baseline, at 150 mg, at target dose, annually; QTc above 450 ms requires dose reduction or discontinuation", "DBS/neurosurgery evaluation: requires comprehensive psychiatric assessment, documented failure of all evidence-based treatments (multiple SRIs, augmentation strategies, adequate ERP, intensive residential treatment), multidisciplinary team review, IRB approval at most centers"],
    management: ["Step 1: SSRI at maximum dose for 12 weeks (sertraline 200 mg, fluoxetine 80 mg, fluvoxamine 300 mg, escitalopram 20 mg); lower doses are inadequate for OCD", "Step 2: Switch SSRI or switch to clomipramine (25 mg, titrate to 150-250 mg with ECG monitoring)", "Step 3: Augment SSRI with aripiprazole 2-10 mg (strongest evidence) or risperidone 0.5-2 mg; ensure patient is receiving adequate ERP (medication without ERP has limited ceiling)", "Step 4: Add glutamate modulator (memantine 5-20 mg or NAC 2400-3000 mg) to existing regimen; consider SSRI + clomipramine combination (with cardiac and serotonin syndrome monitoring)", "Step 5: Intensive residential ERP (may succeed where outpatient failed); deep TMS (FDA-approved: H7 coil targeting anterior cingulate, 6 weeks daily sessions); consider referral for capsulotomy in extreme cases", "IV clomipramine pulse loading (specialized centers): 150-200 mg IV over 90 minutes; achieves rapid therapeutic levels; may provide rapid improvement in severe OCD; followed by oral maintenance"],
    nursingActions: ["Prescribe SSRI at OCD-appropriate doses (maximum therapeutic range) and allow adequate trial duration (12 weeks) before declaring failure", "Select augmentation agent based on evidence: aripiprazole has strongest RCT evidence; risperidone and quetiapine have supporting evidence; glutamate modulators (memantine, NAC) for patients who fail antipsychotic augmentation", "Prescribe and monitor clomipramine: ECG at baseline and dose changes, serum levels at steady state, educate about anticholinergic effects and seizure risk above 250 mg", "Manage SSRI + clomipramine combination: monitor clomipramine levels closely (SSRI inhibition of CYP2D6 raises clomipramine levels); monitor for serotonin syndrome; ECG surveillance", "Coordinate ERP referral and ensure adequacy: medication without ERP has a ceiling of ~50% response; combined treatment produces best outcomes; NP should advocate for access to ERP-trained therapists", "Evaluate for neuromodulation: deep TMS referral for patients who fail 3+ medication trials plus adequate ERP; evaluate surgical candidacy for most severe refractory cases", "Manage OCD in special populations: pregnancy (continue SSRI with informed consent, sertraline preferred), children (ERP first-line; fluoxetine and sertraline FDA-approved for pediatric OCD), elderly (lower SSRI doses, watch for hyponatremia)"],
    assessmentFindings: ["Treatment algorithm position: quantify which steps have been completed with adequate trials; many treatment failures reflect inadequate dose, duration, or missing ERP rather than true treatment resistance", "Medication audit for OCD: verify maximum SSRI doses were used for 12+ weeks each; verify adequate ERP was attempted (not general counseling, but specific ERP with exposure hierarchy and response prevention); verify augmentation trials were adequate (aripiprazole for 6+ weeks)", "Deep TMS candidacy assessment: documented failure of 3+ SRI trials at adequate doses, adequate ERP, augmentation strategies; functional impairment despite treatment; absence of contraindications to TMS (metallic cranial implants, seizure disorder)"],
    signs: { left: ["OCD in remission on optimized medication + ERP maintenance", "Treatment-resistant OCD responding to augmentation strategy", "Deep TMS producing clinically meaningful Y-BOCS reduction", "Quality of life significantly improved with reduced OCD interference"], right: ["Severe refractory OCD despite exhausting all pharmacological and psychotherapy options", "Clomipramine-induced QTc prolongation requiring alternative treatment", "Serotonin syndrome from SRI combination therapy", "OCD with absent insight mimicking psychosis", "Severe OCD-related disability with inability to work or perform self-care", "Neurosurgery consideration for extreme treatment-refractory OCD"] },
    medications: [{ name: "Deep TMS (H7 Coil) for OCD", type: "Neuromodulation (FDA-approved for OCD)", action: "Deep transcranial magnetic stimulation targeting the anterior cingulate cortex and medial prefrontal cortex using the H7 coil; modulates hyperactive CSTC circuit; provocation paradigm (exposure to OCD triggers during stimulation) enhances efficacy", sideEffects: "Headache, scalp discomfort, jaw twitching during stimulation, seizure (rare, less than 0.1%)", contra: "Metallic cranial implants, active seizure disorder, cochlear implants", pearl: "FDA-approved 2018 for OCD after failure of conventional treatments; protocol: daily 20-minute sessions for 6 weeks; provocation-enhanced paradigm: patient exposed to individualized OCD triggers during TMS session, engaging the target circuitry during stimulation; 30-40% response rate in treatment-resistant patients; non-invasive, no anesthesia required; NP can refer for this treatment after documenting adequate prior treatment trials" }, { name: "Fluvoxamine + Aripiprazole Combination", type: "SSRI + antipsychotic augmentation (evidence-based OCD regimen)", action: "Fluvoxamine provides strong serotonin reuptake inhibition (most serotonin-selective SSRI); aripiprazole provides D2 partial agonism and 5-HT2A antagonism augmenting the serotonergic effect; the most evidence-based oral combination for moderate-severe OCD", sideEffects: "Combined: nausea, akathisia, headache, drug interactions from fluvoxamine CYP inhibition (INCREASES aripiprazole levels via CYP3A4 inhibition -- reduce aripiprazole dose)", contra: "Concurrent MAOIs, tizanidine", pearl: "Fluvoxamine 200-300 mg + aripiprazole 2-5 mg (reduce aripiprazole dose because fluvoxamine inhibits CYP3A4 which metabolizes aripiprazole); NP must account for this pharmacokinetic interaction -- standard aripiprazole augmentation dose of 5-10 mg may cause toxicity when combined with fluvoxamine; start aripiprazole at 2 mg with fluvoxamine" }, { name: "Intravenous Clomipramine (specialized treatment)", type: "IV SRI pulse loading", action: "IV administration achieves rapid therapeutic clomipramine levels (bypasses first-pass metabolism) providing faster onset of OCD response compared to oral titration; may overcome treatment resistance through higher CNS drug delivery", sideEffects: "Cardiac arrhythmia (continuous monitoring required), seizures, orthostatic hypotension, nausea", contra: "Cardiac conduction abnormalities, seizure disorder, concurrent MAOIs", pearl: "150-200 mg IV over 90 minutes; available at specialized OCD treatment centers; continuous cardiac monitoring during infusion; may provide response within days to weeks rather than the typical 8-12 weeks for oral SRIs; followed by oral clomipramine maintenance; NP may refer for this procedure when multiple oral SRI trials have failed; evidence from several open-label trials showing 50-70% response in treatment-resistant patients" }],
    pearls: ["Most OCD treatment failures reflect inadequate treatment rather than true treatment resistance: verify maximum SSRI dose for 12+ weeks, adequate ERP (not general therapy), and systematic augmentation before labeling as treatment-resistant", "Deep TMS is a game-changer for treatment-resistant OCD: FDA-approved in 2018, non-invasive, 30-40% response rate in patients who have failed conventional treatments; NP should be aware of this option and refer appropriately", "Drug interactions with fluvoxamine are EXTENSIVE: CYP1A2, CYP2C19, and CYP3A4 inhibition means fluvoxamine interacts with clozapine, olanzapine, theophylline, warfarin, aripiprazole, benzodiazepines, and many others; NP must check interactions carefully", "The optimal OCD treatment is COMBINATION of medication (SSRI at maximum dose) + psychotherapy (ERP): neither alone achieves optimal outcomes; the clinician should prescribe medication AND coordinate ERP referral as a unified treatment plan", "OCD-related suicide: 10-27% lifetime suicide attempt rate; risk factors include comorbid depression, hopelessness, and taboo obsessional content (sexual/violent intrusive thoughts causing shame and isolation); assess suicide risk routinely"],
    quiz: [{ question: "An NP is managing a patient with OCD who failed sertraline 200 mg x 12 weeks and fluvoxamine 300 mg x 12 weeks, both with adequate ERP. The Y-BOCS remains at 32. The NEXT step is:", options: ["Try another SSRI", "Augment current SSRI with aripiprazole 2-10 mg", "Refer for psychosurgery immediately", "Discontinue all medications"], correct: 1, rationale: "After 2 adequate SSRI trials with adequate ERP, augmentation is the next step. Aripiprazole 2-10 mg has the most evidence for OCD augmentation. If the patient is on fluvoxamine, reduce aripiprazole dose due to CYP3A4 interaction." }, { question: "Deep TMS for OCD uses a provocation paradigm, which means:", options: ["The patient is provoked to anger during treatment", "The patient is exposed to their individualized OCD triggers during the TMS session to engage the target circuitry", "The patient receives electrical shocks alongside magnetic stimulation", "The treatment is designed to provoke seizures"], correct: 1, rationale: "Provocation-enhanced TMS involves exposing the patient to their specific OCD triggers during the stimulation session, activating the dysfunctional CSTC circuit while it is being modulated by TMS. This enhances the treatment's effectiveness." }, { question: "When combining fluvoxamine with aripiprazole for OCD, the clinician should:", options: ["Use standard aripiprazole doses (10-15 mg)", "REDUCE aripiprazole dose to 2-5 mg because fluvoxamine inhibits CYP3A4 and increases aripiprazole levels", "Increase fluvoxamine dose to compensate", "There is no interaction between these medications"], correct: 1, rationale: "Fluvoxamine is a potent CYP3A4 inhibitor, and aripiprazole is primarily metabolized by CYP3A4. This interaction significantly increases aripiprazole levels, requiring dose reduction to 2-5 mg (vs usual 5-10 mg for OCD augmentation)." }]
  },
  "suicide-assessment-rpn": {
    title: "Self-Harm and Suicide Assessment",
    cellular: { title: "Understanding Suicidal Behavior and Self-Harm", content: "Suicide is the 10th leading cause of death in the US and the 2nd leading cause among ages 10-34. Suicidal behavior exists on a spectrum: suicidal ideation (passive -- wishing to be dead; active -- thinking about methods), suicidal planning (formulating a specific plan with method, time, place), suicidal intent (determination to carry out the plan), and suicide attempt (self-injurious behavior with intent to die). Non-suicidal self-injury (NSSI) is distinct: self-harm WITHOUT intent to die, serving functions including emotion regulation (reducing overwhelming affect), self-punishment, communication of distress, or feeling something when emotionally numb. NSSI and suicidal behavior can co-occur, and NSSI is a RISK FACTOR for future suicide attempts. Neurobiologically, suicidal behavior involves serotonin system dysfunction (reduced serotonergic function in the prefrontal cortex impairing impulse control and decision-making), HPA axis dysregulation (elevated cortisol reflecting chronic stress), inflammatory markers (elevated IL-6, TNF-alpha in suicidal patients), and reduced BDNF (brain-derived neurotrophic factor reflecting impaired neuroplasticity). The interpersonal theory of suicide (Joiner) identifies three factors: thwarted belongingness (feeling disconnected), perceived burdensomeness (believing others would be better off without them), and acquired capability (habituation to pain and fear of death through prior self-harm, trauma, or substance use). The practical nurse conducts routine suicide screening, implements safety protocols, and provides compassionate monitoring." },
    riskFactors: ["Previous suicide attempt (STRONGEST predictor of future suicide)", "Mental health disorders (depression, bipolar, schizophrenia, BPD, PTSD, substance use)", "Access to lethal means (firearms account for 50% of suicide deaths; medication stockpiles)", "Recent discharge from psychiatric hospitalization (highest risk period: first 1-4 weeks post-discharge)", "Social isolation and thwarted belongingness", "Perceived burdensomeness (believing others would be better off without them)", "Chronic pain or terminal illness", "Recent loss (relationship, job, financial, bereavement)", "Family history of suicide", "LGBTQ+ youth (4x higher attempt rate)", "Male sex (4x higher completion rate; females attempt more often but males use more lethal means)", "Military/veteran status (1.5x higher rate)"],
    diagnostics: ["Columbia Suicide Severity Rating Scale (C-SSRS): gold standard screening tool; assesses ideation severity (wish to be dead, active thoughts, plan, intent, intent with plan), ideation intensity (frequency, duration, controllability, deterrents, reason), and suicidal behavior (actual attempt, interrupted attempt, aborted attempt, preparatory behavior)", "PHQ-9 Item 9: Thoughts that you would be better off dead or of hurting yourself; ANY positive response requires follow-up assessment with C-SSRS", "ASQ (Ask Suicide-Screening Questions): brief 4-question screen validated for medical patients; positive screen requires full assessment", "SAD PERSONS scale: Sex (male), Age (adolescent/elderly), Depression, Previous attempt, Ethanol/drug abuse, Rational thinking loss, Social support lacking, Organized plan, No spouse, Sickness (chronic illness)", "Risk vs protective factors assessment: risk factors increase likelihood; protective factors decrease it (reasons for living, social support, children, religious beliefs, access to care, coping skills)"],
    management: ["Means restriction: the MOST effective suicide prevention intervention; secure firearms (temporary off-site storage), medications (limit supply, lock up), and other lethal means; counsel family members directly", "Safety planning (Stanley-Brown Safety Planning Intervention): collaborative 6-step plan: (1) warning signs, (2) internal coping strategies, (3) social contacts for distraction, (4) family/friends who can help, (5) professionals/crisis services to contact, (6) making the environment safe", "Hospitalization criteria: active suicidal ideation with plan and intent, recent attempt, inability to maintain safety, psychosis with command hallucinations, severe agitation, lack of protective factors", "Crisis resources: 988 Suicide and Crisis Lifeline (call or text 988), Crisis Text Line (text HOME to 741741)", "Pharmacotherapy for underlying conditions: treat depression, psychosis, substance use; lithium has anti-suicidal properties independent of mood stabilization; clozapine reduces suicide risk in schizophrenia"],
    nursingActions: ["Screen ALL patients for suicide risk: use C-SSRS or ASQ; do not avoid asking about suicide (asking does NOT plant the idea -- this is a myth)", "Ask directly and compassionately: Are you having thoughts of killing yourself? Have you thought about how you would do it? Do you have access to the means? Do you intend to act on these thoughts?", "Implement 1:1 continuous observation for patients at imminent risk: maintain line of sight at all times, including bathroom; remove sharps, cords, belts, plastic bags, glass; check environment for ligature points", "Conduct safety rounds: check on patient at irregular intervals (not predictable patterns); document observations of behavior, mood, and statements", "Implement means restriction: remove all potential means from patient area (sharps, medications, cords, belts, shoelaces, plastic bags, glass items); assess environment for ligature points (door handles, shower rods, bed frames)", "Document suicide assessment thoroughly: risk factors identified, protective factors, level of ideation/plan/intent, interventions implemented, plan of care", "Provide post-attempt care with compassion: patients who survive attempts often experience shame and ambivalence; non-judgmental care that validates their pain while expressing hope is therapeutic"],
    assessmentFindings: ["Suicidal ideation assessment: passive (I wish I were dead, I wish I wouldn't wake up) vs active (I want to kill myself, I'm thinking about overdosing); active ideation with plan and intent is highest risk", "Warning signs (acute changes suggesting imminent risk): giving away possessions, saying goodbye, sudden calmness after period of depression (may indicate decision has been made), increased substance use, withdrawal from others, writing a will/suicide note, researching methods", "Protective factors: reasons for living (children, family, pets, faith), future-oriented thinking, social connectedness, engaged in treatment, coping skills, restricted access to means", "NSSI assessment: typically involves cutting (most common), burning, hitting, scratching, head-banging; usually on arms, thighs, or abdomen; function is emotion regulation; does NOT indicate suicidal intent but IS a risk factor for future suicide"],
    signs: { left: ["Passive ideation with strong protective factors managed outpatient", "Safety plan developed and means restriction implemented", "Underlying psychiatric condition being treated effectively", "Social support engaged and crisis resources identified"], right: ["Active suicidal ideation with specific plan, intent, and access to means", "Recent suicide attempt requiring medical treatment", "Command hallucinations directing self-harm", "Severe agitation with inability to contract for safety", "Sudden personality change suggesting decision to attempt", "Post-discharge period (first 1-4 weeks) with inadequate follow-up"] },
    medications: [{ name: "Lithium (anti-suicidal properties)", type: "Mood stabilizer with specific anti-suicidal effect", action: "Beyond mood stabilization, lithium has independent anti-suicidal properties: reduces impulsivity and aggression through serotonin enhancement; the ONLY medication with Level 1 evidence for suicide prevention across diagnoses", sideEffects: "Narrow therapeutic index (0.6-1.2 mEq/L), nephrotoxicity, thyroid suppression, tremor, polyuria/polydipsia (diabetes insipidus), teratogenic (Ebstein anomaly), lithium toxicity (above 1.5: tremor, GI; above 2.0: seizures, coma)", contra: "Severe renal impairment, dehydration/sodium depletion, first trimester pregnancy (Ebstein anomaly)", pearl: "300-600 mg BID-TID; therapeutic level 0.6-1.2 mEq/L; the ONLY medication proven to reduce suicide risk independent of its mood-stabilizing effect (meta-analyses show 60-80% reduction in suicide and suicide attempts); NP should consider lithium for any patient with significant suicide risk regardless of primary diagnosis; NARROW therapeutic index: monitor levels, renal function, thyroid at baseline and every 6 months; patients CANNOT safely stockpile lithium (lethal in overdose) -- prescribe limited quantities" }, { name: "Ketamine/Esketamine (for acute suicidal ideation)", type: "NMDA receptor antagonist / rapid-acting antidepressant", action: "Rapidly reduces suicidal ideation within hours through NMDA receptor blockade, increased BDNF, and rapid synaptogenesis; provides a bridge while traditional antidepressants take effect", sideEffects: "Dissociation, dizziness, nausea, sedation, hypertension, abuse potential", contra: "Aneurysmal vascular disease, uncontrolled hypertension, intracerebral hemorrhage history", pearl: "Esketamine (Spravato) nasal spray: FDA-approved for treatment-resistant depression and depressive symptoms with acute suicidal ideation; 56-84 mg intranasally in certified healthcare setting; must be observed for 2 hours post-dose; REMS program required; provides RAPID reduction in suicidal ideation (within 4-24 hours) while waiting for SSRI/SNRI to take effect; NP should be aware of this option for acute suicidality in depressed patients" }, { name: "Clozapine (anti-suicidal in schizophrenia)", type: "Atypical antipsychotic with anti-suicidal properties", action: "The ONLY antipsychotic with FDA-approved indication for reducing suicidal behavior in schizophrenia and schizoaffective disorder; mechanism of anti-suicidal effect not fully understood but may involve serotonergic and noradrenergic modulation beyond dopamine blockade", sideEffects: "Agranulocytosis (1-2%), metabolic syndrome, myocarditis, seizures, sialorrhea, constipation/ileus", contra: "Previous clozapine-induced agranulocytosis, concurrent myelosuppressive agents", pearl: "FDA-approved for reducing suicide risk in schizophrenia/schizoaffective disorder; InterSePT trial demonstrated 24% reduction in suicidal behavior compared to olanzapine; this anti-suicidal effect is INDEPENDENT of its antipsychotic effect; for patients with schizophrenia and significant suicide risk, clozapine should be strongly considered even before meeting typical TRS criteria" }],
    pearls: ["Asking about suicide does NOT increase suicide risk: research consistently shows that asking directly about suicidal thoughts REDUCES anxiety and opens a therapeutic conversation; avoiding the topic is MORE dangerous than asking about it", "Previous suicide attempt is the SINGLE STRONGEST predictor of future suicide: 25-30% of people who attempt will attempt again; 10% will eventually die by suicide; every attempt must be taken seriously regardless of perceived lethality", "Means restriction is the MOST effective suicide prevention strategy: removing access to lethal means (firearms, medications, ligature points) saves lives; 90% of people who survive a suicide attempt do NOT go on to die by suicide later, demonstrating that the suicidal crisis is often temporary", "The post-discharge period is the HIGHEST risk time: patients are 200x more likely to die by suicide in the first week after psychiatric discharge compared to the general population; ensure follow-up within 72 hours of discharge, safety plan in place, and means restriction counseled", "SUDDEN CALMNESS in a previously distressed patient may indicate the patient has made a decision to attempt suicide and feels relieved; this is a WARNING SIGN, not improvement; increase monitoring and reassess", "988 is the national suicide and crisis lifeline: patients can call or text 988 for immediate crisis support 24/7"],
    quiz: [{ question: "The STRONGEST predictor of future suicide is:", options: ["Male gender", "Previous suicide attempt", "Substance use disorder", "Family history of depression"], correct: 1, rationale: "Previous suicide attempt is the single strongest predictor of future suicide. 25-30% of attempters will attempt again, and 10% will eventually die by suicide. Every attempt must be taken seriously." }, { question: "A depressed patient who has been expressing suicidal thoughts suddenly appears calm and gives away personal belongings. The practical nurse should:", options: ["Document improvement in mood", "Recognize this as a WARNING SIGN that the patient may have decided to attempt suicide; increase monitoring and reassess immediately", "Discharge the patient since they appear better", "Reduce observation level"], correct: 1, rationale: "Sudden calmness after a period of suicidal distress, combined with giving away possessions, is a classic WARNING SIGN that the patient may have made a decision to attempt suicide. This requires immediate reassessment and increased monitoring." }, { question: "The MOST effective suicide prevention strategy is:", options: ["Medication management alone", "Psychotherapy alone", "Means restriction (removing access to lethal means)", "Hospitalization for all suicidal patients"], correct: 2, rationale: "Means restriction is the most effective suicide prevention strategy. 90% of attempt survivors do not go on to die by suicide, demonstrating the crisis is often temporary. Removing access to firearms, medications, and other lethal means prevents impulsive attempts during acute crises." }]
  },
  "suicide-assessment-rn": {
    title: "Suicide Assessment",
    cellular: { title: "Suicide Risk Assessment", content: "The nurse performs comprehensive suicide risk assessment, implements evidence-based safety planning, manages patients during high-risk periods, and coordinates transitions of care to minimize post-discharge suicide risk. Advanced risk stratification moves beyond simple checklists to clinical formulation: integrating static risk factors (demographics, history, diagnosis) with dynamic risk factors (current symptoms, recent stressors, acute intoxication, access to means) and protective factors to determine the overall level of risk. The Three-Step Theory (Klonsky & May) provides a clinically useful framework: Step 1 (pain + hopelessness = ideation), Step 2 (pain + hopelessness + disconnection = strong ideation), Step 3 (strong ideation + capability = attempt). Capability can be dispositional (pain tolerance, fearlessness) or acquired (through prior self-harm, trauma exposure, combat, medical procedures). The nurse uses this framework to identify intervention targets: reduce pain (treat underlying condition), increase hope (therapeutic alliance, treatment plan), increase connectedness (social support, therapeutic relationship), and reduce capability (means restriction). Safety planning (Stanley-Brown model) is more effective than no-suicide contracts: studies show that safety plans reduce suicide attempts by 45% compared to usual care. The nurse also manages the high-risk transition period: same-day follow-up calls after ED discharge, 72-hour post-discharge contact, warm handoffs to outpatient providers, and caring contacts (brief messages showing concern)." },
    riskFactors: ["Acute risk factors (modifiable, immediate): access to lethal means, acute substance intoxication, acute psychotic symptoms, severe insomnia (independent risk factor), acute agitation, recent discharge from psychiatric hospital, recent interpersonal loss", "Chronic risk factors (less modifiable, background): history of attempts, childhood trauma/ACEs, chronic mental illness, chronic pain, traumatic brain injury, family history of suicide", "Post-discharge risk: 200x increased risk in first week; 100x in first month; risk factors for post-discharge suicide: short hospitalization (less than 72 hours), unplanned discharge, no outpatient follow-up arranged, previous attempts", "Warning signs (imminent risk indicators): threat of self-harm, seeking access to means, putting affairs in order, giving away possessions, saying goodbye, dramatic mood shift (sudden calm), substance use escalation, social withdrawal"],
    diagnostics: ["C-SSRS comprehensive assessment: ideation severity (1-5 scale: wish to be dead, active ideation, ideation with method, ideation with intent, ideation with plan and intent), ideation intensity (frequency, duration, controllability, deterrents, reason for ideation), suicidal behavior classification (actual attempt, interrupted attempt, aborted attempt, preparatory behavior, NSSI)", "Risk formulation (not just checklist): narrative integrating risk factors, protective factors, warning signs, and current clinical state to determine acute risk level (low, moderate, high, imminent)", "Chronic vs acute suicidality differentiation: chronic suicidality (ongoing, baseline level of suicidal thinking, often in BPD or chronic depression -- managed with outpatient safety planning, DBT) vs acute suicidality (sudden increase in ideation/intent/plan representing a CHANGE from baseline -- may require hospitalization)", "Lethal means assessment: specific questions about access to firearms (are there guns in the home?), medication stockpiles, other means; assessment of willingness to restrict means"],
    management: ["Safety planning (Stanley-Brown model): Step 1: personalized warning signs (what does crisis look like for THIS patient?); Step 2: internal coping strategies (what can patient do alone to cope?); Step 3: social contacts for distraction (who can patient call/visit?); Step 4: family/friends who can help (who can patient tell they are in crisis?); Step 5: professional/crisis contacts (988 Lifeline, local crisis team, therapist, ED); Step 6: making the environment safe (specific means restriction plan)", "Caring contacts: brief non-demanding messages (letters, texts, calls) sent to patients after ED visits or hospital discharge expressing concern (I was thinking of you. I hope you're doing well); RCTs show 50% reduction in suicide attempts and 75% reduction in suicide deaths with this simple intervention", "Transition management: same-day follow-up call after ED discharge for suicidal ideation, 72-hour post-discharge contact from inpatient, warm handoff to outpatient provider (scheduled appointment before discharge, introduction by phone), bridging prescriptions (no more than 1-week supply of potentially lethal medications)", "Means safety counseling: collaborative discussion with patient and family about temporarily restricting access to firearms, medications, sharps; provide specific instructions (firearms to trusted friend/family, medications to locked location or dispensed daily, remove cords/ropes); follow-up on implementation"],
    nursingActions: ["Conduct comprehensive C-SSRS assessment: ask about each level of ideation severity, ideation intensity dimensions, and any suicidal behaviors; document in structured format", "Develop personalized safety plan collaboratively: use the Stanley-Brown 6-step model; fill out a physical copy WITH the patient; patient keeps a copy; enter into medical record", "Implement means safety counseling: assess specific lethal means access, collaboratively develop plan to restrict access, involve family when appropriate, follow up to verify implementation", "Manage observation levels based on risk: imminent risk = 1:1 continuous observation; high risk = 15-minute checks with arms-length when awake; moderate risk = 30-minute checks; adjust based on ongoing assessment", "Implement caring contacts protocol: for patients discharged from ED after suicidal crisis, send follow-up messages at day 1, day 3, week 1, week 2, and month 1; brief, warm, non-demanding messages", "Coordinate transition of care: schedule outpatient appointment BEFORE discharge, provide warm handoff (call outpatient provider with patient present), limit medication supply, ensure safety plan is active and accessible", "Document risk assessment and formulation: include risk factors, protective factors, warning signs present, clinical rationale for risk level determination, and interventions implemented"],
    assessmentFindings: ["Risk level determination: LOW (passive ideation, strong protective factors, no plan, no intent, no means access, strong social support) -- outpatient management with safety plan; MODERATE (active ideation, some plan elements, ambivalent intent, some means access) -- consider hospitalization vs enhanced outpatient with means restriction; HIGH (active ideation with plan, intent, and means access, few protective factors) -- hospitalization indicated; IMMINENT (expressed intent with immediate plan and available means, behavioral preparation) -- emergency hospitalization", "Safety plan quality assessment: a good safety plan is SPECIFIC (lists actual names, numbers, places), ACCESSIBLE (patient knows where it is and can access it during crisis), PRACTICED (patient has rehearsed using it), and UPDATED (revised as circumstances change)", "Post-discharge vulnerability assessment: patients without scheduled follow-up, without safety plans, with continued means access, without social support, and with ongoing substance use are at HIGHEST post-discharge risk"],
    signs: { left: ["Suicidal ideation resolved with treatment of underlying condition", "Safety plan developed, means restricted, follow-up arranged", "Caring contacts protocol initiated post-discharge", "Chronic suicidality stable at baseline with outpatient DBT"], right: ["Imminent suicide risk requiring emergency hospitalization", "Suicide attempt requiring medical stabilization and psychiatric transfer", "Post-discharge suicide (system-level failure requiring root cause analysis)", "Patient refusing hospitalization despite imminent risk (involuntary commitment evaluation)", "Chronic suicidality with escalating behaviors despite outpatient treatment", "Means access that cannot be adequately restricted (rural firearms access)"] },
    medications: [{ name: "Esketamine (Spravato) Nasal Spray", type: "NMDA antagonist (rapid-acting for suicidal ideation)", action: "S-enantiomer of ketamine; rapidly blocks NMDA receptors increasing BDNF and synaptogenesis; provides rapid reduction in suicidal ideation within 4-24 hours; FDA-approved for treatment-resistant depression AND for depressive symptoms with acute suicidal ideation", sideEffects: "Dissociation (most common, resolves within 2 hours), sedation, dizziness, nausea, increased BP, headache, abuse potential (Schedule III)", contra: "Aneurysmal vascular disease, intracerebral hemorrhage, uncontrolled hypertension", pearl: "56-84 mg intranasally; must be administered in REMS-certified healthcare setting; patient observed for 2 hours post-dose; given concurrently with oral antidepressant; dosing schedule: twice weekly x 4 weeks, then weekly x 4 weeks, then weekly or biweekly; provides RAPID reduction in suicidal ideation while waiting for oral antidepressant to take effect (4-6 weeks); BP monitoring before and 40 minutes after each dose; patients must not drive on treatment day" }, { name: "Lithium (suicide prevention)", type: "Mood stabilizer with independent anti-suicidal properties", action: "Reduces suicide risk by 60-80% in mood disorders; mechanism involves serotonin enhancement reducing impulsivity and aggression; effective for suicide prevention even in conditions beyond bipolar disorder (unipolar depression, schizophrenia)", sideEffects: "Narrow therapeutic index, renal toxicity, hypothyroidism, tremor, weight gain, teratogenicity", contra: "Severe renal impairment, severe cardiac disease, first trimester pregnancy", pearl: "Anti-suicidal dose: 0.6-1.0 mEq/L; studies suggest anti-suicidal effect may occur at lower levels than mood stabilization (some evidence for benefit at 0.4-0.6 mEq/L); the ONLY psychiatric medication with Level 1 evidence for suicide prevention; NP should consider adding lithium for any patient with significant suicide risk, especially in mood disorders; even trace lithium in drinking water is associated with lower population suicide rates" }, { name: "Clonidine (for acute agitation in suicidal patients)", type: "Alpha-2 adrenergic agonist", action: "Reduces noradrenergic hyperactivation providing calming effect; reduces agitation and insomnia without respiratory depression or disinhibition risks of benzodiazepines", sideEffects: "Hypotension, bradycardia, sedation, dry mouth", contra: "Severe hypotension, advanced heart block", pearl: "0.1-0.2 mg PO BID-TID for agitation and insomnia in acutely suicidal patients; safer than benzodiazepines (no disinhibition, no respiratory depression, no dependence); addresses insomnia (severe insomnia is an independent risk factor for suicide); can be combined with other psychiatric medications; monitor BP" }],
    pearls: ["Safety plans are MORE effective than no-suicide contracts: no-suicide contracts have NO evidence of effectiveness and give false reassurance; safety plans are structured, collaborative, and reduce suicide attempts by 45%", "Caring contacts are the SIMPLEST and most cost-effective suicide prevention intervention: brief non-demanding messages sent after crisis episodes reduce suicide deaths by 75% in RCTs; every RN can implement this", "Insomnia is an INDEPENDENT risk factor for suicide: even after controlling for depression, insomnia increases suicide risk; aggressive insomnia treatment (trazodone, melatonin, CBT-I) should be part of suicide risk management; avoid benzodiazepines (disinhibition risk)", "Means restriction saves lives: 90% of suicide attempt survivors do not go on to die by suicide; 70% of firearm suicide attempts are fatal vs 5% of overdose attempts; temporarily removing firearms from the home during crisis periods is the single most impactful intervention", "Post-discharge is the DANGER ZONE: 200x increased risk in first week; key interventions: follow-up call within 24 hours, appointment within 72 hours, caring contacts, safety plan activation, means restriction verification"],
    quiz: [{ question: "An RN is discharging a patient who presented to the ED with suicidal ideation that has resolved. The MOST important discharge intervention is:", options: ["Providing a prescription for antidepressants", "A no-suicide contract", "A collaborative safety plan (Stanley-Brown model) with means restriction counseling and follow-up within 72 hours", "Telling the patient to call if they feel suicidal again"], correct: 2, rationale: "Safety planning (Stanley-Brown model) with means restriction counseling reduces suicide attempts by 45%. No-suicide contracts have NO evidence of effectiveness. Follow-up within 72 hours addresses the high-risk post-discharge period." }, { question: "Caring contacts (brief messages sent after crisis episodes) have been shown to reduce suicide deaths by:", options: ["10%", "25%", "50%", "75%"], correct: 3, rationale: "Randomized controlled trials show that caring contacts (brief, non-demanding messages expressing concern) reduce suicide deaths by approximately 75%. This is one of the simplest and most cost-effective suicide prevention interventions available." }, { question: "An independent risk factor for suicide that should be aggressively treated is:", options: ["Headache", "Insomnia", "Fatigue", "Appetite changes"], correct: 1, rationale: "Insomnia is an independent risk factor for suicide even after controlling for depression. Aggressive insomnia treatment (trazodone, melatonin, CBT-I -- avoid benzodiazepines) should be part of comprehensive suicide risk management." }]
  },
  "suicide-assessment-np": {
    title: "Suicide Assessment",
    cellular: { title: "Suicide Risk Management", content: "The clinician managing suicidal patients integrates advanced risk assessment with evidence-based prescribing, makes hospitalization vs outpatient decisions, manages medico-legal documentation, and implements system-level suicide prevention. The zero suicide framework is an organizational approach that assumes suicide deaths in healthcare settings are preventable through systematic screening, risk assessment, safety planning, means restriction, and follow-up. Risk formulation requires integrating multiple dimensions: static factors (demographics, history, genetics), dynamic factors (current symptoms, stressors, substance use, means access -- these are MODIFIABLE and should be targeted), and contextual factors (therapeutic alliance, social support, barriers to care). The clinician prescribes with suicide safety in mind: limit quantities of lethal medications, prefer medications with lower overdose lethality (SSRIs over TCAs, buprenorphine over methadone, lithium with close monitoring), and consider rapid-acting interventions for acute suicidality (esketamine, lithium loading). For chronic suicidality (common in BPD), the approach differs: outpatient safety planning with DBT, avoiding reactive hospitalization that may reinforce crisis behavior, while maintaining genuine assessment of acute-on-chronic risk elevation. The clinician documents risk assessment using the clinical formulation model: risk factors, protective factors, clinical rationale for risk level, and justification for treatment plan -- this documentation standard protects the patient and the provider." },
    riskFactors: ["Prescribing safety: TCAs are LETHAL in overdose (2-week supply can be fatal); SSRIs have much wider therapeutic index; lithium has narrow therapeutic index; prescribe limited quantities for suicidal patients", "Black Box Warning: FDA antidepressant warning for increased suicidality in youth under 25 during first 1-2 months; monitor weekly for first month; this warning led to decreased antidepressant prescribing and INCREASED suicide rates in youth -- the benefit of treating depression outweighs the small risk", "Chronic vs acute suicidality: hospitalization for chronic BPD suicidality may reinforce crisis-hospitalization cycle; distinguish genuine acute risk elevation from baseline chronic ideation", "Lethal means and prescribing: avoid prescribing large quantities of any potentially lethal medication to suicidal patients; dispense weekly or use refill restrictions", "Post-attempt medical management: acetaminophen overdose (N-acetylcysteine protocol), TCA overdose (sodium bicarbonate for cardiac toxicity), lithium toxicity (hemodialysis)"],
    diagnostics: ["Clinical risk formulation: structured narrative integrating: (1) identified risk factors (static and dynamic), (2) identified protective factors, (3) current warning signs, (4) acute vs chronic suicidality determination, (5) clinical reasoning for risk level (low/moderate/high/imminent), (6) treatment plan rationale", "Dynamic risk reassessment: repeat C-SSRS at each visit, after medication changes, after stressors, and during transitions of care; risk level should be documented at EVERY encounter for suicidal patients", "Pharmacogenomic considerations: CYP2D6 poor metabolizers may have higher TCA levels (increased toxicity risk); CYP2C19 affects citalopram/escitalopram metabolism", "Means assessment audit: at each visit, specifically ask about access to firearms, medication stockpiles, and other lethal means; document means restriction counseling and follow-up on implementation"],
    management: ["Prescribing for suicide safety: SSRIs over TCAs (wider safety margin in overdose); limit prescription quantities (1-2 week supply for acute risk); avoid co-prescribing multiple sedatives; lithium (proven anti-suicidal but narrow therapeutic index -- close monitoring); consider esketamine for rapid ideation reduction", "Rapid-acting interventions for acute suicidality: esketamine nasal spray (reduction in ideation within hours), lithium loading (if not already on lithium, can load with 600-900 mg to achieve therapeutic levels in 3-5 days), ECT (most effective intervention for acute suicidality with psychotic depression)", "Chronic suicidality management: DBT as primary treatment, safety plan rather than no-suicide contract, avoid escalating hospitalization for every crisis, target underlying conditions (depression, BPD, substance use), lithium for long-term suicide risk reduction", "Post-attempt pharmacotherapy reassessment: review medication contributing factors (was overdose with prescribed medication?), simplify regimen, restrict lethal medications, ensure adequate treatment of underlying condition, consider lithium addition for long-term risk reduction", "System-level suicide prevention: implement universal screening (C-SSRS or ASQ for all patients), training for all clinical staff, means restriction counseling as standard practice, caring contacts protocol, warm handoffs for transitions of care"],
    nursingActions: ["Prescribe with suicide safety as a primary consideration: choose medications with lower overdose lethality, limit quantities, use refill restrictions, involve family in medication management when appropriate", "Implement measurement-based care for suicidal patients: C-SSRS at every visit, PHQ-9, means assessment; document risk formulation at each encounter", "Make hospitalization vs outpatient decisions using risk formulation: consider risk factors, protective factors, warning signs, and contextual factors; document rationale clearly", "Prescribe lithium for long-term suicide prevention in mood disorder patients with significant suicide risk; monitor levels, renal function, thyroid every 6 months", "Consider esketamine for patients with depressive symptoms and acute suicidal ideation: initiate in REMS-certified setting, coordinate with oral antidepressant optimization", "Implement zero suicide framework in your practice: universal screening, risk assessment, safety planning, means restriction counseling, caring contacts, and follow-up protocols"],
    assessmentFindings: ["Hospitalization threshold: active ideation with specific plan AND intent AND access to means AND inadequate protective factors = hospitalization; any uncertainty should err on the side of safety with clear documentation of clinical reasoning", "Outpatient management criteria: passive ideation OR active ideation without plan/intent, adequate protective factors, willing to engage in safety plan, means restriction implemented, outpatient support available, able to contract for crisis plan use", "Medication review for suicide safety: identify all potentially lethal medications in patient's possession; assess quantities; implement restriction strategies (daily dispensing, family-managed medications, medication lock boxes)"],
    signs: { left: ["Suicidal ideation resolved with treatment optimization", "Long-term suicide risk reduced with lithium maintenance", "Esketamine providing rapid ideation reduction as bridge to antidepressant effect", "Zero suicide framework implemented in clinical practice"], right: ["Acute suicidality requiring emergency hospitalization", "Post-attempt medical emergency (acetaminophen overdose, TCA overdose)", "Chronic suicidality with escalating behaviors despite optimized treatment", "Medication overdose with prescribed psychiatric medications", "Treatment-resistant depression with persistent suicidality requiring ECT", "System failure contributing to post-discharge suicide"] },
    medications: [{ name: "Lithium (suicide prevention prescribing)", type: "Mood stabilizer with proven anti-suicidal properties", action: "60-80% reduction in suicide and suicide attempts through serotonin enhancement reducing impulsivity; the ONLY medication with Level 1 evidence for suicide prevention across diagnoses", sideEffects: "Narrow therapeutic index, nephrotoxicity, hypothyroidism, tremor, weight gain, teratogenicity", contra: "Severe renal impairment, severe sodium depletion, first trimester pregnancy", pearl: "Anti-suicidal dose 0.6-1.0 mEq/L; NP should strongly consider lithium augmentation for any patient with significant suicide risk, particularly in mood disorders; even at lower levels (0.4-0.6 mEq/L), some anti-suicidal benefit may be present; monitor BMP, TSH, and lithium level at baseline and every 6 months; PRESCRIBE IN LIMITED QUANTITIES for suicidal patients (2-week supply with refill restrictions); lithium overdose itself can be lethal (hemodialysis for levels above 4.0 with symptoms)" }, { name: "ECT (Electroconvulsive Therapy) for acute suicidality", type: "Neuromodulation (most effective treatment for suicidality with psychotic depression)", action: "Induces controlled generalized seizure under general anesthesia; rapidly reduces suicidal ideation (within 1-2 treatments), psychotic symptoms, and depressive symptoms; mechanism involves BDNF increase, dopamine and serotonin modulation, and hypothalamic-pituitary axis normalization", sideEffects: "Temporary confusion, headache, anterograde amnesia (usually resolves), retrograde amnesia (may persist for events around treatment period), rare: cardiovascular complications from anesthesia", contra: "Pheochromocytoma, raised intracranial pressure, recent cerebrovascular event (relative)", pearl: "Most effective treatment for acute suicidality with psychotic depression: response rate 80-90%; onset of anti-suicidal effect within 1-2 treatments (days, not weeks); typically 6-12 treatments over 2-4 weeks; bilateral electrode placement more effective than unilateral for suicidality; NP should refer for ECT when: (1) acute suicidality with psychotic depression, (2) medication failure with persistent suicidality, (3) catatonia with suicidality, (4) pregnancy with severe depression (safe alternative to medications); maintenance ECT prevents relapse" }, { name: "Trazodone (for insomnia in suicidal patients)", type: "Serotonin antagonist and reuptake inhibitor (SARI)", action: "At low doses (25-100 mg), predominantly blocks 5-HT2A and H1 receptors providing sedation without respiratory depression; addresses insomnia (independent suicide risk factor) safely", sideEffects: "Sedation, orthostatic hypotension, priapism (rare but requires emergency treatment), headache", contra: "Concurrent MAOIs, known hypersensitivity", pearl: "25-100 mg at bedtime for insomnia in suicidal patients; insomnia is an INDEPENDENT risk factor for suicide; trazodone is SAFE in overdose (wide therapeutic index, unlike benzodiazepines which cause respiratory depression or TCAs which cause cardiac toxicity); non-addictive (unlike benzodiazepines); NP should aggressively treat insomnia as part of suicide risk management; much safer than benzodiazepines (no disinhibition, no dependence, no respiratory depression)" }],
    pearls: ["Prescribe with suicide safety in mind: SSRIs are much safer in overdose than TCAs (1-2 week TCA supply can be lethal); limit medication quantities for suicidal patients; involve family in medication management", "The FDA Black Box Warning paradox: the warning about increased suicidality with antidepressants in youth led to decreased prescribing, which INCREASED suicide rates; the clinician should treat depression aggressively while monitoring closely (weekly visits for first month)", "ECT is the MOST effective treatment for acute suicidality: 80-90% response rate with onset within 1-2 treatments; it should be considered earlier in treatment-resistant depression with suicidality rather than as a last resort", "Document risk formulation at EVERY encounter: a narrative integrating risk factors, protective factors, warning signs, clinical reasoning, and treatment rationale protects the patient through systematic assessment and protects the provider through clear documentation", "Zero suicide is an ORGANIZATIONAL commitment: universal screening, staff training, means restriction, safety planning, caring contacts, and follow-up protocols; the clinician should advocate for implementing this framework in their practice setting"],
    quiz: [{ question: "An NP is selecting an antidepressant for a depressed patient with recent suicide attempt by overdose. The SAFEST choice is:", options: ["Amitriptyline (TCA)", "Sertraline (SSRI) -- much wider safety margin in overdose", "Phenelzine (MAOI)", "Clomipramine (TCA)"], correct: 1, rationale: "SSRIs have a much wider therapeutic index than TCAs or MAOIs. A 1-2 week supply of TCAs can be lethal in overdose, while SSRIs rarely cause death even in massive overdose. Prescribe limited quantities and prefer safer medications." }, { question: "ECT for acute suicidality provides clinical improvement within:", options: ["6-8 weeks", "2-3 weeks", "1-2 treatments (days)", "3-6 months"], correct: 2, rationale: "ECT provides rapid reduction in suicidal ideation within 1-2 treatments (days). It is the most effective treatment for acute suicidality, especially with psychotic depression, with 80-90% response rates." }, { question: "The ONLY medication with Level 1 evidence for suicide prevention is:", options: ["Fluoxetine", "Quetiapine", "Lithium", "Valproic acid"], correct: 2, rationale: "Lithium is the only medication with Level 1 evidence (meta-analyses) for reducing suicide and suicide attempts, with a 60-80% reduction across mood disorders. This anti-suicidal effect is independent of its mood-stabilizing properties." }]
  },
  "therapeutic-communication-rpn": {
    title: "Therapeutic Communication",
    cellular: { title: "Principles of Therapeutic Communication in", content: "Therapeutic communication is purposeful, goal-directed professional communication that focuses on the patient's needs and promotes healing, trust, and understanding. Unlike social communication, therapeutic communication has clear boundaries, is patient-centered, and uses specific techniques to facilitate expression of feelings, exploration of problems, and development of coping strategies. The therapeutic relationship (Peplau's theory) progresses through four phases: (1) Pre-interaction (nurse reviews patient information, becomes aware of own biases), (2) Orientation (introductions, establishing trust, defining roles and expectations), (3) Working (active problem-solving, using therapeutic techniques, building insight), (4) Termination (summarizing progress, addressing feelings about ending, planning follow-up). Key therapeutic communication techniques include: active listening (attending fully to verbal and nonverbal communication), open-ended questions (Tell me about your experience), reflection (It sounds like you're feeling frustrated), clarification (What do you mean when you say you can't take it anymore?), silence (allowing processing time), summarizing (reviewing key points), validation (acknowledging feelings as real and important), and focusing (redirecting to relevant topics). Non-therapeutic communication blocks include: giving advice (You should...), changing the subject, false reassurance (Everything will be fine), judgmental responses, asking why (perceived as accusatory), and using cliches." },
    riskFactors: ["Communication barriers: language differences, hearing/visual impairment, cognitive impairment, cultural differences, pain, medication effects, emotional distress, health literacy limitations", "Non-therapeutic patterns: giving unsolicited advice, providing false reassurance, using medical jargon, asking closed-ended questions exclusively, changing the subject when patients express distressing emotions, using why questions (perceived as accusatory)", "Boundary violations: excessive self-disclosure, social relationships with patients, accepting gifts, providing personal contact information, engaging in romantic/sexual relationships (professional misconduct)", "Power imbalance: patients are vulnerable; the nurse has authority over medications, daily schedule, documentation, and discharge recommendations; awareness of this power differential is essential for ethical therapeutic communication"],
    diagnostics: ["Communication assessment: evaluate patient's ability to communicate (language, cognition, hearing, vision, literacy, cultural considerations) and adapt approach accordingly", "Therapeutic relationship phase assessment: identify current phase (orientation, working, termination) and use phase-appropriate interventions", "Communication effectiveness evaluation: is the patient able to express feelings? Is the therapeutic alliance strong? Is the patient engaged in care? Are communication barriers being addressed?"],
    management: ["Therapeutic techniques: active listening, open-ended questions, reflection, validation, silence, clarification, summarizing, focusing, exploring, restating, offering self", "Non-therapeutic responses to AVOID: giving advice, false reassurance, judgmental responses, changing the subject, using cliches, asking why, belittling feelings, challenging, defending, disagreeing", "Special communication situations: motivational interviewing for ambivalent patients, trauma-informed communication for trauma survivors, de-escalation for agitated patients, validation for patients with dementia, therapeutic use of self for patients with personality disorders"],
    nursingActions: ["Use open-ended questions to encourage expression: Tell me more about what you're experiencing instead of Are you feeling OK?", "Practice active listening: maintain eye contact (culturally appropriate), lean slightly forward, use minimal encouragers (mmm-hmm, go on, I see), avoid interrupting, focus fully on the patient", "Use reflection to demonstrate understanding: So you're saying that when your family visits, you feel more anxious rather than comforted?", "Validate emotions without judgment: It makes sense that you would feel angry given what you've been through", "Use therapeutic silence: after a patient makes an emotional statement, pause for 5-10 seconds; silence communicates respect and allows the patient to process and continue", "Avoid non-therapeutic responses: do NOT say Everything will be fine (false reassurance), You shouldn't feel that way (belittling), Why did you do that? (accusatory), I know exactly how you feel (cliche), or You should... (giving advice)", "Maintain professional boundaries: appropriate self-disclosure (brief, purposeful, refocused back to patient), no social media connections, no personal contact information, no gifts (discuss policy)"],
    assessmentFindings: ["Effective therapeutic communication indicators: patient shares feelings openly, therapeutic alliance is strong, patient engaged in treatment planning, patient reports feeling heard and understood", "Ineffective communication indicators: patient is withdrawn, guarded, hostile, or disengaged; nurse feels frustrated, helpless, or confused; therapeutic goals not being addressed; patient complaints about feeling unheard", "Cultural communication considerations: eye contact (avoided in some cultures as sign of respect), personal space (varies culturally), touch (may be inappropriate in some cultures), family involvement (some cultures expect family-centered communication), gender-concordant care (important in some cultures)"],
    signs: { left: ["Patient expresses feelings openly and trusts the therapeutic relationship", "Communication barriers identified and addressed", "Cultural considerations integrated into communication approach", "Therapeutic goals being met through effective communication"], right: ["Communication breakdown with patient becoming withdrawn or hostile", "Boundary violation (social relationship, inappropriate self-disclosure, romantic interest)", "Language barrier preventing essential health communication without interpreter", "Cognitive impairment preventing meaningful communication (delirium, severe dementia)", "Cultural misunderstanding leading to patient distress or treatment refusal", "Nurse countertransference interfering with therapeutic communication"] },
    medications: [{ name: "Communication is NOT a medication topic", type: "Therapeutic technique", action: "Therapeutic communication is a nursing skill, not a pharmacological intervention; however, medications that affect communication should be assessed", sideEffects: "N/A", contra: "N/A", pearl: "Medications affecting communication: sedatives (may impair verbal expression), anticholinergics (confusion), opioids (sedation, cognitive dulling), antipsychotics (sedation, cognitive effects); assess medication effects on patient's ability to communicate and time therapeutic conversations when patient is most alert; interpreter services should be used for non-English speaking patients rather than family members (family may filter or alter information)" }, { name: "Interpreter Services", type: "Communication resource", action: "Professional medical interpreters provide accurate, unbiased translation of medical information; legally required under Title VI for patients with limited English proficiency", sideEffects: "Time required for interpreted conversations (plan for longer sessions)", contra: "Using family members as interpreters (potential for bias, omission, role confusion, HIPAA concerns)", pearl: "Federal law requires healthcare facilities to provide interpreter services for patients with limited English proficiency; NEVER use family members (especially children) as interpreters for medical conversations -- they may omit information, add personal opinions, or be emotionally unable to translate difficult medical information; telephone interpreters are available 24/7 in most facilities for over 200 languages; schedule extra time for interpreted sessions (approximately 2x the usual time)" }, { name: "Augmentative and Alternative Communication (AAC)", type: "Communication assistive technology", action: "Provides alternative means of communication for patients who cannot communicate verbally: picture boards, alphabet boards, electronic speech-generating devices, eye-tracking systems", sideEffects: "Requires time and patience; may not capture emotional nuance", contra: "Severe cognitive impairment may limit AAC use", pearl: "AAC should be available for patients who are intubated, post-stroke with aphasia, or have other conditions preventing verbal communication; simple picture boards and Yes/No communication systems should be standard on ICU and medical-surgical units; occupational therapy and speech-language pathology can recommend appropriate AAC for individual patients; frustration is common -- validate the patient's experience and allow adequate time" }],
    pearls: ["The MOST powerful therapeutic communication technique is active listening: fully attending to the patient without distraction, judgment, or planning your response while they speak", "Silence is therapeutic: after a patient makes an emotional statement, resist the urge to fill the silence; pausing 5-10 seconds communicates respect and often leads to deeper disclosure", "Never use Why questions: Why did you stop taking your medication? sounds accusatory; instead ask What made it difficult to continue your medication? or Tell me about your experience with the medication", "False reassurance is NON-therapeutic: Everything will be fine dismisses the patient's legitimate concerns and destroys trust; instead: I can see you're worried. Let's talk about what's concerning you", "Therapeutic self-disclosure is BRIEF, purposeful, and immediately refocused on the patient: I had a similar experience helps normalize; extensive personal stories shift focus to the nurse and cross professional boundaries", "Validate before redirect: when a patient expresses difficult emotions, validate first (That must be very frustrating), THEN redirect to problem-solving; jumping to solutions without validation makes patients feel unheard"],
    quiz: [{ question: "A patient says: I don't think this treatment is going to work. I feel hopeless. The MOST therapeutic response is:", options: ["Don't worry, everything will be fine!", "It sounds like you're feeling discouraged about your treatment. Tell me more about what's making you feel this way.", "You shouldn't feel that way -- the treatment works for most people.", "Let me talk to the doctor about changing your medication."], correct: 1, rationale: "This response uses reflection (acknowledging the feeling), validation (normalizing the emotion), and an open-ended question (inviting further expression). The other responses use false reassurance, belittling, or premature problem-solving." }, { question: "Which question type is MOST therapeutic?", options: ["Do you feel better today? (closed-ended)", "Why aren't you eating? (why question)", "Tell me about your appetite and how meals have been going for you. (open-ended)", "You ate lunch, right? (leading question)"], correct: 2, rationale: "Open-ended questions encourage patients to share their experience in their own words. Closed-ended questions limit responses to yes/no. 'Why' questions feel accusatory. Leading questions suggest the expected answer." }, { question: "Therapeutic silence means:", options: ["Ignoring the patient", "Pausing after an emotional statement to allow processing, demonstrating respect and encouraging deeper disclosure", "Being unable to think of a response", "Punishing the patient by withholding conversation"], correct: 1, rationale: "Therapeutic silence after an emotional statement communicates respect, allows the patient to process their feelings, and often leads to deeper disclosure. It requires intentional restraint from filling the silence." }]
  },
  "therapeutic-communication-rn": {
    title: "Therapeutic Communication",
    cellular: { title: "Communication Strategies for Complex Clinical", content: "The nurse uses advanced therapeutic communication techniques for complex clinical situations: delivering bad news, managing conflict, conducting motivational interviews, navigating cultural communication differences, and maintaining therapeutic relationships with challenging patient populations. Breaking bad news uses the SPIKES protocol: Setting (private, comfortable environment, sit down, make eye contact), Perception (assess what the patient already knows), Invitation (ask how much information the patient wants), Knowledge (share information in clear, simple language, avoid medical jargon), Empathy (respond to emotional reactions with empathy before providing more information), and Strategy/Summary (discuss next steps and plan). Motivational interviewing (MI) is a collaborative communication style for addressing ambivalence about behavior change: express empathy through reflective listening, develop discrepancy between current behavior and personal values/goals, roll with resistance (do not argue or confront), and support self-efficacy. MI uses OARS: Open questions, Affirmations, Reflections, and Summaries. Change talk (patient statements favoring change: desire, ability, reason, need, commitment) should be reinforced; sustain talk (statements against change) should be explored without confrontation. The nurse also navigates difficult conversations about advance directives, goals of care, treatment refusal, and end-of-life decisions, requiring sensitivity to cultural, religious, and personal values." },
    riskFactors: ["Difficult conversation triggers: delivering bad news (diagnosis, prognosis), discussing goals of care, addressing treatment non-adherence, managing family conflict, discussing advance directives, addressing inappropriate behavior", "Cultural communication missteps: imposing Western communication norms (direct eye contact, individual autonomy, emotional expression) on patients from collectivist or high-context cultures", "Motivational interviewing barriers: the righting reflex (nurse's urge to fix the problem by giving advice), arguing with resistant patients, moving to action before the patient is ready for change", "Provider communication burnout: compassion fatigue can impair empathetic communication; nurses who are burned out may become task-focused and lose therapeutic presence"],
    diagnostics: ["Communication skills assessment: self-reflection on communication patterns, peer observation, patient feedback surveys (HCAHPS communication items), video-recorded role plays", "Motivational interviewing fidelity: assess use of OARS techniques, reflection-to-question ratio (should be above 1:1), proportion of complex vs simple reflections, appropriate response to change talk and sustain talk", "Cultural communication assessment: identify patient's preferred communication style, decision-making preferences (individual vs family-centered), information preferences (direct vs indirect), and spiritual/religious considerations affecting health communication", "HCAHPS communication metrics: patient-reported experience measures including Did nurses listen carefully? Did nurses explain things in a way you could understand? These scores reflect communication quality and affect hospital reimbursement"],
    management: ["SPIKES protocol for bad news: systematic approach ensuring patient-centered disclosure with emotional support", "Motivational interviewing for behavior change: ambivalent patients (substance use, medication adherence, lifestyle modification); use OARS, recognize and reinforce change talk", "NURSE mnemonic for empathic responses: Name the emotion, Understand the emotion, Respect the patient, Support the patient, Explore the emotion further", "Ask-Tell-Ask for patient education: Ask what the patient already knows, Tell the information using plain language, Ask if they understood and what questions they have", "Teach-Back method: have the patient repeat information in their own words to verify understanding"],
    nursingActions: ["Deliver bad news using SPIKES: arrange private setting, assess patient's understanding first, share information clearly, respond to emotions with empathy, discuss plan", "Implement motivational interviewing for ambivalent patients: use open questions, affirm strengths, reflect ambivalence, summarize; avoid arguing, advising, or confronting", "Conduct goals of care conversations: explore what the patient values most (quality vs quantity of life, independence, pain control, being at home), what they understand about their condition, and what their hopes and fears are; document in care plan", "Use NURSE mnemonic when patients express strong emotions: I can see this is really upsetting (Name). Most people in your situation would feel the same way (Understand). I admire how you've been handling this (Respect). I'm here to support you (Support). Can you tell me more about what worries you most? (Explore)", "Implement teach-back for all patient education: after explaining medication, procedures, or discharge instructions, ask the patient to explain it back in their own words; if unable, re-teach using different approach", "Navigate cultural communication differences: use professional interpreters, ask about communication preferences, involve family according to patient's wishes, respect religious/spiritual beliefs in care discussions"],
    assessmentFindings: ["Readiness for change (stages of change model): precontemplation (nurse uses MI to build awareness), contemplation (nurse explores ambivalence), preparation (nurse helps identify specific steps), action (nurse supports implementation), maintenance (nurse reinforces change and addresses relapse)", "Health literacy assessment: 36% of US adults have limited health literacy; use plain language, visual aids, teach-back, and limit information to 3-4 key points per session", "Family dynamics assessment: identify family spokesperson, decision-maker, and dynamics that may facilitate or impede communication; address family conflict privately rather than at bedside"],
    signs: { left: ["Patient understanding verified through teach-back", "Motivational interviewing facilitating behavior change", "SPIKES protocol used effectively for difficult conversations", "Cultural communication barriers addressed with interpreter and cultural sensitivity"], right: ["Communication breakdown with patient refusing all interaction", "Family conflict interfering with patient care decisions", "Health literacy barrier leading to medication errors or non-adherence", "Compassion fatigue impairing nurse's therapeutic communication ability", "Cultural misunderstanding leading to treatment refusal or patient harm", "Patient complaint about communication quality"] },
    medications: [{ name: "Communication in Medication Education", type: "Patient education technique", action: "Effective medication education requires therapeutic communication: plain language, teach-back verification, addressing concerns and barriers, cultural sensitivity, and health literacy awareness", sideEffects: "Poor communication leads to medication non-adherence (50% of patients do not take medications as prescribed)", contra: "Using medical jargon, information overload, not addressing patient concerns, not verifying understanding", pearl: "The Three-Question Approach for medication education: (1) What is this medication for? (patient should be able to state the purpose in their own words), (2) How and when do you take it? (patient demonstrates correct technique and timing), (3) What side effects should you watch for? (patient identifies key side effects and what to do if they occur); if patient cannot answer all three, re-teach; medication non-adherence is 50% -- communication is the MOST important factor in adherence" }, { name: "Teach-Back Method", type: "Communication verification technique", action: "After providing health information, ask the patient to explain it back in their own words; this verifies understanding and identifies gaps; improves outcomes across all health literacy levels", sideEffects: "May add time to encounters (offset by reduced errors and readmissions)", contra: "None -- universally recommended", pearl: "Phrases that work: I want to make sure I explained this clearly. Can you tell me in your own words how you'll take this medication? Or To make sure we're on the same page, what will you tell your family about your care plan?; if patient cannot teach back, the problem is the TEACHING not the learner -- simplify, use visual aids, demonstrate, and try again; studies show teach-back reduces 30-day readmissions by 12%" }, { name: "SBAR Communication (Nurse-to-Provider)", type: "Structured communication framework", action: "Standardized format for clinical communication between nurses and providers: Situation (what is happening now), Background (relevant clinical context), Assessment (what I think is happening), Recommendation (what I think we should do); reduces communication errors and improves patient safety", sideEffects: "Requires practice to implement consistently; may feel rigid initially", contra: "None", pearl: "SBAR example: Situation: I'm calling about Mrs. Jones in room 312 who has developed new-onset confusion and a temperature of 101.8F. Background: She is 78 years old, admitted for hip fracture repair 2 days ago, has a Foley catheter and IV. Assessment: I'm concerned she may be developing a UTI or post-operative delirium. Recommendation: I'd like to obtain a urinalysis, CBC, and BMP, and have you evaluate her. SBAR reduces critical communication errors by 30% and is now standard practice in most healthcare settings" }],
    pearls: ["The SPIKES protocol for bad news: never deliver bad news standing up, in a hallway, or without emotional preparation; sit down, make eye contact, and ASSESS what the patient already knows before adding information", "Motivational interviewing rule: NEVER argue with a resistant patient; rolling with resistance (exploring rather than opposing) is more effective than confrontation for facilitating change", "The righting reflex is the biggest MI mistake: the nurse's natural urge to fix the problem leads to giving unsolicited advice, which triggers patient resistance; instead, ask permission (Would it be OK if I shared some information?) and explore ambivalence", "Teach-back is the SINGLE most important patient education technique: I want to make sure I explained this clearly. Can you tell me in your own words? catches misunderstandings before they cause harm", "SBAR reduces communication errors by 30%: structured communication between nurses and providers prevents omission of critical information and improves patient outcomes", "HCAHPS communication scores directly affect hospital reimbursement: Did nurses listen carefully? and Did nurses explain things clearly? are financially incentivized quality metrics"],
    quiz: [{ question: "An RN needs to inform a patient that their biopsy results show cancer. Using the SPIKES protocol, the FIRST step after ensuring a private setting is:", options: ["Telling the patient the diagnosis directly", "Assessing the patient's perception of their condition (what do they already know?)", "Discussing treatment options", "Calling the family to be present"], correct: 1, rationale: "The 'P' in SPIKES stands for Perception -- assessing what the patient already knows or suspects. This helps the nurse gauge the patient's baseline understanding and emotional readiness before providing the diagnosis." }, { question: "A patient with diabetes says: I know I should check my blood sugar, but I just can't seem to do it consistently. The BEST motivational interviewing response is:", options: ["You need to check your blood sugar every day or you'll have complications", "It sounds like you want to manage your diabetes well, but something is making it hard to check consistently. Tell me more about what gets in the way.", "Why aren't you checking your blood sugar?", "I'll show you how to use your glucometer again"], correct: 1, rationale: "This response uses reflection (acknowledging the desire to manage diabetes), affirmation (recognizing the patient's intention), and an open-ended question (exploring barriers). It avoids the 'righting reflex' of telling the patient what to do." }, { question: "After teaching a patient about new medications, the BEST way to verify understanding is:", options: ["Asking 'Do you understand?' (closed-ended)", "Using teach-back: 'I want to make sure I explained clearly. Can you tell me how you'll take these medications at home?'", "Giving the patient a written handout", "Having the patient's family explain it"], correct: 1, rationale: "Teach-back asks the patient to explain information in their own words, verifying actual understanding rather than assumed understanding. 'Do you understand?' typically gets a 'yes' even when the patient does not understand." }]
  },
  "therapeutic-communication-np": {
    title: "Therapeutic Communication",
    cellular: { title: "advanced Communication Leadership", content: "The clinician integrates advanced therapeutic communication into prescriptive practice, informed consent, shared decision-making, interprofessional communication, and system-level communication quality improvement. Shared decision-making (SDM) is the gold standard for treatment decisions: the clinician shares evidence-based information about treatment options (benefits, risks, alternatives, outcomes), the patient shares their values, preferences, and goals, and together they make a treatment decision. SDM is ethically required (patient autonomy), clinically effective (improved adherence and outcomes), and legally protective (informed consent). The clinician conducts informed consent conversations that go beyond legalistic disclosure to true patient understanding: assess decisional capacity (ability to understand, appreciate, reason, and communicate), present information in accessible language, discuss alternatives including no treatment, explore the patient's values and how they apply to the decision, verify understanding through teach-back, and document the process. Health literacy-informed communication: 36% of US adults have limited health literacy, affecting understanding of medical information, medication labels, consent forms, and self-management instructions. The clinician uses plain language (below 6th-grade reading level), visual aids, limited information per session (chunk and check), teach-back verification, and health literacy screening (Newest Vital Sign or REALM). The clinician also leads interprofessional communication: SBAR for clinical handoffs, TeamSTEPPS for team communication, CUS (Concerned, Uncomfortable, Safety issue) for escalating safety concerns, and closed-loop communication for critical orders." },
    riskFactors: ["Informed consent failures: patient did not understand the information, cultural/language barriers not addressed, decisional capacity not assessed, alternatives not discussed, coercion (real or perceived)", "Health literacy gaps: 36% of US adults have limited health literacy; contributes to medication errors, non-adherence, increased ED visits and hospitalizations, and poorer health outcomes", "Interprofessional communication failures: contribute to 70% of sentinel events according to The Joint Commission; handoff errors, unclear orders, failure to escalate concerns", "Shared decision-making barriers: time pressure, provider preference overriding patient values, perceived patient inability to participate, cultural expectations of paternalistic care"],
    diagnostics: ["Decisional capacity assessment: four criteria -- (1) Understanding (can the patient state the information provided?), (2) Appreciation (can they apply it to their own situation?), (3) Reasoning (can they compare options and explain rationale?), (4) Communication (can they consistently state a choice?)", "Health literacy screening: Newest Vital Sign (NVS -- 6-question nutrition label test), REALM (Rapid Estimate of Adult Literacy in Medicine -- word recognition test), or simply ask: How confident are you filling out medical forms? (single-item literacy screener)", "Communication quality metrics: HCAHPS scores, patient complaints, teach-back completion rates, informed consent documentation quality, patient satisfaction surveys"],
    management: ["Shared decision-making framework: present options with evidence-based probabilities, explore patient values and preferences, make a collaborative decision, document the shared decision process", "Health literacy universal precautions: assume ALL patients may have limited health literacy; use plain language, visual aids, teach-back, limited information per session regardless of perceived literacy level", "Informed consent best practices: conversational rather than legalistic, teach-back for comprehension, cultural/language accommodation, capacity assessment when indicated, documentation of the discussion not just the signature", "Interprofessional communication excellence: SBAR for all clinical communications, closed-loop for critical orders, CUS for safety escalation, structured handoffs at shift change and transitions of care"],
    nursingActions: ["Implement shared decision-making for all treatment decisions: present evidence, explore patient values, make collaborative decisions, document the process", "Conduct informed consent as a therapeutic conversation: assess capacity, use plain language, discuss alternatives, explore values, verify understanding with teach-back, document the discussion", "Implement health literacy universal precautions: plain language below 6th-grade reading level, visual aids, chunk and check (small amounts of information with comprehension checks), teach-back verification", "Lead interprofessional communication improvement: implement SBAR standardization, conduct TeamSTEPPS training, establish CUS safety escalation culture, standardize handoff processes", "Model communication excellence: demonstrate advanced therapeutic techniques in clinical encounters, mentor staff in communication skills, address communication breakdowns through coaching rather than punishment", "Develop patient education materials: ensure readability below 6th-grade level, use visual aids, culturally appropriate content, available in relevant languages, reviewed by health literacy experts"],
    assessmentFindings: ["Shared decision-making quality: patient can articulate the decision rationale, the decision aligns with patient values, patient feels heard and respected in the process, documentation reflects collaborative discussion", "Health literacy impact: patient able to demonstrate medication self-management (teach-back), able to navigate healthcare system, able to recognize when to seek care; limited health literacy = higher risk for adverse events", "Interprofessional communication effectiveness: clear role delineation, standardized handoff processes, psychological safety for raising concerns, closed-loop verification for critical communications"],
    signs: { left: ["Shared decision-making producing patient-centered treatment plans", "Health literacy strategies improving patient understanding and adherence", "SBAR standardized across clinical settings reducing communication errors", "Informed consent process verifying genuine patient understanding"], right: ["Informed consent obtained without true patient understanding", "Health literacy barrier causing medication error or adverse event", "Communication failure contributing to sentinel event", "Patient decisional incapacity requiring surrogate decision-maker identification", "Cultural communication barrier leading to treatment refusal or mistrust", "Interprofessional conflict from communication breakdown"] },
    medications: [{ name: "Shared Decision-Making in Prescribing", type: "Communication framework for prescriptive practice", action: "NP shares evidence about medication options (benefits, risks, alternatives, costs, lifestyle impact); patient shares preferences, values, and concerns; together they select the best option", sideEffects: "Requires more time than directive prescribing (offset by improved adherence and outcomes)", contra: "Emergency situations requiring immediate intervention; patients without decisional capacity (use surrogate)", pearl: "SDM in prescribing example: I want to discuss two options for your depression. Sertraline is an SSRI that works well for most people -- benefits include X, risks include Y. Bupropion works through a different mechanism -- benefits include A, risks include B. What matters most to you in choosing a medication? (weight, sexual function, energy, cost?); studies show SDM improves medication adherence by 20-40% and patient satisfaction; the clinician who uses SDM has fewer non-adherence problems and better therapeutic relationships" }, { name: "Plain Language Prescribing Communication", type: "Health literacy strategy", action: "Converting medical prescribing language into plain language that patients can understand and follow", sideEffects: "None (universally beneficial)", contra: "None", pearl: "Instead of: Take metformin 500 mg BID with meals for glycemic control; Say: Take one metformin pill twice a day -- once with breakfast and once with dinner. This helps keep your blood sugar at a healthy level; Instead of: You may experience GI side effects; Say: This medication may upset your stomach at first. Taking it with food helps. If you have diarrhea or nausea that doesn't get better after a week, call us; Using plain language reduces medication errors by 25% and improves adherence across all literacy levels" }, { name: "Motivational Interviewing for Medication Adherence", type: "Communication technique for behavior change", action: "Using MI techniques to explore and resolve ambivalence about medication-taking behavior without confrontation or coercion", sideEffects: "Requires training and practice; initial encounters may take longer", contra: "Emergency situations; patients actively in crisis", pearl: "MI for non-adherence: instead of: You need to take your medication every day or your condition will get worse (confrontation); Say: On one hand, taking the medication every day is difficult and has some side effects you don't like. On the other hand, you've noticed that when you do take it consistently, your symptoms improve and you feel better. Where does this leave you? (developing discrepancy); MI for medication adherence has been shown in meta-analyses to improve adherence by 20-30% across chronic conditions" }],
    pearls: ["Shared decision-making is NOT just asking patients what they want: it is a structured process of evidence-sharing, values exploration, and collaborative decision-making; the clinician brings clinical expertise, the patient brings personal expertise about their own life", "Health literacy universal precautions: treat EVERY patient as potentially having limited health literacy; using plain language and teach-back with all patients is more effective than trying to identify who has limited literacy", "Informed consent is a CONVERSATION, not a form: the signature on a consent form has limited legal value without documentation of the discussion, comprehension assessment, and opportunity for questions", "Communication failures cause 70% of sentinel events: SBAR, closed-loop communication, and CUS are not optional -- they are patient safety tools that prevent death", "The single most impactful thing an NP can do for patient safety is USE TEACH-BACK for every clinical encounter: medication education, discharge instructions, procedure preparation, and self-management teaching"],
    quiz: [{ question: "The four criteria for decisional capacity are:", options: ["Age, education, language, and mental status", "Understanding, Appreciation, Reasoning, and Communication", "Alertness, orientation, memory, and judgment", "Diagnosis, prognosis, treatment, and alternatives"], correct: 1, rationale: "Decisional capacity requires four abilities: Understanding (stating the information), Appreciation (applying it to one's own situation), Reasoning (comparing options with rationale), and Communication (consistently stating a choice)." }, { question: "Health literacy universal precautions means:", options: ["Only screening patients who appear to have low literacy", "Using plain language and teach-back with ALL patients, not just those identified as having limited literacy", "Providing written materials in large font", "Only speaking slowly to elderly patients"], correct: 1, rationale: "Universal precautions means treating every patient as potentially having limited health literacy. Using plain language, visual aids, and teach-back with all patients is more effective and less stigmatizing than selective screening." }, { question: "Shared decision-making improves medication adherence by:", options: ["5%", "10%", "20-40%", "80%"], correct: 2, rationale: "Studies show shared decision-making improves medication adherence by 20-40% compared to directive prescribing. Patients who participate in choosing their treatment are more likely to follow through with it." }]
  },
  "delirium-vs-dementia-rpn": {
    title: "Delirium vs Dementia",
    cellular: { title: "Pathophysiology of Delirium and Dementia", content: "Delirium and dementia are the two most important cognitive disorders in clinical nursing. DELIRIUM is an acute, reversible disturbance in attention and awareness with fluctuating course, caused by an underlying medical condition. It is a MEDICAL EMERGENCY because it signifies an acute physiological derangement. The pathophysiology involves widespread cortical dysfunction from cholinergic deficiency (explaining why anticholinergic medications are a major cause), dopaminergic excess, neuroinflammation (cytokines cross the blood-brain barrier during systemic illness), oxidative stress, and disruption of the sleep-wake cycle. DEMENTIA (now termed Major Neurocognitive Disorder in DSM-5) is a chronic, progressive, generally irreversible decline in cognitive function affecting memory, language, executive function, and daily functioning. Alzheimer disease (AD, 60-70% of dementia) involves amyloid-beta plaque accumulation outside neurons and tau protein neurofibrillary tangle formation inside neurons, leading to synaptic loss and neuronal death, particularly in the hippocampus (memory) and temporal/parietal cortices. Vascular dementia (15-20%) results from cerebrovascular disease (strokes, chronic small vessel disease). Lewy body dementia involves alpha-synuclein protein deposits causing cognitive fluctuation, visual hallucinations, and parkinsonism. Frontotemporal dementia affects personality and language before memory. The critical nursing distinction: delirium is ACUTE and REVERSIBLE (treat the cause); dementia is CHRONIC and PROGRESSIVE (manage symptoms and support function)." },
    riskFactors: ["DELIRIUM risk factors: age above 65 (strongest risk), pre-existing dementia (dementia is the #1 risk factor for delirium), hospitalization (especially ICU), surgery (post-operative delirium occurs in 15-53%), infection (UTI most common precipitant in elderly), medications (anticholinergics, benzodiazepines, opioids, steroids), dehydration, electrolyte imbalance, pain, urinary retention, constipation, sensory deprivation (missing glasses/hearing aids), sleep deprivation, physical restraints", "DEMENTIA risk factors: age (strongest), family history, Down syndrome (virtually 100% develop AD pathology by age 40), cardiovascular risk factors (hypertension, diabetes, hyperlipidemia -- especially for vascular dementia), head trauma (CTE), low education/cognitive reserve, social isolation, depression, hearing loss"],
    diagnostics: ["DELIRIUM assessment: Confusion Assessment Method (CAM): 4 features -- (1) acute onset and fluctuating course (REQUIRED), (2) inattention (REQUIRED), (3) disorganized thinking, (4) altered level of consciousness; features 1+2 plus either 3 or 4 = positive for delirium", "DELIRIUM workup: identify the CAUSE -- CBC, BMP, urinalysis/culture (UTI), chest X-ray (pneumonia), blood cultures, medication review (anticholinergics, benzodiazepines), glucose, TSH, B12, ammonia (hepatic encephalopathy), CT head (if focal neuro signs or fall), ECG", "DEMENTIA assessment: MMSE (Mini-Mental State Exam, score 0-30, below 24 suggests cognitive impairment), MoCA (Montreal Cognitive Assessment, more sensitive, below 26 abnormal), clock drawing test", "DEMENTIA workup: reversible causes must be excluded -- TSH (hypothyroidism), B12 (deficiency), RPR/VDRL (neurosyphilis), metabolic panel, CT/MRI brain (structural causes, vascular disease)", "Key differentiators: delirium = acute onset (hours-days), fluctuating course, impaired ATTENTION, often reversible; dementia = gradual onset (months-years), progressive course, impaired MEMORY, generally irreversible"],
    management: ["DELIRIUM: TREAT THE UNDERLYING CAUSE (this is the treatment; there is no medication that treats delirium itself); infection = antibiotics, medications = discontinue offenders, dehydration = fluids, pain = treat pain, urinary retention = catheterize, constipation = bowel regimen, hypoxia = oxygen, electrolytes = correct", "DELIRIUM non-pharmacological management (FIRST-LINE): reorientation (clock, calendar, familiar objects), ensure glasses and hearing aids, maintain sleep-wake cycle (lights on during day, dark/quiet at night), mobilize early, avoid restraints (worsen delirium), familiar faces, minimize room changes", "DELIRIUM pharmacological management: haloperidol 0.5-1 mg PO/IM for severe agitation (low-dose, short-term only); AVOID benzodiazepines (worsen delirium EXCEPT in alcohol/benzodiazepine withdrawal where benzodiazepines are required)", "DEMENTIA: cholinesterase inhibitors (donepezil, rivastigmine, galantamine) for mild-moderate AD; memantine for moderate-severe AD; no disease-modifying treatment widely available yet", "DEMENTIA behavioral management: non-pharmacological FIRST (redirection, routine, environmental modification, music therapy, validation therapy); antipsychotics ONLY for severe agitation/psychosis with risk assessment (BLACK BOX warning for increased mortality in elderly with dementia)"],
    nursingActions: ["Perform CAM (Confusion Assessment Method) screening for ALL hospitalized elderly patients: acute onset + inattention + (disorganized thinking OR altered LOC) = delirium until proven otherwise", "Implement delirium prevention bundle (HELP program): orientation aids (clock, calendar, whiteboard with date/staff names), ensure glasses and hearing aids are in place, early mobilization, maintain sleep-wake cycle, hydration/nutrition, avoid unnecessary catheters and restraints, minimize medication burden (especially anticholinergics and benzodiazepines)", "Monitor for delirium subtypes: hyperactive (agitation, restlessness, hallucinations -- more easily recognized), hypoactive (lethargy, withdrawal, decreased responsiveness -- MOST COMMON but often missed), mixed (alternating between hyper- and hypoactive)", "For dementia patients: use simple, direct communication (one-step instructions), maintain consistent routine, provide orientation cues, redirect rather than confront, validate emotions, ensure safety (fall prevention, wandering prevention, medication management)", "Assess for delirium superimposed on dementia: patients with dementia are at HIGHEST risk for delirium; any ACUTE change in baseline cognitive function in a dementia patient should be evaluated for delirium", "Implement fall prevention: both delirium and dementia significantly increase fall risk; bed alarm, non-skid footwear, clear pathway, adequate lighting, supervised ambulation"],
    assessmentFindings: ["DELIRIUM: acute onset (hours to days), fluctuating course (worse at night -- sundowning), INATTENTION (cannot count backward, cannot spell WORLD backward, easily distracted), disoriented, altered LOC (hyper- or hypoactive), hallucinations (often visual), sleep-wake cycle disruption, often has identifiable precipitant", "DEMENTIA: gradual onset (months to years), progressive course (no fluctuation until late stages), MEMORY IMPAIRMENT (short-term first, then long-term), language difficulties (word-finding), executive dysfunction (planning, organizing), personality changes, orientation impaired (time first, then place, then person), level of consciousness PRESERVED until late stages", "DELIRIUM vs DEMENTIA comparison: Onset (acute vs gradual), Course (fluctuating vs progressive), Duration (days-weeks vs months-years), Attention (impaired vs preserved until late), Consciousness (altered vs clear until late), Hallucinations (common, visual vs less common except Lewy body), Reversibility (usually reversible vs generally irreversible)"],
    signs: { left: ["Delirium identified early with treatable cause found and corrected", "Delirium prevention measures in place for high-risk patients", "Dementia patient maintaining function with supportive care and routine", "Behavioral symptoms managed with non-pharmacological approaches"], right: ["Unrecognized hypoactive delirium (lethargy mistaken for depression or normal aging)", "Delirium superimposed on dementia (acute change in baseline)", "Severe agitation in delirium requiring pharmacological management", "Dementia with severe behavioral symptoms (aggression, psychosis) requiring antipsychotic risk-benefit discussion", "Wandering and elopement risk in dementia", "Caregiver burnout and elder abuse risk"] },
    medications: [{ name: "Donepezil (Aricept)", type: "Cholinesterase inhibitor (for Alzheimer dementia)", action: "Inhibits acetylcholinesterase enzyme, increasing acetylcholine levels in the synaptic cleft; compensates for cholinergic neuron loss in Alzheimer disease; does NOT alter disease progression but improves symptoms temporarily", sideEffects: "GI (nausea, diarrhea, vomiting -- cholinergic effects), bradycardia, vivid dreams/insomnia (take in morning if problematic), muscle cramps, weight loss", contra: "Known hypersensitivity; caution in sick sinus syndrome, heart block, active peptic ulcer", pearl: "5 mg at bedtime x 4-6 weeks, then 10 mg at bedtime; for mild-moderate Alzheimer disease; provides modest cognitive improvement (delays decline by approximately 6-12 months but does NOT stop progression); GI side effects are CHOLINERGIC (nausea, diarrhea, cramps) and are the most common reason for discontinuation; if patient deteriorates despite treatment, consider adding memantine; when dementia reaches severe stage and medication provides no observable benefit, discuss discontinuation with family (not evidence-based indefinitely)" }, { name: "Memantine (Namenda)", type: "NMDA receptor antagonist (for moderate-severe AD)", action: "Blocks excessive glutamate stimulation at NMDA receptors; glutamate excitotoxicity contributes to neuronal death in AD; regulates glutamate activity without blocking normal learning/memory signaling", sideEffects: "Dizziness, headache, confusion, constipation; generally well-tolerated", contra: "Known hypersensitivity; caution in severe renal impairment (renally cleared)", pearl: "5 mg daily, increase by 5 mg weekly to 10 mg BID (or 28 mg XR daily); for MODERATE to SEVERE Alzheimer disease (different from cholinesterase inhibitors which are for mild-moderate); can be COMBINED with donepezil (different mechanisms -- cholinergic + glutamatergic); combination provides additional modest benefit; better tolerated than cholinesterase inhibitors (fewer GI side effects); dose adjustment needed for renal impairment (CrCl below 30: max 5 mg BID)" }, { name: "Haloperidol (low-dose for delirium agitation)", type: "Typical antipsychotic", action: "D2 receptor blockade reducing agitation, hallucinations, and psychomotor hyperactivity in delirium; does NOT treat delirium itself -- only manages symptoms while underlying cause is treated", sideEffects: "EPS (dystonia, akathisia, parkinsonism), QTc prolongation, sedation", contra: "Parkinson disease/Lewy body dementia (WORSENS parkinsonism and can cause severe neuroleptic sensitivity), QTc prolongation, severe cardiac disease", pearl: "0.5-1 mg PO or IM every 4-6 hours PRN for severe agitation ONLY; LOW doses for SHORT duration; this does NOT treat delirium -- identifying and treating the underlying cause is the treatment; AVOID in Parkinson disease and Lewy body dementia (severe neuroleptic sensitivity -- can cause life-threatening rigidity, obtundation, and autonomic instability); AVOID benzodiazepines for delirium (worsen confusion EXCEPT for alcohol/benzodiazepine withdrawal where they are the treatment); non-pharmacological measures should always be tried first" }],
    pearls: ["Delirium is a MEDICAL EMERGENCY: any acute change in mental status requires immediate workup for underlying cause; the most common causes are infection (UTI #1 in elderly), medications (anticholinergics, benzodiazepines), dehydration, pain, and urinary retention", "Hypoactive delirium is the MOST COMMON and MOST MISSED type: the quiet, withdrawn, lethargic patient is more likely to have delirium than the agitated patient, but is often overlooked because they are not disruptive", "NEVER use benzodiazepines to treat delirium (except alcohol/benzodiazepine withdrawal): benzodiazepines WORSEN delirium by further impairing cholinergic function and consciousness; this is one of the most common harmful prescribing errors in hospitalized elderly", "Pre-existing dementia is the #1 risk factor for developing delirium: any ACUTE change in a dementia patient's baseline cognition should trigger a delirium workup, not be dismissed as just their dementia", "The anticholinergic burden: many common medications have anticholinergic effects (diphenhydramine, oxybutynin, hydroxyzine, TCAs, first-gen antipsychotics) and are major delirium precipitants in elderly; review and discontinue unnecessary anticholinergics", "Delirium prevention is MORE effective than delirium treatment: the HELP (Hospital Elder Life Program) bundle reduces delirium incidence by 30-40% through simple interventions (orientation, glasses/hearing aids, sleep hygiene, early mobilization, hydration)"],
    quiz: [{ question: "The KEY feature that distinguishes delirium from dementia is:", options: ["Memory impairment", "Acute onset with fluctuating course and impaired attention", "Personality changes", "Language difficulties"], correct: 1, rationale: "Delirium is characterized by ACUTE onset (hours-days), fluctuating course (especially worsening at night), and impaired ATTENTION. Dementia has gradual onset (months-years), progressive course, and primarily impaired MEMORY with preserved attention until late stages." }, { question: "An 82-year-old with mild Alzheimer disease is admitted for hip surgery. On post-op day 2, she becomes acutely confused, agitated, and cannot focus attention. The practical nurse should:", options: ["Administer lorazepam for anxiety", "Recognize this as delirium superimposed on dementia; assess for underlying cause (infection, pain, medications, urinary retention)", "Assume her dementia is worsening", "Increase her donepezil dose"], correct: 1, rationale: "Acute change in baseline cognition in a dementia patient = delirium until proven otherwise. Dementia is the #1 risk factor for delirium. The nurse should assess for treatable causes (UTI, pain, medications, dehydration). NEVER give benzodiazepines for delirium." }, { question: "Which medication should be AVOIDED in delirium management?", options: ["Low-dose haloperidol", "Acetaminophen for pain", "Lorazepam (benzodiazepine)", "Antibiotics for infection"], correct: 2, rationale: "Benzodiazepines WORSEN delirium (except in alcohol/benzodiazepine withdrawal). They further impair consciousness and cholinergic function. This is one of the most common prescribing errors in hospitalized elderly." }]
  },
  "delirium-vs-dementia-rn": {
    title: "Delirium vs Dementia",
    cellular: { title: "Delirium Prevention, Assessment", content: "The nurse manages delirium through prevention protocols, early detection, cause identification, and evidence-based intervention, while simultaneously managing chronic dementia care needs. The ABCDEF ICU bundle incorporates delirium prevention: A (Assess, prevent, manage pain), B (Both spontaneous awakening and breathing trials), C (Choice of sedation -- target light sedation, avoid benzodiazepines), D (Delirium assessment and management using CAM-ICU), E (Early mobility and exercise), F (Family engagement and empowerment). Delirium pathophysiology involves multiple converging mechanisms: (1) Cholinergic deficiency (anticholinergic medications, acute illness reducing ACh synthesis), (2) Dopaminergic excess (explaining antipsychotic efficacy for symptoms), (3) Neuroinflammation (systemic inflammation from infection/surgery triggers microglial activation, cytokine production, and BBB disruption), (4) Oxidative stress (ischemia, metabolic derangement), (5) Circadian rhythm disruption (ICU environment, medication timing, sleep deprivation). Delirium has significant prognostic implications: associated with 2-3x increased mortality, longer hospital stay, higher risk of falls, higher rate of post-discharge institutionalization, and ACCELERATED cognitive decline (delirium may cause permanent brain injury -- not always fully reversible as previously thought). For dementia, the nurse implements person-centered care (Kitwood model): recognizing the person behind the disease, maintaining dignity, supporting remaining abilities, and creating a therapeutic environment." },
    riskFactors: ["Delirium predisposing factors (baseline vulnerability): advanced age, cognitive impairment/dementia (#1), functional impairment, sensory impairment, comorbid conditions, malnutrition, dehydration", "Delirium precipitating factors (acute triggers): medications (anticholinergics, benzodiazepines, opioids, steroids, fluoroquinolones), infection, surgery/anesthesia, pain, urinary retention, constipation, sleep deprivation, physical restraints, environment change, dehydration, metabolic abnormalities", "ICU delirium: affects 60-80% of mechanically ventilated patients; independent predictor of 6-month mortality; benzodiazepine sedation is a modifiable risk factor (prefer dexmedetomidine or propofol)", "Delirium as cognitive accelerant: emerging evidence that delirium episodes PERMANENTLY accelerate cognitive decline, even in patients without pre-existing dementia; delirium prevention is therefore cognitive protection", "Dementia behavioral symptom triggers: pain (most common UNRECOGNIZED trigger for agitation in dementia), infection, constipation, environmental overstimulation, unfamiliar caregivers, unmet needs (hunger, toileting, boredom)"],
    diagnostics: ["CAM (Confusion Assessment Method) for general wards: Feature 1 (acute onset/fluctuating) AND Feature 2 (inattention) AND either Feature 3 (disorganized thinking) OR Feature 4 (altered LOC); sensitivity 94-100%, specificity 90-95%", "CAM-ICU for mechanically ventilated patients: modified version using RASS (Richmond Agitation Sedation Scale) for LOC assessment and visual attention tests", "4AT (rapid delirium screening): 4-item tool (alertness, AMT4 orientation, attention/months backward, acute change/fluctuating course); score 4+ suggests delirium; faster than CAM for screening", "Delirium cause investigation protocol: mnemonic DELIRIUM -- Drugs (medication review), Electrolytes (BMP), Lack of drugs (missed home medications, withdrawal), Infection (UA, CBC, CXR, blood cultures), Reduced sensory input (glasses, hearing aids), Intracranial (stroke, seizure, SDH), Urinary/GI (retention, constipation), Myocardial/pulmonary (MI, PE, hypoxia)", "Dementia staging: GDS (Global Deterioration Scale) or FAST (Functional Assessment Staging Test); guides expectations, treatment decisions, and advance care planning discussions"],
    management: ["Delirium prevention (evidence-based bundles): HELP program reduces delirium incidence by 30-40%; multicomponent interventions: orientation protocol, therapeutic activities, sleep protocol (no vitals between 10PM-6AM, minimize noise/light), early mobilization, vision/hearing optimization, hydration protocol, medication review (reduce/eliminate anticholinergics and benzodiazepines)", "ICU delirium management: ABCDEF bundle, minimize benzodiazepine sedation (use dexmedetomidine or propofol instead), daily sedation vacation, early mobilization, family presence, maintain day-night cycle, minimize unnecessary noise/alarms", "Dementia behavioral symptom management: DICE approach -- Describe the behavior objectively, Investigate possible causes (pain, infection, unmet need, environmental), Create a plan (non-pharmacological first: music therapy, validation, redirection, aromatherapy, structured activities, caregiver education), Evaluate the outcome", "Antipsychotic use in dementia agitation: ONLY for severe agitation/psychosis posing danger to self or others; BLACK BOX WARNING: 1.6-1.7x increased mortality in elderly with dementia; use lowest dose for shortest duration; obtain informed consent from surrogate decision-maker", "Advance care planning in dementia: discuss goals of care early (while patient has capacity); establish healthcare proxy; address feeding tube decisions (tube feeding does NOT improve outcomes in advanced dementia), hospitalization preferences, comfort-focused care"],
    nursingActions: ["Screen ALL hospitalized patients above 65 with CAM or 4AT at least every shift; implement delirium prevention bundle for all high-risk patients", "Implement HELP program components: orientation board updated daily, therapeutic activities (reading, conversation, games), sleep protocol (cluster care, minimize nighttime disruption, offer warm milk/tea, dim lights by 9PM), early mobilization (chair for meals, ambulate TID), glasses/hearing aids at bedside, fluid intake tracking", "For ICU patients: implement ABCDEF bundle, use CAM-ICU every shift, target RASS 0 to -1 (light sedation), advocate for dexmedetomidine over benzodiazepine sedation, facilitate early mobilization even with lines/tubes, allow family visitation", "Investigate delirium causes systematically: use DELIRIUM mnemonic; most common causes in hospitalized elderly: UTI, medications (anticholinergics, benzodiazepines added during admission), dehydration, pain, constipation, urinary retention", "Implement person-centered dementia care: learn the patient's history, preferences, and routine; use validation (acknowledge emotions rather than correcting facts); never argue about reality with a dementia patient; redirect gently; provide meaningful activities; involve family in care planning", "Manage sundowning: increase afternoon activity, provide bright light exposure during the day, reduce stimulation in the evening, ensure adequate nutrition, address pain, maintain consistent evening routine; melatonin may help regulate circadian rhythm"],
    assessmentFindings: ["Delirium subtypes with nursing implications: HYPERACTIVE (10-15%: agitation, restlessness, pulling at lines, hallucinations -- recognized more quickly but can cause patient harm); HYPOACTIVE (70%: lethargy, decreased responsiveness, withdrawal -- MORE COMMON but often MISSED, associated with worse outcomes); MIXED (20%: alternating between hyper- and hypoactive)", "CAM scoring: Feature 1 (acute change -- ask family Is this different from baseline?) + Feature 2 (inattention -- can the patient count backward from 20 to 1? Spell WORLD backward?) + Feature 3 (disorganized thinking -- Is a hammer heavier than a leaf? Do stones float on water?) OR Feature 4 (altered LOC -- anything other than alert and oriented)", "Dementia BPSD (Behavioral and Psychological Symptoms of Dementia): agitation (60-70% of dementia patients), depression (40%), apathy (70%), psychosis (30%), wandering (40%), sleep disturbance (25%); these cause more caregiver burden than cognitive symptoms", "Pain assessment in dementia: patients cannot self-report reliably; use behavioral scales (PAINAD: breathing, vocalization, facial expression, body language, consolability); unrecognized pain is the #1 cause of agitation in dementia"],
    signs: { left: ["Delirium prevented through proactive bundle implementation", "Delirium identified early with cause found and treated", "ICU delirium minimized through ABCDEF bundle", "Dementia patient calm with person-centered care and behavioral management"], right: ["Missed hypoactive delirium leading to prolonged hospitalization and poor outcomes", "Delirium superimposed on dementia with unclear baseline", "ICU delirium associated with prolonged ventilation and increased mortality", "Severe dementia agitation requiring antipsychotic with black box risk", "Wandering/elopement event in dementia patient", "Advanced dementia with goals-of-care conflict among family members"] },
    medications: [{ name: "Dexmedetomidine (Precedex) for ICU delirium prevention", type: "Alpha-2 adrenergic agonist", action: "Selective alpha-2 agonism producing sedation without respiratory depression; preserves natural sleep architecture; reduces delirium incidence compared to benzodiazepine sedation in ICU", sideEffects: "Bradycardia, hypotension, dry mouth", contra: "Advanced heart block, severe hemodynamic instability", pearl: "0.2-0.7 mcg/kg/hr infusion; PREFERRED sedation in ICU over benzodiazepines because it reduces delirium incidence by 50%; produces cooperative sedation (patient is arousable) without respiratory depression; preserves natural sleep cycles (unlike benzodiazepines which suppress REM and slow-wave sleep); RN should advocate for dexmedetomidine-based sedation protocols in ICU to reduce delirium" }, { name: "Quetiapine (low-dose for dementia-related psychosis)", type: "Atypical antipsychotic", action: "At low doses (12.5-50 mg), D2 and 5-HT2A antagonism with strong H1 blockade providing sedation; used for severe dementia-related psychosis or agitation when non-pharmacological measures have failed", sideEffects: "Sedation, orthostatic hypotension, falls (major concern in elderly), metabolic effects, QTc prolongation", contra: "BLACK BOX: 1.6-1.7x increased mortality in elderly with dementia (cerebrovascular events and infections); Lewy body dementia (extreme neuroleptic sensitivity)", pearl: "12.5-50 mg at bedtime; USE ONLY as LAST RESORT for severe agitation/psychosis in dementia when non-pharmacological measures have failed AND the behavior poses danger to the patient or others; LOWEST dose for SHORTEST duration; obtain informed consent from surrogate; monitor for falls, sedation, metabolic effects; reassess need within 1-2 weeks; consider trial off medication after behavioral stabilization; NEVER use in Lewy body dementia (severe neuroleptic sensitivity causing rigidity, obtundation, death)" }, { name: "Melatonin (for delirium prevention and sundowning)", type: "Hormone (circadian rhythm regulator)", action: "Exogenous melatonin helps restore disrupted circadian rhythm in hospitalized patients and dementia patients; promotes natural sleep without the delirium-worsening effects of benzodiazepines or sedative-hypnotics", sideEffects: "Minimal: headache, daytime drowsiness, dizziness", contra: "Autoimmune disorders (theoretical immune stimulation)", pearl: "1-5 mg at 8-9PM (2 hours before desired sleep); evidence for delirium PREVENTION in hospitalized elderly (multiple RCTs); also useful for sundowning in dementia (restoring disrupted melatonin secretion); does NOT worsen delirium (unlike benzodiazepines and sedative-hypnotics); SAFE in elderly; RN should incorporate melatonin into delirium prevention protocols and sundowning management; prefer over sedative-hypnotics for hospitalized elderly" }],
    pearls: ["Hypoactive delirium is the MOST COMMON type but the LEAST recognized: the quiet, withdrawn patient in bed 3 who has not been responding normally is MORE likely delirious than the agitated patient pulling at IV lines; screen systematically with CAM, do not rely on behavioral recognition alone", "Benzodiazepine sedation in ICU CAUSES delirium: switching from midazolam to dexmedetomidine reduces ICU delirium by 50%; RN should advocate for benzodiazepine-sparing sedation protocols", "Delirium may cause PERMANENT cognitive damage: previously thought to be fully reversible, emerging evidence shows that delirium episodes accelerate cognitive decline and may cause persistent deficits; delirium PREVENTION is therefore cognitive PROTECTION", "Pain is the #1 MISSED cause of agitation in dementia: non-verbal dementia patients cannot report pain; behavioral changes (agitation, moaning, guarding, grimacing) should trigger pain assessment using PAINAD scale before assuming behavioral/psychiatric cause", "Antipsychotics in dementia carry a BLACK BOX warning: 1.6-1.7x increased mortality (primarily from cerebrovascular events and infections); use ONLY after non-pharmacological interventions fail, lowest dose, shortest duration, with informed consent from surrogate", "Restraints CAUSE delirium: physical restraints are a known delirium PRECIPITANT and should be avoided; the agitation caused by restraints often exceeds the agitation they are intended to control; use alternatives (sitter, family, environmental modification)"],
    quiz: [{ question: "An ICU RN advocates for changing a patient's sedation from midazolam to dexmedetomidine. The PRIMARY rationale is:", options: ["Dexmedetomidine is cheaper", "Dexmedetomidine reduces ICU delirium incidence by approximately 50% compared to benzodiazepine sedation", "Dexmedetomidine provides deeper sedation", "Midazolam is not available"], correct: 1, rationale: "Benzodiazepine sedation (midazolam, lorazepam) is a modifiable risk factor for ICU delirium. Switching to dexmedetomidine reduces delirium by approximately 50%, shortens ventilator time, and preserves natural sleep architecture." }, { question: "A nursing home resident with moderate Alzheimer disease becomes acutely agitated and combative over 24 hours. Before requesting an antipsychotic, the nurse should:", options: ["Administer haloperidol 5 mg IM immediately", "Assess for underlying causes: pain (PAINAD scale), UTI, constipation, medication changes, environmental changes", "Apply physical restraints for safety", "Increase the donepezil dose"], correct: 1, rationale: "Acute behavioral change in dementia = assess for underlying cause first. Pain (using PAINAD), UTI, constipation, and medication changes are the most common treatable precipitants. Antipsychotics carry a black box warning and should be used only after identifying/treating underlying causes and trying non-pharmacological interventions." }, { question: "Physical restraints in hospitalized elderly patients:", options: ["Prevent delirium by keeping patients safe", "Are a known PRECIPITANT of delirium and should be avoided", "Have no effect on delirium risk", "Are recommended for all confused patients"], correct: 1, rationale: "Physical restraints are a known delirium PRECIPITANT. They increase agitation, disorientation, and injury risk. Alternatives (sitters, family presence, environmental modification, treating underlying causes) should be used instead." }]
  },
  "delirium-vs-dementia-np": {
    title: "Delirium vs Dementia",
    cellular: { title: "advanced Delirium Management", content: "The clinician managing delirium and dementia makes complex diagnostic and prescriptive decisions: differentiating delirium from dementia (and identifying delirium superimposed on dementia), prescribing targeted pharmacotherapy, managing behavioral symptoms with attention to safety, implementing prevention protocols, and guiding goals-of-care conversations. Advanced delirium management: the clinician orders and interprets the diagnostic workup, identifies and treats the precipitating cause, minimizes medication-related delirium risk (anticholinergic burden assessment using tools like the Anticholinergic Cognitive Burden scale), and prescribes symptom management judiciously. For dementia, the clinician prescribes cholinesterase inhibitors and memantine, manages behavioral symptoms using the DICE approach, navigates the complex antipsychotic risk-benefit discussion (black box warning), initiates advance care planning, and manages end-of-life decisions specific to dementia (feeding tube futility, comfort-focused care, hospice referral). Emerging dementia therapeutics: anti-amyloid monoclonal antibodies (lecanemab, donanemab) represent the first disease-modifying treatments for early Alzheimer disease, targeting and clearing amyloid-beta plaques. Lecanemab (Leqembi) received FDA approval in 2023 for early AD with confirmed amyloid pathology; it slows cognitive decline by 27% over 18 months but carries risks of ARIA (amyloid-related imaging abnormalities: brain edema and microhemorrhages, occurring in 12-21% of patients). The clinician must evaluate eligibility (early AD only, confirmed amyloid, APOE4 genotyping for ARIA risk), obtain informed consent, and coordinate MRI monitoring." },
    riskFactors: ["Anticholinergic burden: cumulative effect of multiple medications with anticholinergic properties; use Anticholinergic Cognitive Burden (ACB) scale or Beers Criteria to identify and reduce burden; total ACB score above 3 significantly increases delirium and cognitive decline risk", "Medication-related delirium precipitants: anticholinergics (diphenhydramine, oxybutynin, TCAs, first-gen antipsychotics), benzodiazepines, opioids (especially meperidine), corticosteroids, fluoroquinolones, H2 blockers (famotidine, ranitidine)", "ARIA risk with anti-amyloid therapy: APOE4 homozygotes have 35% ARIA-E risk with lecanemab (vs 12% in heterozygotes and 5% in non-carriers); anticoagulation increases ARIA-H risk; MRI monitoring required", "Antipsychotic use in dementia: 1.6-1.7x increased mortality; cerebrovascular events, infections, falls, metabolic effects; Lewy body dementia has extreme neuroleptic sensitivity (contraindicated)"],
    diagnostics: ["Delirium vs dementia vs DSD diagnostic algorithm: (1) Is this acute? (yes = possible delirium, proceed to CAM); (2) Is there baseline cognitive impairment? (yes = possible DSD, still need to identify delirium precipitant); (3) Is attention specifically impaired? (yes favors delirium; preserved attention favors dementia); (4) Is consciousness fluctuating? (yes = delirium); (5) Is there an identifiable precipitant? (yes = delirium)", "Anticholinergic burden assessment: review ALL medications (including OTC and supplements) using ACB scale; score each medication 0-3; total score above 3 = significant risk; systematically reduce/substitute anticholinergic medications", "Dementia subtype diagnosis: Alzheimer (gradual memory loss, temporal-parietal atrophy on MRI, amyloid/tau biomarkers); Vascular (stepwise decline, stroke history, white matter disease on MRI); Lewy body (fluctuating cognition, visual hallucinations, parkinsonism, REM sleep behavior disorder, neuroleptic sensitivity); Frontotemporal (personality/behavior changes before memory loss, frontal-temporal atrophy)", "Anti-amyloid therapy eligibility: early AD (MCI or mild dementia), confirmed amyloid pathology (amyloid PET or CSF biomarkers), APOE genotyping for ARIA risk stratification, baseline MRI, normal coagulation"],
    management: ["Delirium treatment priority: IDENTIFY AND TREAT THE CAUSE; medication review (discontinue/reduce anticholinergics, benzodiazepines, unnecessary opioids), infection treatment, rehydration, pain management, electrolyte correction, urinary retention management", "Delirium symptom management: low-dose haloperidol 0.5-1 mg for severe agitation (avoid in LBD, Parkinson disease); quetiapine 12.5-25 mg alternative; melatonin for sleep-wake cycle restoration; avoid benzodiazepines (worsen delirium except in withdrawal states)", "Dementia pharmacotherapy: mild-moderate AD = donepezil 5-10 mg, rivastigmine 3-12 mg, or galantamine 8-24 mg; moderate-severe AD = add memantine 10 mg BID or 28 mg XR; combination donepezil + memantine provides modest additional benefit", "Anti-amyloid therapy (lecanemab): for early AD with confirmed amyloid pathology; 10 mg/kg IV every 2 weeks; MRI before and at weeks 14, 52, then as indicated for ARIA monitoring; APOE4 homozygotes at highest risk for ARIA-E (35%); requires comprehensive informed consent", "Dementia behavioral management: DICE approach (Describe, Investigate, Create, Evaluate); non-pharmacological first (music, validation, redirection, structured activities, caregiver education); antipsychotic only for severe agitation/psychosis with informed consent; citalopram 10-30 mg for agitation (CitAD trial showed benefit, but QTc monitoring required above 20 mg in elderly); dextromethorphan-quinidine (Nuedexta) for pseudobulbar affect in dementia", "End-of-life dementia care: hospice eligibility (FAST stage 7C: non-ambulatory, minimal speech, assistance with ADLs, recurrent infections), comfort-focused care, discuss tube feeding futility (AMDA, AGS, Choosing Wisely recommend AGAINST in advanced dementia -- does not prevent aspiration, does not improve outcomes)"],
    nursingActions: ["Conduct comprehensive anticholinergic burden assessment: use ACB scale on ALL medications; systematically deprescribe high-burden anticholinergics; substitute safer alternatives (cetirizine for diphenhydramine, mirabegron for oxybutynin)", "Prescribe cholinesterase inhibitors with appropriate titration and monitoring: donepezil 5 mg x 4-6 weeks then 10 mg (monitor for bradycardia, GI effects); when switching between ChEIs, washout period may not be necessary if switching for tolerability", "Initiate memantine for moderate-severe AD: combine with existing ChEI; titrate from 5 mg to target 10 mg BID over 4 weeks; dose-adjust for renal impairment (max 5 mg BID for CrCl below 30)", "Evaluate anti-amyloid therapy candidacy: confirm early AD stage, obtain amyloid PET or CSF biomarkers, APOE4 genotyping, baseline MRI; comprehensive informed consent including ARIA risks; coordinate MRI monitoring schedule", "Navigate antipsychotic prescribing for dementia agitation: document failed non-pharmacological interventions, obtain informed consent from surrogate (including black box warning discussion), prescribe lowest effective dose, set review date (2-4 weeks), attempt dose reduction/discontinuation after behavioral stabilization", "Lead goals-of-care conversations: initiate advance care planning early in dementia course while patient has capacity; discuss tube feeding futility in advanced dementia with family; refer to hospice when eligible; support surrogate decision-makers"],
    assessmentFindings: ["Delirium duration and recovery: most delirium resolves within 1-2 weeks with treatment of underlying cause; persistent delirium (beyond 2-4 weeks) may indicate unidentified precipitant, delirium superimposed on previously undiagnosed dementia, or irreversible brain injury", "Anti-amyloid therapy monitoring: ARIA-E (edema: headache, confusion, visual disturbance -- usually in first 14 weeks) vs ARIA-H (microhemorrhages: usually asymptomatic, detected on MRI); treatment may continue through mild ARIA but must be held for moderate-severe ARIA until resolved", "Dementia medication benefit assessment: cholinesterase inhibitors provide 1-3 point MMSE improvement (modest but meaningful); benefit is SYMPTOMATIC (delays decline but does not alter disease course); reassess benefit periodically; consider discontinuation in advanced dementia when no observable benefit", "Advanced dementia care decisions: tube feeding does NOT prevent aspiration pneumonia in advanced dementia (aspiration of oral secretions continues regardless); careful hand-feeding provides equal or better outcomes with greater comfort and dignity"],
    signs: { left: ["Delirium resolved with identification and treatment of underlying cause", "Anticholinergic burden reduced through medication optimization", "Dementia patient stable on optimized ChEI + memantine with behavioral management", "Goals of care established with advance directives completed"], right: ["Persistent delirium despite treatment of identified causes", "ARIA requiring treatment hold during anti-amyloid therapy", "Severe dementia agitation requiring antipsychotic with black box risk", "Advanced dementia with family disagreement about tube feeding and goals of care", "Delirium superimposed on undiagnosed dementia", "Elder abuse/neglect detected in dementia patient"] },
    medications: [{ name: "Lecanemab (Leqembi)", type: "Anti-amyloid monoclonal antibody (disease-modifying for early AD)", action: "Binds to soluble amyloid-beta protofibrils and facilitates their clearance; reduces amyloid plaque burden in the brain; the first therapy to demonstrate slowing of cognitive decline in Alzheimer disease (27% slowing over 18 months in the CLARITY AD trial)", sideEffects: "ARIA-E (amyloid-related imaging abnormalities -- edema: 12-21%, usually asymptomatic, detected on MRI; can cause headache, confusion, dizziness, visual disturbance), ARIA-H (microhemorrhages: 17%), infusion reactions (20%), headache", contra: "Not indicated for moderate-severe AD (only early AD -- MCI or mild dementia); anticoagulation (increased ARIA-H risk); significant ARIA on MRI requiring treatment hold", pearl: "10 mg/kg IV every 2 weeks; FDA-approved January 2023 for early Alzheimer disease with CONFIRMED amyloid pathology (PET or CSF biomarkers); slows cognitive decline by 27% over 18 months (modest but first-ever disease modification); APOE4 genotyping required (homozygotes have 35% ARIA-E risk vs 5% in non-carriers); MRI monitoring at baseline, before 5th/7th/14th infusions, then as indicated; this is NOT a cure -- it slows progression modestly; very expensive; NP must have in-depth informed consent discussion about realistic benefits, ARIA risks, monitoring burden, and cost" }, { name: "Rivastigmine Patch (Exelon Patch)", type: "Cholinesterase inhibitor (transdermal)", action: "Dual inhibition of acetylcholinesterase and butyrylcholinesterase; transdermal delivery provides steady-state plasma levels reducing GI side effects compared to oral formulation", sideEffects: "Application site reactions, nausea (less than oral), vomiting, diarrhea, weight loss, dizziness", contra: "Known hypersensitivity to rivastigmine or carbamate derivatives", pearl: "Start 4.6 mg/24hr patch, increase to 9.5 mg/24hr after 4 weeks, then 13.3 mg/24hr if tolerated; transdermal delivery significantly reduces GI side effects compared to oral rivastigmine; the ONLY ChEI available as a patch; ideal for patients who cannot swallow pills (advanced dementia) or have significant GI side effects from oral ChEIs; also FDA-approved for Parkinson disease dementia (the ONLY ChEI with this indication); apply to clean, dry, hairless skin on upper back/chest, rotate sites daily, only ONE patch at a time" }, { name: "Citalopram (for dementia-related agitation)", type: "SSRI (off-label for dementia agitation)", action: "Serotonin reuptake inhibition may reduce agitation and irritability in Alzheimer disease through modulation of serotonergic deficits associated with behavioral symptoms", sideEffects: "QTc prolongation (dose-dependent, significant concern in elderly), hyponatremia, falls, GI disturbance", contra: "QTc above 500 ms, concurrent QTc-prolonging drugs", pearl: "10-30 mg daily; the CitAD trial showed significant reduction in agitation in AD at 30 mg, BUT: QTc prolongation and cognitive worsening were noted at 30 mg in elderly; FDA recommends maximum 20 mg in patients above 60; NP must balance agitation reduction against QTc risk and cognitive effects; obtain baseline ECG; some experts recommend 10-20 mg as safer dose range in elderly; this provides a non-antipsychotic option for dementia agitation (no black box mortality warning)" }],
    pearls: ["Anti-amyloid therapy is the first DISEASE-MODIFYING treatment for Alzheimer disease: lecanemab slows cognitive decline by 27% but is NOT a cure, is very expensive, requires IV infusion every 2 weeks, MRI monitoring, and APOE genotyping; NP must provide realistic expectations", "Anticholinergic deprescribing is the single most impactful pharmacological intervention for delirium prevention: review every patient's medication list for anticholinergic burden using the ACB scale; substitute safer alternatives (cetirizine for diphenhydramine, mirabegron for oxybutynin, SSRI for TCA)", "Tube feeding in advanced dementia does NOT improve outcomes: multiple studies and every major medical society (AMDA, AGS, Choosing Wisely) recommend AGAINST feeding tubes in advanced dementia; careful hand-feeding provides equivalent nutrition with greater comfort and dignity; NP should lead these difficult family conversations", "Lewy body dementia and antipsychotics: patients with LBD have EXTREME neuroleptic sensitivity and can develop life-threatening rigidity, obtundation, and autonomic collapse with even low-dose typical antipsychotics; if an antipsychotic is absolutely necessary, quetiapine at the lowest dose is the safest option; HALOPERIDOL is CONTRAINDICATED", "Citalopram for dementia agitation is a useful non-antipsychotic option: the CitAD trial showed benefit at 30 mg but with QTc concerns; using 10-20 mg in elderly provides a safer option that avoids the black box mortality warning of antipsychotics"],
    quiz: [{ question: "An NP is evaluating a patient for lecanemab therapy. Which test is required BEFORE initiating treatment?", options: ["Genetic testing for Huntington disease", "APOE4 genotyping and amyloid PET or CSF biomarkers to confirm amyloid pathology", "Lumbar puncture for tau levels only", "Liver biopsy"], correct: 1, rationale: "Lecanemab is approved for EARLY AD with CONFIRMED amyloid pathology. APOE4 genotyping stratifies ARIA risk (homozygotes 35% risk). Both amyloid confirmation and APOE4 status are required before initiating therapy." }, { question: "A family requests a feeding tube for their mother with advanced dementia who has stopped eating. The clinician should:", options: ["Place the feeding tube immediately", "Explain that tube feeding in advanced dementia does NOT improve outcomes and recommend careful hand-feeding with comfort-focused care", "Refuse to discuss the topic", "Order parenteral nutrition instead"], correct: 1, rationale: "All major medical societies recommend AGAINST tube feeding in advanced dementia. Tube feeding does not prevent aspiration (patients aspirate oral secretions regardless), does not improve survival, and reduces comfort. Careful hand-feeding provides equal or better outcomes." }, { question: "A patient with suspected Lewy body dementia is severely agitated. Which antipsychotic consideration is CRITICAL?", options: ["Give haloperidol 5 mg IM for rapid sedation", "LBD patients have EXTREME neuroleptic sensitivity; haloperidol is contraindicated; if needed, use the lowest dose of quetiapine", "All antipsychotics are equally safe in LBD", "Antipsychotics are always the first-line for LBD agitation"], correct: 1, rationale: "Lewy body dementia patients have extreme neuroleptic sensitivity that can cause life-threatening rigidity, obtundation, and autonomic collapse. Haloperidol and other potent D2 blockers are contraindicated. If an antipsychotic is absolutely necessary, quetiapine at the lowest possible dose is the safest option." }]
  }
};
